_GH_REPO  = "nocompharrison/MLB-HR-Model"   # e.g. "hlee145/mlb-model-files"
def _load_gh_token() -> str:
    # 1. Try environment variable (works in terminal)
    token = os.environ.get("GITHUB_TOKEN", "")
    if token:
        print(f"  🔑 GitHub token loaded from environment variable")
        return token
    # 2. Fall back to .env file — check multiple locations robustly
    # __file__ can be a relative or temp path when called from Excel, so resolve all candidates
    candidates = []
    try:
        candidates.append(Path(__file__).resolve().parent / "github_token.env")
    except Exception:
        pass
    try:
        candidates.append(Path(os.path.abspath(__file__)).parent / "github_token.env")
    except Exception:
        pass
    # Also check current working directory (Excel may set cwd to script folder)
    candidates.append(Path(os.getcwd()) / "github_token.env")

    for env_file in candidates:
        print(f"  🔍 Looking for token at: {env_file}")
        if env_file.exists():
            for line in env_file.read_text().splitlines():
                line = line.strip()
                if line.startswith("GITHUB_TOKEN="):
                    token = line.split("=", 1)[1].strip()
                    if token:
                        print(f"  🔑 GitHub token loaded from: {env_file}")
                        return token
    print(f"  ⚠️  github_token.env not found in any of: {[str(c) for c in candidates]}")
    return ""

_GH_TOKEN = _load_gh_token()
# ─────────────────────────────────────────────────────────────────────────────

def _github_upload(local_path: str, repo_path: str) -> bool:
    """
    Upload a single file to a private GitHub repo via the REST API.
    Creates the file if it doesn't exist; updates (replaces) it if it does.
    Returns True on success, False on failure.
    """
    if not _GH_TOKEN:
        print(f"  ⚠️  GitHub upload skipped — GITHUB_TOKEN env variable not set.")
        return False

    local_path = Path(local_path)
    if not local_path.exists():
        print(f"  ⚠️  GitHub upload skipped — file not found: {local_path}")
        return False

    api_url = f"https://api.github.com/repos/{_GH_REPO}/contents/{repo_path}"
    headers = {
        "Authorization": f"token {_GH_TOKEN}",
        "Accept": "application/vnd.github+json",
        "Content-Type": "application/json",
    }

    # Read and encode file content
    with open(local_path, "rb") as f:
        content_b64 = base64.b64encode(f.read()).decode("utf-8")

    # Check if file already exists (need its SHA to update)
    sha = None
    try:
        req = urllib.request.Request(api_url, headers=headers, method="GET")
        with urllib.request.urlopen(req) as resp:
            existing = json.loads(resp.read())
            sha = existing.get("sha")
    except urllib.error.HTTPError as e:
        if e.code != 404:
            print(f"  ⚠️  GitHub GET error ({e.code}): {e.reason}")
            return False
        # 404 = file doesn't exist yet, that's fine

    # Build PUT payload
    payload = {
        "message": f"Auto-update {repo_path} — {datetime.now().strftime('%Y-%m-%d %H:%M')}",
        "content": content_b64,
    }
    if sha:
        payload["sha"] = sha  # required for updates

    try:
        data = json.dumps(payload).encode("utf-8")
        req = urllib.request.Request(api_url, data=data, headers=headers, method="PUT")
        with urllib.request.urlopen(req) as resp:
            result = json.loads(resp.read())
            action = "Updated" if sha else "Created"
            print(f"  ✅ GitHub {action}: {repo_path}")
            return True
    except urllib.error.HTTPError as e:
        body = e.read().decode("utf-8", errors="replace")
        print(f"  ⚠️  GitHub PUT error ({e.code}): {body[:200]}")
        return False
    except Exception as e:
        print(f"  ⚠️  GitHub upload error: {e}")
        return False


def _upload_to_github(excel_path: str) -> None:
    """
    Upload the daily Excel output and the model Python file to GitHub.
    Called at the end of main() after export_excel() completes.
    """
    print("\n── GitHub Auto-Upload ─────────────────────────────────────────────")
    # Upload today's Excel output
    _github_upload(excel_path, f"outputs/{Path(excel_path).name}")
    # Upload the model source file itself
    _github_upload(__file__, "mlb_hr_model.py")
    print("──────────────────────────────────────────────────────────────────\n")
    
