# ── Hit Score gate for HR scoring (Rec #5) ────────────────────────────────────
# Batters with hit score < this threshold get a soft score penalty.
# Audit: contact is a prerequisite for HRs. Very low hit scores (< 20) are a
# strong fade signal — batter is cold or facing a suppressive matchup.
# ── HitScore zones for HR scoring ────────────────────────────────────────────
# Jun 21 2026 revision: HS zones are INFORMATIONAL only — no conv adjustments.
# Jun 20 post-mortem suggested HS 5-10 boost (+3) and 30-50 fade (-3).
# Jun 21 data reversed this: 0/28 HR getters in HS 5-10; 19/28 in HS 30-50.
# The HS 30-50 zone is the MODAL HR zone, not a fade. Reverted to neutral.
HR_HIT_SCORE_GATE      = 20.0   # below this = mild informational note (no penalty)
HR_HIT_SCORE_GATE_HARD = 10.0   # below this = stronger informational note (no penalty)
HR_HS_BOOST_ZONE_LO    = 5.0    # HS 5-10: informational only (unconfirmed boost)
HR_HS_BOOST_ZONE_HI    = 10.0   # HS 5-10 upper bound
HR_HS_FADE_ZONE_LO     = 30.0   # HS 30-50: informational only (disproven fade)
HR_HS_FADE_ZONE_HI     = 50.0   # HS 30-50 upper bound
# ── Power Floor (Jun 21 2026 revision) ───────────────────────────────────────
# Jun 20: Power ≥ 78 was universal (19/19). Jun 21: Ward (73.4, T3 BBE) HRed.
# Revised: Power ≥ 73 captures 27/28 HR getters across 3 slates.
# Langford (48.3, model PASS) remains correctly excluded by conv floor.
HR_POWER_FLOOR         = 73.0   # revised from 78.0 after Jun 21 evidence

# ── Form / Hit-rate mismatch dampener (Rec #2) ────────────────────────────────
# Caps the HR frequency boost when the batter's recent hit rate is low.
# A player with high power but near-zero contact rate is likely slumping
# or facing a tough pitcher — the HR boost should be capped regardless of
# power numbers.  Applied only when _hr_freq_boost would otherwise boost rate.
FORM_HIT_MISMATCH_L5_THRESHOLD = 0.17   # L5 hit rate below this = mismatch
FORM_HIT_MISMATCH_WHR_THRESHOLD = 0.30  # weighted HR rate below this = mismatch

# ── Opponent HR suppression (Rec #3) ─────────────────────────────────────────
# When the starting pitcher has a low HR/9 (genuinely HR-suppressive arm),
# dampen the HR probability even if overall vuln score is moderate.
# Addresses the "Gore paradox": low HR/9 pitchers keep vuln moderate but
# the model still assigns 20-25% HR prob due to other factors.
OPP_HR9_SUPPRESSION_THRESHOLD  = 0.85   # HR/9 below this = suppressive pitcher
OPP_HR9_SUPPRESSION_RATE_DAMP  = 0.88   # rate multiplier when suppressive
OPP_HR9_SUPPRESSION_SCORE_DAMP = -4.0   # score penalty when suppressive


# ── Signal Score — data-validated across 332 picks / 14 slates ───────────────
# Updated from 13-slate version. Key changes:
#   StrongPM alone removed (decayed 1.32x → 0.74x)
#   PM+HotContact removed (0.65x, below baseline)
#   PM+PowerPark removed (0.94x, no edge)
#   Prob gate added: Sig≥8 capped at 7 when hr_prob < 0.165
#
# 14-slate validated combo HR rates:
#   PM+VulnSweet+Sc40  → 58.3%  (3.03x)
#   PM+Pwr63+Sc40      → 57.1%  (2.93x)  [proxy from 13-slate, directionally confirmed]
#   PM+Sc40            → 55.0%  (2.82x)
#   EliteArm+Pwr63     → 36.4%  (1.89x)
#   PM+EliteArm        → 36.4%  (1.89x)
#   PM+HC+Pwr63        → 30.0%  (1.56x)
#   Pwr63+Sc40         → 47.1%  (2.42x)
#   HIGH_VULN (≥52)    → 10.8%  (0.55x) — TRAP
#   COLD (HS<20)       →  8.7%  (0.45x) — FADE

def compute_signal_score(sc):
    """
    Compute a 0-20 integer signal score and identify the best historical combo.
    Returns (signal_score: int, combo_label: str, combo_hr_rate: str).
    sc: HRScore object with all fields populated.

    14-SLATE CALIBRATION UPDATE (332 picks):
    ─────────────────────────────────────────────────────────────────────────────
    Changes from 13-slate version:
      REMOVED StrongPM alone (decayed 1.32x→0.74x — overfitted to early slates)
      REMOVED PM+HOT_CONTACT (12.5% HR rate, 0.65x — below baseline)
      REMOVED PM+PowerPark (18.2% HR rate, 0.94x — no edge)
      ADDED  prob gate ≥0.165 for Sig≥8: below this threshold, cap at 7 regardless
             of combo. Gate 0.165 splits: above=41.3%(2.14x), below=16.7%(0.86x)
    Validated combo HR rates (332 picks, 14 slates):
      PM+VulnSweet+Sc40  → 58.3%  (3.03x)  [confirmed]
      EliteArm+Pwr63     → 36.4%  (1.89x)  [confirmed]
      PM+HC+Pwr63        → 30.0%  (1.56x)  [confirmed]
      PM alone           → 14.3%  (0.74x)  [REMOVED as standalone]
      PM+HC              → 12.5%  (0.65x)  [REMOVED]
      PM+PowerPark       → 18.2%  (0.94x)  [REMOVED]
    """
    pm    = sc.pitch_matchup_score
    vuln  = sc.pitcher_vuln
    park  = sc.park_factor
    power = sc.batter_power
    score = sc.score
    hs    = sc.hit_score
    prob  = sc.hr_probability


    # ── Boolean signal flags ──────────────────────────────────────────────────
    ELITE_PM    = pm >= 1.07                    # validated: ~31% HR rate, 1.60x
    STRONG_PM   = pm >= 1.04                    # in combo: 30-58%; standalone: 0.74x
    ELITE_ARM   = vuln < 44.0                   # 36.4% HR rate, 1.89x (elite arm paradox)
    VULN_SWEET  = 48.0 <= vuln <= 52.0          # valuable in 3-signal combo only
    HIGH_VULN   = vuln >= 52.0                  # 10.8% HR rate — market trap
    POWER_PARK  = park >= 1.15                  # in strong combo only; standalone ~baseline
    POWER_63    = power >= 80.0                 # 28.2% HR rate in combo context (recal Jun 14 2026: 63→80)
    POWER_60    = power >= 78.0                 # minimum for sharp combo (recal Jun 14 2026: 60→78)
    SCORE_40_45 = 37.0 <= score < 45.0   # lowered 40→37 after double-count fix (May 14)          # 27.6% HR rate, 1.42x (sweet spot)
    SCORE_HIGH  = score >= 50.0                 # top-tier score (27.6% HR, 1.48x after calibration)
    HOT_CONTACT = hs >= 40.0                    # contact quality — in 3-signal combo
    COLD        = 0 < hs < 20.0                 # 8.7% HR rate — strong fade signal
    # Probability gate: Sig>=8 only awarded when underlying prob is meaningful.
    # Gate 0.165 data: above=41.3%(2.14x), below=16.7%(0.86x) across 70 picks.
    # Jun 13 2026 backtest: gated picks (HR prob <14.5%) hit 21.1% (1.35x baseline).
    # The gate was cutting legitimate picks. Colt Emerson at 16.0% — 0.5% below gate — HRed.
    # Lowered from 16.5% → 14.5%: picks at 14.5-16.5% are real picks, not longshots.
    PROB_GATE   = prob >= 0.145

    # ── User-identified Sharp Combo (May 14 analysis) ─────────────────────────
    # All HR hitters for the week had: Mkt≥1.06 + PM≥1.04 + Vuln 48-52 + Pwr≥78 + vs_opp>55%
    # Historical validation: PM+Vuln48-52+Pwr≥60 = 22.2% HR (1.26x). Mkt+vs_opp gate higher.
    # Vuln 52-56 EXCLUDED — that combination collapses to 0.57x (trap pitcher inflates Mkt signal).
    _mkt = sc.market_signal if hasattr(sc, "market_signal") else 0.0
    _vs_opp_pct = 0.0
    # vs_opp note lives in sc.hit_notes (set by compute_hit_score), not sc.notes
    # Must search BOTH lists to find it
    _all_notes = list(sc.notes or []) + list(sc.hit_notes or [])
    for _n in _all_notes:
        import re as _re
        _m = _re.search(r'vs opponent.*?(\d+)%', str(_n), _re.IGNORECASE)
        if _m: _vs_opp_pct = float(_m.group(1)); break
        _m2 = _re.search(r'Hits well.*?(\d+)%', str(_n), _re.IGNORECASE)
        if _m2: _vs_opp_pct = float(_m2.group(1)); break
        _m3 = _re.search(r'Elite vs opponent.*?(\d+)%', str(_n), _re.IGNORECASE)
        if _m3: _vs_opp_pct = float(_m3.group(1)); break
    # PM gate slightly relaxed: 1.035 captures Kurtz (1.039) which is functionally
    # equivalent to 1.04. STRONG_PM (>=1.04) remains for all other combo checks.
    SHARP_COMBO = (pm >= 1.035 and VULN_SWEET and POWER_60 and
                   _mkt >= 1.06 and _vs_opp_pct >= 55.0)   # >= not > for exact 55%

    pts = 0
    best_combo = ""
    best_rate  = ""
    best_pts   = 0

    # ── Step 1: Identify best historical combo (22-slate validated) ──────────
    # ONLY combos with confirmed lift in the 22-slate dataset are included.
    # Previous version had inverted signal (Sig 3-5 = 0% HR, Sig 9-12 = 0.75x).
    # Root cause: combos were firing on Vuln44-48 picks which have 0.75x HR rate.
    # New combo set anchored to actual 22-slate data:
    #
    # Validated combos (22 slates, 620 picks):
    #   Score≥65:                     33.3% HR (2.05x)  ← most reliable
    #   Score≥40+PM1.04-1.06+Pwr≥78:  28.2% HR (1.73x)  ← best multi-signal
    #   Score≥40+PM1.05-1.06:          29.2% HR (1.79x)  ← PM sweet spot
    #   Rank1-3+Score≥50:              33.8% HR (2.08x)  ← rank anchor
    #   Current SHARP+Score≥40:        26.7% HR (1.64x)  ← sharp validated
    #   Vuln<44 (Elite Arm):           17.9% HR (1.10x)  ← mild signal only
    # 
    # REMOVED from previous version (no longer validated):
    #   PM+VulnSweet+Score40-45:  was citing 58% but contaminated by Vuln44-48 picks
    #   PM+Power63+Score40-45:    was citing 66% — small sample, not reproducing
    #   PM alone combos:           consistently ≤baseline in 22-slate data
    #
    # NOTE: PM sweet spot is 1.04-1.06 only. PM≥1.06 reverts to baseline.
    # Using STRONG_PM (≥1.04) as boolean is no longer correct — split it.
    PM_SWEET = (1.04 <= pm < 1.06)   # 22-38 pts HR lift — the real sweet spot
    PM_HIGH  = (pm >= 1.06)          # essentially baseline or worse above here

    if SHARP_COMBO:
        best_combo = "🎯 SHARP: Mkt≥1.06+PM≥1.035+Vuln48-52+Pwr≥78+vs_opp≥55%"
        best_rate  = "26.7% HR (1.63x) — all 5 signals confirmed"
        best_pts   = 15
    elif PM_SWEET and POWER_60 and SCORE_HIGH:
        best_combo = "PM 1.04-1.06 + Power≥60 + Score≥50"
        best_rate  = f"{_grade_rate('signal_combo_hr','24.5%  est')} AT (signal-combo)"
        best_pts   = 12
    elif PM_SWEET and POWER_60 and SCORE_40_45:
        best_combo = "PM 1.04-1.06 + Power≥60 + Score 40-45"
        best_rate  = f"{_grade_rate('signal_combo_hr','24.5%  est')} AT (signal-combo)"
        best_pts   = 11
    elif PM_SWEET and VULN_SWEET and SCORE_HIGH:
        best_combo = "PM 1.04-1.06 + Vuln Sweet(48-52) + Score≥50"
        best_rate  = f"{_grade_rate('signal_combo_hr','~22%  est')} AT (signal-combo)"
        best_pts   = 10
    elif PM_SWEET and VULN_SWEET and SCORE_40_45:
        best_combo = "PM 1.04-1.06 + Vuln Sweet(48-52) + Score 40-45"
        best_rate  = f"{_grade_rate('signal_combo_hr','~22%  est')} AT (signal-combo)"
        best_pts   = 9
    elif PM_SWEET and SCORE_HIGH:
        best_combo = "PM 1.04-1.06 + Score≥50"
        best_rate  = f"{_grade_rate('signal_combo_hr','~20%  est')} AT (signal-combo)"
        best_pts   = 8
    elif PM_SWEET and SCORE_40_45:
        best_combo = "PM 1.04-1.06 + Score 40-45"
        best_rate  = f"{_grade_rate('signal_combo_hr','~20%  est')} AT (signal-combo)"
        best_pts   = 7
    elif POWER_63 and SCORE_HIGH:
        best_combo = "Power≥63 + Score≥50"
        best_rate  = f"{_grade_rate('signal_combo_hr','20.1%  est')} AT (signal-combo)"
        best_pts   = 7
    elif POWER_63 and SCORE_40_45:
        best_combo = "Power≥63 + Score 40-45"
        best_rate  = f"{_grade_rate('signal_combo_hr','19.3%  est')} AT (signal-combo)"
        best_pts   = 6
    # REMOVED: ELITE_ARM alone — 23-slate data: Vuln<44 = 1.01x HR (exactly baseline)
    # Sub-ranges: Vuln38-40=0.73x, Vuln42-44=0.86x — actually below baseline
    # The "Elite Arm Paradox" premise is false over 115 picks. No signal.
    # Removed: PM+EliteArm alone, PM+HC, PM+PowerPark, ELITE_PM alone

    pts += best_pts

    # ── Step 2: Additional signal points not captured by combo ────────────────
    # Trimmed based on 22-slate audit — only keep signals with confirmed lift
    # REMOVED: ELITE_ARM bonus (+2) — 23-slate data shows 1.01x HR (baseline). No edge.
    if POWER_PARK and "Power Park" not in best_combo: pts += 1   # park matters in combo

    # BZM: pull matchup edge — independent signal (keep, it fires on real matchups)
    _notes_str = " ".join(sc.notes) if hasattr(sc, "notes") and sc.notes else ""
    if "BZM: pull matchup edge" in _notes_str: pts += 3

    # vs_opp HR rate via notes (Owns/Hits well = strong independent signal)
    if "Owns this pitcher" in _notes_str:            pts += 4
    elif "Hits well vs this pitcher" in _notes_str:  pts += 2
    elif "Hits well vs this opponent" in _notes_str: pts += 2

    # REMOVED: ELITE_PM alone (+2), SCORE_40_45 alone (+2), HOT_CONTACT (+1)
    # These were adding noise without confirmed HR lift in 22-slate data

    # ── Individual pitch-type edge signal (June 2026) ────────────────────────
    # When a batter has a confirmed individual pitch-type crush (SL/CU/CH/ST/SI/FC/FF)
    # AND that pitch is the pitcher's primary weapon (≥20% usage), award signal pts.
    # This is independent of PitchMix wOBA — it captures the "Cruz vs Teng sweeper"
    # scenario where one specific pitch is the mechanism, not the overall mix.
    # Gates: must have a 💥 edge flag (wOBA edge ≥0.100 or barrel% ≥15%) to count.
    # +2 pts for confirmed individual pitch crush; +1 for strong (but not elite) edge.
    _notes_for_sig = " ".join(sc.notes) if hasattr(sc, "notes") and sc.notes else ""
    _has_elite_pitch_crush = any(
        f in _notes_for_sig for f in
        ("Crushes slider", "Crushes curveball", "Crushes changeup",
         "Handles sweeper", "Crushes sinkers", "Crushes cutters", "Crushes four-seamers")
    )
    _has_good_pitch_edge = any(
        f in _notes_for_sig for f in
        ("Good vs slider", "Good vs curveball", "Good vs changeup",
         "Good vs four-seamer", "Good vs sinker")
    )
    # Only award if pitch edge isn't already captured by the main combo (avoids double-counting)
    if _has_elite_pitch_crush and "SHARP" not in best_combo and "PM 1.04-1.06" not in best_combo:
        pts += 2   # specific pitch mechanism confirmed — meaningful independent lift
    elif _has_good_pitch_edge and "SHARP" not in best_combo and PM_SWEET and pm < 1.07:
        pts += 1   # supporting evidence — only relevant in the sweet PM zone

    # Power 65+ & Vuln 36-44 & PM ≥1.05 — "elite power vs average arm" boost
    # Backtest (June 2026, n=36): Power65+&Vuln38-44 = 27.8% HR (1.83x baseline).
    # The Schwarber archetype: truly elite barrel power against a pitcher who is
    # soft-to-moderate (Vuln36-44). Requires PM≥1.05 to confirm pitch-mix edge.
    # Note: Vuln42-44 (VULN_HARD) applies a -3 pts penalty, so the net for that
    # sub-range is -1 pts — intentional, those are the weakest picks in the combo.
    # Vuln44-45 is now a POSITIVE zone (1.32x) so this combo window caps at 45.
    _pwr65_lowvuln = (power >= 81.0 and 36.0 <= vuln < 44.0 and pm >= 1.05)
    if _pwr65_lowvuln and "Power≥63" not in best_combo and "SHARP" not in best_combo:
        pts += 2
        # Surface in notes if available
        if hasattr(sc, "notes") and sc.notes is not None:
            sc.notes.append(f"💪 Elite power ({power:.0f}) vs avg arm (Vuln {vuln:.0f}) + PM {pm:.3f} — 1.83x HR hist (+2 sig pts)")

    # ── Step 3: Bonuses and Penalties ─────────────────────────────────────────
    # Vuln48-52 + Power≥60 + Park≥0.95 = 28.8% HR (1.68x, 24-slate, n=139) — strongest non-SHARP combo
    POWER_60 = power >= 78.0
    if VULN_SWEET and POWER_60 and park >= 0.95:
        pts += 2   # validated: park filters for quality + Vuln48-52 is genuine sweet zone

    if HIGH_VULN:                    pts -= 3   # Vuln52-56 = 9.3% HR (0.57x) — trap
    if COLD:                         pts -= 3   # WHR<20 in HS = 0.53x HR
    # Recalibrated vuln penalties (June 2026 granular backtest, 1-unit bins):
    # Vuln 42-44: 0.68x flat — genuine trap, PM does NOT rescue (PM≥1.04&Vuln42-44=0.77x)
    # Vuln 44-45: 1.32x POSITIVE — NOT a trap, removed from penalty window
    # Vuln 45-48: 0.90x flat (mild), BUT Score60+&Vuln45-48 = 0/17 HR (0.00x) — confirmed trap
    VULN_HARD       = 42.0 <= vuln < 44.0   # always penalized regardless of score
    VULN_HIGH_TRAP  = 45.0 <= vuln < 48.0   # only penalized when score >= 60
    VULN_4448       = VULN_HARD or VULN_HIGH_TRAP  # combined flag for output/display
    if VULN_HARD:
        pts -= 3   # 0.68x flat, -3 pts (was -2/-4; increased since PM doesn't rescue)
    if VULN_HIGH_TRAP and score >= 60.0:
        pts -= 3   # Score60+&Vuln45-48 = 0/17 HR; no penalty below 60

    # ── Step 4: Probability gate for high-signal tiers ───────────────────────
    # SHARP_COMBO exempt from prob gate — the combo itself validates the pick
    if pts >= 8 and not PROB_GATE and not SHARP_COMBO:
        pts = min(pts, 7)

    pts = max(0, min(20, pts))
    return pts, best_combo, best_rate

