# ── Rec #4: Upset profile loader ──────────────────────────────────────────────
# The upset builder (mlb_hr_upset_builder.py) writes a JSON file with per-player
# LA-spike and upset-score data. The model loads the most recent file at startup.
# If no file exists, the feature is silently disabled (no crash).
UPSET_PROFILE_SCORE_BOOST   = 8.0   # max score pts added for a pure LA-spike flag
UPSET_PROFILE_RATE_BOOST    = 1.12  # rate multiplier for high-upset-score batters
UPSET_SCORE_THRESHOLD       = 70.0  # above this → apply rate boost
# Raised 60→70 (May 8 audit: 60 let too many false positives through;
# only players with score ≥70 showed meaningful upset HR signal)
UPSET_LA_SPIKE_MIN           = 4.0  # degrees of LA spike to trigger a note

def load_upset_profiles() -> dict:
    """
    Load the most recent upset_profiles_YYYY-MM-DD.json from OUTPUT_DIR.
    Returns dict keyed by player_id (int) or {} if none found.
    Looks back up to 3 days to handle days where the builder wasn't run.
    """
    for days_back in range(0, 4):
        d = date.today() - timedelta(days=days_back)
        path = OUTPUT_DIR / f"upset_profiles_{d.strftime('%Y-%m-%d')}.json"
        if path.exists():
            try:
                with open(path) as f:
                    raw = json.load(f)
                # Keys may be strings from JSON — normalise to int
                profiles = {int(k): v for k, v in raw.items()}
                print(f"  ⚡ Upset profiles loaded: {len(profiles)} players "
                      f"({path.name})")
                return profiles
            except Exception as e:
                print(f"  ⚠️ Could not load upset profiles ({path.name}): {e}")
    return {}

