# ── Shared player-name key for ActionNetwork odds matching ────────────────────
# Builds "{lastname}_{first3offirst}". Must be used IDENTICALLY when building the
# odds dict (loader) and when looking a batter up, or keys drift apart.
# Fixes (Jun 2026): (1) strip generational suffixes — "Vladimir Guerrero Jr."
# was keying to "jr_vla" instead of "guerrero_vla", silently dropping every
# Jr./Sr. player's odds; (2) transliterate accents (José→jose, García→garcia)
# instead of deleting the accented letter, which had turned "García" into "garca".
_AN_NAME_SUFFIXES = {"jr", "sr", "ii", "iii", "iv"}
def _an_name_key(name) -> str:
    import unicodedata as _ud, re as _re_an
    s = _ud.normalize("NFKD", str(name or "")).encode("ascii", "ignore").decode()
    s = _re_an.sub(r"[^a-zA-Z\s]", " ", s).lower().split()
    s = [t for t in s if t not in _AN_NAME_SUFFIXES]
    return f"{s[-1]}_{s[0][:3]}" if len(s) >= 2 else "".join(s)

