_sgo_balance_before: Optional[int] = None   # balance before first SGO call this run

def _track_credits(used=1, label: str = ""):
    """
    Track SGO API credit usage. NOTE: SGO charges per player-prop record returned,
    not per API call — so 'used' here counts API calls, not actual credits consumed.
    Real credit consumption is shown at the end of the Vegas section via balance diff.
    """
    global _credits_used
    _credits_used += used
    tag = f" ({label})" if label else ""
    if _credits_used >= 2500:
        raise RuntimeError(f"SGO monthly credit limit reached ({_credits_used}/2500). "
                           "No more SGO calls will be made this month.")
    if _credits_used >= 2000:
        print(f"  ⚠️  💳 SGO API calls this run: {_credits_used}{tag} — approaching monthly limit!")

def fetch_sgo_credit_balance() -> Optional[int]:
    """
    Call SportsGameOdds v2 /account/usage endpoint to get remaining monthly credits.
    Returns remaining credits as int, or None if unable to fetch.
    Uses v2 API with x-api-key header (per SGO docs).
    """
    import urllib.request, json
    url = "https://api.sportsgameodds.com/v2/account/usage"
    req = urllib.request.Request(
        url,
        headers={
            "x-api-key": SPORTSGAMEODDS_KEY,
            "Accept": "application/json",
            "User-Agent": "Mozilla/5.0",
        }
    )
    try:
        with urllib.request.urlopen(req, timeout=10) as resp:
            data = json.loads(resp.read().decode("utf-8"))
            if data.get("success") and "data" in data:
                limits = data["data"].get("rateLimits", {}).get("per-month", {})
                current = limits.get("current-entities")
                max_val = limits.get("max-entities")
                if current is not None and max_val is not None:
                    return int(max_val) - int(current)
            return None
    except Exception as e:
        print(f"  ⚠️  Could not fetch SGO credit balance: {e}")
        return None
        
