# ============================================================
# ── DATA CLASSES ─────────────────────────────────────────────
# ============================================================

@dataclass
class BatterProfile:
    name: str
    team: str
    hand: str
    lineup_spot: int      = 4
    # Defaults = true MLB league averages (so missing-data players score ~50, not 100)
    iso: float            = 0.145
    savant_id: int        = 0    # Baseball Savant player ID (for batter-vs-pitcher lookups)
    barrel_pct: float     = 7.5
    hard_hit_pct: float   = 36.5
    avg_ev: float         = 87.5
    sweet_spot_pct: float = 29.0
    fb_pct: float         = 34.0
    pull_air_pct: float   = 16.0
    pull_brl_pct: float   = 0.0    # Season PullBrl% from Savant leaderboard (pull_brl_percent)
    hr_fb_pct: float      = 11.5
    xslg: float           = 0.390
    xwoba: float          = 0.315
    xiso:  float          = 0.145
    xwoba_contact: float  = 0.355   # xwOBAcon: contact quality removing Ks (Savant)   # expected ISO (from Statcast EV/LA) — purer power than observed ISO
    xwoba_contact: float  = 0.355   # xwOBAcon: contact quality removing strikeouts (Savant)
    # Better than xwOBA for HR prediction — isolates what happens when batter makes contact
    woba_vs_fastball: float = 0.320   # FF+SI+FC combined (used as fallback)
    woba_vs_breaking: float = 0.280   # SL+CU+ST combined
    woba_vs_offspeed: float = 0.295   # CH+FS combined
    # Sub-type splits (more specific — Trout vs sinker vs cutter are very different)
    woba_vs_sinker:   float = 0.0     # 0 = unknown, fall back to woba_vs_fastball
    woba_vs_cutter:   float = 0.0     # 0 = unknown
    woba_vs_fourseam: float = 0.0     # 0 = unknown
    woba_vs_sweeper:  float = 0.0     # 0 = unknown (ST pitch type)
    # ── Individual breaking/offspeed wOBA splits (June 2026) ─────────────────
    # Previously only tracked as grouped (woba_vs_breaking, woba_vs_offspeed).
    # The Toad Sports / Barrel Boyz methodology requires per-pitch splits to surface
    # Cruz's 100% barrel on sweeper vs 27% on slider — impossible with aggregates.
    woba_vs_slider:   float = 0.0     # SL — 0 = fall back to woba_vs_breaking
    woba_vs_curveball: float = 0.0    # CU/KC — 0 = fall back to woba_vs_breaking
    woba_vs_changeup: float = 0.0     # CH/FS — 0 = fall back to woba_vs_offspeed
    # Per-pitch barrel% for batter (individual, not grouped)
    barrel_pct_vs_slider:   float = 0.0   # SL barrel% (0 = use vs_breaking)
    barrel_pct_vs_curveball: float = 0.0  # CU barrel% (0 = use vs_breaking)
    barrel_pct_vs_changeup: float = 0.0   # CH barrel% (0 = use vs_offspeed)
    barrel_pct_vs_sweeper:  float = 0.0   # ST barrel% (0 = use vs_breaking)
    # Per-pitch HR/PA for batter
    hr_pa_vs_slider:    float = 0.0   # 0 = use vs_breaking proxy
    hr_pa_vs_curveball: float = 0.0
    hr_pa_vs_changeup:  float = 0.0
    hr_pa_vs_fourseam:  float = 0.0   # 0 = use vs_fastball proxy
    hr_pa_vs_sinker:    float = 0.0
    # ── Platoon wOBA splits (vs RHP / LHP) ───────────────────────────────────
    # Season wOBA split by pitcher hand — 50-100pt splits are common.
    # Alvarez/Judge-type batters are notable for minimal platoon splits.
    woba_vs_rhp: float = 0.0    # overall wOBA vs right-handed pitchers (0 = not loaded)
    woba_vs_lhp: float = 0.0    # overall wOBA vs left-handed pitchers (0 = not loaded)
    slg_vs_sinker:    float = 0.0     # SLG vs sinker (power indicator)
    slg_vs_cutter:    float = 0.0     # SLG vs cutter
    slg_vs_fourseam:  float = 0.0     # SLG vs four-seam
    barrel_pct_vs_fastball: float = 9.0
    barrel_pct_vs_breaking: float = 7.0
    barrel_pct_vs_offspeed: float = 6.5
    # Tier 1 upgrade: per-pitch-type damage metrics (EV, SLG, HR/PA)
    # Sourced from Statcast pitch-type splits via _fetch_via_statcast_agg
    ev_vs_fastball:      float = 87.5   # avg EV on contacted fastballs
    ev_vs_breaking:      float = 86.0   # avg EV on contacted breaking balls
    ev_vs_offspeed:      float = 85.5   # avg EV on contacted offspeed
    hr_rate_vs_fastball: float = 0.040  # HR/PA vs fastballs (league avg)
    hr_rate_vs_breaking: float = 0.025  # HR/PA vs breaking
    hr_rate_vs_offspeed: float = 0.028  # HR/PA vs offspeed
    # Tier 2 upgrade: pitch-location zone damage
    # Fraction of pitches batter damages in each zone (heart/shadow/chase)
    zone_contact_rate:   float = 0.78   # contact rate on in-zone pitches
    heart_zone_slg:      float = 0.520  # SLG on heart-of-plate pitches
    # ── 2D pitch-location zone grid (9 horizontal × 5 vertical zones) ─────────
    # HR% by Savant zone — built from batted-ball plate_x/plate_z at startup.
    # None = not loaded; falls back to heart_zone_slg proxy (existing behavior).
    zone_hr_grid:  object = None  # np.ndarray shape (9,5) or None
    # Zone grid multiplier pre-computed in score_player (1.0 = league avg)
    zone_grid_mult: float = 1.0
    recent_barrel_pct: float = 7.5
    recent_ev: float         = 87.5
    recent_hard_hit_pct: float = 36.5  # last-14-day hard hit % (fix 3)
    # ── Rolling xStats — expected stats from recent form (Suggestion #4) ──────
    # More stable than raw WHR: measures contact quality regardless of luck
    # xwOBA 0.315 = league avg; xSLG 0.420 = league avg contact
    recent_xwoba: float = 0.315   # rolling 14-day xwOBA (0=not loaded, use season)
    recent_xslg:  float = 0.420   # rolling 14-day xSLG
    # ── L5-specific pitch-type contact quality (from fetch_recent_form) ───────
    # Image 1 signals: Jo Adell L5 vs LHP Four-seam = 106.4 EV, 60% barrel%
    # These update ev_vs_fastball etc. when fresh L5 data is available
    l5_ev_vs_fastball:      float = 0.0   # 0 = use season value
    l5_ev_vs_breaking:      float = 0.0
    l5_ev_vs_offspeed:      float = 0.0
    l5_barrel_vs_fastball:  float = 0.0   # barrel% in last 14 days vs fastballs
    l5_barrel_vs_breaking:  float = 0.0
    l5_barrel_vs_offspeed:  float = 0.0
    # ── Fly-ball carry distance (Propfinder distance signal, from fetch_recent_form) ──
    # Projected distance (ft) on true fly balls (LA 20-40) over the L14 window.
    # Used to test whether the batter physically reaches today's pull-side fence.
    recent_air_dist_avg:  float = 0.0   # mean fly-ball distance, ft (0 = no data)
    recent_air_dist_p90:  float = 0.0   # 90th-pct (top-end carry), ft (0 = no data)
    launch_angle_avg: float  = 10.5    # avg launch angle; HR zone = 20-35 deg
    launch_angle_hr_pct: float = 0.22  # fraction of batted balls in 20-35 deg band
    # Fix #5 proxy: zone contact damage (hard_hit% × xSLG relative to league avg)
    # Approximates "what damage does this batter do when he makes contact"
    zone_damage_score: float = 1.0    # >1.0 = above-avg zone damage, <1.0 = below
    # Fix #10 proxy: hitter's count approach (swing% in favorable counts)
    # Approximated from BB% + HR/FB: high BB% + high HR/FB = patient power hitter
    hitter_count_score: float = 1.0   # >1.0 = sells out for power in hitter counts
    split_factor: float      = 0.0
    hr_over_price: float     = 0.0
    hr_odds_source: str      = ""
    hr_line_movement: float  = 0.0
    hr_early_price: float     = 0.0   # baseline (snapshot) odds for line-movement display
    # ── DailyBatter sheet fields (FL matchup history vs specific pitcher) ─────
    # Scraped daily from FantasyLabsMLB DailyBatter sheet
    fl_hrf:          float = 0.0    # FL HR Factor — composite env (park+weather+wind) already computed
    fl_qab_pct:      float = 0.0    # Quality AB % vs this pitcher (0=not loaded)
    fl_hh_pct:       float = 0.0    # Hard Hit % vs this pitcher (0=not loaded)
    fl_career_ab:    int   = 0      # Career AB vs this pitcher (sample size)
    fl_career_hr:    int   = 0      # Career HRs vs this pitcher — direct HR rate
    fl_career_ops:   float = 0.0    # Career OPS vs this pitcher (0=not loaded)
    fl_career_bb:    int   = 0      # Career BBs vs this pitcher
    hr_odds_source: str      = ""    # "FanDuel", "Consensus", "SGO", "OddsAPI"
    hr_line_movement: float  = 0.0   # positive = odds shortened (sharp money in)
    hr_line: float           = 0.5
    hits_over_price: float   = 0.0   # OddsAPI batter_hits market
    hits_line: float         = 0.5
    rbi_over_price: float    = 0.0   # OddsAPI batter_rbis
    tb_over_price: float     = 0.0   # OddsAPI batter_total_bases
    tb_line: float           = 1.5
    luck_regression: float = 1.0   # HR vs xHR differential: <1.0 = due for regression, >1.0 = positive regression
    recent_hr_rate:  float = 0.034  # HR/PA over last 15 days — used as same-team tiebreaker
    ev_consistency: float  = 1.0   # contact quality consistency: hard_hit% / sweet_spot% ratio
    k_pct: float = 0.220          # strikeout rate (league avg ~22%)
    k_vs_opp: float = 0.0         # K rate vs today's specific pitcher (0=unknown)
    k_vs_opp_ab: int = 0          # AB sample size for k_vs_opp (reliability gate)
    bb_pct: float = 0.085         # walk rate (league avg ~8.5%) — plate discipline proxy
    sprint_speed: float = 27.0    # Savant sprint speed ft/sec (league avg ~27). Fast=28+, Slow=<26
    # ── Squared-up and Blast rate (Image 1: SQUP%, BLAST%) ───────────────────
    squp_pct:  float = 27.5   # league avg ~27.5%
    blast_pct: float = 11.0   # league avg ~11%
    # ── L5/L10 hit rates ─────────────────────────────────────────────────────
    recent_hit_rate_l5:  float = 0.0   # hit rate last 5 games (0=unknown)
    recent_hit_rate_l10: float = 0.0   # hit rate last 10 games
    # ── Hand/home-road splits + L7 slugging (transcript signal additions) ───────
    slg_vs_rhp:      float = 0.0   # SLG% vs RHP (FanGraphs splits)
    slg_vs_lhp:      float = 0.0   # SLG% vs LHP
    hr_pct_vs_rhp:   float = 0.0   # HR/PA vs RHP
    hr_pct_vs_lhp:   float = 0.0   # HR/PA vs LHP
    wrc_plus_vs_rhp: int   = 0     # wRC+ vs RHP (100=avg; Barrel Boyz "wRHP% 147")
    wrc_plus_vs_lhp: int   = 0     # wRC+ vs LHP
    ba_vs_rhp:       float = 0.0   # batting average vs RHP (for display parity with image)
    ba_vs_lhp:       float = 0.0   # batting average vs LHP
    ba_home:         float = 0.0   # home BA
    ba_road:         float = 0.0   # road BA
    hr_count_vs_rhp: int   = 0     # count of HRs vs RHP ("10 of 11 vs RHP")
    hr_count_vs_lhp: int   = 0     # count of HRs vs LHP
    slg_home:        float = 0.0   # SLG% at home
    slg_road:        float = 0.0   # SLG% on road
    hr_home:         int   = 0     # HR count at home
    hr_road:         int   = 0     # HR count on road
    l7_slg:          float = 0.0   # SLG% last 7 days (power recency signal)
    l7_ba:           float = 0.0   # BA last 7 days
    l7_hr:           int   = 0     # HRs last 7 days
    # ── New stats from FantasyLabs batter view ────────────────────────────────
    near_hr_count: int   = 0      # near-HRs (hard-hit fly balls near wall) — power signal
    near_hr_pa:    int   = 0      # PA in which near_hr_count was accumulated
    gb_pct:        float = 44.0   # ground ball % (high GB% = fewer HRs; inverse of FB%)
    first_pitch_swing_pct: float = 0.0  # 1st pitch swing % (0=unknown; aggression signal)
    swstr_pct:  float = 0.0   # batter swinging strike % (high = harder to get hits; contact gate)
    meatball_swing_pct: float = 0.0  # % of meatballs swung at (aggression/awareness)

    # ── Rec #4: LA-spike / upset profile fields ───────────────────────────────
    # Populated from upset_profiles_YYYY-MM-DD.json (built by mlb_hr_upset_builder.py).
    # These fields capture sudden launch-angle shifts that the season-aggregate
    # barrel% / EV metrics are too slow to detect.
    upset_score:          float = 0.0   # 0-100 composite upset likelihood (from builder)
    la_spike:             float = 0.0   # recent 14d avg LA minus season avg LA (degrees)
    la_spike_flag:        bool  = False # True when la_spike >= LA_SPIKE_THRESHOLD (4°)
    la_hr_zone_pct_14d:   float = 0.22  # % of recent batted balls in 20-35° HR band
    la_hr_zone_pct_szn:   float = 0.22  # season average for comparison
    # ── Savant sheet fields (bat tracking + batted ball + mechanics) ───────────
    # Loaded daily from Savant sheet in workbook
    avg_bat_speed:        float = 73.8   # avg bat speed mph (league avg ~73.8)
    ideal_attack_angle_rate: float = 0.528  # % swings in 5-20° ideal HR window
    swing_tilt:           float = 32.0   # swing path tilt degrees
    attack_angle:         float = 10.0   # avg attack angle degrees
    blast_per_contact:    float = 0.324  # blasts per bat contact (barrel proxy)
    squared_up_per_contact: float = 0.245 # squared-up per bat contact (hit quality)
    batter_run_value:     float = 0.0    # season run value (negative = below avg)
    whiff_per_swing:      float = 0.20   # whiff rate (K risk proxy)
    pull_air_pct_savant:  float = 0.206  # pull fly ball rate (HR direction signal)
    pu_rate_savant:       float = 0.08   # popup rate (weak contact penalty)
    ld_rate_savant:       float = 0.24   # line drive rate (hit quality)
    hard_swing_rate:      float = 0.40   # fast swing rate (≥75mph)
    competitive_swing_pct: float = 0.902  # % competitive swings (discipline)

    @property
    def form_factor(self) -> float:
        """
        Multi-metric recent form factor (fix #14).
        Blends recent barrel%, EV trend, and hard-hit% trend.
        Weighted: barrel=50%, EV=30%, hard-hit=20%.
        """
        if self.barrel_pct == 0 or self.avg_ev == 0:
            return 1.0
        barrel_ratio  = self.recent_barrel_pct / max(self.barrel_pct, 0.1)
        ev_ratio      = self.recent_ev / max(self.avg_ev, 70.0)
        hh_ratio      = self.recent_hard_hit_pct / max(self.hard_hit_pct, 1.0)
        blended = 0.50 * barrel_ratio + 0.30 * ev_ratio + 0.20 * hh_ratio
        return max(0.70, min(blended, 1.40))

    @property
    def market_signal(self) -> float:
        """
        Composite market signal from HR odds, hits, and TB props.
        - HR price is the primary signal (direct bet on our outcome)
        - Short hits odds (-200+) = hot bat → secondary boost
        - High TB line (2.5+) = power expected → secondary boost
        Each source contributes proportionally; combined signal capped at 1.20 / 0.85.
        """
        def _implied(price):
            if price == 0: return None
            return (-price)/(-price+100) if price < 0 else 100/(price+100)

        signals = []

        # HR odds — primary signal (weight 1.5, center 0.18)
        # Center lowered from 0.38 to 0.18: HR odds range from ~+200 to +800,
        # giving implied probs of 11%-33%. 38% center made ALL signals negative.
        # 0.18 center (~+455 odds) = midpoint of typical HR-candidate range.
        # Weight raised from 1.0→1.5: market has consistently outperformed model.
        hr_imp = _implied(self.hr_over_price)
        if hr_imp is not None:
            signals.append((hr_imp - 0.18) * 0.50 * 1.5)   # centered at 18% implied

        # Hits over price — secondary signal (weight 0.50)
        hits_imp = _implied(self.hits_over_price)
        if hits_imp is not None:
            # INCREASED weight from 0.35 to 0.50 per audit
            # If odds are -110 or worse (imp >= 0.52), this starts to de-rate the score
            signals.append((hits_imp - 0.52) * 0.30 * 0.50)

        # RBI over price — tertiary signal (weight 0.20)
        # Sourced from RotoWire sheet (graceful fallback to 0 when not available).
        # RBI odds confirm run-scoring environment and batter's lineup protection.
        rbi_imp = _implied(self.rbi_over_price)
        if rbi_imp is not None:
            signals.append((rbi_imp - 0.42) * 0.25 * 0.20)   # center at ~42% implied 

        if not signals:
            return 1.0
        combined = sum(signals)
        # REMOVED the 1.25 cap to allow the market to aggressively de-rate "trap" streaks
        return max(0.70, 1.0 + combined)

        # Total bases line — tertiary signal (weight 0.25)
        # High TB line (2.5 vs 1.5 baseline) means power expected
        if self.tb_line > 0:
            tb_adj = (self.tb_line - 1.5) * 0.04 * 0.25   # 0.04 per 0.5 TB above avg
            signals.append(tb_adj)

        if not signals:
            return 1.0
        combined = sum(signals)
        return max(0.82, min(1.0 + combined, 1.25))   # wider range post-calibration


@dataclass
class PitcherProfile:
    name: str
    team: str
    hand: str
    # Defaults = true MLB league averages for pitchers
    savant_id:  int   = 0    # Baseball Savant player ID
    era: float  = 4.20
    whip: float = 1.30
    hr9: float  = 1.20
    barrel_pct_allowed: float   = 7.5
    hard_hit_pct_allowed: float = 36.5
    avg_ev_allowed: float       = 87.5
    fb_pct_allowed: float       = 35.0
    hr_fb_pct_allowed: float    = 11.5
    xera: float          = 4.20
    xslg_allowed: float  = 0.400
    xwoba_allowed: float = 0.315
    fastball_pct: float  = 55.0
    breaking_pct: float  = 25.0
    offspeed_pct: float  = 20.0
    recent_hr_factor: float = 1.0   # auto-set from L5 starts when data available
    # ── Last-5-starts window (auto-populated by fetch_pitcher_l5_starts) ──────
    # These are the recency window the video explicitly recommends alongside
    # current season + prior season for the three-window blend.
    l5_era:    float = 0.0   # ERA over last 5 starts (0=not loaded)
    l5_k9:     float = 0.0   # K/9 over last 5 starts
    l5_hr9:    float = 0.0   # HR/9 over last 5 starts  ← key HR predictor
    l5_bb9:    float = 0.0   # BB/9 over last 5 starts  ← command indicator
    l5_ip:     float = 0.0   # total IP across last 5 starts (sample size gate)
    # ── Last-2-starts window for extreme blowup detection ─────────────────────
    # When a pitcher allows 3+ HRs in their last 2 starts and that diverges
    # from their L5 avg by ≥2.0 HR/9, it signals an acute vulnerability that
    # the L5 average masks (e.g. Alcantara: L5=1.57 but 5 HRs in last 2 starts).
    l2_hr9:    float = 0.0   # HR/9 over last 2 starts only (0=not loaded)
    l2_ip:     float = 0.0   # total IP across last 2 starts
    first_start_of_season: bool = False   # True when all L5 appearances are relief (GS=0)
    bb9:       float = 0.0   # season BB/9 (0=not loaded, derived from WHIP otherwise)
    # ── Pitcher discipline metrics (from FanGraphs advanced tab) ──────────────
    # These implement the video's workflow: efficiency → batted ball quality → outcomes
    csw_pct:      float = 0.0    # Called Strikes + Whiffs % of total pitches. Target >30%.
                                 # Better than SwStr% alone — includes K-looking, not just misses.
    o_swing_pct:  float = 0.0    # O-Swing%: batters swinging at pitches OUTSIDE zone. Avg=32%.
                                 # High = pitcher gets batters to expand zone = fewer good counts.
    z_contact_pct: float = 0.0   # Z-Contact%: contact rate when batter swings IN zone. Avg=86%.
                                 # ≥88% = bad for pitcher: batters making easy contact. Key gate for
                                 # xwOBACON conditional logic (use xwoba quality when contact is high).
    foul_pct:     float = 0.0    # Foul ball % of total pitches. >20% = high workload, lots of fouls
                                 # but also fewer hard hits (foul balls are weak contact by definition).
    siera:        float = 0.0    # Skill-Interactive ERA — accounts for K%, BB%, GB% better than FIP.
                                 # SIERA > FIP usually means pitcher benefiting from HR luck.
    era_composite: float = 0.0   # Average of available estimators (FIP, xFIP, SIERA).
                                 # More stable than any single metric. 0=not computed.
    # Tier 2: pitch-location fields
    heart_zone_pct:     float = 0.32   # fraction thrown in heart of zone (mistake rate proxy)
    heart_zone_hr_rate: float = 0.060  # HR/PA on heart-zone pitches (league avg ~6%)
    chase_zone_pct:     float = 0.28   # fraction in chase zone (pitcher-friendly)
    # ── 2D pitch-frequency zone grid ─────────────────────────────────────────
    # Pitch frequency by Savant zone — how often pitcher throws to each cell.
    # None = not loaded; falls back to heart_zone_pct proxy.
    zone_pitch_grid: object = None  # np.ndarray shape (9,5) or None
    # ── Batted-ball profile ───────────────────────────────────────────────────
    gb_pct: float = 44.0   # ground ball % (league avg ~44%). High GB% suppresses park HR factor.
    k9:     float = 8.5    # season K/9 (league avg ~8.5). Fallback when no prop K line.
    # ── OddsAPI pitcher props (injected at scoring time) ─────────────────────
    prop_k_line:    float = 0.0   # market K line O/U → implies K/9
    prop_outs_line: float = 0.0   # market outs line → implied IP = outs/3
    prop_er_line:   float = 0.0   # market ER line → ERA proxy
    prop_hits_line: float = 0.0   # market hits allowed → WHIP proxy
    # ── New stats from FantasyLabs game view ─────────────────────────────────
    fip:            float = 4.20  # Fielding Independent Pitching (better ERA proxy)
    xfip:           float = 4.20  # Expected FIP (normalizes HR/FB to league avg) — best pitcher quality metric
    stuff_plus:     float = 100.0 # Stuff+ (pitch quality model, 100=avg, >100=better than avg)
    pitching_plus:  float = 100.0 # Pitching+ (Stuff+ + Location + Sequencing, best forward-looking metric)
    whiff_pct:      float = 21.5  # Swinging strike rate on swings (swing-and-miss)
    swstr_pct:      float = 9.5   # Swinging strike % of all pitches (SwStr%)
    first_pitch_strike_pct: float = 60.0  # 1st pitch strikes % (command indicator)
    gb_pct_allowed: float = 44.0  # Ground ball % allowed (high = fewer HRs)
    meatball_pct:  float = 8.5   # % of pitches in heart of zone (league avg ~8-9%)
    # High meatball% = pitcher leaving fat pitches in the zone = easy barrels
    # Direct measure of "HR-friendly contact" from Propfinder methodology
    pull_air_pct_allowed: float = 16.5  # Pull+air allowed % (high = more HRs)
    pull_barrel_pct_allowed: float = 4.0  # Pull-side barrel % allowed (PB% in tweet)
    # PB% = barrels specifically on the pull side. More predictive than overall barrel%
    # because ~85% of HRs are pulled. A pitcher with 9% barrel% but 6% PB% is far more
    # HR-vulnerable to pull hitters than one with 9% barrel% and 3% PB%.
    # League average: ~4% of batted balls are pull-side barrels.
    # Sourced from Statcast: is_barrel=True AND (batter pull direction).
    putaway_pct:    float = 14.0  # Put-away% on 2-strike counts (dominance)
    days_rest:      int   = 5     # days since last start (5 = normal, ≤3 = short rest)
    home_era:       float = 0.0   # ERA at home park
    away_era:       float = 0.0   # ERA away
    hr9_home:       float = 0.0   # HR/9 at home (0=use overall)
    hr9_road:       float = 0.0   # HR/9 on road (0=use overall)
    is_home:        bool  = False # True if pitcher is starting at home
    # ── Hand-split pitch usage (batter-hand-specific) ────────────────────────
    # From Savant pitch-type splits vsLHB/vsRHB — more precise than overall usage
    fastball_pct_vs_rhb: float = 0.0
    fastball_pct_vs_lhb: float = 0.0
    breaking_pct_vs_rhb: float = 0.0
    breaking_pct_vs_lhb: float = 0.0
    offspeed_pct_vs_rhb: float = 0.0
    offspeed_pct_vs_lhb: float = 0.0
    # ── HR/9 and BA by batter hand ────────────────────────────────────────────
    hr9_vs_rhb:   float = 0.0
    hr9_vs_lhb:   float = 0.0
    ba_ff_vs_rhb:  float = 0.0
    ba_ff_vs_lhb:  float = 0.0
    ba_brk_vs_rhb: float = 0.0
    ba_brk_vs_lhb: float = 0.0
    ba_off_vs_rhb:  float = 0.0
    ba_off_vs_lhb:  float = 0.0
    # Per-pitch-type vulnerability (Barrel Boyz + Propfinder methodology)
    woba_allowed_ff:  float = 0.0   # wOBA allowed on four-seam
    woba_allowed_si:  float = 0.0   # wOBA allowed on sinker
    woba_allowed_sl:  float = 0.0   # wOBA allowed on slider
    woba_allowed_st:  float = 0.0   # wOBA allowed on sweeper
    woba_allowed_ch:  float = 0.0   # wOBA allowed on changeup
    woba_allowed_cu:  float = 0.0   # wOBA allowed on curveball
    woba_allowed_fc:  float = 0.0   # wOBA allowed on cutter
    barrel_pct_ff:    float = 0.0   # barrel% on four-seam
    barrel_pct_si:    float = 0.0   # barrel% on sinker
    barrel_pct_sl:    float = 0.0   # barrel% on slider
    barrel_pct_ch:    float = 0.0   # barrel% on changeup
    # PitchMix wOBA: batter wOBA weighted by THIS pitcher's actual pitch distribution
    # This is the "Barrel Boyz" core signal: a single number representing
    # how well this batter matches up against this pitcher's specific mix.
    pitchmix_woba:  float = 0.0   # computed in injection loop, used in score_player
    # ── Per-pitch-type whiff% and barrel% (from Savant pitcher arsenal) ───────
    # These are the Image 3 metrics: Chase Burns slider whiff=50.7%, FB whiff=21.9%
    # Critical for matchup: if pitcher's best whiff pitch is batter's weak pitch → HR down
    whiff_pct_fastball:  float = 0.0  # whiff% on fastballs (0=unknown, use overall)
    whiff_pct_breaking:  float = 0.0  # whiff% on breaking balls
    whiff_pct_offspeed:  float = 0.0  # whiff% on offspeed
    barrel_pct_fastball: float = 0.0  # barrel% allowed on fastballs (0=unknown)
    barrel_pct_breaking: float = 0.0  # barrel% allowed on breaking balls
    barrel_pct_offspeed: float = 0.0  # barrel% allowed on offspeed
    # ── Sub-type pitch usage (SI/FC separate from FF) ────────────────────────
    # Critical for matchup specificity: sinker (SI) and cutter (FC) are bucketed
    # into "fastball" overall but behave differently and batters' splits differ.
    # Severino: SI=35%, FC=11%, FF=19% — "fastball" = 65% but very different pitches.
    # Trout: wOBA .449 vs sinker, .550 vs cutter, .368 vs four-seam — HUGE difference.
    sinker_pct:   float = 0.0   # sinker (SI) usage % (0=unknown)
    cutter_pct:   float = 0.0   # cutter (FC) usage % (0=unknown)
    fourseam_pct: float = 0.0   # four-seam FB (FF) usage % (0=unknown)
    sweeper_pct:  float = 0.0   # sweeper (ST) usage % (0=unknown)
    # ── Individual breaking/offspeed usage % (June 2026) ─────────────────────
    # Previously missing — only ST/FC/SI/FF were tracked individually.
    # Required for: Teng sweeper 31% / curve 14% / changeup 17% matchup specificity.
    slider_pct:   float = 0.0   # slider (SL) usage % (0=unknown)
    curveball_pct: float = 0.0  # curveball (CU/KC) usage % (0=unknown)
    changeup_pct: float = 0.0   # changeup (CH) usage % (0=unknown)
    # ── Hand-specific individual pitch usage % (vs RHB / vs LHB) ────────────
    # Sale throws 4SFB 44% to RHB vs different mix to LHB — grouped fields existed
    # but individual per-pitch hand-specific splits were missing.
    ff_pct_vs_rhb:  float = 0.0; ff_pct_vs_lhb:  float = 0.0
    si_pct_vs_rhb:  float = 0.0; si_pct_vs_lhb:  float = 0.0
    sl_pct_vs_rhb:  float = 0.0; sl_pct_vs_lhb:  float = 0.0
    st_pct_vs_rhb:  float = 0.0; st_pct_vs_lhb:  float = 0.0
    ch_pct_vs_rhb:  float = 0.0; ch_pct_vs_lhb:  float = 0.0
    cu_pct_vs_rhb:  float = 0.0; cu_pct_vs_lhb:  float = 0.0
    fc_pct_vs_rhb:  float = 0.0; fc_pct_vs_lhb:  float = 0.0
    # ── Pitcher HR surrendered per pitch type vs each batter hand ─────────────
    # "Sale has 2 HRs vs LHB on the fastball" — enables hand-specific vulnerability note
    hr_vs_lhb_ff:  int = 0; hr_vs_rhb_ff:  int = 0
    hr_vs_lhb_si:  int = 0; hr_vs_rhb_si:  int = 0
    hr_vs_lhb_sl:  int = 0; hr_vs_rhb_sl:  int = 0
    hr_vs_lhb_st:  int = 0; hr_vs_rhb_st:  int = 0
    hr_vs_lhb_ch:  int = 0; hr_vs_rhb_ch:  int = 0
    hr_vs_lhb_cu:  int = 0; hr_vs_rhb_cu:  int = 0
    hr_vs_lhb_fc:  int = 0; hr_vs_rhb_fc:  int = 0
    # barrel% and whiff% per sub-type (from pitcher arsenal fetch)
    barrel_pct_sinker:  float = 0.0
    barrel_pct_cutter:  float = 0.0
    barrel_pct_fourseam: float = 0.0
    whiff_pct_sinker:   float = 0.0
    whiff_pct_cutter:   float = 0.0
    whiff_pct_sweeper:  float = 0.0
    # ── L5 batter-specific EV and barrel% by pitch type ──────────────────────
    # Populated at scoring time if FantasyLabs pitch-type split data available
    # These override season averages when fresh L5 data exists (Image 1 signal)
    l5_ev_vs_fastball:      float = 0.0   # 0 = no L5 data, use season
    l5_barrel_pct_fastball: float = 0.0   # 0 = no L5 data
    # ── Batting order position splits (Jun 26 2026) ───────────────────────────
    # wOBA allowed by batting order position (1-9). Populated by
    # _fetch_pitcher_order_splits() via Baseball Savant statcast CSV endpoint.
    # Minimum 50 PA gate enforced in fetch — sparse positions remain 0.0.
    # Used to fire WEAK SPOT / PRIME WEAK SPOT supplemental grade when the
    # batter's lineup_spot matches a position where the pitcher allows ≥0.370 wOBA.
    # League average wOBA ~0.320; 0.370+ = meaningful weakness; 0.400+ = prime zone.
    order_woba: object = None   # dict {1: float, 2: float, ..., 9: float} or None
    order_pa:   object = None   # dict {1: int, ..., 9: int} — sample size per position
    # ── Situational splits (FanGraphs POST API, Jun 27 2026) ─────────────────
    home_woba: object = None; home_tbf: object = None
    away_woba: object = None; away_tbf: object = None
    vs_lhb_woba: object = None; vs_lhb_tbf: object = None
    vs_rhb_woba: object = None; vs_rhb_tbf: object = None
    risp_woba: object = None; risp_tbf: object = None
    bases_loaded_woba: object = None; bases_loaded_tbf: object = None
    inn1_woba: object = None; inn1_tbf: object = None
    inn2_woba: object = None; inn2_tbf: object = None
    inn3_woba: object = None; inn3_tbf: object = None
    inn4_woba: object = None; inn4_tbf: object = None
    inn5_woba: object = None; inn5_tbf: object = None
    # ── FanGraphs pitch-type count splits (Jul 1 2026) ───────────────────────
    # Zone% per pitch type: how often pitcher throws each pitch IN the strike zone.
    # Low zone% on primary pitch = pitcher losing the zone on their best weapon = batter-friendly.
    # Source: FanGraphs splits API, strType="2" (pitching stats), split_ids for ahead/behind counts.
    zone_pct_ff:  float = 0.0   # four-seam zone% (0 = not loaded)
    zone_pct_si:  float = 0.0   # sinker zone%
    zone_pct_sl:  float = 0.0   # slider zone%
    zone_pct_ch:  float = 0.0   # changeup zone%
    zone_pct_cu:  float = 0.0   # curveball zone%
    zone_pct_fc:  float = 0.0   # cutter zone%
    zone_pct_st:  float = 0.0   # sweeper zone%
    # HR/FB% per pitch type: what fraction of fly balls on each pitch type leave the yard.
    # Identifies which specific pitch is the HR-surrender weapon, beyond overall HR/FB%.
    # High HR/FB% on primary pitch = every fly ball on that pitch is a threat.
    hr_fb_pct_ff: float = 0.0   # HR/FB% on four-seam (0 = not loaded)
    hr_fb_pct_si: float = 0.0   # HR/FB% on sinker
    hr_fb_pct_sl: float = 0.0   # HR/FB% on slider
    hr_fb_pct_ch: float = 0.0   # HR/FB% on changeup
    hr_fb_pct_cu: float = 0.0   # HR/FB% on curveball
    hr_fb_pct_fc: float = 0.0   # HR/FB% on cutter
    hr_fb_pct_st: float = 0.0   # HR/FB% on sweeper
    # Velocity trend: avg fastball velo last 5 starts vs season avg.
    # Declining velo (-1.5+ mph) = pitcher losing stuff = elevated HR risk.
    # Source: FanGraphs game log (type=4 leaderboard) — per-start velocity.
    avg_ff_velo:    float = 0.0   # season average four-seam velocity (0 = not loaded)
    l5_ff_velo:     float = 0.0   # L5 starts average four-seam velocity (0 = not loaded)
    velo_trend:     float = 0.0   # l5_ff_velo - avg_ff_velo (negative = declining)


