FANTASYLABS_FILE = r"C:\Users\hlee145\Documents\FanDuel Spreadsheets\HR Models\FantasyLabsMLB.xlsm"

def _fl_wind_out(wind_dir_str: str) -> bool:
    """Convert FantasyLabs wind direction string to wind_out bool."""
    if not wind_dir_str: return False
    s = str(wind_dir_str).strip().lower()
    return s in ("toright", "out", "blowing out", "out to cf", "out to lf", "out to rf")

def _fl_parse_name_hand(raw: str) -> tuple:
    """
    Parse 'Aaron Judge (R)' → ('Aaron Judge', 'R')
    or 'Luis Rengifo (S)' → ('Luis Rengifo', 'S')
    """
    if not raw: return "", "R"
    raw = str(raw).strip()
    m = __import__("re").match(r"^(.+?)\s*\(([LRS])\)\s*$", raw)
    if m:
        return m.group(1).strip(), m.group(2)
    return raw, "R"

def _fl_parse_pitcher(raw: str) -> tuple:
    """
    Parse 'LAA - B Suter (L)' → ('B Suter', 'L')
    or '@NYY - M Fried (L)'  → ('M Fried', 'L')
    """
    if not raw: return "", "R"
    raw = str(raw).strip()
    # Remove leading team part: "LAA - " or "@NYY - "
    m = __import__("re").match(r"^[@]?[A-Z]{2,3}\s*-\s*(.+?)\s*\(([LRS])\)\s*$", raw)
    if m:
        return m.group(1).strip(), m.group(2)
    # Fallback: no hand specified
    parts = raw.split("-", 1)
    name = parts[-1].strip() if len(parts) > 1 else raw
    return name, "R"

def _fl_parse_umpire(raw: str) -> tuple:
    """
    Parse '-0.2\xa0Lance Barksdale' → (-0.2, 'Lance Barksdale')
    Returns (ump_value, ump_name)
    """
    if not raw: return 0.0, ""
    raw = str(raw).replace("\xa0", " ").strip()
    m = __import__("re").match(r"^([+-]?\d*\.?\d+)\s+(.+)$", raw)
    if m:
        try:
            return float(m.group(1)), m.group(2).strip()
        except Exception:
            pass
    return 0.0, raw

def _ump_value_to_factor(ump_val: float) -> float:
    """
    Convert FantasyLabs umpire value (e.g. -0.2) to model umpire_factor multiplier.
    FL value is run-impact centered at 0. Positive = more offense, negative = less.
    Scale: ±0.5 FL units → ±3% HR factor (conservative)
    """
    return max(0.93, min(1.0 + ump_val * 0.06, 1.07))


@functools.lru_cache(maxsize=1)
def load_fantasylabs(filepath: str = FANTASYLABS_FILE) -> list[dict]:
    """
    Load FantasyLabs MLB XLSM and return list of player dicts.
    Cached — file is read only once per process.

    Returns list of dicts with keys:
      name, hand, team, opp, lineup_spot, pos,
      pitcher_name, pitcher_hand, pitcher_team,
      woba, iso, slg, so_ab,
      implied_runs, opp_implied_runs, game_total, moneyline, pct_ml_bet,
      temp_f, wind_speed, wind_out, humidity, precip_pct,
      park_friendly, ump_value, ump_name, ump_factor,
      proj, ceiling, floor, proj_own,
      yr_ppg, mo_ppg, consistency, upside,
    """
    from pathlib import Path
    import openpyxl

    path = Path(filepath)
    if not path.exists():
        print(f"  ⚠️  FantasyLabs file not found: {filepath}")
        return []

    try:
        wb = openpyxl.load_workbook(str(path), read_only=True, keep_vba=True, data_only=True)
    except Exception as e:
        print(f"  ⚠️  FantasyLabs open failed: {e}")
        return []

    ws = wb["FantasyLabsMLB"]
    all_rows = [row for row in ws.iter_rows(values_only=True) if any(v is not None for v in row)]
    if len(all_rows) < 3:
        print("  ⚠️  FantasyLabs: too few rows")
        return []

    headers = [str(h).strip() if h is not None else "" for h in all_rows[1]]
    def _col(name):
        try: return headers.index(name)
        except ValueError: return -1

    # Column indices
    C = {
        "player":      _col("Player"),
        "salary":      _col("Salary"),
        "pos":         _col("Pos"),
        "order":       _col("Order"),
        "team":        _col("Team"),
        "pitcher":     _col("Opp Pitcher"),
        "opp":         _col("Opp"),
        "proj":        _col("Proj"),
        "ceiling":     _col("Ceiling"),
        "floor":       _col("Floor"),
        "proj_own":    _col("Proj Own"),
        "woba":        _col("wOBA"),
        "iso":         _col("ISO"),
        "slg":         _col("SLG"),
        "so_ab":       _col("SO/AB"),
        "runs":        _col("Runs"),
        "opp_runs":    _col("Opp Run"),
        "ou":          _col("O/U"),
        "ml":          _col("MoneyLine"),
        "pct_ml_bet":  _col("% ML Bet"),
        "temp":        _col("Temp"),
        "wind_spd":    _col("Wind Spd"),
        "wind_dir":    _col("Wind Dir"),
        "humidity":    _col("Humidity"),
        "precip":      _col("Precip %"),
        "park":        _col("Park Friendly"),
        "umpire":      _col("Umpire"),
        "yr_ppg":      _col("PPG"),
        "mo_ppg":      _col("PPG_2"),
        "consistency": _col("Consistency"),
        "upside":      _col("Upside"),
        "opp_run_rtg": _col("Opp Run"),
    }

    def _f(row, key, default=0.0):
        idx = C.get(key, -1)
        if idx < 0 or idx >= len(row): return default
        v = row[idx]
        if v is None or str(v).strip() in ("", "N/A"): return default
        try: return float(v)
        except Exception: return default

    def _s(row, key, default=""):
        idx = C.get(key, -1)
        if idx < 0 or idx >= len(row): return default
        v = row[idx]
        return str(v).strip() if v is not None else default

    players = []
    for row in all_rows[2:]:
        raw_player = _s(row, "player")
        if not raw_player: continue

        name, hand = _fl_parse_name_hand(raw_player)
        pitcher_raw = _s(row, "pitcher")
        pitcher_name, pitcher_hand = _fl_parse_pitcher(pitcher_raw)
        pitcher_team = _s(row, "opp").lstrip("@")

        ump_raw   = _s(row, "umpire")
        ump_val, ump_name = _fl_parse_umpire(ump_raw)

        # Wind: FantasyLabs uses "ToLeft"/"ToRight"/"In"/"Out" conventions
        wind_dir_str = _s(row, "wind_dir")
        wind_out = _fl_wind_out(wind_dir_str)

        # Lineup order — FL col "Order" is batting order (1-9)
        order_raw = _f(row, "order", default=0)
        lineup_spot = int(order_raw) if 1 <= order_raw <= 9 else 5

        players.append({
            "name":             name,
            "hand":             hand,
            "team":             _s(row, "team"),
            "opp":              _s(row, "opp").lstrip("@"),
            "lineup_spot":      lineup_spot,
            "pos":              _s(row, "pos"),
            "salary":           _f(row, "salary",      0.0),
            "pitcher_name":     pitcher_name,
            "pitcher_hand":     pitcher_hand,
            "pitcher_team":     pitcher_team,
            # Batter stats
            "woba":             _f(row, "woba",        0.315),
            "iso":              _f(row, "iso",         0.145),
            "slg":              _f(row, "slg",         0.390),
            "so_ab":            _f(row, "so_ab",       0.22),
            # Vegas / implied runs
            "implied_runs":     _f(row, "runs",        4.5),
            "opp_implied_runs": _f(row, "opp_runs",    4.5),
            "game_total":       _f(row, "ou",          9.0),
            "moneyline":        _f(row, "ml",          0.0),
            "pct_ml_bet":       _f(row, "pct_ml_bet",  50.0),
            # Weather
            "temp_f":           _f(row, "temp",        72.0),
            "wind_speed":       _f(row, "wind_spd",    0.0),
            "wind_out":         wind_out,
            "wind_dir_str":     wind_dir_str,
            "humidity":         _f(row, "humidity",    0.5),
            "precip_pct":       _f(row, "precip",      0.0),
            # Park + umpire
            "park_friendly":    _f(row, "park",        50.0),
            "ump_value":        ump_val,
            "ump_name":         ump_name,
            "ump_factor":       _ump_value_to_factor(ump_val),
            # Projections / form
            "proj":             _f(row, "proj",        0.0),
            "ceiling":          _f(row, "ceiling",     0.0),
            "floor":            _f(row, "floor",       0.0),
            "proj_own":         _f(row, "proj_own",    0.0),
            "yr_ppg":           _f(row, "yr_ppg",      0.0),
            "mo_ppg":           _f(row, "mo_ppg",      0.0),
            "consistency":      _f(row, "consistency", 0.0),
            "upside":           _f(row, "upside",      0.0),
        })

    print(f"  ✅ FantasyLabs: {len(players)} players loaded from {Path(filepath).name}")
    return players



def load_daily_pitch(filepath: str = FANTASYLABS_FILE) -> tuple:
    """
    Load DailyPitch sheet — combined pitcher + batter pitch-type data from Savant.
    Single-header format: pitcher rows first (sorted by PA desc), then batter rows.
    Boundary detected by a significant upward jump in PA count after the first block.

    Returns: (pitcher_pitch: dict, batter_pitch: dict)
      pitcher_pitch: { player_id (int): { 'SI': {usage_pct, woba_allowed, whiff_pct, rv100}, ... } }
      batter_pitch:  { player_id (int): { 'FF': {woba, slg, hh_pct, whiff_pct, usage_pct}, ... } }
    """
    import openpyxl as _opxl
    try:
        wb = _opxl.load_workbook(filepath, read_only=True, data_only=True)
    except Exception as e:
        print(f"  ⚠️ DailyPitch load failed: {e}"); return {}, {}
    if "DailyPitch" not in wb.sheetnames:
        print("  ⚠️ DailyPitch sheet not found"); return {}, {}

    ws = wb["DailyPitch"]
    rows = list(ws.iter_rows(values_only=True))

    # Column spec (same for both blocks):
    # last_name, first_name | player_id | team | pitch_type | pitch_name |
    # rv/100 | run_value | pitches | pitch_usage | pa |
    # ba | slg | woba | whiff% | k% | put_away | est_ba | est_slg | est_woba | hard_hit%
    FIXED_COLS = {
        "last_name, first_name": 0, "player_id": 1, "team_name_alt": 2,
        "pitch_type": 3, "pitch_name": 4, "run_value_per_100": 5, "run_value": 6,
        "pitches": 7, "pitch_usage": 8, "pa": 9, "ba": 10, "slg": 11,
        "woba": 12, "whiff_percent": 13, "k_percent": 14, "put_away": 15,
        "est_ba": 16, "est_slg": 17, "est_woba": 18, "hard_hit_percent": 19,
    }

    def _sf(row, col_idx, default=0.0):
        if col_idx < len(row) and row[col_idx] is not None:
            try: return float(str(row[col_idx]).replace('%', '').strip())
            except: pass
        return default

    def _is_header(row):
        """Detect a header row by presence of 'last_name' or 'player_id' in first cols."""
        if not row: return False
        for v in row[:5]:
            s = str(v or "").lower().strip().strip('"').strip("'").strip('﻿')
            if 'last_name' in s or s == 'player_id' or s == 'pitch_type':
                return True
        return False

    # Single-header format: skip header row, collect all data rows
    first_header_seen = False
    all_data_rows = []
    for row in rows:
        if _is_header(row):
            if not first_header_seen:
                first_header_seen = True
            # skip all header rows (handles old two-header and new single-header format)
            continue
        if first_header_seen and row and row[0] is not None:
            all_data_rows.append(row)

    # Detect pitcher/batter boundary by PA reset:
    # Pitcher block sorted desc by PA → count drops to low values.
    # Batter block starts again with higher PA count → upward jump marks boundary.
    # Find the largest upward PA jump in the dataset (after ignoring first 10 rows).
    PA_COL = FIXED_COLS.get("pa", 9)
    def _pa(row):
        try: return int(float(row[PA_COL] or 0)) if PA_COL < len(row) else 0
        except: return 0

    split_idx = len(all_data_rows)  # default: all pitcher rows
    if len(all_data_rows) > 20:
        best_jump = 0
        for i in range(10, len(all_data_rows) - 1):
            prev_pa = _pa(all_data_rows[i])
            next_pa = _pa(all_data_rows[i + 1])
            jump = next_pa - prev_pa
            if jump > best_jump:
                best_jump = jump
                split_idx = i + 1
        # Only split if we found a real reset (jump > 20 PA)
        if best_jump < 20:
            split_idx = len(all_data_rows)  # no batter block found

    block1_rows = all_data_rows[:split_idx]   # pitcher-side
    block2_rows = all_data_rows[split_idx:]   # batter-side

    def _parse_block(block_rows, is_pitcher: bool) -> dict:
        result = {}
        for row in block_rows:
            if not row or row[0] is None: continue
            try:
                pid = int(_sf(row, FIXED_COLS["player_id"]))
            except Exception:
                continue
            if pid <= 0: continue

            pt = str(row[FIXED_COLS["pitch_type"]] or "").strip().upper()
            if not pt or len(pt) > 3: continue

            usage  = _sf(row, FIXED_COLS["pitch_usage"])
            woba   = _sf(row, FIXED_COLS["woba"])
            slg    = _sf(row, FIXED_COLS["slg"])
            hh     = _sf(row, FIXED_COLS["hard_hit_percent"])
            whiff  = _sf(row, FIXED_COLS["whiff_percent"])
            rv100  = _sf(row, FIXED_COLS["run_value_per_100"])

            if pid not in result:
                result[pid] = {}
            if is_pitcher:
                result[pid][pt] = {
                    "usage_pct": usage, "woba_allowed": woba,
                    "whiff_pct": whiff, "hh_pct": hh, "rv100": rv100,
                }
            else:
                result[pid][pt] = {
                    "usage_pct": usage, "woba": woba, "slg": slg,
                    "hh_pct": hh, "whiff_pct": whiff, "rv100": rv100,
                }
        return result

    pitcher_pitch = _parse_block(block1_rows, is_pitcher=True)
    batter_pitch  = _parse_block(block2_rows, is_pitcher=False)

    if pitcher_pitch or batter_pitch:
        print(f"  ✅ DailyPitch: {len(pitcher_pitch)} pitchers + {len(batter_pitch)} batters loaded")
    return pitcher_pitch, batter_pitch

def load_savant_sheet(filepath: str = FANTASYLABS_FILE) -> dict:
    """
    Load the Savant sheet from the workbook.
    Contains three sub-tables combined:
      1. Swing mechanics: avg_bat_speed, swing_tilt, attack_angle, ideal_attack_angle_rate
      2. Batted ball:     gb_rate, air_rate, fb_rate, ld_rate, pu_rate, pull_air_rate
      3. Bat tracking:    squared_up_per_bat_contact, blast_per_bat_contact,
                         batter_run_value, whiff_per_swing, hard_swing_rate

    Returns: dict keyed by savant_id (int) → dict of all available fields.
    """
    import openpyxl as _opxl_sv
    try:
        wb = _opxl_sv.load_workbook(filepath, read_only=True, data_only=True)
    except Exception as e:
        print(f"  ⚠️  Savant sheet load failed: {e}"); return {}
    if "Savant" not in wb.sheetnames:
        print("  ⚠️  Savant sheet not found in workbook"); return {}
    ws = wb["Savant"]
    rows = list(ws.iter_rows(values_only=True))
    if not rows:
        return {}

    # Detect sub-tables. Tables 1-3 start with a header row where col[0]='id'.
    # Table 6 (new Jul 2026 full leaderboard) has col[0]='last_name first_name'
    # and uses player_id in col[1] as the key. Both formats are handled below.
    def _clean(v):
        return str(v or "").replace("﻿","").replace("​","").replace('"',"").strip().lower()

    def _is_id_header(row):
        return bool(row and row[0] is not None and _clean(row[0]) == "id")

    def _is_t6_header(row):
        # Table 6: first col = 'last_name first_name', second col = 'player_id'
        if not row or row[0] is None: return False
        c0 = _clean(row[0])
        c1 = _clean(str(row[1] or ""))
        return "last_name" in c0 and ("player_id" in c1 or "player_id" in c0)

    sub_tables   = []   # (header_list, data_rows, is_t6)
    current_header = None
    current_rows   = []
    current_is_t6  = False
    for row in rows:
        if _is_id_header(row):
            if current_header is not None:
                sub_tables.append((current_header, current_rows, current_is_t6))
            current_header = [_clean(v) for v in row]
            current_rows   = []
            current_is_t6  = False
        elif _is_t6_header(row):
            if current_header is not None:
                sub_tables.append((current_header, current_rows, current_is_t6))
            current_header = [_clean(v) for v in row]
            current_rows   = []
            current_is_t6  = True
        elif current_header is not None and row[0] is not None:
            current_rows.append(row)
    if current_header is not None and current_rows:
        sub_tables.append((current_header, current_rows, current_is_t6))

    if not sub_tables:
        return {}

    result = {}  # savant_id → merged dict

    def _flt(v, default=0.0):
        try: return float(v) if v not in (None, '', 'NaN') else default
        except: return default

    for header, rows, is_t6 in sub_tables:
        # Map column names to indices
        col = {h: i for i, h in enumerate(header)}

        # Table 6 uses 'last_name first_name' combined in col 0, player_id in col 1
        # Tables 1-3 use 'id' in col 0, 'name' in col 1
        if is_t6:
            id_col   = col.get('player_id', 1)
            name_col = col.get('last_name first_name', 0)
        else:
            id_col   = col.get('id', 0)
            name_col = col.get('name', 1)

        for row in rows:
            try:
                sid = int(float(str(row[id_col] or '').replace('"', '').strip()))
            except:
                continue
            if sid <= 0:
                continue
            if sid not in result:
                result[sid] = {'name': str(row[name_col] or '').strip()}

            d = result[sid]
            def g(key, default=0.0):
                idx = col.get(key)
                return _flt(row[idx], default) if idx is not None and idx < len(row) else default

            # Sub-table 1: swing mechanics
            if 'avg_bat_speed' in col:
                d['avg_bat_speed']            = g('avg_bat_speed', 73.8)
                d['swing_tilt']               = g('swing_tilt', 32.0)
                d['attack_angle']             = g('attack_angle', 10.0)
                d['attack_direction']         = g('attack_direction', 0.0)
                d['ideal_attack_angle_rate']  = g('ideal_attack_angle_rate', 0.528)
                d['competitive_swings']       = g('competitive_swings', 0)

            # Sub-table 2: batted ball
            if 'gb_rate' in col:
                d['gb_rate']          = g('gb_rate', 0.44)
                d['air_rate']         = g('air_rate', 0.56)
                d['fb_rate']          = g('fb_rate', 0.34)
                d['ld_rate']          = g('ld_rate', 0.24)
                d['pu_rate']          = g('pu_rate', 0.08)
                d['pull_rate']        = g('pull_rate', 0.40)
                d['pull_air_rate']    = g('pull_air_rate', 0.206)
                d['straight_air_rate']= g('straight_air_rate', 0.20)
                d['oppo_air_rate']    = g('oppo_air_rate', 0.16)

            # Sub-table 3: bat tracking
            if 'squared_up_per_bat_contact' in col:
                d['squared_up_per_contact'] = g('squared_up_per_bat_contact', 0.245)
                d['hard_swing_rate']        = g('hard_swing_rate', 0.40)
                d['batter_run_value']       = g('batter_run_value', 0.0)
                d['whiff_per_swing']        = g('whiff_per_swing', 0.20)
                d['competitive_swing_pct']  = g('percent_swings_competitive', 0.902)
                d['swing_length']           = g('swing_length', 7.5)
                # Blast% fix: blast_per_bat_contact is a decimal (0.22 = 22%)
                # Multiply by 100 to get true Blast% — old ×34 proxy was wrong
                _bpc_raw = g('blast_per_bat_contact', 0.11)
                d['blast_per_contact']      = _bpc_raw  # keep raw for backward compat
                d['blast_pct_direct']       = _bpc_raw * 100.0  # true Blast% (0-100)

            # ── Table 6 (Jul 2026): full leaderboard with all PropFinder gate stats ──
            # Keyed by player_id in col 1, name combined in col 0.
            # Column names use Savant's internal field names (e.g. barrel_batted_rate,
            # hard_hit_percent, groundballs_percent, flyballs_percent, pull_percent).
            # This is the primary source for season-stat PropFinder gate fallbacks
            # when L10 BBE data (pybaseball) is unavailable.
            if is_t6 or 'barrel_batted_rate' in col or 'hard_hit_percent' in col:
                # xISO — gate: >0.2
                _xiso = g('xiso', 0.0)
                if _xiso > 0:
                    d['xiso_season'] = _xiso

                # Barrel% — gate: >15  (stored as integer % e.g. 19.0)
                _barrel = g('barrel_batted_rate', 0.0)
                if _barrel > 0:
                    d['barrel_pct_season'] = _barrel

                # HH% — gate: >40  (stored as integer % e.g. 54.0)
                _hh = g('hard_hit_percent', 0.0)
                if _hh > 0:
                    d['hard_hit_pct_season'] = _hh

                # Pull% — gate: >30  (stored as % e.g. 41.2)
                _pull = g('pull_percent', 0.0)
                if _pull > 0:
                    d['pull_pct_season'] = _pull

                # GB% — gate: <40  (stored as % e.g. 28.0). Air% = 100 - GB%
                _gb = g('groundballs_percent', 0.0)
                if _gb > 0:
                    d['gb_pct_season'] = _gb

                # FB% — gate: >35  (stored as % e.g. 38.8)
                _fb = g('flyballs_percent', 0.0)
                if _fb > 0:
                    d['fb_pct_season'] = _fb

                # Blast% — gate: >15. Table 6 stores as integer % (e.g. 22.0 = 22%)
                # This is already the true Blast% — no ×100 needed (unlike blast_per_bat_contact).
                _blast = g('blasts_contact', 0.0)
                if _blast > 0:
                    # If value looks like a decimal fraction (e.g. 0.22), convert to %
                    d['blast_pct_direct'] = _blast * 100.0 if _blast < 2.0 else _blast

                # Avg EV, EV50 — supplemental power metrics
                _avg_ev = g('exit_velocity_avg', 0.0)
                if _avg_ev > 0:
                    d['avg_ev_season'] = _avg_ev

                _ev50 = g('avg_best_speed', 0.0)  # Table 6 calls it avg_best_speed
                if _ev50 > 0:
                    d['ev50'] = _ev50

                # Attack angle / ideal angle — supplemental bat path metrics
                _iaa = g('ideal_angle_rate', 0.0)
                if _iaa > 0:
                    d['ideal_attack_angle_pct'] = _iaa if _iaa > 1.0 else _iaa * 100.0

                _atk = g('attack_angle', 0.0)
                if _atk:
                    d['attack_angle'] = _atk

                # Bat speed — supplement / override sub-table 1 value
                _bspd = g('avg_swing_speed', 0.0)
                if _bspd > 0:
                    d['avg_bat_speed'] = _bspd

                # Blast per contact (decimal) for backward compat
                _bpc = g('blasts_contact', 0.0)
                if _bpc > 0:
                    d['blast_per_contact'] = _bpc / 100.0 if _bpc > 2.0 else _bpc

    print(f"  ✅ Savant sheet: {len(result)} players loaded ({len(sub_tables)} sub-tables)")
    return result


def load_daily_batter(filepath: str = FANTASYLABS_FILE) -> dict:
    """
    Load FL DailyBatter sheet — career batter vs specific pitcher matchup history.
    Returns: { batter_name: { hrf, qab_pct, hh_pct, career_ab, career_hr, career_ops, career_bb } }
    Columns: Batter | Pitcher | Game | HRF | qAB | HH% | AB | H | 2B/3B | HR | BB | BA | OBP | OPS
    """
    import openpyxl as _opxl, re as _re_db
    try:
        wb = _opxl.load_workbook(filepath, read_only=True, data_only=True)
    except Exception as e:
        print(f"  ⚠️ DailyBatter load failed: {e}"); return {}
    if "DailyBatter" not in wb.sheetnames:
        print("  ⚠️ DailyBatter sheet not found"); return {}

    ws = wb["DailyBatter"]
    rows = list(ws.iter_rows(values_only=True))

    # Find header row
    header_idx, cols = None, {}
    for i, row in enumerate(rows[:10]):
        if row[0] == "Batter" or (row[0] and "Batter" in str(row[0])):
            header_idx = i
            cols = {str(v).strip(): j for j, v in enumerate(row) if v is not None}
            break
    if header_idx is None:
        # No header found — assume fixed column order from spec
        # Batter | Pitcher | Game | HRF | qAB | HH% | AB | H | 2B/3B | HR | BB | BA | OBP | OPS
        cols = {"Batter":0,"Pitcher":1,"Game":2,"HRF":3,"qAB":4,"HH%":5,
                "AB":6,"H":7,"2B/3B":8,"HR":9,"BB":10,"BA":11,"OBP":12,"OPS":13}
        header_idx = 0

    def _col(row, *keys, default=None):
        for k in keys:
            idx = cols.get(k)
            if idx is not None and idx < len(row) and row[idx] is not None:
                v = row[idx]
                if isinstance(v, (int, float)): return v
                s = str(v).replace('%','').strip()
                try: return float(s)
                except: return default
        return default

    def _norm_name(s):
        """Normalize 'O. Albies, 2B (B)' → 'Ozzie Albies' or at least 'O. Albies'"""
        if not s: return ""
        # Strip position and hand: ", 2B (B)" or " D" (day-to-day)
        s = _re_db.sub(r',\s*\w{1,2}\s*\(.\)', '', str(s)).strip()
        s = _re_db.sub(r'\s+[DIL]{1,2}$', '', s).strip()  # strip IL/D flags
        # "O. Albies" → keep as is for fuzzy matching
        return s.strip()

    result = {}
    for row in rows[header_idx + 1:]:
        if not row or row[0] is None: continue
        batter_raw = str(row[0]).strip()
        if batter_raw in ('---', '', 'Batter') or 'no matchup' in batter_raw.lower():
            continue
        name = _norm_name(batter_raw)
        if not name: continue

        hrf    = _col(row, "HRF", default=0.0) or 0.0
        _qab_raw = _col(row, "qAB", default=0.0) or 0.0
        _hh_raw  = _col(row, "HH%", default=0.0) or 0.0
        # Excel may store percentages as decimals (0.44 = 44%) or whole numbers (44)
        # Detect: if value < 1.5, it's a decimal → multiply by 100
        qab    = _qab_raw * 100 if 0 < _qab_raw < 1.5 else _qab_raw
        hh     = _hh_raw  * 100 if 0 < _hh_raw  < 1.5 else _hh_raw
        ab     = int(_col(row, "AB",  default=0) or 0)
        hr     = int(_col(row, "HR",  default=0) or 0)
        bb     = int(_col(row, "BB",  default=0) or 0)
        ops    = _col(row, "OPS", default=0.0) or 0.0
        # OPS could also be stored as decimal by some scrapers (e.g. 0.998 vs 0.998 — already fine)
        # BA/OBP similarly fine as decimals

        # Only store if we have meaningful data
        if ab > 0 or hrf > 0:
            result[name] = {
                "hrf": hrf, "qab_pct": qab, "hh_pct": hh,
                "career_ab": ab, "career_hr": hr, "career_bb": bb, "career_ops": ops,
            }

    if result:
        print(f"  ✅ DailyBatter: {len(result)} batter-pitcher matchups loaded")
    return result


def load_fl_projections(filepath: str = FANTASYLABS_FILE) -> dict:
    """
    Load FantasyLabs daily projections from the FL_Data sheet in FantasyLabsMLB.xlsm.

    Returns two sub-dicts keyed by normalized player name:
      {
        "pitchers": {
            norm_name: {
                "fl_er": float,   # projected earned runs
                "fl_k":  float,   # projected strikeouts
                "fl_h":  float,   # projected hits allowed
                "fl_ip": float,   # projected innings pitched
                "team":  str,
            }
        },
        "batters": {
            norm_name: {
                "fl_hr":  float,  # projected HR (0.06–0.41 range)
                "fl_h":   float,  # projected hits (singles+doubles+triples)
                "fl_r":   float,  # projected runs
                "team":   str,
            }
        },
      }
    """
    import unicodedata as _ud, re as _re

    def _norm(s):
        s = _ud.normalize("NFKD", str(s)).encode("ascii","ignore").decode().lower().strip()
        return _re.sub(r"[^a-z ]", "", s)

    def _strip(s):
        return _re.sub(r"\s+(jr\.?|sr\.?|ii|iii|iv)\s*$", "",
                       str(s).strip(), flags=_re.IGNORECASE)

    result = {"pitchers": {}, "batters": {}}

    try:
        import openpyxl as _opxl
        wb = _opxl.load_workbook(filepath, read_only=True, data_only=True)
        if "FL_Data" not in wb.sheetnames:
            print("  ⚠️  FL_Data sheet not found in workbook")
            return result

        ws = wb["FL_Data"]
        raw = list(ws.iter_rows(values_only=True))
        if not raw:
            return result

        hdr = [str(v).strip() if v is not None else "" for v in raw[0]]

        def _col(name):
            try: return hdr.index(name)
            except ValueError: return None

        c_player = _col("Player");   c_team  = _col("Team")
        c_pos    = _col("Position"); c_ip    = _col("PitchIP")
        c_er     = _col("PitchER");  c_k     = _col("PitchK")
        c_ph     = _col("PitchH");   c_hr    = _col("HR")
        c_sin    = _col("Singles");  c_dbl   = _col("Doubles")
        c_tri    = _col("Triples");  c_r     = _col("R")

        if any(c is None for c in [c_player, c_team, c_pos]):
            print("  ⚠️  FL_Data missing required columns")
            return result

        seen: set = set()   # deduplicate by (name, team) — prefer higher HR proj
        for row in raw[1:]:
            if not row or row[c_player] is None:
                continue
            pname = str(row[c_player]).strip()
            team  = str(row[c_team] or "").strip().upper()
            pos   = str(row[c_pos]  or "").strip().upper()
            if not pname:
                continue

            def _flt(c):
                if c is None or c >= len(row): return 0.0
                try: return float(row[c] or 0)
                except: return 0.0

            key_norm = _norm(_strip(pname))

            # Two-way players (e.g. Ohtani): position=SP but batting today
            # Treat as batter when HR projection > 0 and PitchIP = 0
            _is_pitcher_row = (pos in ("SP", "RP", "P") and _flt(c_ip) > 0)

            if _is_pitcher_row:
                ip = _flt(c_ip)
                if ip <= 0:
                    # No IP but listed as pitcher — check if also has batter stats
                    hr = _flt(c_hr)
                    if hr > 0:
                        existing = result["batters"].get(key_norm, {})
                        if existing.get("fl_hr", 0) < hr:
                            hits = _flt(c_sin) + _flt(c_dbl) + _flt(c_tri)
                            result["batters"][key_norm] = {
                                "fl_hr": hr, "fl_h": hits,
                                "fl_r": _flt(c_r), "team": team, "orig_name": pname,
                            }
                    continue
                # For pitchers: keep the one with highest IP (usually the SP)
                existing = result["pitchers"].get(key_norm, {})
                if existing.get("fl_ip", 0) >= ip:
                    continue
                result["pitchers"][key_norm] = {
                    "fl_er": _flt(c_er),
                    "fl_k":  _flt(c_k),
                    "fl_h":  _flt(c_ph),
                    "fl_ip": ip,
                    "team":  team,
                    "orig_name": pname,
                }
            else:
                # Also capture two-way players (SP with no PitchIP but has HR proj)
                hr = _flt(c_hr)
                if hr <= 0:
                    continue
                # For batters: if duplicate (two players named Max Muncy),
                # keep the one with higher HR projection (the real/active one)
                existing = result["batters"].get(key_norm, {})
                if existing.get("fl_hr", 0) >= hr:
                    continue
                hits = _flt(c_sin) + _flt(c_dbl) + _flt(c_tri)
                result["batters"][key_norm] = {
                    "fl_hr": hr,
                    "fl_h":  hits,
                    "fl_r":  _flt(c_r),
                    "team":  team,
                    "orig_name": pname,
                }

        n_p = len(result["pitchers"])
        n_b = len(result["batters"])
        print(f"  ✅ FL_Data: {n_p} pitchers | {n_b} batters  "
              f"(ER range {min((v['fl_er'] for v in result['pitchers'].values()), default=0):.2f}"
              f"–{max((v['fl_er'] for v in result['pitchers'].values()), default=0):.2f}, "
              f"HR range {min((v['fl_hr'] for v in result['batters'].values()), default=0):.3f}"
              f"–{max((v['fl_hr'] for v in result['batters'].values()), default=0):.3f})")

    except Exception as e:
        print(f"  ⚠️  FL_Data load failed: {e}")

    return result


def load_rotowire_props(
        csv_path: str = "",
        xlsx_path: str = FANTASYLABS_FILE
) -> dict:
    """
    Load pitcher AND batter props from the RotoWire daily props CSV.
    The CSV has one row per player per market, with per-book columns:
      {Book} Line, {Book} Less (under odds), {Book} More (over odds)
    Books: FanDuel, DraftKings, BetMGM, Caesars, BetRivers, Hard Rock

    Consensus line  = median across books that have a line.
    Consensus price = vig-removed average implied probability → back to American odds.

    Returns:
      {
        "pitchers": {
            name: {
                "k_line":    float,   "k_over_price":    int (American),
                "outs_line": float,   "outs_over_price": int,
                "er_line":   float,   "er_over_price":   int,
                "hits_line": float,   "hits_over_price": int,
                "rw_k_proj": float,   (RotoWire projection, when available)
            }
        },
        "batters": {
            name: {
                "hits_line": float,  "hits_over_price": int,
                "tb_line":   float,  "tb_over_price":   int,
            }
        },
        "pitcher_norm": { normalized_name: (orig_name, data) },
        "batter_norm":  { normalized_name: (orig_name, data) },
      }
    """
    import statistics, unicodedata as _ud, csv as _csv, io as _io

    def _norm(s):
        return _ud.normalize("NFKD", str(s)).encode("ascii","ignore").decode().lower().strip()

    # ── Sportsbook column definitions ────────────────────────────────────────
    BOOKS = {
        "FanDuel":    ("FanDuel Line",    "FanDuel Less",    "FanDuel More"),
        "DraftKings": ("DraftKings Line", "DraftKings Less", "DraftKings More"),
        "BetMGM":     ("BetMGM Line",     "BetMGM Less",     "BetMGM More"),
        "Caesars":    ("Caesars Line",     "Caesars Less",    "Caesars More"),
        "BetRivers":  ("BetRivers Line",  "BetRivers Less",  "BetRivers More"),
        "HardRock":   ("Hard Rock Line",  "Hard Rock Less",  "Hard Rock More"),
    }
    PITCHER_MARKETS = {
        "Pitcher Strikeouts": ("k_line",    "k_over_price"),
        "Outs":               ("outs_line", "outs_over_price"),
        "Earned Runs":        ("er_line",   "er_over_price"),
        "Hits Allowed":       ("hits_line", "hits_over_price"),
    }
    BATTER_MARKETS = {
        "Hits":        ("hits_line",  "hits_over_price"),
        "Total Bases": ("tb_line",    "tb_over_price"),
        "RBI":         ("rbi_line",   "rbi_over_price"),   # RotoWire covers RBI lines
    }

    def _to_implied(s):
        """American odds string → implied probability (None if invalid)."""
        try:
            v = float(str(s).replace("+", "").strip())
            if v == 0: return None
            return (-v) / (-v + 100) if v < 0 else 100 / (v + 100)
        except Exception:
            return None

    def _to_american(prob):
        """Vig-removed probability → American odds integer."""
        if prob is None or prob <= 0 or prob >= 1:
            return None
        if prob >= 0.5:
            return int(round(-(prob / (1 - prob)) * 100))
        else:
            return int(round(((1 - prob) / prob) * 100))

    def _cell_str(v):
        import datetime as _dt
        if v is None: return ""
        if isinstance(v, (int, float)): return str(v)
        if isinstance(v, (_dt.datetime, _dt.time)): return "-"
        return str(v).strip()

    def _consensus(row):
        """Compute (median_line, vig_removed_over_american) from all books."""
        lines_v, over_probs = [], []
        for _, (lc, less_c, more_c) in BOOKS.items():
            line_s = _cell_str(row.get(lc, ""))
            less_s = _cell_str(row.get(less_c, ""))
            more_s = _cell_str(row.get(more_c, ""))
            if line_s in ("", "-"):
                continue
            try:
                lines_v.append(float(line_s))
            except Exception:
                continue
            p_over  = _to_implied(more_s) if more_s not in ("", "-") else None
            p_under = _to_implied(less_s)  if less_s  not in ("", "-") else None
            if p_over is not None and p_under is not None:
                total = p_over + p_under
                if total > 0:
                    over_probs.append(p_over / total)   # vig-removed
        if not lines_v:
            return None, None, 0
        line = statistics.median(lines_v)
        price = _to_american(statistics.mean(over_probs)) if over_probs else None
        return line, price, len(lines_v)

    # ── Load raw rows ─────────────────────────────────────────────────────────
    raw_rows = []

    # Source A: CSV file
    if csv_path:
        try:
            with open(csv_path, newline="", encoding="utf-8-sig") as f:
                content = f.read()
            csv_lines = content.split("\n")
            if csv_lines:
                hdr = next(_csv.reader(_io.StringIO(csv_lines[0])))
                for cl in csv_lines[1:]:
                    if not cl.strip():
                        continue
                    rv = next(_csv.reader(_io.StringIO(cl)))
                    while len(rv) < len(hdr):
                        rv.append("")
                    raw_rows.append(dict(zip(hdr, rv)))
            if raw_rows:
                print(f"  📊 RotoWire props CSV: {len(raw_rows)} rows")
        except Exception as e:
            print(f"  ⚠️  RotoWire CSV load failed: {e}")

    # Source B: RotoWire sheet in Excel (fallback)
    if not raw_rows and xlsx_path:
        try:
            import openpyxl
            wb = openpyxl.load_workbook(xlsx_path, read_only=True, data_only=True)
            sheet = next((s for s in wb.sheetnames if "rotowire" in s.lower()), None)
            if sheet:
                ws = wb[sheet]
                xrows = list(ws.iter_rows(values_only=True))
                if len(xrows) >= 2:
                    xhdr = [str(v).strip() if v is not None else "" for v in xrows[0]]
                    for xr in xrows[1:]:
                        if not xr or not any(v is not None for v in xr):
                            continue
                        raw_rows.append({
                            xhdr[i]: (str(xr[i]).strip() if i < len(xr) and xr[i] is not None else "")
                            for i in range(len(xhdr))
                        })
                if raw_rows:
                    print(f"  📊 RotoWire Excel sheet: {len(raw_rows)} rows")
        except Exception as e:
            print(f"  ⚠️  RotoWire Excel load failed: {e}")

    if not raw_rows:
        return {"pitchers": {}, "batters": {}, "pitcher_norm": {}, "batter_norm": {}}

    # ── Build props dicts ─────────────────────────────────────────────────────
    # One row per player per market — take consensus across all book columns
    # (rows already represent one player+market combination; multiple Site rows
    #  exist but book columns are the same across rows → just deduplicate by player)
    pitcher_data: dict = {}
    batter_data:  dict = {}

    is_pitcher = lambda r: r.get("Position", "").upper() in ("P", "SP", "RP")

    # Track best RW projection per pitcher
    rw_projections: dict = {}

    for row in raw_rows:
        player  = row.get("Player", "").strip()
        market  = row.get("Market Name", "").strip()
        if not player or not market:
            continue

        # Get RotoWire projection from the dedicated column if present
        rw_proj_col = next((k for k in row if "rotowire projection" in k.lower()
                            and "factor" not in k.lower()
                            and "difference" not in k.lower()), None)
        rw_proj = None
        if rw_proj_col:
            try:
                v = float(row[rw_proj_col])
                if v > 0:
                    rw_proj = v
            except Exception:
                pass

        if is_pitcher(row) and market in PITCHER_MARKETS:
            line_field, price_field = PITCHER_MARKETS[market]
            line, price, n = _consensus(row)
            if line is None:
                continue
            if player not in pitcher_data:
                pitcher_data[player] = {}
            # Take first (or best) value — rows may repeat per site, values are same
            if line_field not in pitcher_data[player]:
                pitcher_data[player][line_field] = line
            if price is not None and price_field not in pitcher_data[player]:
                pitcher_data[player][price_field] = price
            # Store RW projection for K/9 estimation
            if rw_proj and market == "Pitcher Strikeouts":
                rw_projections[player] = rw_proj

        elif not is_pitcher(row) and market in BATTER_MARKETS:
            line_field, price_field = BATTER_MARKETS[market]
            line, price, n = _consensus(row)
            if line is not None:
                if player not in batter_data:
                    batter_data[player] = {}
                if line_field not in batter_data[player]:
                    batter_data[player][line_field] = line
                if price is not None and price_field not in batter_data[player]:
                    batter_data[player][price_field] = price
            # Fall through — _by_market stores WHR/L5 regardless of line

        # All batter markets: store signal data for hit score (Hits, TB, H+R+RBI, etc.)
        # Prefer sportsbook rows over DFS-only rows for over_prob accuracy.
        # Update an existing entry if current row has sportsbook odds and stored one doesn't.
        if not is_pitcher(row) and player:
            if player not in batter_data:
                batter_data[player] = {}
            if "_by_market" not in batter_data[player]:
                batter_data[player]["_by_market"] = {}

            def _flt(k):
                try: return float(row.get(k, "") or 0)
                except: return 0.0

            # Compute vig-removed over probability from sportsbook columns
            _oprobs = []
            for _, (_lc2, _lsc2, _mrc2) in BOOKS.items():
                _po = _to_implied(row.get(_mrc2,""))
                _pu = _to_implied(row.get(_lsc2,""))
                if _po is not None and _pu is not None and (_po + _pu) > 0:
                    _oprobs.append(_po / (_po + _pu))
            _over_prob = statistics.mean(_oprobs) if _oprobs else None

            # Get line directly from row — no dependency on BATTER_MARKETS `line` variable
            try:
                _row_line = float(row.get("Line", "") or 0) or None
            except (ValueError, TypeError):
                _row_line = None

            _existing = batter_data[player]["_by_market"].get(market)
            # Write if: not seen yet, OR existing has no odds but this row does
            _should_write = (
                _existing is None or
                (_existing.get("over_prob") is None and _over_prob is not None)
            )
            if _should_write:
                batter_data[player]["_by_market"][market] = {
                    "line":       _row_line,
                    "rw_proj":    rw_proj or 0.0,
                    "over_prob":  _over_prob,
                    "whr":        _flt("Weighted Hit Rate"),
                    "hr_l5":      _flt("Hit Rate: Last 5"),
                    "hr_l10":     _flt("Hit Rate: Last 10"),
                    "hr_season":  _flt("Hit Rate: Season"),
                    "hr_vs_opp":  _flt("Hit Rate: Vs Opponent"),
                    "sb_factor":  _flt("Sportsbooks Factor"),
                    "rw_factor":  _flt("RotoWire Projection Factor"),
                    "lean":       row.get("Lean", ""),
                }

    # Attach RW K projections
    for player, proj in rw_projections.items():
        if player in pitcher_data:
            pitcher_data[player]["rw_k_proj"] = proj

    # Build normalized lookup maps
    import re as _re_suf
    def _strip_name_suffix(s):
        """Strip Jr./Sr./II/III/IV from name before indexing."""
        return _re_suf.sub(r"\s+(jr\.?|sr\.?|ii|iii|iv)\s*$", "", str(s).strip(),
                           flags=_re_suf.IGNORECASE)

    pitcher_norm = {_norm(k): (k, v) for k, v in pitcher_data.items()}
    batter_norm  = {}
    for _bname_raw, _bval in batter_data.items():
        # Primary key: suffix-stripped normalized name ("fernando tatis jr." → "fernando tatis")
        _bstripped = _strip_name_suffix(_bname_raw)
        _bkey_main = _norm(_bstripped)
        batter_norm[_bkey_main] = (_bname_raw, _bval)
        # Secondary key: original (covers cases where bname also has suffix)
        _bkey_orig = _norm(_bname_raw)
        if _bkey_orig != _bkey_main:
            batter_norm[_bkey_orig] = (_bname_raw, _bval)
        # Alias: first initial + last word of stripped key ("j merrill", "f tatis")
        _bparts = _bkey_main.split()
        if len(_bparts) >= 2:
            _alias = _bparts[0][:1] + " " + _bparts[-1]
            if _alias not in batter_norm:
                batter_norm[_alias] = (_bname_raw, _bval)

    p_k    = sum(1 for v in pitcher_data.values() if "k_line"    in v)
    p_outs = sum(1 for v in pitcher_data.values() if "outs_line" in v)
    p_er   = sum(1 for v in pitcher_data.values() if "er_line"   in v)
    b_hits = sum(1 for v in batter_data.values()  if "hits_line" in v)
    b_tb   = sum(1 for v in batter_data.values()  if "tb_line"   in v)
    print(f"  ✅ RotoWire pitcher props: {len(pitcher_data)} pitchers "
          f"({p_k} K, {p_outs} outs, {p_er} ER lines — with consensus odds)")
    print(f"  ✅ RotoWire batter props:  {len(batter_data)} batters "
          f"({b_hits} hits, {b_tb} TB lines — with consensus odds)")

    return {
        "pitchers":     pitcher_data,
        "batters":      batter_data,
        "pitcher_norm": pitcher_norm,
        "batter_norm":  batter_norm,
    }

# Backward-compatible alias
load_rotowire_pitcher_props = load_rotowire_props



def fantasylabs_lookup(fl_players: list[dict]) -> dict:
    """
    Build lookup dicts from FantasyLabs data:
      by_name: { normalized_name → player_dict }  (4-tier keys stored at build time)
      by_team: { team_abbr → [player_dict, ...] }
      weather: { team → {temp_f, wind_speed, wind_out, ...} }
      implied: { team → {own, opp, total, ml} }
      umpire:  { team → ump_factor }
    Use fl_lookup_name(by_name, mlb_api_name) for lookups — it handles
    abbreviated first names ("G. Stanton"), Jr./Sr. suffixes, and exact names.
    """
    import unicodedata, re as _re

    def _norm(s):
        s = unicodedata.normalize("NFKD", str(s)).encode("ascii","ignore").decode().lower().strip()
        return _re.sub(r"[^a-z ]", "", s)

    def _fl_strip_suffix(s: str) -> str:
        """Remove Jr./Sr./II/III/IV suffixes from a normalized name string."""
        return _re.sub(r"\s+(jr\.?|sr\.?|ii|iii|iv)\s*$", "", s.strip())

    def _last(name):
        if not name or not name.strip(): return ""
        parts = _fl_strip_suffix(_norm(name)).split()
        return parts[-1] if parts else ""

    by_name  = {}
    by_team  = {}
    weather  = {}
    implied  = {}
    umpire   = {}

    for p in fl_players:
        fl_name = p["name"]
        fl_norm = _norm(fl_name)
        fl_last = _last(fl_name)

        # Tier 1: exact normalized FL name  (e.g. "aaron judge")
        by_name[fl_norm] = p

        # Tier 2: initial + last key  (e.g. "g stanton" for "G. Stanton")
        # This lets MLB API "Giancarlo Stanton" → "g stanton" → match
        fl_parts = fl_norm.split()
        if fl_parts:
            init = fl_parts[0].rstrip(".")
            if len(init) == 1:           # abbreviated first name "g"
                key2 = f"{init} {fl_last}"
                by_name[key2] = p

        # Tier 3: last name only (fallback for any remaining mismatches)
        if fl_last and fl_last not in by_name:
            by_name[fl_last] = p

        # Team grouping
        team = p["team"]
        by_team.setdefault(team, []).append(p)

        # Weather: aggregate across ALL players per team (not just first-seen).
        # Use max(precip_pct) so a game with 66% precip on most rows isn't zeroed
        # by one player row that had 0. Use median(temp_f) for stability.
        opp = p["opp"]
        for _t in (team, opp):
            if _t not in weather:
                weather[_t] = {
                    "temp_f_vals":    [p["temp_f"]],
                    "wind_speed":     p["wind_speed"],
                    "wind_out":       p["wind_out"],
                    "wind_dir":       p["wind_dir_str"],
                    "humidity_vals":  [p["humidity"]],
                    "precip_vals":    [p["precip_pct"]],
                    "source":         "FantasyLabs",
                }
            else:
                # Accumulate values — will reduce to max/median after loop
                weather[_t]["temp_f_vals"].append(p["temp_f"])
                weather[_t]["humidity_vals"].append(p["humidity"])
                weather[_t]["precip_vals"].append(p["precip_pct"])
                # Keep highest wind speed seen (most conservative)
                if p["wind_speed"] > weather[_t]["wind_speed"]:
                    weather[_t]["wind_speed"] = p["wind_speed"]
                    weather[_t]["wind_out"]   = p["wind_out"]
                    weather[_t]["wind_dir"]   = p["wind_dir_str"]

        # Implied runs: store by both teams
        # implied_runs = this batter's team runs; opp_implied_runs = opponent
        implied.setdefault(team, {})["own"]  = p["implied_runs"]
        implied.setdefault(team, {})["opp"]  = p["opp_implied_runs"]
        implied.setdefault(team, {})["total"] = p["game_total"]
        implied.setdefault(team, {})["ml"]    = p["moneyline"]
        implied.setdefault(opp,  {})["own"]   = p["opp_implied_runs"]
        implied.setdefault(opp,  {})["opp"]   = p["implied_runs"]
        implied.setdefault(opp,  {})["total"] = p["game_total"]

        # Umpire: stored by home team (affects both)
        if p["ump_name"] and p["ump_factor"] != 1.0:
            umpire[team] = p["ump_factor"]
            umpire[opp]  = p["ump_factor"]

    # Reduce accumulated weather values: max precip, median temp, max humidity
    import statistics as _stats
    for _t, wx in weather.items():
        if "precip_vals" in wx:
            wx["temp_f"]     = round(_stats.median(wx.pop("temp_f_vals")), 1)
            wx["humidity"]   = round(max(wx.pop("humidity_vals")), 3)
            wx["precip_pct"] = round(max(wx.pop("precip_vals")), 1)   # MAX: worst-case rain

    return {"by_name": by_name, "by_team": by_team,
            "weather": weather, "implied": implied, "umpire": umpire}

# ============================================================
# ── SECTION 2: MLB STATS API ─────────────────────────────────
# ============================================================

_pitcher_hand_cache: dict = {}
_batter_hand_cache:  dict = {}   # populated from lineup bat side data

def fl_lookup_name(by_name: dict, mlb_name: str) -> Optional[dict]:
    """
    Look up a player in the fl_lookup["by_name"] dict built by fantasylabs_lookup().
    Handles abbreviated first names ("G. Stanton"), accents, Jr./Sr. suffixes.
    Returns the FL player dict or None if not found.
    """
    import unicodedata as _ud2, re as _re2

    def _fn(s):
        s = _ud2.normalize("NFKD", str(s)).encode("ascii","ignore").decode().lower().strip()
        return _re2.sub(r"[^a-z ]", "", s)

    if not mlb_name or not by_name:
        return None

    import re as _re_fl
    def _strip_fl(s):
        return _re_fl.sub(r"\s+(jr\.?|sr\.?|ii|iii|iv)\s*$", "",
                          str(s).strip(), flags=_re_fl.IGNORECASE)

    # Tier 1: suffix-stripped exact normalized match
    # "Fernando Tatis Jr." → "Fernando Tatis" → "fernando tatis"
    key = _fn(_strip_fl(mlb_name))
    if key in by_name:
        return by_name[key]

    # Tier 1b: original (in case by_name also has suffix)
    key_orig = _fn(mlb_name)
    if key_orig != key and key_orig in by_name:
        return by_name[key_orig]

    # Tier 2: last-name-only match on stripped key
    parts = key.split()
    if parts:
        last = parts[-1]
        if last in by_name:
            return by_name[last]

    # Tier 3: initial + last name ("j merrill" → "jackson merrill", "f tatis" → "fernando tatis")
    if len(parts) >= 2:
        first_initial = parts[0][:1]
        last = parts[-1]
        for stored_key, entry in by_name.items():
            stored_parts = stored_key.split()
            if len(stored_parts) >= 2 and stored_parts[-1] == last:
                if stored_parts[0].startswith(first_initial):
                    return entry

    return None


def _fetch_batter_hand(player_name: str, player_id: int = 0) -> str:
    """
    Get batter hand from cache (populated by batch fetch) or single lookup.
    Returns "L" or "R". Switch hitters default to "L" (platoon advantage vs RHP).
    """
    if player_name in _batter_hand_cache:
        return _batter_hand_cache[player_name]
    if player_id:
        data = _get(f"https://statsapi.mlb.com/api/v1/people/{player_id}?fields=people,batSide")
        if data and data.get("people"):
            code = data["people"][0].get("batSide", {}).get("code", "R")
            hand = "L" if code == "L" else "R"
            _batter_hand_cache[player_name] = hand
            return hand
    return "R"


# Persistent hand lookup: MLB player ID → hand (survives across games in same run)
_player_id_to_hand: dict = {}   # { mlb_id: "L" or "R" }
_player_id_to_name: dict = {}   # { mlb_id: fullName }


def batch_fetch_player_hands(player_ids: dict) -> None:
    """
    Batch-fetch batting hand for multiple players in ONE API call.
    player_ids: { player_name: mlb_player_id }
    Populates _batter_hand_cache AND _player_id_to_hand in-place.
    Matches by ID (not name) to avoid Unicode/accent mismatches.
    """
    missing = {name: pid for name, pid in player_ids.items()
               if pid and pid not in _player_id_to_hand}
    if not missing:
        # All IDs already fetched — populate name cache from ID cache
        for name, pid in player_ids.items():
            if pid in _player_id_to_hand and name not in _batter_hand_cache:
                _batter_hand_cache[name] = _player_id_to_hand[pid]
        return

    ids_str = ",".join(str(pid) for pid in set(missing.values()))
    url = (f"https://statsapi.mlb.com/api/v1/people"
           f"?personIds={ids_str}&fields=people,id,fullName,batSide")
    data = _get(url)
    if not data or "people" not in data:
        return

    for person in data["people"]:
        pid  = person.get("id", 0)
        code = person.get("batSide", {}).get("code", "R")
        hand = "L" if code == "L" else "R"
        fname = person.get("fullName", "")
        if pid:
            _player_id_to_hand[pid] = hand
            if fname:
                _player_id_to_name[pid] = fname
                _batter_hand_cache[fname] = hand   # cache by /people fullName too

    # Now map original names → hand via their IDs
    for name, pid in player_ids.items():
        if pid in _player_id_to_hand:
            _batter_hand_cache[name] = _player_id_to_hand[pid]


def _fetch_pitcher_hand(player_id: int) -> str:
    if player_id in _pitcher_hand_cache:
        return _pitcher_hand_cache[player_id]
    data = _get(f"https://statsapi.mlb.com/api/v1/people/{player_id}?fields=people,pitchHand")
    hand = "R"
    if data and data.get("people"):
        hand = data["people"][0].get("pitchHand", {}).get("code", "R")
    _pitcher_hand_cache[player_id] = hand
    return hand


def batch_fetch_pitcher_hands(pitcher_id_map: dict) -> None:
    """
    Batch-fetch pitching hand for multiple pitchers in one API call.
    pitcher_id_map: { player_id: pitcher_name }
    Populates _pitcher_hand_cache in-place.
    """
    missing_ids = [pid for pid in pitcher_id_map if pid not in _pitcher_hand_cache]
    if not missing_ids:
        return
    ids_str = ",".join(str(pid) for pid in missing_ids)
    url = (f"https://statsapi.mlb.com/api/v1/people"
           f"?personIds={ids_str}&fields=people,id,fullName,pitchHand")
    data = _get(url)
    if not data or "people" not in data:
        return
    for person in data["people"]:
        pid  = person.get("id", 0)
        hand = person.get("pitchHand", {}).get("code", "R")
        _pitcher_hand_cache[pid] = hand


def fetch_mlb_schedule(target_date: date) -> list[dict]:
    """
    Returns list of game dicts:
    { game_pk, home_team, away_team, commence_time,
      home_pitcher, away_pitcher, home_pitcher_hand, away_pitcher_hand,
      home_lineup, away_lineup, lineups_confirmed }
    """
    ds  = target_date.strftime("%Y-%m-%d")
    url = (f"https://statsapi.mlb.com/api/v1/schedule"
           f"?startDate={ds}&endDate={ds}&sportId=1"
           f"&hydrate=probablePitcher,startingPitchers,lineups(person(batSide)),team,linescore")
    print(f"  📡 MLB API: schedule for {ds}...")
    data = _get(url)
    if not data or not data.get("dates"):
        print("  ⚠️  No games found from MLB API")
        return []

    games = []
    for g in data["dates"][0].get("games", []):
        try:
            pk      = g["gamePk"]
            home_id = g["teams"]["home"]["team"]["id"]
            away_id = g["teams"]["away"]["team"]["id"]
            home    = MLB_TEAM_ID_MAP.get(home_id, "UNK")
            away    = MLB_TEAM_ID_MAP.get(away_id, "UNK")

            # Pitcher priority: startingPitcher (actual SP when game started) >
            # probablePitcher (pre-game, can be stale/wrong).
            # startingPitchers is populated by MLB API once lineups are confirmed.
            def _get_pitcher(side):
                """Return (name, id) preferring startingPitcher over probablePitcher."""
                sp_data = g["teams"][side].get("startingPitchers", [])
                if sp_data and isinstance(sp_data, list) and sp_data:
                    p = sp_data[0]
                    name = p.get("fullName", "") or p.get("name", "")
                    pid  = p.get("id", 0)
                    if name:
                        return name, pid
                prob = g["teams"][side].get("probablePitcher", {})
                return prob.get("fullName", ""), prob.get("id", 0)

            home_p, home_pid = _get_pitcher("home")
            away_p, away_pid = _get_pitcher("away")
            if home_pid or away_pid:
                pitcher_id_map = {}
                if home_pid: pitcher_id_map[home_pid] = home_p
                if away_pid: pitcher_id_map[away_pid] = away_p
                batch_fetch_pitcher_hands(pitcher_id_map)
            home_p_hand = _pitcher_hand_cache.get(home_pid, "R") if home_pid else "R"
            away_p_hand = _pitcher_hand_cache.get(away_pid, "R") if away_pid else "R"

            def parse_lu(players):
                sorted_players = sorted(players, key=lambda x: x.get("battingOrder", 9999))
                result = []
                player_id_map = {}   # name → mlb_id for batch hand fetch
                for list_idx, p in enumerate(sorted_players, 1):
                    raw_order = p.get("battingOrder", 0)
                    if raw_order and raw_order > 0:
                        spot = max(1, min(9, round(raw_order / 100)))
                    else:
                        spot = list_idx if list_idx <= 9 else 9
                    # batSide sometimes in lineup objects, sometimes not
                    bat_side = p.get("batSide", {}).get("code", "")
                    name     = p.get("fullName", "")
                    pid      = p.get("id", 0)
                    if name and pid:
                        player_id_map[name] = pid
                    result.append((name,
                                   p.get("position",{}).get("abbreviation",""),
                                   spot,
                                   bat_side))
                # Batch-fetch missing hands in one API call
                if player_id_map:
                    batch_fetch_player_hands(player_id_map)
                # Second pass: for any player still missing from hand cache,
                # fall back to _player_id_to_hand using the pid directly
                for pname, pid in player_id_map.items():
                    if pname not in _batter_hand_cache and pid in _player_id_to_hand:
                        _batter_hand_cache[pname] = _player_id_to_hand[pid]
                return result

            # ── Game status: skip ONLY postponed/cancelled/suspended ──────────
            # NOTE: MLB API reuses coded='P' for both "Pre-Game" and "Postponed"
            # so we must use detailedState string only — never codedGameState alone.
            _status   = g.get("status", {})
            _detailed = _status.get("detailedState", "").lower()
            _SKIP_WORDS = {"postponed", "cancelled", "suspended", "canceled"}
            if any(w in _detailed for w in _SKIP_WORDS):
                print(f"    ⏭️  {away} @ {home} — skipped ({_detailed})")
                continue
            # All other statuses (pre-game, delayed start, live, final) are included

            lineups_node = g.get("lineups", {})
            home_lu = parse_lu(lineups_node.get("homePlayers", []))
            away_lu = parse_lu(lineups_node.get("awayPlayers", []))
            confirmed = bool(home_lu or away_lu)

            # Fallback: try boxscore endpoint if lineups not in schedule
            if not confirmed:
                bx = _get(f"https://statsapi.mlb.com/api/v1/game/{pk}/boxscore")
                if bx:
                    bx_lu = bx.get("lineups", {})
                    home_lu = parse_lu(bx_lu.get("homePlayers", []))
                    away_lu = parse_lu(bx_lu.get("awayPlayers", []))
                    confirmed = bool(home_lu or away_lu)

            games.append({
                "game_pk": pk, "home_team": home, "away_team": away,
                "commence_time": g.get("gameDate",""),
                "home_pitcher": home_p, "away_pitcher": away_p,
                "home_pitcher_id": home_pid,  # MLB player ID for L5 starts fetch
                "away_pitcher_id": away_pid,  # MLB player ID for L5 starts fetch
                "home_pitcher_hand": home_p_hand, "away_pitcher_hand": away_p_hand,
                "home_lineup": home_lu, "away_lineup": away_lu,
                "lineups_confirmed": confirmed,
                "game_status": _detailed or _abstract,
            })
        except Exception as e:
            print(f"    ⚠️  Game parse error: {e}")

    print(f"  ✅ MLB API: {len(games)} games, "
          f"{sum(1 for g in games if g['lineups_confirmed'])} with confirmed lineups")
    return games


