def _parse_underdog_tweet(text: str) -> Optional[tuple]:
    """Parse 'Angels 4/5  Neto SS Trout CF ... Klassen SP' → (abbr, data)."""
    text = re.sub(r"^Updated\s+", "", text.strip())
    date_match = re.search(r"\d+/\d+", text)
    if not date_match:
        return None

    team_part = text[:date_match.start()].strip()
    rest      = text[date_match.end():].strip()

    team_abbr = None
    for name, abbr in TEAM_NAME_MAP.items():
        if team_part.lower().startswith(name.lower()):
            team_abbr = abbr
            break

    if not team_abbr:
        return None

    tokens  = rest.split()
    lineup  = []
    pitcher = ""
    order   = 1
    i = 0
    while i < len(tokens):
        if i + 1 < len(tokens) and tokens[i + 1] in TWEET_POSITIONS:
            name, pos = tokens[i], tokens[i + 1]
            if pos == "SP":
                pitcher = name
            elif pos not in ("RP",):
                lineup.append((name, pos, order))
                order += 1
            i += 2
        else:
            i += 1

    return (team_abbr, {"lineup": lineup, "pitcher": pitcher}) if lineup else None



