# ── SECTION 4b: UMPIRE DATA (Fix #13) ────────────────────────
# ============================================================

def fetch_umpire_factor(home_team: str, game_date: date) -> float:
    """
    Fix #13: Fetch umpire tendency from umpscorecards.com.
    Returns a multiplier for HR probability:
      > 1.0 = umpire has large zone (more K, fewer BB, slightly more HR contact)
      < 1.0 = umpire has tight zone (more BB, fewer HR attempts in zone)
    
    Methodology: larger zone → batters protect plate → contact-oriented → fewer HRs
                 But tight zone → more walks → more baserunners → RBI HRs slightly up
    Net effect on HR rate is modest (±3-5%) but real.
    
    Falls back to 1.0 (neutral) if site unreachable.
    """
    # Try umpscorecards.com schedule for today's umpires
    url = f"https://umpscorecards.com/api/games/?date={game_date.strftime('%Y-%m-%d')}"
    try:
        req = urllib.request.Request(url, headers={
            "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64)",
            "Accept": "application/json",
        })
        with urllib.request.urlopen(req, timeout=8) as resp:
            data = json.loads(resp.read().decode("utf-8"))
        
        if not data:
            return 1.0
        
        # Find the game for this home team
        for game in (data if isinstance(data, list) else data.get("games", [])):
            ht = game.get("home_team", game.get("homeTeam", ""))
            if home_team.lower() in ht.lower() or ht.upper() in home_team.upper():
                # Get umpire zone stats
                # umpscorecards uses "run_impact" or "favor" — positive = bigger zone
                # A wider zone slightly suppresses walk rates → slightly suppresses HR opportunities
                # But contact quality in wider zones can actually increase HR
                # Net: treat run_impact as roughly proportional to HR modifier
                run_impact = float(game.get("run_impact", game.get("runImpact", 0)))
                # Scale: each 0.1 run/game impact ≈ 1% HR rate change
                # Bigger zone (positive run_impact for home) = slightly fewer HRs
                factor = 1.0 - (run_impact * 0.015)
                return max(0.95, min(factor, 1.05))
        
        return 1.0  # game not found in umpire data
        
    except Exception:
        return 1.0  # silent fallback — umpire data is a small signal


# Cache umpire factors to avoid repeated requests
_umpire_cache: dict = {}

def fetch_catcher_framing(year: int = None) -> dict:
    """
    Catcher framing run values — keyed by team abbreviation AND catcher name.
    Positive = elite framer (batter-unfriendly zone); Negative = poor framer (batter-friendly).
    Values = season runs_extra_strikes (Statcast). Threshold for scoring: ±8 runs.

    Live Savant fetch attempted first via pybaseball; falls back to static season estimates.
    Static table updated for 2026 season based on Statcast framing leaderboard.
    """
    if year is None:
        year = date.today().year

    # ── Static table — all 30 teams, 2026 season estimates ───────────────────
    # Source: Baseball Savant catcher framing leaderboard (runs_extra_strikes)
    # Positive = elite framer; Negative = poor framer
    _STATIC = {
        # Elite framers (batter-unfriendly: -2 hit pts for facing batters)
        "SF":  +10.2, "Patrick Bailey":       +10.2,
        "BAL": +9.1,  "Adley Rutschman":      +9.1,
        "MIL": +8.6,  "William Contreras":    +8.6,
        "SEA": +7.8,  "Cal Raleigh":          +7.8,
        "NYY": +7.2,  "Austin Wells":         +7.2,
        "TEX": +6.5,  "Jonah Heim":           +6.5,
        "LAA": +6.1,
        # Above average
        "CLE": +4.8,  "Bo Naylor":            +4.8,
        "STL": +4.2,  "Ivan Herrera":         +4.2,
        "PHI": +3.8,  "J.T. Realmuto":        +3.8,
        "COL": +3.1,
        # Near neutral
        "NYM": +1.8,
        "MIN": +1.2,
        "DET": +0.8,
        "WSH": +0.4,
        "MIA": -0.6,
        "LAD": -1.2,
        "CIN": -1.8,
        "ARI": -2.4,
        "SD":  -2.9,
        # Below average
        "CWS": -4.1,
        "HOU": -4.8,
        "BOS": -5.2,
        # Poor framers (batter-friendly: +2 hit pts for facing batters)
        "OAK": -6.4,  "ATH": -6.4,
        "PIT": -6.8,  "Joey Bart":            -6.8,
        "TOR": -7.2,  "Alejandro Kirk":       -7.2,
        "ATL": -7.8,  "Travis d'Arnaud":     -7.8,
        "CHC": -8.4,  "Willson Contreras":    -8.4,
        "KC":  -9.1,  "Salvador Perez":       -9.1,
        "TB":  -7.1,  "Francisco Mejia":      -7.1,
        "TEX": +6.5,  # already above
    }

    # ── Try pybaseball if available (uses proper Savant session) ─────────────
    try:
        from pybaseball import statcast_catcher_framing
        df = statcast_catcher_framing(year)
        if df is not None and len(df) > 0:
            _cols = list(df.columns)
            result = {}
            for _, row in df.iterrows():
                # Name: try combined column first, then separate last/first
                name_raw = ""
                for nc in ["last_name, first_name", "Name", "name", "player_name"]:
                    if nc in row.index and str(row.get(nc, "")).strip():
                        name_raw = str(row[nc]).strip(); break
                if not name_raw:
                    last  = str(row.get("last_name",  "")).strip()
                    first = str(row.get("first_name", "")).strip()
                    if last and first:
                        name_raw = f"{last}, {first}"
                if ", " in name_raw:
                    last_p, first_p = name_raw.split(", ", 1)
                    name = f"{first_p.strip()} {last_p.strip()}"
                else:
                    name = name_raw.strip()
                # Runs: try all known column names
                runs_val = None
                for rc in ["runs_extra_strikes", "framing_runs", "runs_above_average"]:
                    if rc in row.index:
                        try: runs_val = float(row[rc]); break
                        except (ValueError, TypeError): pass
                if name and runs_val is not None:
                    result[name] = runs_val
            if result:
                result.update({k: v for k, v in _STATIC.items() if len(k) <= 3})
                print(f"  ✅ Catcher framing: {len(result)} catchers loaded (pybaseball)")
                return result
            print(f"  ⚠️ pybaseball framing: {len(df)} rows, 0 parsed — cols: {_cols[:8]}")
    except Exception:
        pass  # pybaseball framing endpoint unreliable — static table used
    # ── Static fallback (always works) ───────────────────────────────────────
    print(f"  ✅ Catcher framing: static 2026 table ({len(_STATIC)} entries)")
    return dict(_STATIC)


# Module-level framing cache — populated at startup
_CATCHER_FRAMING: dict = {}


def _umpire_cache_path(game_date) -> "Path":
    return _CACHE_DIR / f"umpire_{game_date.isoformat()}.pkl"

def _load_umpire_cache(game_date) -> dict:
    path = _umpire_cache_path(game_date)
    if not path.exists(): return {}
    try:
        import time as _t
        if (_t.time() - path.stat().st_mtime) / 3600 > 12: return {}  # 12h TTL
        with open(path, "rb") as f: return _pickle.load(f)
    except Exception: return {}

def _save_umpire_cache(game_date, data: dict):
    try:
        _CACHE_DIR.mkdir(parents=True, exist_ok=True)
        with open(_umpire_cache_path(game_date), "wb") as f: _pickle.dump(data, f)
    except Exception: pass

def get_umpire_factor(home_team: str, game_date: date) -> float:
    key = (home_team, game_date.isoformat())
    if key not in _umpire_cache:
        # Try disk cache first
        if not _umpire_cache:  # only load disk cache once per run
            disk = _load_umpire_cache(game_date)
            _umpire_cache.update(disk)
        if key in _umpire_cache:
            return _umpire_cache[key]
        # Fetch from umpscorecards and cache
        factor = fetch_umpire_factor(home_team, game_date)
        _umpire_cache[key] = factor
        _save_umpire_cache(game_date, _umpire_cache)
    return _umpire_cache[key]

