# Maps baseballwx team name abbreviations → our team abbrs
# baseballwx uses city/short names in the game rows
_BWX_TEAM_MAP = {
    "ARI":"ARI","ATL":"ATL","BAL":"BAL","BOS":"BOS","CHC":"CHC",
    "CWS":"CWS","CIN":"CIN","CLE":"CLE","COL":"COL","DET":"DET",
    "HOU":"HOU","KC":"KC","LAA":"LAA","LAD":"LAD","MIA":"MIA",
    "MIL":"MIL","MIN":"MIN","NYM":"NYM","NYY":"NYY","OAK":"OAK",
    "PHI":"PHI","PIT":"PIT","SD":"SD","SF":"SF","SEA":"SEA",
    "STL":"STL","TB":"TB","TEX":"TEX","TOR":"TOR","WSH":"WSH",
    # alternate spellings baseballwx sometimes uses
    "CHW":"CWS","KAN":"KC","KCR":"KC","SDP":"SD","SFG":"SF",
    "TBR":"TB","WSN":"WSH","AZ":"ARI",
}


def fetch_baseballwx() -> dict:
    import re, urllib.request
    url = "https://www.baseballwx.com/index.html"
    req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0"})
    try:
        with urllib.request.urlopen(req, timeout=15) as resp:
            html = resp.read().decode("utf-8", errors="ignore")
    except Exception as e:
        print(f"  ⚠️  baseballwx error: {e}")
        return {}

    results = {}
    # Find each game block (starts with <a name="...">)
    blocks = re.split(r'<a name="\d+">', html)
    for block in blocks[1:]:
        # Extract team names from the matchup header
        matchup = re.search(r'<th colspan="8">(.*?)</th>', block, re.DOTALL)
        if not matchup:
            continue
        matchup_text = matchup.group(1)
        # Parse "Kansas City Royals at Cleveland Guardians"
        at_match = re.search(r'(.+?)\s+at\s+(.+?)(?:,|$)', matchup_text)
        if not at_match:
            continue
        away_raw = at_match.group(1).strip()
        home_raw = at_match.group(2).strip()
        away = TEAM_NAME_MAP.get(away_raw, away_raw.upper()[:3])
        home = TEAM_NAME_MAP.get(home_raw, home_raw.upper()[:3])

        # Check dome
        if "roof or dome" in block.lower() or "retractable roof" in block.lower():
            results[(away, home)] = {
                "temp_f": 72, "wind_speed": 0, "wind_out": False,
                "condition": "Dome", "run_adj": 0.0, "bso_adj": 0.0, "source": "dome"
            }
            continue

        # Find the index of the bold hour (game time)
        hours_row = re.search(r'<tr class="hours">(.*?)</tr>', block, re.DOTALL)
        bold_idx = 2  # default to 3rd column (6pm)
        if hours_row:
            hour_cells = re.findall(r'<td[^>]*>(.*?)</td>', hours_row.group(1))
            for i, cell in enumerate(hour_cells):
                if 'bold' in cell:
                    bold_idx = i
                    break

        # Temperature: find the row with "Temperature"
        temp_row = re.search(r'<tr>.*?Temperature.*?</tr>', block, re.DOTALL)
        temp_f = 72.0
        if temp_row:
            temp_cells = re.findall(r'<td[^>]*>(\d+)°', temp_row.group(0))
            if bold_idx < len(temp_cells):
                temp_f = float(temp_cells[bold_idx])

        # Wind speed: find the row with "Wind Dir & Speed"
        wind_row = re.search(r'Wind Dir &amp; Speed.*?</tr>', block, re.DOTALL)
        wind_speed = 0
        wind_dir = ""
        if wind_row:
            wind_cells = re.findall(r'<td[^>]*>(.*?)</td>', wind_row.group(0), re.DOTALL)
            if bold_idx < len(wind_cells):
                wind_cell = wind_cells[bold_idx]
                w_match = re.search(r'([A-Z]+)<br>\s*(\d+)\s*mph', wind_cell)
                if w_match:
                    wind_dir = w_match.group(1)
                    wind_speed = int(w_match.group(2))

        wind_out = wind_dir in ['N', 'NNW', 'NW', 'WNW', 'W'] and wind_speed >= 8

        # Runs adjustment
        runs_match = re.search(r'Runs\s+([+-]\d+\.?\d*)%', block)
        run_adj = float(runs_match.group(1))/100 if runs_match else 0.0

        results[(away, home)] = {
            "temp_f": temp_f,
            "wind_speed": wind_speed,
            "wind_out": wind_out,
            "condition": "baseballwx",
            "run_adj": run_adj,
            "bso_adj": compute_weather_adjs(temp_f, wind_speed, wind_out)[1],
            "source": "baseballwx"
        }

    print(f"  ✅ baseballwx: {len(results)} games parsed")
    return results


def _fetch_openmeteo(lat, lon, game_date, game_hour, is_historical, home_team) -> dict:
    """Single-game Open-Meteo fetch (used as fallback when baseballwx misses a game)."""
    base = ("https://archive-api.open-meteo.com/v1/archive"
            if is_historical else
            "https://api.open-meteo.com/v1/forecast")
    url = (f"{base}?latitude={lat}&longitude={lon}"
           f"&hourly=temperature_2m,wind_speed_10m,wind_direction_10m,weather_code"
           f"&wind_speed_unit=mph&temperature_unit=fahrenheit"
           f"&timezone=auto&start_date={game_date}&end_date={game_date}")
    data = _get(url)
    if not data or "hourly" not in data:
        return {"temp_f":72.0, "wind_speed":0.0, "wind_out":False,
                "dome":False, "condition":"Unknown", "run_adj":0.0,
                "bso_adj":0.0, "source":"default"}
    h      = data["hourly"]
    times  = h.get("time", [])
    target = f"{game_date}T{game_hour:02d}:00"
    idx    = next((i for i, t in enumerate(times) if t >= target), 0)
    temp_f   = float(h["temperature_2m"][idx] or 72)
    wind_mph = float(h["wind_speed_10m"][idx] or 0)
    wind_dir = float(h["wind_direction_10m"][idx] or 0)
    w_code   = int((h.get("weather_code",[0]*24))[idx] or 0)
    wind_out = _wind_is_out(wind_dir, wind_mph, home_team)
    cond = ("Clear" if w_code==0 else "Partly Cloudy" if w_code<=3
            else "Foggy" if w_code<=49 else "Rainy" if w_code<=69
            else "Thunderstorms" if w_code<=99 else "Unknown")
    return {"temp_f":round(temp_f,1), "wind_speed":round(wind_mph,1),
            "wind_out":wind_out, "wind_dir_deg":round(wind_dir,1),
            "dome":False, "condition":cond,
            "run_adj":0.0, "bso_adj":0.0, "source":"open-meteo"}


# ── Weather cache helpers ─────────────────────────────────────────────────────
_WEATHER_CACHE_TTL_HOURS = 3.0   # re-fetch if > 3h old (forecasts shift, esp. precip)

def _weather_cache_path(target_date) -> "Path":
    return _CACHE_DIR / f"weather_{target_date.isoformat()}.pkl"

def _sgo_cache_path(target_date) -> "Path":
    return _CACHE_DIR / f"sgo_props_{target_date.isoformat()}.pkl"

def _load_sgo_cache(target_date) -> dict:
    """Load today's SGO props cache. Returns {} if missing. No TTL — SGO odds
    don't change meaningfully intraday and we want to avoid burning credits."""
    path = _sgo_cache_path(target_date)
    if not path.exists():
        return {}
    try:
        import time as _time2
        age_h = (_time2.time() - path.stat().st_mtime) / 3600
        with open(path, "rb") as f:
            data = _pickle.load(f)
        n = len(data.get("props", {}))
        print(f"  💾 SGO cache: {n} players ({age_h:.1f}h old) — skipping SGO fetch")
        return data
    except Exception:
        return {}

def _save_sgo_cache(target_date, data: dict):
    """Save SGO props keyed by player name."""
    try:
        _CACHE_DIR.mkdir(parents=True, exist_ok=True)
        with open(_sgo_cache_path(target_date), "wb") as f:
            _pickle.dump(data, f)
        print(f"  💾 SGO cache saved: {len(data.get('props', {}))} players → sgo_props_{target_date.isoformat()}.pkl")
    except Exception as e:
        print(f"  ⚠️  SGO cache write failed: {e}")

def _load_weather_cache(target_date) -> dict:
    """Load today's weather cache. Returns {} if missing or stale."""
    path = _weather_cache_path(target_date)
    if not path.exists():
        return {}
    try:
        import time as _time
        age_h = (_time.time() - path.stat().st_mtime) / 3600
        if age_h > _WEATHER_CACHE_TTL_HOURS:
            return {}
        with open(path, "rb") as f:
            data = _pickle.load(f)
        print(f"  💾 Weather cache: {len(data)} games ({age_h:.1f}h old) — refetches after {_WEATHER_CACHE_TTL_HOURS:.0f}h")
        return data
    except Exception:
        return {}

def _save_weather_cache(target_date, data: dict):
    """Save weather data keyed by home_team."""
    try:
        _CACHE_DIR.mkdir(parents=True, exist_ok=True)
        with open(_weather_cache_path(target_date), "wb") as f:
            _pickle.dump(data, f)
    except Exception as e:
        print(f"  ⚠️  Weather cache write failed: {e}")


def fetch_weather(lat: float, lon: float, game_time_utc: str,
                  dome: bool, home_team: str, away_team: str,
                  bwx_cache: dict,
                  target_date: Optional[date] = None,
                  weather_day_cache: Optional[dict] = None) -> dict:
    """weather_day_cache: mutable dict shared across all games in one run.
    Pass the same dict object for every call; it is populated lazily."""
    if dome:
        return {"temp_f":72.0, "wind_speed":0.0, "wind_out":False,
                "dome":True, "condition":"Dome", "run_adj":0.0,
                "bso_adj":0.0, "source":"dome"}

    # ── Per-run in-memory cache check ────────────────────────────────────────
    if weather_day_cache is not None and home_team in weather_day_cache:
        return weather_day_cache[home_team]

    is_historical = (target_date is not None) and (target_date < date.today())

    # For historical dates, always use Open‑Meteo archive
    if is_historical:
        try:
            dt = datetime.fromisoformat(game_time_utc.replace("Z","+00:00"))
            game_hour = dt.hour
            game_date = dt.strftime("%Y-%m-%d")
        except Exception:
            game_date = target_date.strftime("%Y-%m-%d")
            game_hour = 19
        time.sleep(1.0)  # be gentle
        result = _fetch_openmeteo(lat, lon, game_date, game_hour, True, home_team)
        if weather_day_cache is not None:
            weather_day_cache[home_team] = result
        return result

    # For today: try Open‑Meteo first (with retries), then baseballwx cache
    try:
        dt = datetime.fromisoformat(game_time_utc.replace("Z","+00:00"))
        game_hour = dt.hour
        game_date = dt.strftime("%Y-%m-%d")
    except Exception:
        game_date = date.today().strftime("%Y-%m-%d")
        game_hour = 19

    # Try Open‑Meteo (primary)
    result = _fetch_openmeteo(lat, lon, game_date, game_hour, False, home_team)
    if result.get("source") != "default":   # successful fetch
        if weather_day_cache is not None:
            weather_day_cache[home_team] = result
        return result

    # Fallback to baseballwx cache
    key = (away_team, home_team)
    if key in bwx_cache:
        res = dict(bwx_cache[key])
        res["dome"] = False
        if weather_day_cache is not None:
            weather_day_cache[home_team] = res
        return res

    # Ultimate fallback
    fallback = {"temp_f":72.0, "wind_speed":0.0, "wind_out":False,
                "dome":False, "condition":"Unknown", "run_adj":0.0,
                "bso_adj":0.0, "source":"default"}
    if weather_day_cache is not None:
        weather_day_cache[home_team] = fallback
    return fallback


def _wind_is_out(wind_dir_deg: float, speed: float, home_team: str) -> bool:
    """
    True if wind is blowing out toward the outfield.
    Wind direction (meteorological): degrees FROM which wind blows.
    0° = wind from North (blows south), 90° = from East (blows west).
    "Out" means wind blows TOWARD the outfield of the given stadium.
    Uses ±65° threshold (wider than 45° — outfield spans ~120° arc).
    """
    if speed < 4:
        return False
    outfield_dir = STADIUM_OUTFIELD_DIR.get(home_team, 270)
    # Wind blows FROM wind_dir_deg, so it blows TOWARD (wind_dir_deg + 180) % 360
    wind_toward = (wind_dir_deg + 180) % 360
    diff = abs(wind_toward - outfield_dir)
    if diff > 180:
        diff = 360 - diff
    # ±65° covers the outfield arc; strong winds (>15mph) get wider tolerance
    threshold = 75 if speed >= 15 else 65
    return diff <= threshold


