def fetch_pitcher_discipline(year: int) -> dict:
    """
    Fetch pitcher discipline stats from FanGraphs advanced tab (type=8).
    Returns dict: {pitcher_name: {csw_pct, o_swing_pct, z_contact_pct, foul_pct, siera}}

    Video metrics:
    - CSW%:      Called Strikes + Whiffs. Target >30%. Better command signal than SwStr% alone.
    - O-Swing%:  Batters swing on out-of-zone pitches. Avg 32%. High = pitcher expands zone.
    - Z-Contact%: Contact rate IN zone. Avg 86%. ≥88% = batters making easy contact.
    - Foul%:     Foul ball %. >20% = high workload but fewer hard hits.
    - SIERA:     Skill-Interactive ERA from FanGraphs standard tab.

    Source: FanGraphs public API (no auth required).
    """
    import json as _json
    import urllib.request as _req3

    result = {}

    # ── Fetch 1: Advanced tab (type=8) for CSW%, O-Swing%, Z-Contact% ────────
    try:
        url_adv = (
            f"https://www.fangraphs.com/api/leaders/major-league/data"
            f"?age=0&pos=all&stats=pit&lg=all&qual=10&season={year}&season1={year}"
            f"&startdate=&enddate=&ind=0&team=0&rost=0&players=0"
            f"&type=8&pageitems=2000&pagenum=1"
        )
        with _req3.urlopen(url_adv, timeout=12) as _r:
            _data = _json.loads(_r.read())
        _rows = _data.get("data", []) if isinstance(_data, dict) else []
        for _row in _rows:
            _name = str(_row.get("PlayerName") or _row.get("playerName") or "").strip()
            if not _name:
                continue
            def _fl(key, default=0.0):
                v = _row.get(key)
                try: return float(v) if v is not None else default
                except: return default
            # FanGraphs API returns these rate stats as DECIMAL FRACTIONS
            # (e.g. 0.32 for 32%), but every downstream consumer — the note
            # formatter (f"{x:.1f}% O-Swing") and the vuln scoring adjustment
            # ((32.0 - o_swing_pct)*0.3) — expects PERCENTAGE POINTS (32.0).
            # Without normalization the model printed "0.3% O-Swing" on every
            # pitcher and applied a bogus ~+9.5 vuln adjustment slate-wide.
            def _pct(v):
                return v * 100.0 if 0.0 < v < 1.5 else v
            _csw  = _pct(_fl("CSW")   or _fl("csw_pct")   or _fl("CSW%"))
            _osz  = _pct(_fl("O-Swing%") or _fl("o_swing") or _fl("OSwing%") or _fl("O_Swing"))
            _zcn  = _pct(_fl("Z-Contact%") or _fl("z_contact") or _fl("ZContact%") or _fl("Z_Contact"))
            _foul = _pct(_fl("F-Strike%") or _fl("Foul%") or _fl("foul_pct"))  # F-Strike isn't foul, but foul% is in Statcast
            if _csw or _osz or _zcn:
                result[_name] = {"csw_pct": _csw, "o_swing_pct": _osz, "z_contact_pct": _zcn, "foul_pct": _foul}
    except Exception as _e:
        pass  # silent fallback; SIERA fetch below may still work

    # ── Fetch 2: Standard tab (type=0) for SIERA ──────────────────────────────
    try:
        url_std = (
            f"https://www.fangraphs.com/api/leaders/major-league/data"
            f"?age=0&pos=all&stats=pit&lg=all&qual=10&season={year}&season1={year}"
            f"&startdate=&enddate=&ind=0&team=0&rost=0&players=0"
            f"&type=0&pageitems=2000&pagenum=1"
        )
        with _req3.urlopen(url_std, timeout=12) as _r:
            _data = _json.loads(_r.read())
        _rows = _data.get("data", []) if isinstance(_data, dict) else []
        for _row in _rows:
            _name = str(_row.get("PlayerName") or _row.get("playerName") or "").strip()
            if not _name:
                continue
            _siera_v = _row.get("SIERA") or _row.get("siera") or _row.get("SIERA-")
            try: _siera_f = float(_siera_v) if _siera_v is not None else 0.0
            except: _siera_f = 0.0
            if _siera_f > 0:
                if _name in result:
                    result[_name]["siera"] = _siera_f
                else:
                    result[_name] = {"csw_pct": 0.0, "o_swing_pct": 0.0,
                                     "z_contact_pct": 0.0, "foul_pct": 0.0,
                                     "siera": _siera_f}
    except Exception as _e:
        pass

    if result:
        n_csw   = sum(1 for v in result.values() if v.get("csw_pct",   0) > 0)
        n_siera = sum(1 for v in result.values() if v.get("siera",     0) > 0)
        elite_csw = [n for n, v in result.items() if v.get("csw_pct", 0) >= 30]
        print(f"  ✅ Pitcher discipline: {len(result)} pitchers | CSW={n_csw} | SIERA={n_siera}"
              + (f" | Elite CSW (≥30%): {', '.join(elite_csw[:3])}" if elite_csw else ""))

    return result


def fetch_pitcher_l5_starts(pitcher_id_map: dict, season: int = 2026) -> dict:
    """
    Fetch last-5-start stats for each starting pitcher using the MLB Stats API.
    This is the "recency window" the video recommends alongside season + prior season.

    Args:
        pitcher_id_map: {pitcher_name: mlb_player_id}  (collected from schedule fetch)
        season: current season year

    Returns:
        {pitcher_name: {l5_era, l5_k9, l5_hr9, l5_bb9, l5_ip, recent_hr_factor}}

    recent_hr_factor is the ratio L5_HR9 / season_HR9:
      > 1.20 = pitcher is getting hit hard lately (HR-prone recently)
      < 0.80 = pitcher is suppressing HRs lately (buy-low)
      1.00   = at season average (neutral)
    """
    import urllib.request as _req2, json as _js2
    results = {}

    for name, pid in pitcher_id_map.items():
        if not pid:
            continue
        try:
            url = (f"https://statsapi.mlb.com/api/v1/people/{pid}/stats"
                   f"?stats=gameLog&group=pitching&season={season}&gameType=R"
                   f"&fields=stats,splits,stat,era,strikeoutsPer9Inn,homeRunsPer9,"
                   f"walksPer9Inn,inningsPitched,numberOfPitches,gamesStarted,type")
            with _req2.urlopen(url, timeout=8) as _r2:
                data = _js2.loads(_r2.read())
        except Exception:
            continue

        splits = []
        for stat_block in data.get("stats", []):
            for split in stat_block.get("splits", []):
                s = split.get("stat", {})
                try:
                    ip = float(s.get("inningsPitched", 0) or 0)
                    gs = int(s.get("gamesStarted", 0) or 0)
                    # Track all appearances (including relief) to detect first-start-of-season.
                    # Relief appearances (gs=0) are stored with gs=0 tag but excluded from
                    # L5 averages (only starts count for ERA/K9/HR9 calculations).
                    if ip < 0.1:
                        continue   # skip genuine 0-IP appearances (mop-up entries)
                    if gs == 0:
                        # Relief appearance — track the gs=0 tag but skip L5 stat calc
                        splits.append({"ip": ip, "era": 0.0, "k9": 0.0, "hr9": 0.0,
                                        "bb9": 0.0, "gs": 0})
                        continue
                    if gs == 0:   # (unreachable — kept for linter) skip relief appearances
                        continue
                    era  = float(s.get("era",                "4.50") or 4.50)
                    k9   = float(s.get("strikeoutsPer9Inn",  "8.50") or 8.50)
                    hr9  = float(s.get("homeRunsPer9",       "1.20") or 1.20)
                    bb9  = float(s.get("walksPer9Inn",       "3.00") or 3.00)
                    splits.append({"ip": ip, "era": era, "k9": k9, "hr9": hr9, "bb9": bb9})
                except (ValueError, TypeError):
                    continue

        if not splits:
            continue

        # Take the last 5 starts (most recent first from game log)
        last5 = splits[-5:] if len(splits) >= 5 else splits
        total_ip = sum(g["ip"] for g in last5)
        if total_ip < 5.0:   # too few innings — unreliable (sample size gate)
            continue

        # IP-weighted averages across the last 5 starts
        l5_era = sum(g["era"] * g["ip"] for g in last5) / total_ip
        l5_k9  = sum(g["k9"]  * g["ip"] for g in last5) / total_ip
        l5_hr9 = sum(g["hr9"] * g["ip"] for g in last5) / total_ip
        l5_bb9 = sum(g["bb9"] * g["ip"] for g in last5) / total_ip

        # season_hr9 needs the full season for the ratio — use all splits average
        all_ip   = sum(g["ip"] for g in splits)
        szn_hr9  = sum(g["hr9"] * g["ip"] for g in splits) / max(all_ip, 1.0)

        # recent_hr_factor: how much MORE (or less) HR-prone than season average
        # Cap at [0.70, 1.45] — extreme values are noise, not signal
        if szn_hr9 > 0:
            recent_hr_factor = max(0.70, min(l5_hr9 / szn_hr9, 1.45))
        else:
            recent_hr_factor = 1.0

        # ── First start of season detection ─────────────────────────────────
        # A pitcher is making their first start of 2026 if ALL appearances in the
        # game log are relief stints (gs=0 tag). The last5 total_ip window may be
        # < 5 IP for a relief-only pitcher (e.g. Madden: 2.38 ERA in short stints),
        # so we use ALL splits ip — not the last5 window — for this check.
        # The gs key is ONLY set for entries added via the relief path (gs=0 tag);
        # regular start entries have no "gs" key, so get("gs", 1) defaults to 1.
        _all_relief = all(g.get("gs", 1) == 0 for g in splits) if splits else False
        _all_splits_ip = sum(g["ip"] for g in splits)
        _first_start = _all_relief and _all_splits_ip >= 1.0   # at least 1 IP proof they've pitched

        # ── Last-2-starts window ────────────────────────────────────────────
        # Computed from the same splits list, taking the final 2 entries.
        last2    = splits[-2:] if len(splits) >= 2 else splits
        l2_ip    = sum(g["ip"] for g in last2)
        l2_hr9   = (sum(g["hr9"] * g["ip"] for g in last2) / l2_ip
                    if l2_ip >= 2.0 else 0.0)

        results[name] = {
            "l5_era":               round(l5_era, 2),
            "l5_k9":                round(l5_k9,  2),
            "l5_hr9":               round(l5_hr9,  2),
            "l5_bb9":               round(l5_bb9,  2),
            "l5_ip":                round(total_ip, 1),
            "l2_hr9":               round(l2_hr9,  2),
            "l2_ip":                round(l2_ip,   1),
            "recent_hr_factor":     round(recent_hr_factor, 3),
            "first_start_of_season": _first_start,
        }

    return results


def fetch_bullpen_fatigue_3d(target_date=None) -> dict:
    """
    Fetch last-3-day bullpen workload from MLB Stats API.
    Returns {team_abbr: (total_ip_3d, fatigue_mult)} where fatigue_mult > 1 = tired.
    Uses /api/v1/schedule with game log data — completely free, no OddsAPI credits.

    Fatigue thresholds (from bullpen research):
      < 6 IP in 3 days: fresh (1.00x)
      6-9 IP in 3 days: moderate (1.05x)
      9-12 IP in 3 days: tired (1.12x)
      > 12 IP in 3 days: exhausted (1.20x)
    """
    import datetime, urllib.request, json
    if target_date is None:
        target_date = datetime.date.today()
    if isinstance(target_date, str):
        target_date = datetime.date.fromisoformat(target_date)

    team_ip: dict = {}
    for days_back in range(1, 4):
        d = target_date - datetime.timedelta(days=days_back)
        url = (f"https://statsapi.mlb.com/api/v1/schedule?sportId=1"
               f"&date={d.isoformat()}&gameType=R"
               f"&hydrate=linescore,boxscore&fields="
               f"dates,games,gamePk,teams,teamName,pitchers,pitchingStats,inningsPitched")
        try:
            with urllib.request.urlopen(url, timeout=8) as r:
                data = json.loads(r.read())
        except Exception:
            continue

        for date_entry in data.get("dates", []):
            for game in date_entry.get("games", []):
                for side in ["home", "away"]:
                    team_data = game.get("teams", {}).get(side, {})
                    abbr = team_data.get("team", {}).get("abbreviation", "")
                    if not abbr:
                        continue
                    # Sum IP for all non-starters (bullpen = pitchers after the first)
                    pitchers = team_data.get("pitchers", [])
                    bullpen_pitchers = pitchers[1:] if len(pitchers) > 1 else []
                    for pid in bullpen_pitchers:
                        p_stats = (game.get("boxscore", {})
                                   .get("teams", {}).get(side, {})
                                   .get("players", {})
                                   .get(f"ID{pid}", {})
                                   .get("stats", {}).get("pitching", {}))
                        ip_str = str(p_stats.get("inningsPitched", "0.0") or "0.0")
                        try:
                            ip_parts = ip_str.split(".")
                            ip_val = float(ip_parts[0]) + float(ip_parts[1]) / 3 if len(ip_parts) > 1 else float(ip_str)
                        except (ValueError, IndexError):
                            ip_val = 0.0
                        team_ip[abbr] = team_ip.get(abbr, 0.0) + ip_val

    # Convert to fatigue multipliers
    result = {}
    for abbr, total_ip in team_ip.items():
        if total_ip < 6.0:
            mult = 1.00
        elif total_ip < 9.0:
            mult = 1.05
        elif total_ip < 12.0:
            mult = 1.12
        else:
            mult = 1.20
        result[abbr] = {"ip_3d": round(total_ip, 1), "fatigue_mult": mult}
    return result

def fetch_bullpen_stats(year: int) -> dict:
    """
    Fix #6: Auto-fetch bullpen HR stats.
    Sources tried in order:
      1. Disk cache
      2. pybaseball statcast_pitcher_exitvelo_barrels (relievers via role filter)
      3. MLB Stats API team pitching stats (always works)
      4. Prior-year versions of above
    """
    # Cache check
    cached = _load_cache(year, "bullpens")
    if cached and len(cached) >= 20:
        return cached

    bullpens: dict = {}

    # ── Source 1: Statcast exitvelo for relievers ─────────────
    try:
        from pybaseball import statcast_pitcher_exitvelo_barrels
        print(f"  📡 pybaseball: bullpen statcast exitvelo ({year})...")
        df = statcast_pitcher_exitvelo_barrels(year, minBBE=5)
        if df is not None and not df.empty:
            # We don't have role (SP/RP) in this endpoint directly
            # Proxy: pitchers with low BF counts are likely relievers
            # FanGraphs role column not available here — skip role filter,
            # use all pitchers and weight by team aggregate
            col_map = {
                "last_name, first_name": "_raw_name",
                "exit_velocity_avg": "EV",
                "barrel_batted_rate": "Barrel%",
                "hard_hit_percent": "HardHit%",
                "xwoba": "xwOBA",
                "team_name_abbrev": "Team",
                "p_throws": "Throws",
            }
            df = df.rename(columns={k: v for k, v in col_map.items() if k in df.columns})
            # HR/9 not in exitvelo endpoint — use xwOBA as proxy for vulnerability
            # xwOBA → HR/9 rough mapping: xwOBA 0.300 ≈ 1.0 HR/9, 0.350 ≈ 1.5 HR/9
            if "xwOBA" in df.columns:
                df["HR/9"] = (df["xwOBA"].fillna(0.315).astype(float) - 0.270) * 15 + 1.0
    except Exception as e:
        print(f"  ⚠️  Statcast bullpen failed: {e}")
        df = None

    # ── Source 2: MLB Stats API team bullpen (always works) ───
    print(f"  📡 MLB Stats API: team pitching stats ({year})...")
    try:
        url = (f"https://statsapi.mlb.com/api/v1/stats"
               f"?stats=season&group=pitching&season={year}&sportId=1"
               f"&gameType=R&limit=2000")
        data = _get(url)
        if data and "stats" in data:
            for s in data["stats"][0].get("splits", []):
                team_info = s.get("team", {})
                team_id   = team_info.get("id", 0)
                team_abbr = MLB_TEAM_ID_MAP.get(team_id, "")
                if not team_abbr:
                    continue
                stat = s.get("stat", {})
                # Get team-level totals
                ip_str = str(stat.get("inningsPitched", "0"))
                try:
                    ip = float(ip_str)
                except Exception:
                    ip = 0
                hr  = int(stat.get("homeRuns", 0) or 0)
                hh_pct  = 38.0   # not in Stats API
                fb_pct  = 35.0   # not in Stats API
                xwoba   = 0.315  # not in Stats API
                # Early season: use league-avg if fewer than 10 IP logged
                hr9 = (hr / max(ip, 1)) * 9 if ip >= 10 else 1.30

                # Estimate bullpen portion: assume bullpen threw ~40% of IP
                bullpen_hr9 = hr9 * 1.05   # bullpens slightly worse than rotation avg
                if team_abbr not in bullpens:
                    bullpens[team_abbr] = BullpenProfile(
                        team=team_abbr,
                        hr9_allowed     = round(bullpen_hr9, 3),
                        hard_hit_pct    = hh_pct,
                        fb_pct_allowed  = fb_pct,
                        xwoba_allowed   = xwoba,
                        expected_innings= 3.5,
                    )
        if bullpens:
            print(f"  ✅ MLB Stats API bullpen: {len(bullpens)} teams")
    except Exception as e:
        print(f"  ⚠️  MLB Stats API bullpen failed: {e}")

    # Prior-year fallback
    if len(bullpens) < 20 and year >= 2024:
        prior = year - 1
        print(f"  ⚠️  Bullpen thin for {year}, trying {prior}...")
        try:
            url = (f"https://statsapi.mlb.com/api/v1/stats"
                   f"?stats=season&group=pitching&season={prior}&sportId=1"
                   f"&gameType=R&limit=2000")
            data = _get(url)
            if data and "stats" in data:
                for s in data["stats"][0].get("splits", []):
                    team_id   = s.get("team", {}).get("id", 0)
                    team_abbr = MLB_TEAM_ID_MAP.get(team_id, "")
                    if not team_abbr or team_abbr in bullpens:
                        continue
                    stat = s.get("stat", {})
                    ip_str = str(stat.get("inningsPitched", "0"))
                    try:
                        ip = float(ip_str)
                    except Exception:
                        ip = 0
                    hr  = int(stat.get("homeRuns", 0) or 0)
                    hr9 = (hr / max(ip, 1)) * 9 * 1.05 if ip > 0 else 1.30
                    bullpens[team_abbr] = BullpenProfile(
                        team=team_abbr,
                        hr9_allowed=round(hr9, 3),
                        hard_hit_pct=38.0, fb_pct_allowed=35.0,
                        xwoba_allowed=0.315, expected_innings=3.5,
                    )
                print(f"  ✅ Prior-year bullpen ({prior}): {len(bullpens)} teams")
        except Exception as e:
            print(f"  ⚠️  Prior-year bullpen failed: {e}")

    if bullpens:
        _save_cache(year, "bullpens", bullpens)
        print(f"  ✅ Bullpen stats: {len(bullpens)} teams")
    else:
        print("  ⚠️  All bullpen sources failed — bullpen factor will be neutral (1.0)")


    # ── 14-day dynamic enrichment: blend in recent bullpen HR/9 ──────────────
    # Uses last-14-day MLB Stats API team pitching stats as a faster proxy
    # (avoids expensive statcast bulk pull; team HR/9 is available from Stats API)
    try:
        import datetime
        today = datetime.date.today()
        start_str = (today - datetime.timedelta(days=14)).strftime("%Y-%m-%d")
        end_str   = today.strftime("%Y-%m-%d")
        recent_url = (f"https://statsapi.mlb.com/api/v1/stats"
                      f"?stats=byDateRange&group=pitching&season={year}&sportId=1"
                      f"&gameType=R&startDate={start_str}&endDate={end_str}&limit=2000")
        recent_data = _get(recent_url)
        if recent_data and "stats" in recent_data:
            recent_updated = 0
            for s in recent_data["stats"][0].get("splits", []):
                team_id  = s.get("team", {}).get("id", 0)
                team     = MLB_TEAM_ID_MAP.get(team_id, "")
                if not team: continue
                stat = s.get("stat", {})
                ip_str = str(stat.get("inningsPitched", "0"))
                try:    ip_14 = float(ip_str)
                except: ip_14 = 0
                hr_14 = int(stat.get("homeRuns", 0) or 0)
                if ip_14 < 10: continue   # too few innings — unreliable
                hr9_14 = (hr_14 / ip_14) * 9
                if team in bullpens and 0.3 <= hr9_14 <= 3.5:
                    # 60% season-level, 40% recent-14d
                    blended = round(0.60 * bullpens[team].hr9_allowed + 0.40 * hr9_14, 3)
                    bullpens[team].hr9_allowed = blended
                    recent_updated += 1
            if recent_updated:
                print(f"  ✅ 14-day bullpen blend: {recent_updated} teams updated")
    except Exception as e:
        print(f"  ℹ️  14-day bullpen enrichment skipped: {e}")

    _save_cache(year, "bullpens", bullpens)
    return bullpens


# FanGraphs team name → our abbreviation map
