    _pde_l5,  _pde_all  = _gs_hr("pitch_dom_elite_hr",   "28%  Emerging","28.0%  7/25")
    _spm_l5,  _spm_all  = _gs_hr("sharp_pm_hr",          "29.3%  12/41","21.1%  20/95")
    _ms_l5,   _ms_all   = _gs_hr("mid_score_hr",         "28.1%  9/32", "18.3%  24/131")
    _sigpm_l5,_sigpm_all= _gs_hr("sig_pm_hr",            "24.6%  16/65","18.1%  47/259")
    _scrpv_l5,_scrpv_all= _gs_hr("scream_powervuln_hr",  "29%  Emerging","29.3%  36/123")
    _scrpm_l5,_scrpm_all= _gs_hr("scream_highpm_hr",     "26%  Emerging","25.6%  10/39")
    _scrsg_l5,_scrsg_all= _gs_hr("scream_sigpm_hr",      "24%  Emerging","24.3%  9/37")
    _scr5s_l5,_scr5s_all= _gs_hr("scream_five_signal_hr","12%  1/9 Jun22","36.4%  8/22 (Jun21+22 complete)")
    _esig_l5, _esig_all = _gs_hr("elite_signal_hr",      "19%  Emerging","19.1%  9/47")
    _sses_l5, _sses_all = _gs_hr("sweet_star_edge_spike_hr", "38%  3/8 (pkl)", "38.5%  10/26 (58-slate bt)")
    _pto_l5,  _pto_all  = _gs_hr("power_trap_outlier_hr",    "100%  Tracking", "100%  2/2 (58-slate bt — RARE)")
    _pve_l5,  _pve_all  = _gs_hr("pwr_vuln_env_hr",          "NEW", "50%  8/16 primary (2.87x, pkl Jun24)")
    _spspm_l5,_spspm_all= _gs_hr("supp_park_sweet_pm_hr",    "NEW", "33.3%  6/18 (4.40x, pkl Jun25)")
    _scombo_l5,_scombo_all = _gs_hr("strong_hr_combo",   "23%  est",     "23%  est")
    _sigc_l5, _sigc_all = _gs_hr("signal_combo_hr",      "20%  est",     "20%  est")
    _slv_l5,  _slv_all  = _gs_hr("slm_vuln_hr",          "50%  1/2",    "42%  8/19")
    _shr_l5,  _shr_all  = _gs_hr("strong_hr",            "14%  Emerging","13%  Emerging")
    _shrg_l5, _shrg_all = _gs_hr("strong_hr_gated",      "5%   Emerging", "6%  Emerging")
    _ag_l5,   _ag_all   = _gs_hr("any_grade_hr",         "28%  8/29",    "18%  71/389")
    _a2g_l5,  _a2g_all  = _gs_hr("any2_grade_hr",        "50%  1/2",    "18%  20/114")
    _ng_l5,   _ng_all   = _gs_hr("no_grade_hr",          "13%  22/174", "11%  136/1234")
    _ichk_l5, _ichk_all = _gs_hr("ic_highk_stack",       "33%  1/3",    "27%  3/11")
    _hksp_l5, _hksp_all = _gs_hr("highk_sweet_stack",    "19%  4/21",   "18%  14/76")
    _hkpd_l5, _hkpd_all = _gs_hr("highk_pd_stack",       "36%  9/25",   "33%  9/27")
    _ics_l5,  _ics_all  = _gs_hr("ice_cold_sweet_hr",    "40%  2/5",    "19%  5/27")
    _ic_spm_l5, _ic_spm_all = _gs_hr("ic_signal_sharp_pm","33.3%  2/6", "26.7%  4/15")
    _ms_sig_l5, _ms_sig_all = _gs_hr("mid_score_sig_stack","27.3%  3/11","24.0%  18/75")
    _pm_ms_l5,  _pm_ms_all  = _gs_hr("power_pm_mid_stack", "38.5%  5/13","26.8%  15/56")
    _3g_l5,   _3g_all   = _gs_hr("three_grade_stack",    "33%  1/3",    "27%  3/11")
    _svic_l5, _svic_all = _gs_hr("slm_vuln_ic_stack",    "100%  2/2",   "100%  4/4")
    _svhk_l5, _svhk_all = _gs_hr("slm_vuln_highk_stack", "100%  1/1",   "100%  2/2")
    _sigpm_ic_l5,_sigpm_ic_all = _gs_hr("sig_pm_ic_stack","42.9%  3/7", "38.5%  5/13")
    _cm_l5,   _cm_all   = _gs_hr("confirmed_match_hr",  "73%  8/11",   "73%  8/11")
    _agcm_l5, _agcm_all = _gs_hr("any_grade_conf_match", "73%  8/11",  "73%  8/11")
    _era_l5,  _era_all  = _gs_hr("era_understated_hr",  "23%  Emerging",  "22.7%  5/22")
    _ff_l5,   _ff_all   = _gs_hr("pitch_reliant_hr",    "35%  Emerging",  "35.3%  12/34")

    # ── HR success-rate engine ────────────────────────────────────────────────
    # Single source of truth shared by (a) the conviction sort of the TOP HR PICKS
    # table and (b) the "HR success rate L5/AT" summary appended to each rationale.
    # Pulls the SAME rate strings shown in the grade table above, so the rationale
    # number always matches the table. Aggregates a player's firing grades + known
    # stacking combos (best validated signal wins, mirroring the STACKING rows),
    # then applies a documented fade-flag haircut.
    import re as _re_succ
    _hr_rate_lookup = {
        "confirmed_match_hr": (_cm_l5, _cm_all),
        "ice_cold_signal_hr": (_ic_l5, _ic_all),
        "high_k_hr":          (_hk_l5, _hk_all),
        "sweet_pm_hr":        (_sp_l5, _sp_all),
        "pitch_dom_hr":       (_pd_l5, _pd_all),
        "pitch_dom_elite_hr": (_pde_l5, _pde_all),
        "sharp_pm_hr":        (_spm_l5, _spm_all),
        "mid_score_hr":       (_ms_l5, _ms_all),
        "sig_pm_hr":          (_sigpm_l5, _sigpm_all),
        "scream_powervuln_hr":(_scrpv_l5, _scrpv_all),
        "scream_highpm_hr":   (_scrpm_l5, _scrpm_all),
        "scream_sigpm_hr":    (_scrsg_l5, _scrsg_all),
        "scream_five_signal_hr": (_scr5s_l5, _scr5s_all),
        "elite_signal_hr":    (_esig_l5, _esig_all),
        "sweet_star_edge_spike_hr": (_sses_l5, _sses_all),
        "power_trap_outlier_hr":    (_pto_l5,  _pto_all),
        "pwr_vuln_env_hr":          (_pve_l5,  _pve_all),
        "supp_park_sweet_pm_hr":    (_spspm_l5,_spspm_all),
        "strong_hr_combo":    (_scombo_l5, _scombo_all),
        "signal_combo_hr":    (_sigc_l5, _sigc_all),
        "slm_vuln_hr":        (_slv_l5, _slv_all),
        "era_understated_hr": (_era_l5, _era_all),
        "pitch_reliant_hr":   (_ff_l5, _ff_all),
        "strong_hr":          (_shr_l5, _shr_all),
        "strong_hr_gated":    (_shrg_l5, _shrg_all),
    }
    # Named grades detectable by label substring in hr_grade (order = priority for ties).
    _hr_named_keys = [
        ("CONFIRMED MATCH HR", "confirmed_match_hr"),
        ("PITCH-RELIANT",      "pitch_reliant_hr"),
        ("PITCH DOM ELITE HR", "pitch_dom_elite_hr"),
        ("PITCH DOMINANCE HR", "pitch_dom_hr"),
        ("ICE COLD",           "ice_cold_signal_hr"),
        ("HIGH-K HR",          "high_k_hr"),
        ("SWEET PM HR",        "sweet_pm_hr"),
        ("SHARP PM HR",        "sharp_pm_hr"),
        ("MID-SCORE HR",       "mid_score_hr"),
        ("SIG+PM",             "sig_pm_hr"),
        ("ELITE SIGNAL HR",    "elite_signal_hr"),
        # ("STRONG HR COMBO", "strong_hr_combo"),  # RETIRED — removed from grade lookup
        ("SHARP LINE + VULN",  "slm_vuln_hr"),
        ("ERA Understated HR", "era_understated_hr"),
        ("PWR-VULN-ENV HR",    "pwr_vuln_env_hr"),   # Jun 24 2026 — 50% (2.87x, n=16)
        ("SUPP-PARK SWEET-PM", "supp_park_sweet_pm_hr"),  # Jun 25 2026 — 33.3% (4.40x, n=18)
    ]
    # Stacking combos — fire when ALL component label substrings are present.
    # Mirrors the STACKING rows; lets a 2+ grade pick inherit the (higher) stack rate.
    _hr_stack_lookup = [
        (("SHARP LINE + VULN", "ICE COLD"), (_svic_l5, _svic_all)),
        (("SHARP LINE + VULN", "HIGH-K"),   (_svhk_l5, _svhk_all)),
        (("SIG+PM", "ICE COLD"),            (_sigpm_ic_l5, _sigpm_ic_all)),
        (("MID-SCORE HR", "SIG+PM"),        (_ms_sig_l5, _ms_sig_all)),
        (("ICE COLD", "SHARP PM HR"),       (_ic_spm_l5, _ic_spm_all)),
        (("HIGH-K HR", "PITCH DOM"),        (_hkpd_l5, _hkpd_all)),
    ]

    def _succ_pct(s):
        m = _re_succ.search(r"(\d+(?:\.\d+)?)\s*%", str(s or ""))
        return float(m.group(1)) if m else None

    def _hr_success_rate(sc, sh):
        """Return (l5_pct, all_pct): aggregated HR rate for this pick's firing
        grades/stacks, after a documented fade-flag haircut. Used for both the
        conviction sort and the rationale summary."""
        g     = sh.get("hr_grade", "") or ""
        flags = " ".join(sh.get("flags", []))
        score = getattr(sc, "score", 0.0)
        pm    = getattr(sc, "pitch_matchup_score", 1.0)
        power = getattr(sc, "batter_power", 0.0)
        vuln  = getattr(sc, "pitcher_vuln", 50.0)
        sig   = getattr(sc, "signal_score", 0) or 0
        cands = []   # (all_pct, l5_pct)
        for lbl, key in _hr_named_keys:
            if lbl in g:
                l5s, als = _hr_rate_lookup.get(key, (None, None))
                ap = _succ_pct(als)
                if ap is not None: cands.append((ap, _succ_pct(l5s)))
        # SCREAM grades from raw fields (independent of label text)
        for key, cond in (
            ("scream_powervuln_hr", False),  # RETIRED — no longer used in L5/AT lookup (0.93x baseline)
            ("scream_highpm_hr",    55.0 <= score < 60.0 and 1.07 <= pm < 1.10),
            ("scream_sigpm_hr",     1 <= sig < 5 and 1.04 <= pm < 1.07),
        ):
            if cond:
                l5s, als = _hr_rate_lookup.get(key, (None, None))
                ap = _succ_pct(als)
                if ap is not None: cands.append((ap, _succ_pct(l5s)))
        # Stacking combos — inherit the (usually higher) stack rate when all parts fire
        for comps, (sl5, sal) in _hr_stack_lookup:
            if all(c in g for c in comps):
                ap = _succ_pct(sal)
                if ap is not None: cands.append((ap, _succ_pct(sl5)))
        if not cands:
            # No named grade — pts-based: use the Strong/Strong-Gated baseline
            base_key = "strong_hr_gated" if (sh.get("is_gated") and not sh.get("gate_override")) else "strong_hr"
            l5s, als = _hr_rate_lookup.get(base_key, ("11%", "11%"))
            cands = [(_succ_pct(als) or 11.0, _succ_pct(l5s) or 11.0)]
        all_pct, l5_pct = max(cands, key=lambda x: x[0])
        if l5_pct is None: l5_pct = all_pct
        # Fade-flag haircut — compound documented multipliers (multiple red flags
        # stack), floored at 5%. Keeps stacked-but-trapped picks from floating up.
        mult = 1.0
        if "Vuln42-44" in flags or "Vuln 42-44" in flags: mult *= 0.78  # 41-slate 0.78x
        if "Vuln52" in flags:                              mult *= 0.55  # 41-slate 0.55x
        if (sh.get("is_gated") and not sh.get("gate_override")): mult *= 0.60
        if pm >= 1.15:                                     mult *= 0.80  # PM>=1.15 true kill zone (pkl Jun25)
        return (max(l5_pct * mult, 5.0), max(all_pct * mult, 5.0))

    def _hr_conviction_score(sc, sh):
        """Jun 17 2026 OVERHAUL — Pitcher-First 4-Pillar Conviction Architecture.

        OLD model: named grades drove the score (0-30 pts), batter attributes
        stacked on top (+power +PitchMix +Sig), pitcher-first BBE was a small bonus.
        Result: gold picks went 0-for while low-conv players HRed.

        NEW model: pitcher vulnerability × batter target match is the ANCHOR.
        Named grades now CONFIRM the pitcher signal, not replace it.
        Batter tools and market context are tertiary confirmation only.

        ─────────────────────────────────────────────────────────────────────
        PILLAR 1 — Pitcher Target Match (0–40 pts): PRIMARY DRIVER
          The pitch the pitcher is most vulnerable on × batter L10 BBE evidence.
          T4 (≥2 HR in L10 BBE vs target + strong pitcher vuln ≥18): 38 pts
          T3 (1 HR in L10 BBE vs target + pitcher vuln ≥18):          28 pts
          T2 (hard contact in L10 BBE, HH%≥50% + pitcher vuln ≥18):   18 pts
          T1 (target pitch identified, pitcher vuln ≥12, carry signal):  8 pts
          T0 (no pitcher-target match data):                             0 pts

        PILLAR 2 — Named Grade Support (0–20 pts): SECONDARY CONFIRMATION
          Independently validated grades now CONFIRM the pitcher-first signal.
          When P1 fires: grade credit capped at 15 (prevents double-counting).
          When P1 = 0: grade credit capped at 20 (fallback for no-data slates).
          CONFIRMED MATCH: +18 (24.1% HR, 1.51x — CSV 57-sl validated)
          PITCH-RELIANT: +14 (22.1% HR, 1.38x — CSV 57-sl; was 35.3% overstated)
          ERA Understated ≥1.25: +10 (standalone primary from Jun 17 2026)
          ERA Understated ≥0.75: +7 (supplemental)
          PITCH DOMINANCE HR: +6
          SCREAM High-PM: +5 (23.9% HR, 1.50x — CSV 57-sl validated)
          SCREAM Power-Vuln: +0 (RETIRED — 14.8% HR, 0.93x baseline, CSV 57-sl)
          ICE COLD + SIGNAL: +4 (20.5% HR, 1.29x — CSV 57-sl)
          BZM COMBO: +5 (tracking)
          POWER PARK: +3 (tracking)
          SIG+PM / ELITE SIGNAL: +3

        PILLAR 3 — Batter Profile Confirmation (0–12 pts): TERTIARY
          Power, contact quality, platoon — confirms batter can capitalize.
          Can't drive a PLAY on its own; confirms a pitcher-first signal.
          Power 87+: +5, 83-86: +3, 78-82: +1
          PitchMix wOBA ≥0.48: +5, ≥0.42: +3, ≥0.38: +1
          Vuln sweet zone 47-52: +3, 44-47: +1
          BZM zone count: 3+: +4, 2: +3, 1: +1 (zone overlap = structural evidence)

        PILLAR 4 — Market Context (0–8 pts): QUATERNARY
          Probability, bullpen, sharp money — context not primary signal.
          HR prob ≥19%: +4, ≥17%: +2, ≥15%: +1
          Weak bullpen HR/9 ≥1.60: +3
          Sharp money / market shortening: +2
          PRIME (owns pitcher + pitch edge): +4 (validated 26.5% HR / 1.70x)

        GRADE OVERRIDES (absolute floors — empirically validated, unchanged):
          CONFIRMED MATCH clean: floor 45 (gold)
          CONFIRMED MATCH with headwinds: floor 35 (amber)
          EXTREME PWR (v42-44 or v52+): floor 40 (amber+)
          SCREAM PV: floor 16, hard cap 30 (baseline-performing grade)

        PENALTIES (same structural fades as before):
          Vuln42-44 dead zone: -8 (-4 if PitchMix ≥0.48 overrides)
          Vuln52+ trap: -8 (-4 if park ≥1.15 partially rescues)
          PM≥1.10 priced-in: -5
          Short-start (bullpen HR/9 < 1.50 only): -6
          Suppressive park <0.93: -6
          High edge / over-bullish: -4
          Same-side non-elite: -3
          K-danger + elite arm Vuln<38: -5
          PA < 4.0: -5
        ─────────────────────────────────────────────────────────────────────
        """
        g       = sh.get("hr_grade", "") or ""
        flags_s = " ".join(sh.get("flags", []))
        notes_s = " ".join(sc.notes or [])
        power   = getattr(sc, "batter_power", 0.0)
        vuln    = getattr(sc, "pitcher_vuln", 50.0)
        pm      = getattr(sc, "pitch_matchup_score", 1.0)
        sig     = getattr(sc, "signal_score", 0) or 0
        prob    = getattr(sc, "hr_probability", 0.0)
        park    = getattr(sc, "park_factor", 1.0) or 1.0
        scr     = getattr(sc, "score", 0.0)

        # ═══════════════════════════════════════════════════════════════════
        # PILLAR 1: PITCHER TARGET MATCH (0–40 pts) — DOMINANT SIGNAL
        # ═══════════════════════════════════════════════════════════════════
        _ptm_bonus = getattr(sc, "ptm_conv_bonus", 0.0) or 0.0
        _ptm_target_score = getattr(sc, "pitcher_target_score", 0.0) or 0.0

        # T4/T3 alone should produce gold/amber before penalties and before any
        # named grade stacks on top. That means T4 needs to clear the 45 gold
        # threshold on its own; T3 needs to clear 34 amber on its own.
        # PRIME (≥3 HR on target pitch) is the new ceiling — unconditionally gold.
        if   _ptm_bonus >= 12.0: p1 = 52.0   # PRIME: ≥3 HR on pitcher's weak pitch — unconditional gold
        elif _ptm_bonus >= 8.0:  p1 = 42.0   # T4: solo gold even with modest P2/P3
        elif _ptm_bonus >= 5.0:  p1 = 32.0   # T3: solo amber; gold with P2/P3 support
        elif _ptm_bonus >= 3.0:  p1 = 20.0   # T2: LEAN — hard contact, no HR yet
        elif _ptm_bonus >= 1.0:  p1 = 10.0   # T1: informational, carry signal only
        else:                     p1 =  0.0   # T0: no pitcher-target data

        # L10 BBE carry bonus — quality of contact on the matched pitch type (stackable)
        _l10_hr_ct   = getattr(sc, 'l10_bbe_primary_hr',   0)
        _l10_n       = getattr(sc, 'l10_bbe_primary_n',    0)
        _l10_dist    = getattr(sc, 'l10_bbe_primary_dist', 0.0)
        _l10_hh      = getattr(sc, 'l10_bbe_primary_hh',  0.0)
        _l10_brl     = getattr(sc, 'l10_bbe_primary_barrel', 0.0)
        _l10_carry_bonus = 0.0
        if _l10_n >= 3:
            if _l10_dist >= 295.0 and _l10_hh >= 50.0:  _l10_carry_bonus = 3.0
            elif _l10_dist >= 280.0 and _l10_hh >= 38.0: _l10_carry_bonus = 1.5
            if _l10_brl >= 25.0:                          _l10_carry_bonus += 1.0  # barrel rate confirms
        p1 += _l10_carry_bonus

        conv = p1

        # ═══════════════════════════════════════════════════════════════════
        # PILLAR 2: NAMED GRADE SUPPORT (0–20 pts) — SECONDARY CONFIRMATION
        # Cap when P1 fires to prevent grade-stacking from overriding pitcher-first.
        # ═══════════════════════════════════════════════════════════════════
        _p2_cap = 15.0 if p1 > 0 else 20.0   # compress grade credit when P1 fires
        _p2 = 0.0

        # High-tier validated grades — each credits its validated lift independently
        if "LIVE CONFIRMED MATCH" in g:  _p2 = max(_p2, 18.0)  # highest validated, separate from P1
        elif "CONFIRMED MATCH" in g:     _p2 = max(_p2, 18.0)  # 35% AT (1.93x), validated
        if "PITCH-RELIANT" in g:
            # Jun 19 2026: +2 conv when usage % is hand-specific (confirmed vs this batter's hand).
            # A pitcher throwing FF 52% vs LHB specifically is a stronger setup than 52% overall
            # which might be 38% vs LHB. Grade label carries "(vs LHB)" or "(vs RHB)" when HS.
            if "vs LHB" in g or "vs RHB" in g:
                _p2 = max(_p2, 16.0)   # hand-specific: +2 vs base (better signal quality)
            else:
                _p2 = max(_p2, 14.0)   # overall stats: base credit (35% AT, one-pitch mechanism)

        # ERA gap for standalone path
        _era_gap_p2 = 0.0
        for _el in (sc.notes or []):
            _era_m2 = _re_succ.search(r"ERA composite ([\d.]+).*vs ERA ([\d.]+)", str(_el))
            if _era_m2:
                try: _era_gap_p2 = float(_era_m2.group(1)) - float(_era_m2.group(2))
                except: pass
                break
        if "ERA Understated HR" in g:
            # Jul 1 2026: ERA understated is supplemental (stacks with T4/PITCH-RELIANT for HR edge).
            # Standalone ERA understated is weak HR signal (20% HR, 1.28x, n=15) — not enough to
            # inflate conviction meaningfully. Keep small supplemental credit only.
            if _era_gap_p2 >= 1.25:  _p2 = max(_p2,  8.0)   # meaningful skill deception (was 14.0)
            else:                     _p2 = max(_p2,  4.0)   # supplemental confirmation (was 7.0)

        if "PITCH DOMINANCE HR" in g:    _p2 = max(_p2, 6.0)
        if "BZM COMBO HR" in g:          _p2 = max(_p2, 5.0)
        if "SCREAM HR (High-PM)" in g:   _p2 = max(_p2, 5.0)  # 27% AT validated
        if "ICE COLD" in g:              _p2 = max(_p2, 4.0)
        if "POWER PARK HR" in g:         _p2 = max(_p2, 3.0)
        if "SCREAM HR (Power-Vuln)" in g: _p2 = max(_p2, 3.0)  # baseline 16% — minimal credit
        if "SHARP PM HR" in g:           _p2 = max(_p2, 3.0)
        if "SIG+PM" in g or "ELITE SIGNAL" in g: _p2 = max(_p2, 3.0)
        if "SHARP LINE + VULN" in g:     _p2 = max(_p2, 4.0)

        # Grade count stacking — only adds when genuinely independent (not pitch-family repeats)
        _pitch_grades = sum(1 for t in ("CONFIRMED MATCH", "PITCH DOM ELITE",
                                        "PITCH DOMINANCE HR", "PITCH-RELIANT") if t in g)
        gc = sh.get("grade_count", 0)
        _eff_gc = max(0, gc - max(0, _pitch_grades - 1))
        if _eff_gc >= 3: _p2 = min(_p2 + 5.0, _p2_cap)   # 3+ independent grades
        elif _eff_gc == 2: _p2 = min(_p2 + 2.0, _p2_cap)

        conv += min(_p2, _p2_cap)

        # ═══════════════════════════════════════════════════════════════════
        # PILLAR 3: BATTER PROFILE CONFIRMATION (0–12 pts) — TERTIARY
        # ═══════════════════════════════════════════════════════════════════
        _p3 = 0.0

        # Power — confirms batter can physically capitalize
        if   power >= 87: _p3 += 5.0
        elif power >= 83: _p3 += 3.0
        elif power >= 78: _p3 += 1.0

        # PitchMix wOBA — contact quality vs THIS pitcher's actual arsenal
        _pmix = 0.0
        for m in _re_succ.finditer(r"(?:PitchMix|PITCHMIX) wOBA[:\s]+(\d\.\d+)", notes_s):
            _pmix = max(_pmix, float(m.group(1)))
        if   _pmix >= 0.48: _p3 += 5.0   # elite override tier
        elif _pmix >= 0.42: _p3 += 3.0
        elif _pmix >= 0.38: _p3 += 1.0

        # Vuln zone — pitcher structural vulnerability zone
        if   47.0 <= vuln <= 52.0: _p3 += 3.0   # sweet zone
        elif 44.0 <= vuln < 45.0:  _p3 += 1.5
        elif 45.0 <= vuln < 47.0:  _p3 += 0.5

        # BZM zone overlap — location-level structural edge (different evidence from P1)
        _bzm = getattr(sc, 'batter_bzm_count', 0)
        if   _bzm >= 3: _p3 += 4.0
        elif _bzm == 2: _p3 += 3.0
        elif _bzm == 1: _p3 += 1.0

        # Pitch-correlation × non-suppressive park — validated 1.94x when both fire
        if ("PITCH CORRELATION" in notes_s or "CONFIRMED MATCH" in g) and park >= 1.00:
            _p3 += 1.5

        # Z-Contact + pitch-edge stacking (different mechanism from P1 BBE)
        _has_high_zcont = "High Z-Contact" in notes_s
        _pitch_edge_val = 0.0
        for _m in _re_succ.finditer(r"pitch edge [+]([\d.]+)", notes_s):
            _pitch_edge_val = max(_pitch_edge_val, float(_m.group(1)))
        if _has_high_zcont and _pitch_edge_val >= 5.0:
            _p3 += 2.0

        # ── Jun 18 2026: Z-Contact + platoon + park structural combo ────────
        # Jun 17 post-mortem (Rec #5): Bellinger (Z-Contact 91.3%, platoon, park 1.22x),
        # PCA (platoon, high env+implied), Carroll (platoon, ERA understated) all HRed
        # as PASS picks (conv < 10). Common structural thread: the pitcher makes easy
        # in-zone contact (Z-Contact) + the batter has platoon advantage + decent park.
        # This combo adds +6 conv pts to lift these picks from PASS → LEAN territory
        # so they don't get filtered out entirely.
        _platoon_val = getattr(sc, 'platoon', 1.0)
        _has_platoon_edge = _platoon_val >= 1.04  # meaningful platoon advantage
        _env_val = getattr(sc, 'env_factor', 1.0) or 1.0
        if _has_high_zcont and _has_platoon_edge and park >= 1.05:
            _p3 += 5.0   # Z-Contact + platoon + power park: structural HR enabler
        elif _has_high_zcont and _has_platoon_edge and _env_val >= 1.10:
            _p3 += 3.0   # Z-Contact + platoon + hot env (no park boost)

        # Fly-ball profile (HR opportunity creation)
        _fb_bat = getattr(sc, 'batter_fb_pct', 34.0)
        if   _fb_bat >= 42.0: _p3 += 1.5
        elif _fb_bat >= 38.0: _p3 += 0.5

        # Popup penalty (weak contact signal)
        _pu = getattr(sc, 'batter_pu_rate', 0.08)
        if _pu >= 0.15 and "CONFIRMED MATCH" not in g: _p3 -= 1.5

        conv += min(_p3, 12.0)

        # ═══════════════════════════════════════════════════════════════════
        # PILLAR 4: MARKET CONTEXT (0–8 pts) — QUATERNARY
        # ═══════════════════════════════════════════════════════════════════
        _p4 = 0.0

        # Model HR probability
        if   prob >= 0.19: _p4 += 4.0
        elif prob >= 0.17: _p4 += 2.0
        elif prob >= 0.15: _p4 += 1.0

        # Bullpen vulnerability — meaningful for HR props specifically
        _bpen_hr9 = 0.0
        for _bm in _re_succ.finditer(r"HR/9[:\s]+([\d.]+)", notes_s):
            _bpen_hr9 = max(_bpen_hr9, float(_bm.group(1)))
        if   _bpen_hr9 >= 2.00: _p4 += 4.0
        elif _bpen_hr9 >= 1.60: _p4 += 3.0
        elif _bpen_hr9 >= 1.30: _p4 += 1.5

        # Sharp money / market confirmation
        # Jul 1 2026: SLM is a HIT signal (74.5% hit, 1.28x) NOT an HR signal (13.8% HR, 0.87x).
        # Reducing conv credit for SLM from +2 to +0.5 (informational only, does not drive HR ranking).
        if sh.get("has_slm"):                                     _p4 += 0.5
        if "market is shortening" in notes_s or "MKT CAUGHT" in g: _p4 += 1.5

        # PRIME signal — owns pitcher or ERA-understated on top of pitch edge
        _prime_owns = ("Owns this pitcher" in notes_s or "Career HR rate vs pitcher" in notes_s)
        _prime_era  = ("ERA Understated HR" in g or "ERA understated" in notes_s)
        _kdanger_block = ("K-Danger" in flags_s and vuln < 38.0)
        if not _kdanger_block:
            # Jul 1 2026: differentiate — "owns pitcher" is a direct HR predictor (career HR vs this arm).
            # ERA understated is a pitcher quality signal that helps hits as much as HRs.
            if _prime_owns:   _p4 += 4.0   # validated 26.5% HR (1.70x) — strong HR predictor
            elif _prime_era:  _p4 += 1.5   # supplemental — helps overall matchup quality not specifically HR

        conv += min(_p4, 8.0)

        # ═══════════════════════════════════════════════════════════════════
        # GRADE OVERRIDES — absolute floors for empirically validated grades
        # Applied BEFORE penalties so they don't get wiped by structural flags.
        # These grades have sufficient sample to guarantee a minimum tier.
        # ═══════════════════════════════════════════════════════════════════
        _is_conf_match  = "CONFIRMED MATCH" in g
        _is_extreme_pwr = ((42.0 <= vuln < 44.0 and power >= 81.0 and pm >= 1.10) or
                           (vuln >= 52.0 and power >= 83.0))
        _is_scream_pv   = ("SCREAM HR (Power-Vuln)" in g or
                           (40.0 <= scr < 60.0 and 1.04 <= pm < 1.07
                            and power >= 78.0 and 44.0 <= vuln < 52.0))
        _is_ptm_prime   = "PRIME PITCHER TARGET MATCH HR" in g

        # ── Jul 5 2026: Suppressing L5 Hard Fade Gate ───────────────────────────
        # Fires when ALL of:
        #   1. Suppressing L5 present in notes (pitcher actively NOT giving up HRs)
        #   2. No T4 or PRIME grade (T4 BBE history overrides the suppression —
        #      proven recent HR contact on THIS pitcher's arsenal beats L5 recency)
        #   3. No CONFIRMED MATCH (two-sided pitch correlation is independent of L5)
        #   4. Vuln < 42.0 (truly elite arm — Vuln 42-48 is still at baseline or
        #      above; the fade only fires on genuinely elite/suppressing arms)
        # Effect: caps conviction at LEAN 34 (same level as 2-headwind PRIME cap).
        # Rationale: when a pitcher is in active suppression mode AND the batter has
        # no proven L10 HR contact on this specific arsenal (no T4/PRIME), the model
        # has no current-cycle edge to rely on. The Suppressing L5 signal is the
        # market's live read that the pitcher is hot right now.
        _has_t4_or_prime = (
            "T4" in g or "PRIME PITCHER TARGET" in g
        )
        _supp_l5_in_notes = any(
            "Suppressing L5" in str(n) for n in (sc.notes or [])
        )
        _supp_l5_fade_fires = (
            _supp_l5_in_notes
            and not _has_t4_or_prime
            and not _is_conf_match
            and vuln < 42.0
        )
        if _supp_l5_fade_fires:
            conv = min(conv, 34.0)
            conv = max(conv, 10.0)   # keep pick visible, not hidden
            return max(0, min(100, round(conv)))

        # NEW PRIME: T4 BBE (≥2 HR in L10 BBE) + pitcher recency (extreme L2 or HR-prone L5)
        # Jun 17 validated: 3/4 HR (75%). One false positive: Turang (K-Danger + Vuln42-44).
        # Apply small K-Danger + dead zone penalty but maintain gold floor otherwise.
        #
        # Jun 18 2026 post-mortem: PRIME-K interaction added.
        # Buxton (PRIME Conv 70, K-Warning vs Leiter) → 0 HR, 0 hits.
        # K-Warning/K-Danger is a plate-level contact suppressor — if the batter can't
        # consistently put the ball in play vs this pitcher, the BBE edge can't materialize.
        # When K-Warning OR K-Danger fires on a PRIME candidate, apply -8 conv penalty
        # and label as PRIME-K. Still ✅ PLAY, but the conviction is honest about the risk.
        #
        # Jul 1 2026 post-mortem (Jun 30 slate): PRIME with 2+ headwind flags underperformed.
        # Goodman (ShortStart+PM≥1.15), Schwarber (ShortStart+PM≥1.15), Wood (SuppPark+K-Warning),
        # Dingler (EliteArm+K-Danger), W.Contreras (Vuln52+ShortStart) — ALL 0 HR.
        # Chourio (Vuln52+ShortStart) — 1 HR (only survivor).
        # Finding: PRIME with ≥2 headwind flags should cap at amber LEAN (≤34 conv), NOT gold PLAY.
        # PRIME concept is still valid (underlying BBE match + recency are real), but the structural
        # suppressors mean the BBE opportunity never fully materializes today.
        # Exception: CONFIRMED MATCH always overrides (two-sided pitch correlation survives headwinds).
        if _is_ptm_prime:
            # Jul 1 2026: 2+ headwind flags → LEAN cap (amber tier, ≤34)
            # Recompute headwind variables locally (this is _hr_conviction_score, a separate
            # inner function — _short_pre/_park_pre/v from compute_conv_score are out of scope)
            _hc_notes_s  = " ".join(str(n) for n in (sc.notes or []))
            _hc_short    = any("short-start alert" in str(n).lower() for n in (sc.notes or []))
            _hc_park     = getattr(sc, 'park_hr_factor', 1.00)
            _prime_hw_count = sum([
                _hc_short,                                              # short start
                _hc_park < 0.93,                                        # suppressive park
                vuln >= 52.0,                                           # Vuln52+ trap
                42.0 <= vuln < 44.0,                                    # Vuln42-44 dead zone
                pm >= 1.10,                                             # PM priced in
                ("K-Danger" in flags_s or "K-Warning" in flags_s),     # contact risk
                bool(sh.get('is_gated') and not sh.get('gate_override')),
            ])
            _prime_hw_override = _is_conf_match  # CONFIRMED MATCH always wins
            if _prime_hw_count >= 2 and not _prime_hw_override:
                # Cap at amber LEAN — PRIME signal is real but headwinds block full conversion today
                conv = min(conv, 34.0)
                conv = max(conv, 20.0)   # still show as a pick, not hidden
                return max(0, min(100, round(conv)))
            # ── Jul 4 2026: Three single-headwind demotions inside PRIME ──────────
            # These run AFTER the 2-headwind cap. CONFIRMED MATCH picks are exempt.
            # Extreme L2 Blowup grades also return before these checks (handled above).
            #
            # Demotion A: Suppressing L5 inside PRIME (Jul 4 2026)
            # When the pitcher is actively NOT surrendering HRs recently, the PRIME BBE
            # history may be from a different period. Market has already priced the
            # buy-low narrative; the edge is structurally weaker right now.
            # Cap: LEAN 34 (same as 2-headwind). Exception: CONFIRMED MATCH.
            _prime_is_suppressing = (
                any("Suppressing L5" in str(n) for n in (sc.notes or []))
                and not _is_conf_match
            )
            if _prime_is_suppressing:
                conv = min(conv, 34.0)
                conv = max(conv, 20.0)
                return max(0, min(100, round(conv)))
            #
            # Demotion B: Vuln42-44 dead zone inside PRIME (Jul 4 2026)
            # Vuln42-44 is the structural dead zone — 0/17 HR at Score≥60.
            # Even T4 BBE + recency doesn't overcome this zone. Hard-cap gold conviction.
            # Exception: CONFIRMED MATCH overrides this zone by design.
            _prime_is_dead_zone = (
                42.0 <= vuln < 44.0
                and not _is_conf_match
            )
            if _prime_is_dead_zone:
                conv = min(conv, 34.0)
                conv = max(conv, 20.0)
                return max(0, min(100, round(conv)))
            #
            # Demotion C: PM < 1.00 inside PRIME (Jul 4 2026)
            # When the market is more bullish than the model (PM < 1.00), the market has
            # already priced in the PRIME signal — there is no edge left to capture.
            # Anti-edge: market is ahead of us on this pick. Cap at LEAN 34.
            # Exception: CONFIRMED MATCH (the pitch correlation is independent of PM).
            _prime_market_overpriced = (
                pm < 1.00
                and not _is_conf_match
            )
            if _prime_market_overpriced:
                conv = min(conv, 34.0)
                conv = max(conv, 20.0)
                return max(0, min(100, round(conv)))
            # ── End Jul 4 2026 single-headwind demotions ─────────────────────────
            # Single headwind or clean — maintain gold floor
            conv = max(conv, 55.0)   # guaranteed gold floor (clean/1-flag PRIME)
            # Demotion 1: K-Danger in Vuln42-44 dead zone (Turang case)
            if "K-Danger" in flags_s and 42.0 <= vuln < 45.0:
                conv = max(conv - 10.0, 45.0)   # still gold but reduced — Turang false positive
            # Demotion 2 (Jun 18 2026): K-Warning or K-Danger present — PRIME-K penalty
            # The batter has demonstrated contact issues vs this arm. A HR requires contact
            # first; elevated K rate directly reduces the number of BBE opportunities.
            # CONFIRMED MATCH overrides (the pitch correlation is specific enough to beat K risk).
            elif ("K-Danger" in flags_s or "K-Warning" in flags_s) and not _is_conf_match:
                conv = max(conv - 8.0, 47.0)   # gold tier maintained but reduced — PRIME-K
            return max(0, min(100, round(conv)))

        # SCREAM HR Power-Vuln: RETIRED (CSV audit: 0.93x baseline).
        # No special conviction handling — falls through to normal scoring.

        # ⚡ EXTREME L2 BLOWUP HR conviction floor (Jun 18 2026 post-mortem)
        # 4/6 all-time HR rate (66.7%) — highest single-signal benchmark in the model.
        # When this grade fires, enforce minimum conviction based on matchup quality:
        #   Standalone L2 (no named grade): floor 30 — guaranteed LEAN territory
        #   L2 + PM≥1.04 + Power≥78: floor 42 — PLAY territory, strong matchup confirms
        #   L2 + named grade (any): floor 45 — gold PLAY floor (pitcher actively exploitable)
        # Suppressors that can reduce below floor: K-Danger + suppressive park (compound)
        # ⚡ EXTREME L2 BLOWUP + VULN52 OVERRIDE — automatic PLAY floor (Jun 19 2026)
        # Highest-confidence version of L2 signal: Vuln52+ trap CONFIRMS the acute
        # vulnerability. 3/3 (100%, n=3). Enforce PLAY floor at conv 45 minimum.
        # ⚡ EXTREME L2 BLOWUP + VULN52 OVERRIDE conviction floor (REVISED Jun 21 2026)
        # ──────────────────────────────────────────────────────────────────────
        # Jun 20 2026 post-mortem: ALL three CWS batters vs Melton (Montgomery,
        # Vargas, Grichuk) went 0-for-HR. Signal is now 3/6 (50%) — volatile.
        # DEMOTED: was ALWAYS PLAY (floor 50). Now LEAN (floor 30).
        # Requires stacking with another named grade to reach PLAY (floor 45).
        _is_extreme_l2_v52 = "EXTREME L2 BLOWUP + VULN52 OVERRIDE" in g
        if _is_extreme_l2_v52:
            _l2v52_headwind = 0.0
            if ("K-Danger" in flags_s) and ("Suppressive park" in notes_s or park < 0.93):
                _l2v52_headwind = 5.0
            # LEAN floor (30) unless stacked with another named grade → PLAY (45)
            _has_stack_grade = any(x in g for x in [
                "T3", "T4", "PRIME", "PITCH-RELIANT", "PITCH DOM",
                "CONFIRMED MATCH", "ICE COLD+SIGNAL", "ERA Understated",
            ])
            _l2v52_floor = 45.0 if _has_stack_grade else 30.0
            conv = max(conv, _l2v52_floor - _l2v52_headwind)
            return max(0, min(100, round(conv)))

        _is_extreme_l2_grade = "EXTREME L2 BLOWUP HR" in g
        if _is_extreme_l2_grade:
            _l2_headwind = 0.0
            _l2_compound_suppress = (
                ("K-Danger" in flags_s) and
                ("Suppressive park" in notes_s or park < 0.93)
            )
            if _l2_compound_suppress:
                _l2_headwind = 6.0   # compound suppressor reduces floor but doesn't kill the grade
            if _is_conf_match or _is_extreme_pwr:
                # Already handled above, but L2 alongside confirms to gold
                conv = max(conv, 45.0 - _l2_headwind)
            elif any(x in g for x in ["PITCH-RELIANT", "PITCH DOM", "ICE COLD+SIGNAL",
                                        "SHARP LINE", "MKT CAUGHT UP", "SCREAM"]):
                # L2 + any other named grade = gold PLAY floor
                conv = max(conv, 45.0 - _l2_headwind)
            elif pm >= 1.04 and power >= 78.0:
                # L2 + solid matchup quality = PLAY floor
                conv = max(conv, 42.0 - _l2_headwind)
            else:
                # L2 standalone — guaranteed LEAN minimum
                conv = max(conv, 30.0 - _l2_headwind)
            return max(0, min(100, round(conv)))

        # CONFIRMED MATCH + EXTREME PWR (REVISED Jun 21 2026)
        # ──────────────────────────────────────────────────────────────────────
        # Jun 20 2026 post-mortem: Alvarez (Conv 67, CONFIRMED MATCH) and Kurtz
        # (Conv 45, CONFIRMED MATCH) both went 0-for-HR. The override status was
        # overclaiming. All-time: 7/27 (26%) — solid above baseline but not
        # near-certain. CONFIRMED MATCH is now a strong supplemental +10 conv
        # bonus, not an auto-PLAY override.
        # EXTREME PWR retains gold floor (structural override, different basis).
        if _is_extreme_pwr:
            # EXTREME PWR backtest (66 slates): validates strongly at reasonable odds
            # but completely collapses at +500+:
            #   Odds ≤+300:   41.2% HR (2.84x, n=34)
            #   Odds +301-400: 28.6% HR (1.97x, n=35)
            #   Odds +401-500: 26.1% HR (1.80x, n=23)
            #   Odds +501-700:  4.0% HR (0.28x, n=25) ← market is correct, override fails
            #   Odds +700+:    12.5% HR (0.86x, n=8)
            # At +500+, market is fading for structural reasons (short start, suppressive
            # park, platoon) that override even elite raw power. Cap at LEAN when odds>500.
            _epwr_odds_raw = getattr(sc, 'hr_over_price', 0) or 0
            _epwr_long_odds = (abs(_epwr_odds_raw) > 500 and abs(_epwr_odds_raw) != 0)
            if _epwr_long_odds:
                # Market has a structural reason for fading — respect it
                conv = min(conv, 34.0)   # cap at LEAN; grade still shows but no gold override
                conv = max(conv, 20.0)
            else:
                conv = max(conv, 45.0)   # gold PLAY floor at reasonable odds
                if "K-Danger" in flags_s: conv = max(conv - 8.0, 34.0)
            return max(0, min(100, round(conv)))

        # ── SUPER NUCLEAR override (Jul 1 2026): all 9 PropFinder gates pass ─
        # Per Harrison's explicit request: 9/9 PropFinder gates = automatic PLAY.
        # Hard override: conv floor 45 (gold tier), bypasses most fade-flag penalties.
        # STRUCTURAL CAPS still apply — SUPER NUCLEAR means the batter has elite
        # batted-ball profile, but structural blockers (short start = pitcher pulled
        # before BBE can materialize; Vuln52+ trap = market has priced in the
        # pitcher's vulnerability; PM≥1.10 = matchup already fully priced in) still
        # suppress HR conversion regardless of batter profile quality.
        # Exception: K-Danger reduces floor to 34 (contact risk).
        # NOTE: PRIME 2HW cap (above) returns before reaching here, so Schwarber-
        # type PRIME + 2 headwind picks are correctly capped at 34 before this block.
        # Independent of ☢️ NUCLEAR ranking badge (that is Power+Odds+PM+Score).
        # Tracking only — not yet backtested; promote/demote after 10+ slates.
        _is_super_nuclear = "SUPER NUCLEAR" in notes_s or "SUPER NUCLEAR" in g
        if _is_super_nuclear:
            # Structural caps that override even 9/9 profile quality
            _sn_short_start  = "ShortStart" in flags_s or "Short-start" in notes_s or "short-start alert" in notes_s.lower()
            _sn_vuln52       = vuln >= 52.0
            _sn_pm_priced    = pm >= 1.10   # matchup fully priced in by market
            _sn_structural_blocked = _sn_short_start or (_sn_vuln52 and _sn_pm_priced)
            # Jul 3 2026 backtest: NUCLEAR badge on Vuln<40 arms = 10% HR (0.58x, n=10).
            # Elite-arm pitchers with low Vuln suppress HR conversion even on elite power bats.
            # SUPER NUCLEAR's 9/9 batted-ball profile measures batter quality, not the matchup.
            # When facing a genuinely elite arm (Vuln<40), cap at LEAN 34 regardless of
            # contact profile. EXCEPTION: EXTREME L2 BLOWUP confirms the pitcher IS hittable
            # RIGHT NOW, overriding the seasonal Vuln reading — maintain gold floor in that case.
            _sn_elite_arm    = (vuln < 40.0
                                and "EXTREME L2 BLOWUP" not in g
                                and not _is_conf_match)
            if _sn_structural_blocked or _sn_elite_arm:
                # Structural blocker or elite arm: reduce to LEAN floor (34), not gold PLAY
                conv = min(conv, 34.0)
                conv = max(conv, 20.0)
            else:
                conv = max(conv, 45.0)   # gold PLAY floor
                if "K-Danger" in flags_s:
                    conv = max(conv - 8.0, 34.0)   # K-Danger exception: amber floor
            return max(0, min(100, round(conv)))

        if _is_conf_match:
            # Supplemental bonus applied to whatever formula produced; amber floor only
            conv = max(conv, 30.0)   # minimum amber — CONFIRMED MATCH is real but not overriding
            # Headwind reduction (unchanged)
            _top_headwind = 0.0
            if "K-Danger" in flags_s or "K-Warning" in flags_s: _top_headwind += 8.0
            if ("Suppressive park" in notes_s) and park < 0.93:  _top_headwind += 6.0
            conv = max(conv - _top_headwind, 24.0)
            # Gold only when genuinely stacked (named grade + CONFIRMED MATCH + clean)
            _conf_stack_grade = any(x in g for x in [
                "T4", "PRIME", "PITCH-RELIANT", "PITCH DOM ELITE", "ICE COLD+SIGNAL",
            ])
            if _conf_stack_grade and _top_headwind == 0.0:
                conv = max(conv, 45.0)   # gold only when cleanly stacked
            return max(0, min(100, round(conv)))

        # ═══════════════════════════════════════════════════════════════════
        # PENALTIES — structural fades (applied after grade overrides)
        # ═══════════════════════════════════════════════════════════════════
        # Jul 3 2026 backtest (67-slate CSV): Vuln<38 + PM≥1.04 (named grade proxy) = 14.1% HR
        # (0.81x) — below baseline. K-Danger on elite arms is a real structural suppressor.
        # Increased from -5 to -10 to properly reflect the below-baseline performance.
        # EXCEPTION: CONFIRMED MATCH and EXTREME L2 BLOWUP grades have their own validated
        # override logic above and do not reach this code path.
        if "K-Danger" in flags_s and vuln < 38.0:
            conv -= 10.0   # elite arm + K-danger = meaningfully reduced HR ceiling (0.81x backtest)

        # Vuln dead zone — PitchMix ≥0.48 reduces to half penalty (Ohtani case)
        if "Vuln42-44" in flags_s:
            conv -= 4.0 if _pmix >= 0.48 else 8.0

        if "Vuln52" in flags_s:
            _v52_park   = getattr(sc, 'park_hr_factor', 1.00)
            _v52_odds_r = getattr(sc, 'hr_over_price', 0) or 0
            _v52_odds_v = abs(_v52_odds_r) if abs(_v52_odds_r) > 0 else 9999
            # Jul 2 2026 backtest (N=2391 CSV): Vuln52+ is NOT a uniform trap.
            # It is odds-gated: Odds ≤+300 → 37.5% HR (2.16x, n=40);
            # +301-400 → 24.0% HR (1.38x, n=50); +401-500 → 19.0% (baseline);
            # +500+ → 6-7% HR (0.40x — genuine trap zone).
            # Additionally, Pwr≥78 + Odds≤+400 sub-pop = 37.5% (2.16x, n=48).
            # New rule: within the Vuln52+ population, if the pick clears the
            # odds gate (≤+400) AND power gate (≥78), apply a +8 BOOST instead
            # of a penalty. Otherwise apply the standard penalty graded by odds.
            if power >= 78.0 and _v52_odds_v <= 400:
                # VULN52+ HIGH-ODDS OVERRIDE: market has NOT priced in the vulnerability.
                # The trap classification is unwarranted — apply positive conv boost.
                conv += 8.0
                # Note: does not stack with EXTREME L2 V52 or EXTREME PWR (handled above).
            elif power >= 78.0 and _v52_odds_v <= 500:
                # Odds 401-500 zone: baseline-performing, no penalty no boost
                pass
            else:
                # Long odds (+500+) or low power: genuine trap — penalize
                conv -= 5.0 if _v52_park >= 1.15 else 10.0

        if sh.get("is_gated") and not sh.get("gate_override"): conv -= 8.0
        # Jun 26 2026 post-mortem: PM >= 1.08 without a strong named grade is a HR suppressor.
        # Live slate evidence (Jun 25): ALL 11 HR getters had PM < 1.08.
        # pkl backtest (n=2534) reveals the nuance:
        #   PM>=1.08 + T3+/CONFIRMED/PRIME/RELIANT = 33.3% HR (1.92x) — STRONG
        #   PM>=1.08 + no named grade = 20.0% HR (1.15x) — modest
        #   PM>=1.08 + T3+ (pkl) = 37.5% (2.15x) — but Jun 25 live went 0/8
        # Jun 25 was a SLATE-LEVEL ANOMALY, not a structural rule change.
        # The correct lesson: PM>=1.08 without a T3+/CONFIRMED match = penalize.
        # PM>=1.08 WITH a named grade = still valid but market has priced it partially.
        _has_strong_named_grade = any(x in g for x in [
            "T3", "T4", "PRIME", "CONFIRMED MATCH", "PITCH-RELIANT",
            "EXTREME L2", "ICE COLD+SIGNAL",
        ])
        if pm >= 1.15:
            conv -= 10.0 if not _has_strong_named_grade else 4.0   # dead zone without grade; partial with
        elif pm >= 1.10:
            conv -= 7.0 if not _has_strong_named_grade else 3.0    # strongly priced; grade rescues partially
        elif pm >= 1.08:
            conv -= 5.0 if not _has_strong_named_grade else 2.0    # priced-in zone; named grade softens

        # Short-start: only penalize when bullpen is NOT homer-prone (Jun 17 2026)
        # Jun 26 2026 post-mortem: T2/T3 picks WITHOUT CONFIRMED MATCH failed on short starts.
        # Kerry Carpenter (T3, 4.2 IP) → 0 HR; Colt Emerson (T2+PITCH-RELIANT, 4.8 IP) → 0 HR.
        # Short start = pitcher pulled before batter can face them a 2nd time = BBE signal
        # never fully materializes. Hard gate: T2/T3-only + short start + no CONFIRMED MATCH
        # = hard cap at 30 (LEAN) regardless of bullpen quality.
        if "ShortStart" in flags_s or "Short-start" in notes_s:
            _is_t2_t3_only = (p1 <= 32.0 and p1 >= 10.0)   # T2/T3 range only (not T4/PRIME)
            _has_conf_match = "CONFIRMED MATCH" in g
            _has_pitch_reliant_strong = ("PITCH-RELIANT" in g and _bpen_hr9 >= 1.80)
            if _is_t2_t3_only and not _has_conf_match and not _has_pitch_reliant_strong:
                conv = min(conv, 30.0)   # hard cap: T2/T3 + short start + no CONFIRMED MATCH
            elif _bpen_hr9 < 1.50:
                conv -= 6.0   # good bullpen → short start is genuinely suppressive

        if "Suppressive park" in notes_s or "Supp.Park" in flags_s: conv -= 6.0
        if "High edge" in flags_s or "over-bullish" in notes_s:     conv -= 4.0
        if "Vuln45-48 Sc60" in flags_s:                             conv -= 3.0
        if ("Same-side (R vs R)" in notes_s) and ("elite power" not in notes_s.lower()):
            conv -= 3.0

        # PA security — fewer PAs = real prop-void risk
        _pa_conv = getattr(sc, 'pa_per_game', 4.3) if sc is not None else 4.3
        if _pa_conv < 4.0: conv -= 5.0

        # Pitcher-Target-Match T3/T4 floor: if the primary signal fired strongly,
        # guarantee a PLAY designation (≥24) — the pitcher-first evidence is real
        if p1 >= 28.0:
            conv = max(conv, 24.0)
        elif p1 >= 18.0:
            conv = max(conv, 18.0)

        # PITCH-RELIANT clean floor
        if "PITCH-RELIANT" in g and "Vuln52" not in flags_s and "Vuln42-44" not in flags_s:
            conv = max(conv, 24.0)

        # ── Jun 23 2026 New Grade Conviction Boosts ──────────────────────────
        # SWEET★ EDGE SPIKE HR: HS★+Edge≥15%+Sig≥4 → 38% HR (both datasets)
        # At 5.0x baseline this belongs in the top tier alongside CONFIRMED MATCH.
        _edge_cv = getattr(sc, 'edge_vs_market', 0.0) or 0.0
        _hs_cv   = getattr(sc, 'hit_score', 0.0)
        _sig_cv  = getattr(sc, 'signal_score', 0) or 0
        if 35.0 <= _hs_cv < 40.0 and _edge_cv >= 0.15 and _sig_cv >= 4:
            conv += 15
        # POWER TRAP OUTLIER: Pwr≥87 + V≥52 + HS<20 → 100% record (n=2, very rare)
        _hs_pt = getattr(sc, 'hit_score', 0.0)
        if power >= 87.0 and vuln >= 52.0 and 0 < _hs_pt < 20.0:
            conv = max(conv, 40.0)

        # ── Qualitative + Mixed Combo Boosts (Jun 23 2026 — CSV-validated) ──
        # From 57-slate CSV backtest + qualitative grade search (570 HR / 5,833 Hit combos).
        # These combine grade labels with quantitative metrics. Validated against master pkl.
        _notes_s = " ".join(str(n) for n in (sc.notes or []))
        _bzm_count = getattr(sc, 'batter_bzm_count', 0) or 0
        _is_pitch_reliant = "PITCH-RELIANT" in g and "HIT" not in g[:g.find("PITCH-RELIANT")+15] if "PITCH-RELIANT" in g else False
        _has_pitch_edge_flag = "💥" in _notes_s or "PITCH EDGE" in _notes_s.upper()
        _is_prime = "PRIME" in g and "PITCHER TARGET" in g
        _is_play_qual = ("✅ PLAY" in g or "✅ PLAY" in flags_s)
        _is_t4 = ("T4" in g or "PRIME" in g)

        # 1) BZM_3plus + convMed → 45% HR (2.9x, n=11)
        if _bzm_count >= 3 and 20.0 <= conv <= 40.0:
            conv += 10
        # 2) T4_BBE + Park≥1.1 + Pw≥82 → 50% HR (3.1x, n=8)
        if _is_t4 and park >= 1.1 and power >= 82.0:
            conv += 12
        # 3) PitchReliant + Sig≥10 → 41% HR (2.6x, n=17)
        if _is_pitch_reliant and sig >= 10:
            conv += 10
        # 4) isPlay + Pw≥87 + Edge≥15% → 43% HR (2.7x, n=7)
        if _is_play_qual and power >= 87.0 and _edge_cv >= 0.15:
            conv += 10
        # 5) T4_BBE + Sc≥60 → 38% HR (2.4x, n=21)
        if _is_t4 and scr >= 60.0 and not (_is_t4 and park >= 1.1 and power >= 82.0):
            conv += 8
        # 6) BZM_zones + Sc<50 + Vu≥52 → 3/3=100% (n=3, RARE trap-breaker)
        if _bzm_count >= 1 and scr < 50.0 and vuln >= 52.0:
            conv = max(conv, 35.0)
        # NOTE: visible labels for these combos are injected in _score_sharp after
        # conviction score is computed — flags/g are not in scope here.

        # ── Jun 23 2026 Backtest Combo Boosts — REBUILT from CSV ground truth ─
        # Original pkl-based numbers were WRONG (self-selected SHARP PICKS sample).
        # Re-validated against 2,534 picks × 57 slates from FantasyLabsMLB.csv.
        # HR baseline confirmed at 15.9% in full dataset.
        #
        # Validated HR combos (≥35%, ≥2.2x, all from 57-slate CSV):
        #   SWEET★ + Sc60-68:         17/46=37% (2.3x) — KEY validated signal
        #   SWEET★ + Edge≥15%:        10/28=36% (2.2x) — Edge drives the edge
        #   SWEET★ + Edge≥15%+Sig≥4:   9/20=45% (2.8x) — strongest HR signal in CSV
        #   Pw≥87 + Edge≥15%:          7/17=41% (2.6x) — elite power + underpriced
        #   Vu≥52 + Pw≥85:             8/20=40% (2.5x) — extreme power v52 override validated
        #   Park≥1.1 + Pw≥85:         10/27=37% (2.3x)
        #   Sig≥10 + Edge≥15%:         9/25=36% (2.3x)
        #   Sc≥65 + Edge≥15%:         10/27=37% (2.3x)
        #
        # DEPRECATED combos (were 50-57% from pkl, actually 17-22% from full CSV):
        #   SHARP_PM_HR + Sig1-5: was 57% (pkl), actually 17% (CSV) — NEAR BASELINE
        #   SHARP_PM_HR + Sc60-68: was 50% (pkl), actually 22% (CSV) — WEAK
        #   ICE_COLD + PM≥1.04 + Vuln44-52: was 40% (pkl), actually 21% (CSV)
        #   All SHARP_PM_HR combos: near-baseline in full CSV (1.0-1.3x)

        _is_sweet_star = (35.0 <= getattr(sc, 'hit_score', 0.0) < 40.0)
        _is_sharp_pm   = "SHARP PM HR" in g
        _is_ice_cold   = (0 < getattr(sc, 'hit_score', 0.0) < 20)
        _edge_val      = getattr(sc, 'edge_vs_market', 0.0) or 0.0
        _bt_notes = []

        # 1) SWEET★ + Edge≥15% + Sig≥4 → 9/20=45% (2.8x) ← STRONGEST CSV signal
        if _is_sweet_star and _edge_val >= 0.15 and sig >= 4:
            conv += 16
            _bt_notes.append(f"🔥 BACKTEST: SWEET★+Edge{_edge_val*100:+.0f}%+Sig{sig:.0f} → 45% HR (2.8x, n=20, 57-slate CSV)")

        # 2) Pw≥87 + Edge≥15% → 7/17=41% (2.6x)
        if power >= 87.0 and _edge_val >= 0.15:
            conv += 12
            _bt_notes.append(f"🔥 BACKTEST: Pw{power:.0f}(≥87)+Edge{_edge_val*100:+.0f}%(≥15%) → 41% HR (2.6x, n=17, 57-slate CSV)")

        # 3) SWEET★ + Sc60–68 → 17/46=37% (2.3x) ← good n, clean signal
        if _is_sweet_star and 60.0 <= scr < 68.0:
            conv += 12
            _bt_notes.append(f"🔥 BACKTEST: SWEET★+Sc{scr:.0f}(60-68) → 37% HR (2.3x, n=46, 57-slate CSV)")

        # 4) SWEET★ + Edge≥15% (without Sig gate) → 10/28=36% (2.2x)
        if _is_sweet_star and _edge_val >= 0.15 and not any("SWEET★+Edge" in n for n in _bt_notes):
            conv += 10
            _bt_notes.append(f"🔥 BACKTEST: SWEET★+Edge{_edge_val*100:+.0f}%(≥15%) → 36% HR (2.2x, n=28, 57-slate CSV)")

        # 5) Sig≥10 + Edge≥15% → 9/25=36% (2.3x)
        if sig >= 10 and _edge_val >= 0.15:
            conv += 10
            _bt_notes.append(f"🔥 BACKTEST: Sig{sig:.0f}(≥10)+Edge{_edge_val*100:+.0f}%(≥15%) → 36% HR (2.3x, n=25, 57-slate CSV)")

        # 6) Sc≥65 + Edge≥15% → 10/27=37% (2.3x)
        if scr >= 65.0 and _edge_val >= 0.15:
            conv += 10
            _bt_notes.append(f"🔥 BACKTEST: Sc{scr:.0f}(≥65)+Edge{_edge_val*100:+.0f}%(≥15%) → 37% HR (2.3x, n=27, 57-slate CSV)")

        # 7) Park≥1.1 + Pw≥85 → 10/27=37% (2.3x)
        if park >= 1.1 and power >= 85.0 and not any("Pw" in n and "Edge" in n for n in _bt_notes):
            conv += 10
            _bt_notes.append(f"🔥 BACKTEST: Park{park:.2f}(≥1.1)+Pw{power:.0f}(≥85) → 37% HR (2.3x, n=27, 57-slate CSV)")

        if _bt_notes:
            _bt_notes.sort(key=lambda x: -float(x.split("→")[1].split("%")[0].strip()) if "→" in x else 0)

        # ── Jun 24 2026: PWR-VULN-ENV HR conviction boosts ───────────────────
        # Backtest: master_picks.pkl (n=2534, baseline 17.4%)
        # Mechanism: power bat vs genuinely HR-prone pitcher (Vuln≥50) in a
        # favorable game environment (Env≥1.05). Env≥1.05 doubles the edge vs Env<1.0.
        # Does NOT require BBE history — different evidence chain from T3/T4.
        _env_cv = getattr(sc, 'env_factor', 1.0) or 1.0
        _pve_primary   = (power >= 78.0 and vuln >= 50.0 and _env_cv >= 1.05 and sig >= 10)
        _pve_secondary = (power >= 78.0 and vuln >= 50.0 and _env_cv >= 1.05 and sig >= 8 and not _pve_primary)
        _pve_broad     = (power >= 78.0 and vuln >= 50.0 and _env_cv >= 1.05 and pm >= 1.03 and sig < 8)
        if _pve_primary:
            conv += 15
            _bt_notes.append(
                f"🔥 BACKTEST: Pwr{power:.0f}(≥78)+Vuln{vuln:.0f}(≥50)+Env{_env_cv:.2f}(≥1.05)+Sig{sig:.0f}(≥10) "
                f"→ 50% HR (2.87x, n=16, pkl Jun24)"
            )
        elif _pve_secondary:
            conv += 12
            _bt_notes.append(
                f"🔥 BACKTEST: Pwr{power:.0f}(≥78)+Vuln{vuln:.0f}(≥50)+Env{_env_cv:.2f}(≥1.05)+Sig{sig:.0f}(≥8) "
                f"→ 45.5% HR (2.61x, n=22, pkl Jun24)"
            )
        elif _pve_broad:
            conv += 8
            _bt_notes.append(
                f"🔥 BACKTEST: Pwr{power:.0f}(≥78)+Vuln{vuln:.0f}(≥50)+Env{_env_cv:.2f}(≥1.05)+PM{pm:.3f}(≥1.03) "
                f"→ 40.0% HR (2.30x, n=35, pkl Jun24)"
            )

