    def _ht_tier_of(grade):
        if "🥇" in grade or "No hit grade" in grade or ("──" in grade and "STACK" in grade.upper()):
            return ("stacking", 999)
        for i, (sig, t) in enumerate(_hit_tier_sig):
            if sig in grade:
                return (t, i)
        return ("stacking", 999)
