    _ht_ranked.sort(key=lambda x: (x[0], x[1]))

    def _fc_hit(r):
        rr = str(r)
        if not rr or not rr[0].isdigit(): return "595959"
        try: v = float(rr.split('%')[0])
        except: return "595959"
        return "1F6B1F" if v >= 67 else ("C00000" if v < 60 else "595959")
    def _emit_hit(grade, desc, r5, r28, bg):
        _c(ws, row, 1, grade, bg=bg, bold=("🥇" in grade or "🏆" in grade), size=9)
        ws.merge_cells(f"B{row}:D{row}")
        _c(ws, row, 2, desc, bg=bg, size=9)
        _c(ws, row, 5, r5,  bg=bg, align="center", bold=("100%" in str(r5) or "80" in str(r5)), size=9, fc=_fc_hit(r5))
        _c(ws, row, 6, r28, bg=bg, align="center", size=9, fc=_fc_hit(r28))
        ws.row_dimensions[row].height = 13

    _last_ht = None
    for _tr, _i, _t, (grade, desc, r5, r28) in _ht_ranked:
        if _t != _last_ht:
            _hb = _ht_hdrbg[_t]
            _c(ws, row, 1, _ht_hdrtxt[_t], bg=_hb, fc="FFFFFF", bold=True, size=9)
            ws.merge_cells(f"B{row}:F{row}"); _c(ws, row, 2, "", bg=_hb)
            ws.row_dimensions[row].height = 14; row += 1
            _last_ht = _t
        _emit_hit(grade, desc, r5, r28, _ht_fill[_t]); row += 1
    # ── Stacking + baseline section ─────────────────────────────────────────
    _c(ws, row, 1, "🥇 STACKING / BASELINE  ·  multiple hit grades or none", bg="7F6000", fc="FFFFFF", bold=True, size=9)
    ws.merge_cells(f"B{row}:F{row}"); _c(ws, row, 2, "", bg="7F6000"); ws.row_dimensions[row].height = 14; row += 1
    for _tr, _i, _t, (grade, desc, r5, r28) in _ht_stack:
        if "──" in grade and "STACK" in grade.upper():
            continue
        _emit_hit(grade, desc, r5, r28, "F7F7F7" if "──" in grade else ("F2F2F2" if "No hit grade" in grade else "FFD700")); row += 1
    row += 1

    ws.merge_cells(f"A{row}:H{row}")
    _hdr(ws, row, 1, "⭐  TOP HIT PICKS  — sorted by conviction score (higher = more signals aligned)", bg="1F3864", size=11)
    ws[f"A{row}"].alignment = Alignment(horizontal="left", vertical="center", wrap_text=True, indent=1)
    ws.row_dimensions[row].height = 20; row += 1
    for col, lbl in enumerate(["Rank","Batter","Hit Score","Conv","Grade","Why","Key Signals","Flags"], 1):
        _hdr(ws, row, col, lbl, bg="2E75B6"); ws.row_dimensions[row].height = 15
    row += 1

    _HR_ONLY_FLAGS = {"⚠️ Gated","⚠️ Dead zone","🚫 No-signal","⚠️ Vuln42-44","⚠️ Vuln45-48","⚠️ Vuln44-48","⚠️ Vuln52+"}

    def _hit_conviction(sc, sh):
        """
        Conviction score 0-12 combining HS zone value + supporting signals - penalties.
        Replaces grade-first sort so high-signal picks (Buxton, Marte) surface above
        generic grade-label picks with fewer supporting signals.
        """
        hs    = sc.hit_score
        pm    = sc.pitch_matchup_score
        grade = sh.get("hit_grade","")
        hgc   = sh.get("hit_grade_count",0)
        nl    = " ".join(sc.hit_notes or []).lower()
        flags = " ".join(sh.get("flags",[]))

        # Base: HS zone value
        if 35 <= hs < 40:       base = 4   # Sweet★ — best zone
        elif hs >= 47 and sh.get("rank",99) <= 3: base = 4  # High+Top3
        elif hs < 20 and hs > 0: base = 1  # ICE COLD — DEMOTED Jun 2026 (was 3). Cold bats as
                                           # TOP hit picks failed live (Trout/Raley/Haase 0/0/0 Jun 8);
                                           # the cold-bat hit edge is real but NOT top-conviction. This
                                           # re-sorts hot WHR≥70% clean bats (Contreras/Arozarena/Yelich/
                                           # Chapman/Ramírez) above the cold bats, which is what hit.
        elif hs >= 40:           base = 2  # Avg/High
        else:                    base = 1  # Low

        # Signal bonuses (each independently validated)
        bonus = 0
        if "sharp line move" in nl:                                    bonus += 3  # 81% hit
        if "hot hitter" in nl and "weighted hit rate" in nl:           bonus += 2  # WHR≥70%
        if "red hot" in nl:                                            bonus += 1  # L5 hot
        if "high-consensus over" in nl or "strong hits probability" in nl: bonus += 1
        if any("hits well vs" in n.lower() or "elite vs" in n.lower()
               for n in (sc.hit_notes or [])):                         bonus += 1
        if pm >= 1.04:                                                 bonus += 1  # PM sweet zone
        if hgc >= 2 and not ("ICE COLD" in grade and "Cold+PM" in grade and hgc == 2):
            bonus += 2  # multi-grade — but ❄️ ICE COLD + 🔥🔥 SCREAM HIT Cold+PM are the SAME
                        # cold root; don't credit that pair as an independent two-grade stack
        if "🏆 SHARP LINE" in grade:                                   bonus += 2
        if "🎯 PITCH-RELIANT HIT" in grade:                            bonus += 2  # rare but strong (77.8%/1.24x, n=27) — tied with SHARP LINE / multi-grade tier; promote toward top-tier if the live tracker holds ≥72%
        if "🎯 SWEET★+PM" in grade or "🎯 SWEET★+PA" in grade:        bonus += 1
        # ── Env + PM sweet zone combo (Jun 15 2026) ──────────────────────────
        # Jun 15 post-mortem: nearly ALL 2+ hit getters had PM 1.00-1.10 + Env ≥ 1.05.
        # The triple combo (Env ≥ 1.05 + PM 1.03-1.10 + game environment note in hit_notes)
        # was the most consistent pattern across multi-hit getters.
        # Already: Env adds +3 pts to hit_score in compute_hit_score.
        # New: +1 hit_conv bonus when BOTH Env ≥ 1.05 AND PM is in the efficient sweet range.
        # This surfaces the synergy at the conviction level, not just the score level.
        _env_val = getattr(sc, 'env_factor', 1.00) or 1.00
        if _env_val >= 1.05 and 1.03 <= pm <= 1.10:                   bonus += 1  # Env+PM sweet combo
        # ── ICE COLD + SCREAM HIT continues validating strongly (Jun 15 2026) ──────
        # Carrigg (2H), Durán (2H), Rumfield (2H) — all had ICE COLD + PM ≥ 1.03.
        # The cold-bat hit edge is real at SCREAM HIT level. The base=1 for ICE COLD
        # is correct (cold bats shouldn't top the list), but when SCREAM HIT fires
        # on a cold bat it deserves a small conviction lift vs a plain cold bat.
        if hs < 20 and hs > 0 and "🔥🔥 SCREAM HIT" in grade and pm >= 1.03:
            bonus += 1  # cold bat confirmed by SCREAM HIT pattern → slight lift

        # Penalties
        penalty = 0
        _hit_flags_str = " ".join(flags)
        _hit_notes_str = " ".join(str(n) for n in (sc.notes or []))
        _has_l7_override = ("L7 surge overrides" in _hit_flags_str and
                            ("🔥 L7 power surge" in _hit_notes_str or
                             any("HRs last 7 days" in str(n) for n in (sc.notes or []))))
        # CHANGE 1C (Jun 14 2026): L7 hot streak + pitch correlation overrides career
        # fade penalty. Full penalty when cold career data only; reduced when live recency
        # data confirms the batter is hot on the pitcher's exact primary pitch types.
        if any(x in flags for x in ["📉 Weak vs","⚠️ Below-avg vs"]):
            penalty += 1 if _has_l7_override else 2  # halve penalty when L7 surge overrides
        if "❄️ Cold" in flags and hs < 20:                             penalty += 1  # cold + weak-vs = fade
        # Jul 1 2026: K-Danger penalty increased from 2 → 3 in hit conv table.
        # Jun 30 review: Kurtz (K-Danger, 0 hits), Burger (K-Risk, 0 hits), Goldschmidt
        # (K-Danger, 0 hits), Dingler (K-Danger, 0 hits) all went hitless.
        # When a batter consistently strikes out vs this pitcher type, they don't get the
        # contact needed to register hits. K-Danger was underpenalized relative to outcome.
        if "⚡ K-Danger" in flags:                                      penalty += 3  # was 2

        # ── HS 47-56 WEAK+CLEAN cap (30-slate backtest) ──────────────────────────
        # WEAK+CLEAN / SHARP WEAK+CLEAN in the HS 47-56 band hit only 56.8% (0.92x,
        # 71/125) WITHOUT a real edge, vs 63.6% (1.03x) WITH one — WHR + clean flags
        # were lifting these to 6-7/12 while they underperformed base. Cap at 5 unless
        # a real edge is present: Sig≥4, two-sided pitch correlation, or a sharp line move.
        _wc = ("WEAK+CLEAN" in grade) or ("WEAK + Clean" in grade)
        if _wc and 47 <= hs <= 56:
            _sig_v   = getattr(sc, "signal_score", 0) or 0
            _has_corr = any("PITCH CORRELATION" in str(n) for n in (sc.notes or []))
            _has_sharp = "sharp line move" in nl
            if not ((_sig_v >= 4) or _has_corr or _has_sharp):
                return max(0, min(5, base + bonus - penalty))

        # ── Jul 4 2026: PRIME+PitchEdge guaranteed gold-tier hit conviction ───────
        # Validated at 100% hit (4/4 live, 10/10 lifetime as of Jul 3 2026).
        # When PRIME PITCHER TARGET MATCH fires AND a confirmed 💥 pitch edge note
        # is present, the hit conviction must be at least 9/12 (gold tier).
        # Exception: K-Danger reduces the floor to 7/12 (still strong but honest
        # about contact risk). This overrides any HS-zone penalty or WEAK+CLEAN cap.
        _prime_pe_hit = (
            ("PRIME PITCHER TARGET" in grade or "PRIME PITCHER TARGET" in " ".join(str(n) for n in (sc.hit_notes or [])))
            and any("💥" in str(n) or "PRIME+PitchEdge" in str(n) for n in (sc.notes or sc.hit_notes or []))
        )
        if _prime_pe_hit:
            _k_danger_present = "⚡ K-Danger" in " ".join(flags)
            _pe_floor = 7 if _k_danger_present else 9
            return max(_pe_floor, min(12, base + bonus - penalty))

        return min(12, base + bonus - penalty)

    def _hit_key_signals(sc, sh):
        """Compact inline signal summary for the Key Signals column."""
        nl    = " ".join(sc.hit_notes or []).lower()
        pm    = sc.pitch_matchup_score
        hs    = sc.hit_score
        grade = sh.get("hit_grade","")
        parts = []
        # HS zone
        if 35 <= hs < 40:       parts.append(f"Sweet★ {hs:.0f}")
        elif hs >= 47 and sh.get("rank",99) <= 3: parts.append(f"High+T3 {hs:.0f}")
        elif hs < 20 and hs > 0: parts.append(f"ICE COLD {hs:.0f}")
        elif hs >= 47:           parts.append(f"HS {hs:.0f}")
        # WHR
        import re as _re
        whr_m = _re.search(r'(\d+)%\s+weighted hit rate', nl)
        if whr_m and int(whr_m.group(1)) >= 65:
            parts.append(f"WHR {whr_m.group(1)}%")
        # Sharp line
        if "sharp line move" in nl:  parts.append("Sharp$")
        # Consensus
        cons_m = _re.search(r'(\d+)%\s+of books project hit', nl)
        if cons_m and int(cons_m.group(1)) >= 62:
            parts.append(f"Cons {cons_m.group(1)}%")
        # vs pitcher
        for n in (sc.hit_notes or []):
            if ("hits well vs" in n.lower() or "elite vs" in n.lower()) and "%" in n:
                pct_m = _re.search(r'(\d+)%', n)
                if pct_m: parts.append(f"vs SP {pct_m.group(1)}%"); break
        # PM
        if pm >= 1.04: parts.append(f"PM {pm:.3f}")
        return "  ·  ".join(parts[:4])  # max 4 to keep readable

    def _build_hit_rationale_ctx(picks):
        """
        Slate-wide context for hit rationale comparisons.
        Computes max WHR, SLM picks, and multi-grade picks so
        _hit_rationale can say 'hottest bat', 'one of X SLM picks', etc.
        """
        import re as _rrc
        ctx = {
            "max_whr": 0.0, "max_whr_name": "",
            "slm_names": [], "multi_grade_names": [],
        }
        for _sc, _sh in picks:
            _nl = " ".join(_sc.hit_notes or []).lower()
            _wm = _rrc.search(r"(\d+)%\s+weighted hit rate", _nl)
            if _wm:
                _w = float(_wm.group(1))
                if _w > ctx["max_whr"]:
                    ctx["max_whr"] = _w
                    ctx["max_whr_name"] = _sc.batter_name
            if "sharp line move" in _nl:
                ctx["slm_names"].append(_sc.batter_name)
            if _sh.get("hit_grade_count", 0) >= 2:
                ctx["multi_grade_names"].append(_sc.batter_name)
        return ctx

    def _hit_success_rate(sc, sh):
        """(l5_pct, all_pct) historical HIT rate for this pick's firing hit grade,
        mirroring _hr_success_rate. Reuses the 30-slate hit-grade reference rates
        (loaded from the pkl above). Takes the strongest matching grade; falls back
        to the no-grade baseline."""
        g = sh.get("hit_grade", "") or ""
        _hit_keys = [
            ("SCREAM HIT: Cold", (_ic_hit_l5, _ic_hit_all)),
            ("Cold+PM",          (_ic_hit_l5, _ic_hit_all)),
            ("DUAL SCREAMER",    (_sigpm_hit_l5, _sigpm_hit_all)),
            ("SIG+PM HIT",       (_sigpm_hit_l5, _sigpm_hit_all)),
            ("SHARP LINE",       (_slm_hit_l5, _slm_hit_all)),
            ("PITCH DOM hit",    (_pd_hit_l5, _pd_hit_all)),
            ("SWEET★+PM",        (_swpm_l5, _swpm_all)),
            ("SWEET★ + PM",      (_swpm_l5, _swpm_all)),
            ("SWEET★+PA",        (_swpa_l5, _swpa_all)),
            ("SWEET★ + PA",      (_swpa_l5, _swpa_all)),
            ("SWEET★",           (_sw_l5, _sw_all)),
            ("ICE COLD",         (_ic_hit_l5, _ic_hit_all)),
            ("SHARP WEAK+CLEAN", (_swc_l5, _swc_all)),
            ("ELITE HIT",        (_sh_l5, _sh_all)),
            ("SHARP HIT",        (_sh_l5, _sh_all)),
            ("WEAK+CLEAN",       (_wc_l5, _wc_all)),
            ("WEAK + Clean",     (_wc_l5, _wc_all)),
            ("Strong hit",       (_wc_l5, _wc_all)),
            ("Sig=0 FADE",       (_hs55fade_l5, _hs55fade_all)),
            ("Moderate",         (_ng_hit_l5, _ng_hit_all)),
            ("Weak",             (_wf_l5, _wf_all)),
        ]
        cands = []
        for lbl, (l5s, als) in _hit_keys:
            if lbl in g:
                ap = _succ_pct(als)
                if ap is not None:
                    cands.append((ap, _succ_pct(l5s)))
        if not cands:
            cands = [(_succ_pct(_ng_hit_all) or 47.0, _succ_pct(_ng_hit_l5) or 47.0)]
        all_pct, l5_pct = max(cands, key=lambda x: x[0])
        if l5_pct is None:
            l5_pct = all_pct
        return (l5_pct, all_pct)

    def _hit_rationale(sc, sh, ctx=None):
        """
        Plain English one-sentence summary for a hit pick.
        Same philosophy as _hr_rationale — reads like analyst commentary,
        not a metric dump. Leads with grade uniqueness, adds form context,
        then the specific pitcher matchup or park factor.
        """
        import re as _rre
        if ctx is None:
            ctx = {}

        grade    = sh.get("hit_grade", "")
        hgc      = sh.get("hit_grade_count", 0)
        flags    = sh.get("flags", [])
        flags_str = " ".join(flags)

        hs       = sc.hit_score
        pm       = sc.pitch_matchup_score
        hn       = " ".join(sc.hit_notes or [])
        hnl      = hn.lower()
        _last    = sc.batter_name.split()[-1]
        _pitcher = sc.pitcher_name.split()[-1] if sc.pitcher_name else "today's starter"

        # ── Extract from hit notes ─────────────────────────────────────────────
        _wm  = _rre.search(r"(\d+)%\s+weighted hit rate", hnl)
        whr  = int(_wm.group(1)) if _wm else 0

        _cm  = _rre.search(r"(\d+)%\s+of books project hit", hnl)
        cons = int(_cm.group(1)) if _cm else 0

        # vs pitcher hit rate (from hit notes)
        _vm  = _rre.search(r"vs\s+\w+\s+\(sp\)[:\s]+(\d+)%", hnl)
        if not _vm:
            _vm = _rre.search(r"(?:hits well|elite) vs.*?(\d+)%", hnl)
        vsp  = int(_vm.group(1)) if _vm else 0

        # WHR raw number (not a percent — "hot hitter: 72% weighted hit rate")
        slm_active  = "sharp line move" in hnl
        is_red_hot  = "red hot last 5" in hnl
        is_cold_bat = hs < 20 and hs > 0

        # Pitch correlation from main notes (sc.notes, not hit_notes)
        _pc_nl  = " ".join(sc.notes or [])
        _pcm    = _rre.search(
            r"PITCH CORRELATION: Pitcher's (\w+) → wOBA ([\d.]+) allowed"
            r" \| Batter \w+ → wOBA ([\d.]+)", _pc_nl)
        pc_pitcher_w = float(_pcm.group(2)) if _pcm else 0.0
        pc_batter_w  = float(_pcm.group(3)) if _pcm else 0.0

        # PitchMix wOBA from main notes
        _pmx     = _rre.search(r"PitchMix wOBA ([\d.]+)", _pc_nl)
        pitchmix = float(_pmx.group(1)) if _pmx else 0.0

        # Park note from flags
        _park_note = ""
        for _f in flags:
            _pkm = _rre.search(r"(LHB|RHB) park ([\d.]+)x", _f)
            if _pkm:
                _park_note = (
                    f"{'left' if _pkm.group(1)=='LHB' else 'right'}-handed "
                    f"park factor of {_pkm.group(2)}x here"
                )
                break

        # Context
        max_whr   = ctx.get("max_whr", 0.0)
        slm_names = ctx.get("slm_names", [])

        is_hottest  = whr > 0 and max_whr > 0 and whr >= max_whr - 1
        is_very_hot = whr >= 80
        is_hot      = whr >= 70
        has_neg     = any(x in flags_str for x in
                          ["📉 Weak vs", "⚠️ Below-avg vs", "⚡ K-Danger"])

        # Negative flag label for caveat
        _neg_label = ""
        for _f in flags:
            if any(x in _f for x in ["📉 Weak vs", "⚠️ Below-avg vs", "⚡ K-Danger"]):
                _neg_label = (_f.replace("📉 ","").replace("⚠️ ","").replace("⚡ ",""))
                break

        parts = []

        # ── LEAD: what makes this hit pick compelling ──────────────────────────
        if hgc >= 2:
            _grade_parts = []
            if "🏆 SHARP LINE"    in grade: _grade_parts.append("sharp money on the game")
            if "SWEET★"          in grade: _grade_parts.append("sweet-zone contact score")
            if "PITCH DOM"       in grade: _grade_parts.append("pitch-dominance edge")
            if "SHARP WEAK+CLEAN" in grade: _grade_parts.append("clean high-score matchup")
            elif "WEAK+CLEAN"    in grade: _grade_parts.append("clean high-score matchup")
            elif "⚪✅"           in grade: _grade_parts.append("clean high-score matchup")
            if "ICE COLD"        in grade: _grade_parts.append("validated cold-bat signal")
            if "SHARP HIT"       in grade: _grade_parts.append("strong supporting signals")
            if len(_grade_parts) >= 2:
                _combo = f"{_grade_parts[0]} and {_grade_parts[1]}"
            elif _grade_parts:
                _combo = _grade_parts[0]
            else:
                _combo = "two independent signals"
            parts.append(f"Two hit signals stacking — {_combo}")
        elif "🏆 SHARP LINE" in grade:
            _n_slm = len(slm_names)
            if _n_slm == 1:
                parts.append(f"Sharp money moved the line — the only SLM pick on today's slate")
            elif _n_slm == 2:
                parts.append(f"Sharp money moved the line — one of only 2 SLM picks today")
            else:
                parts.append(f"Sharp money moved the line on this game")
        elif "🔥 SIG" in grade or "🔥 MID-HS" in grade:
            parts.append(
                f"Market and pitch-match signals both confirming — "
                f"the model's most reliable hit pattern"
            )
        elif "🎯 PITCH DOM hit" in grade:
            parts.append(
                f"Pitch-dominance edge against today's starter — "
                f"HR grade demoted but hit rate is excellent on this matchup type"
            )
        elif "🎯 SWEET★+PM" in grade or "🎯 SWEET★+PA" in grade:
            parts.append(
                f"In the model's best validated hit-score zone with a favorable pitch match"
            )
        elif "🌟 SWEET★" in grade:
            parts.append(
                f"Hit score in the 35-39 sweet zone — "
                f"the best validated contact range in the model"
            )
        elif "⭐ HIGH+Top3" in grade:
            parts.append(f"Top-3 ranked bat on the slate with a high contact score")
        elif "🎯 SHARP WEAK+CLEAN" in grade:
            parts.append(
                f"High contact score with a confirmed pitch-type edge "
                f"and no negative flags"
            )
        elif "🎯 PITCH-RELIANT HIT" in grade:
            parts.append(
                f"Power bat crushing a one-pitch starter's primary offering — "
                f"emerging hit signal the model is tracking (small sample)"
            )
        elif "🎯 SHARP HIT" in grade:
            parts.append(f"Multiple supporting signals pointing to a hit today")
        elif "❄️ ICE COLD" in grade:
            parts.append(
                f"Cold bat the model has validated hits above baseline — "
                f"67.9% hit rate on ICE COLD picks historically, don't fade the streak"
            )
        elif "⚪✅" in grade or "WEAK + Clean" in grade:
            parts.append(
                f"High contact score with no negative signals "
                f"in a clean matchup today"
            )
        else:
            parts.append(f"Strong supporting signals pointing to a hit")

        # ── FORM: how hot is the batter right now ─────────────────────────────
        if is_very_hot and is_hottest:
            parts.append(f"hottest bat on the slate by recent hit rate ({whr}%)")
        elif is_very_hot:
            parts.append(f"on fire recently with a {whr}% weighted hit rate")
        elif is_red_hot:
            parts.append(f"red hot over the last 5 games")
        elif is_hot and not any(str(whr) in p for p in parts):
            parts.append(f"hitting well lately ({whr}% weighted hit rate)")
        elif is_cold_bat:
            parts.append(f"cold by recent stats but the ICE COLD pattern is validated above baseline")

        # ── MATCHUP: pitcher-specific edge ────────────────────────────────────
        if vsp >= 70 and not any("historically hits" in p for p in parts):
            parts.append(f"historically hits {_pitcher} at a {vsp}% clip")
        elif pc_pitcher_w > 0 and pc_batter_w > 0:
            _verb = "crushes" if pc_batter_w > pc_pitcher_w else "is strong on"
            parts.append(f"{_last} {_verb} the pitch {_pitcher} throws most")
        elif pitchmix >= 0.400 and not any("pitch" in p for p in parts):
            parts.append(
                f"elite contact quality across {_pitcher}'s entire arsenal"
            )
        elif _park_note and not any("park" in p for p in parts):
            parts.append(_park_note)
        elif cons >= 65 and not any("books" in p for p in parts):
            parts.append(f"{cons}% of books agree")

        # ── CAVEAT ────────────────────────────────────────────────────────────
        if has_neg and _neg_label:
            parts.append(f"⚠️ {_neg_label}")

        # Enrich the existing sharp-money mention with the exact odds move (in place,
        # so it doesn't consume one of the 3 rationale slots).
        if slm_active:
            def _od(x):
                try: x = int(round(float(x)))
                except (ValueError, TypeError): return ""
                return f"+{x}" if x > 0 else f"{x}"
            _e_od = _od(getattr(sc, "hr_early_price", 0.0))
            _c_od = _od(getattr(sc, "hr_over_price", 0.0))
            if _e_od and _c_od:
                for _i, _p in enumerate(parts):
                    if ("sharp money" in _p.lower() or "moved the line" in _p.lower()) and "→" not in _p:
                        parts[_i] = f"{_p} ({_e_od} → {_c_od})"
                        break

        sentence = "; ".join(p for p in parts[:3] if p)
        _hsucc = sh.get("_hit_succ")
        if _hsucc is None:
            _hsucc = _hit_success_rate(sc, sh); sh["_hit_succ"] = _hsucc

        # ── Backtest Elite hit combo note ────────────────────────────────────
        # Surface the BACKTEST ELITE label inline in the rationale text so the
        # player sees the empirical rate right where they read the pick.
        _bt_hit_note = ""
        _flags_str = " ".join(sh.get("flags", []))
        if "BACKTEST ELITE" in _flags_str:
            # Extract the highest-rate BACKTEST ELITE flag
            import re as _btre
            _bt_matches = _btre.findall(r"(🔥🔥? BACKTEST ELITE[^🔥]*?(?:\d+%[^,)]+))", _flags_str)
            if _bt_matches:
                _bt_hit_note = _bt_matches[0].strip()
                # Ensure we don't duplicate if already in sentence
                if "BACKTEST ELITE" not in sentence:
                    _bt_hit_note = f"  🔥 {_bt_hit_note}."
                else:
                    _bt_hit_note = ""

        # ── Stacking combo backtest clause (Jul 1 2026) ──────────────────────
        # Same lookup table as HR rationale — surfaces the validated hit rate
        # for the best matching multi-grade combo firing on this pick.
        _hit_stack_clause = ""
        try:
            _hs_pm   = getattr(sc, "pitch_matchup_score", 1.0) or 1.0
            _hs_pwr  = getattr(sc, "batter_power", 0.0) or 0.0
            _hs_vuln = getattr(sc, "pitcher_vuln", 50.0) or 50.0
            _hs_env  = getattr(sc, "game_environment", 1.0) or 1.0
            _hs_scr  = getattr(sc, "score", 0.0) or 0.0
            _hs_sig  = sh.get("sig_score", 0) or 0
            _hs_hs   = getattr(sc, "hit_score", 50.0) or 50.0
            _hs_edge = getattr(sc, "edge_vs_market", 0.0) or 0.0
            _hs_park = getattr(sc, "park_hr_factor", 1.0) or 1.0
            _hs_odds = None
            try:
                _hs_odds = int(str(getattr(sc, "hr_over_price", "") or "").replace("+", ""))
            except (ValueError, TypeError):
                pass

            # Use hr_grade string for named-grade detection, same as HR rationale fix
            _hs_g = sh.get("hr_grade", "") or ""

            _hgf_nuclear     = ("☢️" in _hs_g) or (_hs_pwr >= 84 and _hs_odds is not None
                                and 0 < _hs_odds <= 399 and 1.02 <= _hs_pm <= 1.08 and _hs_scr < 66)
            _hgf_t4ptm       = any(x in _hs_g for x in ["T4", "T3", "PRIME PITCHER TARGET"]) or (
                                _hs_pm >= 1.04 and _hs_pwr >= 78
                                and any(x in _hs_g for x in ["T4", "T3", "PRIME"]))
            _hgf_pitch_dom   = any(x in _hs_g for x in ["PITCH DOMINANCE", "PITCH DOM ELITE"]) or (
                                1.06 <= _hs_pm <= 1.08 and _hs_pwr >= 74 and _hs_sig >= 5)
            _hgf_pitch_rel   = ("PITCH-RELIANT" in _hs_g) or (
                                _hs_pm >= 1.04 and _hs_pwr >= 78 and _hs_sig >= 8)
            _hgf_sharp_pm    = ("SHARP PM" in _hs_g) or (1.08 <= _hs_pm <= 1.15 and 40 <= _hs_scr <= 70)
            _hgf_sweet_edge  = ("SWEET★ EDGE SPIKE" in _hs_g) or (
                                35 <= _hs_hs <= 39 and _hs_edge >= 15 and _hs_sig >= 4)
            _hgf_pve         = ("PWR-VULN-ENV" in _hs_g) or (
                                _hs_pwr >= 78 and _hs_vuln >= 50 and _hs_env >= 1.05
                                and (_hs_sig >= 8 or _hs_pm >= 1.03))
            _hgf_ice_cold    = ("ICE COLD" in _hs_g) or (_hs_hs < 20 and _hs_pm >= 1.04 and _hs_scr >= 40)
            _hgf_scream_cold = (_hs_hs < 20 and _hs_pm >= 1.03)
            _hgf_sweet_star  = (35 <= _hs_hs <= 39)
            _hgf_sweet_pm    = ("SWEET PM" in _hs_g) or (
                                1.03 <= _hs_pm <= 1.07 and 44 <= _hs_vuln <= 55 and _hs_scr < 65)
            _hgf_mid_score   = ("MID-SCORE" in _hs_g) or (
                                50 <= _hs_scr <= 60 and _hs_pm >= 1.04 and 44 <= _hs_vuln <= 53)
            _hgf_elite_sig   = ("ELITE SIGNAL" in _hs_g) or (_hs_sig >= 12 and _hs_pwr >= 78)
            _hgf_sig_pm      = ("SIG+PM" in _hs_g) or (_hs_sig >= 5 and _hs_pm >= 1.04 and _hs_scr >= 40)
            _hgf_scream_hipm = (55 <= _hs_scr <= 60 and 1.07 <= _hs_pm <= 1.10)
            _hgf_t4_park     = (_hs_park >= 1.10 and _hs_pwr >= 82 and _hs_pm >= 1.04
                                and any(x in _hs_g for x in ["T4", "T3", "PRIME"]))
            _hgf_play_pwr85  = (_hs_pwr >= 85 and _hs_pm >= 1.04
                                and ("✅ PLAY" in _hs_g or sh.get("hr_play_tag","") == "PLAY"))
            _hgf_p85_e15     = (_hs_pwr >= 85 and _hs_pm >= 1.04 and _hs_edge >= 15
                                and ("✅ PLAY" in _hs_g or sh.get("hr_play_tag","") == "PLAY"))
            _hgf_vu44_p85    = (44 <= _hs_vuln <= 48 and _hs_pwr >= 85 and _hs_edge >= 15)
            _hgf_supp_park   = (1.022 <= _hs_pm <= 1.082 and _hs_park < 0.90
                                and 30 <= _hs_vuln <= 55 and _hs_edge >= 1)

            # Same lookup table as HR rationale — sorted strongest/most specific first.
            # Focus on hit-dominant combos (high hit%) plus the best dual HR+Hit combos.
            _HIT_STACK_TABLE = [
                # ── Best hit rate combos from audit ───────────────────────────
                ((_hgf_nuclear, _hgf_pve),
                 "NUCLEAR+PWR_VULN_ENV", 12, 50.0, 2.88, 91.7),
                ((_hgf_nuclear, _hgf_pitch_rel, _hgf_pve),
                 "NUCLEAR+PITCH_RELIANT+PWR_VULN_ENV", 7, 57.1, 3.29, 85.7),
                ((_hgf_nuclear, _hgf_t4ptm, _hgf_pve),
                 "NUCLEAR+T4_PTM+PWR_VULN_ENV", 7, 42.9, 2.47, 85.7),
                ((_hgf_nuclear, _hgf_t4ptm, _hgf_pitch_rel, _hgf_pve),
                 "NUCLEAR+T4_PTM+PITCH_RELIANT+PWR_VULN_ENV", 6, 50.0, 2.88, 83.3),
                ((_hgf_nuclear, _hgf_pve, _hgf_sig_pm),
                 "NUCLEAR+PWR_VULN_ENV+SIG_PM", 6, 50.0, 2.88, 83.3),
                ((_hgf_t4ptm, _hgf_supp_park),
                 "T4_PTM+SUPP_PARK", 10, 0.0, 0.00, 90.0),
                ((_hgf_mid_score, _hgf_supp_park),
                 "MID_SCORE+SUPP_PARK", 10, 20.0, 1.15, 90.0),
                ((_hgf_nuclear, _hgf_ice_cold),
                 "NUCLEAR+ICE_COLD_SIG", 11, 27.3, 1.57, 81.8),
                ((_hgf_scream_cold, _hgf_t4_park),
                 "SCREAM_COLD_PM+T4_PARK", 15, 33.3, 1.92, 80.0),
                ((_hgf_sweet_pm, _hgf_supp_park),
                 "SWEET_PM+SUPP_PARK", 20, 20.0, 1.15, 80.0),
                ((_hgf_pitch_dom, _hgf_sweet_star),
                 "PITCH_DOM+SWEET_STAR", 15, 26.7, 1.54, 80.0),
                ((_hgf_nuclear, _hgf_scream_cold),
                 "NUCLEAR+SCREAM_COLD_PM", 14, 28.6, 1.65, 78.6),
                ((_hgf_ice_cold, _hgf_t4_park),
                 "ICE_COLD_SIG+T4_PARK", 14, 28.6, 1.65, 78.6),
                ((_hgf_pve, _hgf_t4_park),
                 "PWR_VULN_ENV+T4_PARK", 22, 31.8, 1.83, 77.3),
                ((_hgf_pitch_rel, _hgf_pve),
                 "PITCH_RELIANT+PWR_VULN_ENV", 29, 37.9, 2.19, 72.4),
                ((_hgf_pve, _hgf_sig_pm),
                 "PWR_VULN_ENV+SIG_PM", 29, 31.0, 1.79, 72.4),
                ((_hgf_pitch_dom, _hgf_pitch_rel),
                 "PITCH_DOM+PITCH_RELIANT", 56, 30.4, 1.75, 73.2),
                ((_hgf_t4ptm, _hgf_pve),
                 "T4_PTM+PWR_VULN_ENV", 28, 32.1, 1.85, 75.0),
                ((_hgf_pve, _hgf_elite_sig),
                 "PWR_VULN_ENV+ELITE_SIG", 16, 43.8, 2.52, 75.0),
                ((_hgf_pitch_dom, _hgf_pitch_rel, _hgf_play_pwr85),
                 "PITCH_DOM+PITCH_RELIANT+PLAY_PWR85", 14, 42.9, 2.47, 78.6),
                ((_hgf_t4ptm, _hgf_sweet_star),
                 "T4_PTM+SWEET_STAR", 34, 29.4, 1.69, 70.6),
                ((_hgf_sharp_pm, _hgf_sweet_edge),
                 "SHARP_PM+SWEET_EDGE", 9, 44.4, 2.56, 77.8),
                ((_hgf_nuclear, _hgf_pitch_rel),
                 "NUCLEAR+PITCH_RELIANT", 32, 34.4, 1.98, 65.6),
                ((_hgf_sweet_star, _hgf_scream_hipm),
                 "SWEET_STAR+SCREAM_HI_PM", 7, 57.1, 3.29, 71.4),
                ((_hgf_t4ptm, _hgf_scream_cold),
                 "T4_PTM+SCREAM_COLD_PM", 58, 15.5, 0.89, 77.6),
                ((_hgf_t4ptm, _hgf_ice_cold),
                 "T4_PTM+ICE_COLD_SIG", 58, 15.5, 0.89, 77.6),
                ((_hgf_sig_pm, _hgf_supp_park),
                 "SIG_PM+SUPP_PARK", 18, 16.7, 0.96, 77.8),
                # T4/T3 BBE paired with secondary hit grades
                ((_hgf_t4ptm, _hgf_pitch_dom),
                 "T4_PTM+PITCH_DOM", 21, 38.1, 2.19, 76.2),
                ((_hgf_t4ptm, _hgf_sharp_pm),
                 "T4_PTM+SHARP_PM", 14, 35.7, 2.06, 71.4),
                ((_hgf_t4ptm, _hgf_sig_pm),
                 "T4_PTM+SIG_PM", 56, 28.6, 1.64, 67.9),
                ((_hgf_t4ptm, _hgf_mid_score),
                 "T4_PTM+MID_SCORE", 29, 24.1, 1.39, 69.0),
                ((_hgf_t4ptm, _hgf_elite_sig),
                 "T4_PTM+ELITE_SIG", 17, 29.4, 1.69, 70.6),
                ((_hgf_t4ptm, _hgf_scream_hipm),
                 "T4_PTM+SCREAM_HI_PM", 18, 27.8, 1.60, 66.7),
                ((_hgf_t4ptm, _hgf_sweet_pm),
                 "T4_PTM+SWEET_PM", 42, 21.4, 1.23, 64.3),
                ((_hgf_pitch_rel, _hgf_pitch_dom),
                 "PITCH_RELIANT+PITCH_DOM", 19, 26.3, 1.51, 68.4),
                ((_hgf_pitch_rel, _hgf_sig_pm),
                 "PITCH_RELIANT+SIG_PM", 51, 25.5, 1.47, 66.7),
                ((_hgf_pitch_rel, _hgf_sharp_pm),
                 "PITCH_RELIANT+SHARP_PM", 16, 25.0, 1.44, 62.5),
                ((_hgf_pitch_rel, _hgf_elite_sig),
                 "PITCH_RELIANT+ELITE_SIG", 24, 25.0, 1.44, 66.7),
                ((_hgf_pitch_rel, _hgf_ice_cold),
                 "PITCH_RELIANT+ICE_COLD", 31, 22.6, 1.30, 67.7),
                ((_hgf_pitch_rel, _hgf_mid_score),
                 "PITCH_RELIANT+MID_SCORE", 38, 21.1, 1.21, 65.8),
                ((_hgf_pitch_dom, _hgf_sharp_pm),
                 "PITCH_DOM+SHARP_PM", 14, 28.6, 1.65, 64.3),
                ((_hgf_pitch_dom, _hgf_sig_pm),
                 "PITCH_DOM+SIG_PM", 26, 23.1, 1.33, 65.4),
                ((_hgf_pitch_dom, _hgf_ice_cold),
                 "PITCH_DOM+ICE_COLD", 17, 23.5, 1.35, 70.6),
                ((_hgf_nuclear, _hgf_pitch_dom),
                 "NUCLEAR+PITCH_DOM", 22, 27.3, 1.57, 68.2),
                ((_hgf_nuclear, _hgf_t4ptm),
                 "NUCLEAR+T4_PTM", 31, 25.8, 1.48, 67.7),
                ((_hgf_nuclear, _hgf_sig_pm),
                 "NUCLEAR+SIG_PM", 18, 27.8, 1.60, 66.7),
                ((_hgf_nuclear, _hgf_mid_score),
                 "NUCLEAR+MID_SCORE", 16, 25.0, 1.44, 62.5),
            ]

            _hbest_label = None
            _hbest_n = 0
            _hbest_hr = None
            _hbest_mult = None
            _hbest_hit = None

            for _hflags, _hlabel, _hn, _hhr, _hmult, _hhit in _HIT_STACK_TABLE:
                if _hn < 5:
                    continue
                if all(_hflags):
                    # For hits, prefer the entry with the highest hit rate among matches
                    if _hbest_label is None or _hhit > (_hbest_hit or 0):
                        _hbest_label = _hlabel
                        _hbest_n = _hn
                        _hbest_hr = _hhr
                        _hbest_mult = _hmult
                        _hbest_hit = _hhit

            if _hbest_label is not None:
                _hit_stack_clause = (
                    f"  🔥 STACK: {_hbest_label} → "
                    f"{_hbest_hit:.0f}% Hit + {_hbest_hr:.0f}% HR ({_hbest_mult:.2f}x, "
                    f"n={_hbest_n} AT, Jul 1 2026 audit)"
                )
        except Exception:
            _hit_stack_clause = ""

        _hit_stack_line = (f"\n📊 {_hit_stack_clause.strip()}" if _hit_stack_clause else "")

        # ── Elite Contact Profile note in hit rationale ───────────────────────
        # Surface when BOTH PullBrl%>10 AND FB%>35 fire — indicates elite HR-contact
        # profile that also correlates with elevated hit probability (air-ball + pull power).
        _ecp_hit_note = ""
        for _ecp_h_candidate in (sc.notes or []):
            _ecp_h_ns = str(_ecp_h_candidate)
            if "ELITE CONTACT PROFILE" in _ecp_h_ns and "PullBrl%" in _ecp_h_ns and "FB%" in _ecp_h_ns:
                _ecp_hit_note = f"  🔥 {_ecp_h_ns.strip()}"
                break

        return (f"{sentence}.  Hit success rate L5/AT: {_hsucc[0]:.0f}%/{_hsucc[1]:.0f}%"
                + (_bt_hit_note if _bt_hit_note else "")
                + (_ecp_hit_note if _ecp_hit_note else "")
                + _hit_stack_line)

    hit_picks = sorted(
        [(sc,sh) for sc,sh in scored if
         sh.get("hit_grade_count",0) >= 1 or
         sh["hit_grade"] in ("🎯 SHARP HIT","⭐ ELITE HIT","🟢 Strong hit") or
         sh["hit_pts"] >= 8 or
         (35 <= sc.hit_score < 40) or
         (sc.hit_score >= 47 and sc.hit_score > 0)],
        key=lambda x: (-_hit_conviction(x[0],x[1]), -x[0].hit_score))

    # ── PLAY / LEAN / PASS tag for hits (Jun 2026) ──────────────────────────
    # Hits run on different drivers than HR (base ~60%). Validated signals only.
    def _hit_play_tag(sc, sh, conv):
        import re as _re
        hg  = sh.get("hit_grade", "") or ""
        fl  = " ".join(sh.get("flags", []))
        hs  = getattr(sc, "hit_score", 0.0)
        sig = getattr(sc, "signal_score", 0) or 0
        pm  = getattr(sc, "pitch_matchup_score", 1.0)
        # Parse squared-up rate from hit_notes (stored as "NN% squared-up rate")
        _hn = " ".join(sc.hit_notes or [])
        _sq_m = _re.findall(r'(\d+)%\s+squared.up rate', _hn)
        _sq   = max(int(x) for x in _sq_m) if _sq_m else 0
        # Parse qAB% vs pitcher from hit_notes
        _qab_m = _re.findall(r'qAB[%\s]+(?:vs pitcher[:\s]+)?(\d+)%', _hn)
        _qab   = max(int(x) for x in _qab_m) if _qab_m else 0
        # ── Hard fades ────────────────────────────────────────────────────────
        if "Weak vs" in fl or "Below-avg vs" in fl:
            # FIX 2A (Jun 14 2026, Burleson case): Two override paths for weak-career PASS:
            # Path A (original Change 1B): L7 surge + pitch correlation → fall through.
            # Path B (new): Structural pitch correlation confirmed (PITCH CORRELATION
            #   note in sc.notes + PM≥1.04 + Power≥78) → fall through to LEAN/PLAY.
            #   This catches Burleson: PITCH CORRELATION note confirmed but L7 data
            #   not loading from API. The structural evidence is sufficient — if the
            #   model confirmed the pitcher is weak on their primary pitch AND the
            #   batter crushes that same pitch, a small-sample career rate (9%) is
            #   noise that should not PASS-block the pick.
            _fl_notes = " ".join(str(n) for n in (sc.notes or []))
            _power = getattr(sc, "batter_power", 0.0) or 0.0
            _pc_confirmed = ("🎯 PITCH CORRELATION" in _fl_notes and
                             pm >= 1.04 and _power >= 78.0)
            _l7_override = ("L7 surge overrides" in fl and
                            ("🔥 L7 power surge" in _fl_notes or
                             any("HRs last 7 days" in str(n) for n in (sc.notes or []))))
            if _pc_confirmed or _l7_override:
                pass  # fall through — structural signal overrides small-sample career rate
            else:
                return "⛔ PASS (hit) — weak career vs this pitcher.  "
        # Jul 1 2026: Cold + K-Danger compound = hard PASS.
        # Jun 30 review: Kurtz (cold + K-danger 0 hits), Dingler (cold + K-danger 0 hits).
        # When a batter is BOTH cold (hs<20 = recent contact suppressed) AND has elevated
        # K rate vs this pitcher type, the compounding suppression removes any hit edge.
        # Exception: SCREAM HIT grade overrides (validated 66%+ even on cold bats with PM≥1.03).
        _is_cold_hit = hs < 20 and hs > 0
        _has_scream_hit = "SCREAM HIT" in (sh.get("hit_grade", "") or "")
        if _is_cold_hit and "K-Danger" in fl and not _has_scream_hit:
            return "⛔ PASS (hit) — cold + K-danger compound (double suppression).  "
        if "K-Danger" in fl:
            return "⛔ PASS (hit) — K-danger matchup.  "
        if 47.0 <= hs <= 55.0 and sig == 0:
            return "⛔ PASS (hit) — HS 47-55 + Sig 0 (0.91x).  "
        # ── Top-tier plays (unchanged — SLM and SCREAM already validated ≥72%) ──
        if sh.get("has_slm") or "SHARP LINE" in hg:
            return "✅ PLAY (hit) — sharp line move (78%, 1.30x).  "
        if "SCREAM HIT" in hg:
            return "✅ PLAY (hit) — SCREAM HIT zone (Cold+PM≥1.03 = 66.2%, 1.14x, 57-sl CSV).  "
        # ── ICE COLD: require sq≥30 for PLAY; bare cold drops to LEAN ──────────
        # Backtest: ICE COLD + PM≥1.03 alone = 66.9%; adding sq≥30 → 72.0% (1.20x, holds OOS)
        if (0 < hs < 20) and pm >= 1.03:
            if _sq >= 30:
                return f"✅ PLAY (hit) — cold bat + sq {_sq}% + PM edge (72%, 1.20x).  "
            return f"🟡 LEAN (hit) — cold bat + PM edge, sq {_sq}% below 30% gate.  "
        if "ICE COLD" in hg:
            return "🟡 LEAN (hit) — validated cold-bat, no sq confirmation.  "
        # ── SWEET★: tiered by sq-up confirmation ────────────────────────────────
        # sq≥35 + SWEET★ = 73.5% (1.23x, holds OOS) — upgraded PLAY
        # sq≥30 + PM≥1.03 + SWEET★ = 66.7% (1.11x) — standard PLAY
        # bare SWEET★ alone = 61.7% (1.03x) — demoted to LEAN
        if 35.0 <= hs < 40.0:
            if _sq >= 35:
                return f"✅ PLAY (hit) — SWEET★ + sq {_sq}% (73.5%, 1.23x).  "
            if _sq >= 30 and pm >= 1.03:
                return f"✅ PLAY (hit) — SWEET★ + sq {_sq}% + PM (66.7%, 1.11x).  "
            if _qab >= 75 and _sq >= 30:
                return f"✅ PLAY (hit) — SWEET★ + qAB {_qab}% + sq {_sq}% (72.7%, 1.21x).  "
            # bare SWEET★ — real but only 1.03x, demote to LEAN
            return f"🟡 LEAN (hit) — SWEET★ zone, sq {_sq}% below confirmation gate.  "
        # ── Remaining PLAY/LEAN by conviction ───────────────────────────────────
        if conv >= 7:  return f"✅ PLAY (hit) — Conv {conv}/12.  "
        if conv >= 5:  return f"🟡 LEAN (hit) — Conv {conv}/12.  "
        return "🟡 LEAN (hit) — no top hit signal.  "

    # Build hit rationale context once before the loop
    _hit_rationale_ctx = _build_hit_rationale_ctx(hit_picks)

    for sc, sh in hit_picks:
        hs    = sc.hit_score
        hgc   = sh.get("hit_grade_count", 0)
        conv  = _hit_conviction(sc, sh)
        grade = sh["hit_grade"]
        # Background: conviction-based rather than grade-based
        if conv >= 9:    h_bg = "FFD700"   # gold — highest conviction
        elif conv >= 7:  h_bg = "DDEEFF"   # blue — strong
        elif conv >= 5:  h_bg = "E2F0D9"   # green — solid
        elif conv >= 3:  h_bg = "FFF2CC"   # yellow — moderate
        else:            h_bg = "E2EFDA"   # pale — low
        _grade_disp = f"🥇 {grade}" if hgc >= 2 else grade
        _rank_disp_h = {1:"🥇",2:"🥈",3:"🥉"}.get(sh["rank"], str(sh["rank"]))
        _key_sigs = _hit_key_signals(sc, sh)
        # Hit flags: show ONLY genuine negative signals that are independent of the grade.
        # Strip: HR-only flags, grade references (duplicate Grade col), Sweet PM hit tag,
        #        Gate Override (HR context), Supp.Park+ShortStart (HR compound).
        # Keep:  Pitcher weakness, K-danger, cold bat, conv warning, neg momentum.
        _HIT_STRIP = {
            "🎯 Sweet PM hit",      # shown in Grade column already
            "🔓 Gate Override",     # HR-context only
            "⚠️ Supp.Park+ShortStart",  # HR compound — hit rate unaffected
        }
        _hit_flags = [
            f for f in sh["flags"]
            if f not in _HIT_STRIP
            and not any(hr in f for hr in _HR_ONLY_FLAGS)
            and not f.startswith("🎯 Hit grade:")   # duplicates Grade column
            and not f.startswith("🎯 CONVICTION")   # HR pick-selection grade only
            and not f.startswith("📊 GOOD PLAY")    # HR pick-selection grade only
            and f != "✅ Clean"                       # placeholder, not a real flag
        ]
        _c(ws,row,1,_rank_disp_h,       bg=h_bg,align="center",bold=True)
        _c(ws,row,2,sc.batter_name,     bg=h_bg,bold=(conv>=9))
        _c(ws,row,3,f"{hs:.1f}",        bg=h_bg,align="center")
        _c(ws,row,4,f"{conv}/12",       bg=h_bg,align="center",bold=(conv>=7))
        _c(ws,row,5,_grade_disp,        bg=h_bg,bold=(hgc>=2),size=9)
        _c(ws,row,6,_hit_play_tag(sc, sh, conv) + _hit_rationale(sc, sh, _hit_rationale_ctx), bg=h_bg,size=9)
        _c(ws,row,7,_key_sigs,          bg=h_bg,size=9)
        _c(ws,row,8,"  ".join(_hit_flags) or "✅ Clean", bg=h_bg,size=9)
        ws.row_dimensions[row].height = 18; row += 1
    row += 1

    # Fades: only show picks with hit-relevant negative signals.
    # June 2 fix: Cold bats with PM≥1.04 are NOT fades — ICE COLD+SIGNAL is a valid
    # HR grade (20.8% HR, 67.9% hit rate). Only cold-fade when PM<1.04 OR when
    # Negative hit signals — a player must have ≥2 to qualify as a fade.
    # A single soft negative alongside positive grades is contradictory, not a fade.
    _HIT_NEG = ["❄️ Cold","⚡ K-Danger","📉 Weak vs","⚠️ K-Warning","⚠️ Below-avg"]

    # Flag prefixes that are positive signals — never shown in the fade row
    _POS_PREFIXES = ("🎯 Hit grade","💥","🎯 Pitch corr","🎯 PitchMix","🎯 Sweet PM",
                     "🔓","🏟️","🏆","✅ Clean","🎯 SHARP","🎯 PITCH","🎯 Crushes",
                     "🎯 CONFIRMED")

    def _should_fade(sc, sh):
        flags_str = " ".join(sh["flags"])
        # FIX (Jun 14 2026): When "⚠️ Below-avg vs" or "📉 Weak vs" was downgraded
        # by structural pitch correlation ("pitch match overrides" / "L7 surge overrides"),
        # don't count it as a negative signal for fades. The flag is informational only.
        _override_active = any(x in flags_str for x in ["pitch match overrides", "L7 surge overrides"])
        neg_signals = [x for x in _HIT_NEG if x in flags_str
                       and not (_override_active and x in ["⚠️ Below-avg", "📉 Weak vs"])]
        # Cold bat exemption: ICE COLD+SIGNAL with PM≥1.04 and cold is the only negative
        _sc_pm = sc.pitch_matchup_score
        if "❄️ Cold" in flags_str and _sc_pm >= 1.04 and len(neg_signals) == 1:
            return False
        # Require 2+ confirmed negative signals — one soft negative is not a fade
        return len(neg_signals) >= 2 and (sh.get("hit_grade_count",0) >= 1 or sh["hit_pts"] >= 6)

    fades = [(sc,sh) for sc,sh in scored if _should_fade(sc, sh)]
    if fades:
        ws.merge_cells(f"A{row}:H{row}")
        _hdr(ws, row, 1, "🚫  FADES  (confirmed negative signals)", bg="404040", size=11)
        ws.row_dimensions[row].height = 20; row += 1
        for sc, sh in sorted(fades, key=lambda x:-x[0].score)[:8]:
            _rank_disp_f = {1:"🥇",2:"🥈",3:"🥉"}.get(sh["rank"], str(sh["rank"]))
            _c(ws,row,1,_rank_disp_f,bg="F2F2F2",align="center",fc="808080")
            _c(ws,row,2,sc.batter_name,bg="F2F2F2",fc="808080")
            ws.merge_cells(f"C{row}:H{row}")
            # Show ONLY negative signals — no positive flags, no HR-only flags
            _HR_ONLY = {"⚠️ Gated","⚠️ Dead zone","🚫 No-signal","⚠️ Vuln44-48",
                        "⚠️ Vuln52+","⚠️ Vuln42","⚠️ Vuln45"}
            _neg_only = [
                f for f in sh["flags"]
                if any(neg in f for neg in _HIT_NEG)
                and not any(f.startswith(p) for p in _POS_PREFIXES)
                and not any(hr in f for hr in _HR_ONLY)
            ]
            _c(ws,row,3,"  |  ".join(_neg_only) if _neg_only else "Multiple negative signals",
               bg="F2F2F2",fc="C00000")
            ws.row_dimensions[row].height = 15; row += 1

    # ── Glossary table ────────────────────────────────────────────────────────

    row += 1

    ws.merge_cells(f"A{row}:H{row}")
