def parse_args():
    """Parse command-line arguments. Returns (target_date, is_historical, top_n, out_file)."""
    parser = argparse.ArgumentParser(
        description=(
            "MLB Home Run Model  |  Phase 2 Monte Carlo Simulator\n"
            "Ranks batters for FanDuel DFS HR contests using 10,000 simulations per player.\n"
            "\n"
            "DATA SOURCES (in priority order):\n"
            "  1. FantasyLabs (FL)     — Lineups, implied runs, weather, salary, batting order\n"
            "  2. SportsGameOdds (SGO) — HR odds (anytime + first HR fallback), 2500 tokens/mo\n"
            "  3. OddsAPI              — HR odds fallback for any player SGO missed\n"
            "  4. Baseball Savant      — Barrel%, HardHit%, EV, xSLG, SweetSpot% (cached)\n"
            "  5. FanGraphs            — ISO, wOBA, K%, wRC+ (cached)\n"
            "  6. MLB API              — Confirmed lineups, batting order, schedule\n"

            "  8. PropLine             — Implied run totals fallback (when FL not available)\n"
            "  9. Open-Meteo           — Live weather fallback (when FL not available)\n"
            "\n"
            "SCORING FACTORS:\n"
            "  Batter Power     — Barrel%, HardHit%, ISO, EV, SweetSpot% vs league avg\n"
            "  Pitcher Vuln     — ERA, HR/9, Barrel% allowed, HardHit% allowed\n"
            "  Pitch Matchup    — L/R handedness split advantage\n"
            "  Park Factor      — HR-adjusted park factor (Coors=1.38, etc.)\n"
            "  Environment      — Temp, wind speed/direction, dome adjustment\n"
            "  Lineup Spot      — PA/game estimate from batting order position\n"
            "  Implied Runs     — Vegas-implied team run total boosts power hitters\n"
            "  Form Factor      — Recent vs season stat weighting (when in-season data available)\n"
            "\n"
            "OUTPUT:\n"
            "  Excel workbook with 4 tabs: Rankings, Detailed Stats, Pitchers, Game Context\n"
            "  Saved to: C:\\Users\\hlee145\\Documents\\FanDuel Spreadsheets\\HR Models\\"
        ),
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
COMMANDS:
  python mlb_hr_model.py                         Run today's slate (standard daily use)
  python mlb_hr_model.py --refresh-odds          Force fresh odds fetch (deletes today's OddsAPI/SGO cache)
  python mlb_hr_model.py --refresh-snapshot  -s  Rebuild odds baseline from current actionnetwork_hr_odds.csv
                                                  USE THIS: after re-downloading the CSV (e.g. at noon)
                                                  so line-move comparisons reflect fresh odds, not yesterday's
  python mlb_hr_model.py --refresh-weather   -w  Delete weather cache and re-fetch from FantasyLabs
                                                  USE THIS: after opening the FantasyLabs sheet to pick up
                                                  updated temp/wind/precip data
  python mlb_hr_model.py --date 2026-04-15       Score a historical slate by date
  python mlb_hr_model.py --date 04/15/2026       Alternate date format (MM/DD/YYYY)
  python mlb_hr_model.py --top 20                Show top 20 instead of default 15
  python mlb_hr_model.py --out my_picks.xlsx     Custom output filename

TYPICAL DAILY WORKFLOW:
  1. Morning run (before odds refresh):
     python mlb_hr_model.py
  2. After re-downloading actionnetwork_hr_odds.csv (e.g. at noon):
     python mlb_hr_model.py --refresh-snapshot
  3. After opening FantasyLabs to pick up updated weather:
     python mlb_hr_model.py --refresh-weather
  4. Full refresh (new CSV + weather + fresh odds):
     python mlb_hr_model.py --refresh-snapshot --refresh-weather --refresh-odds

COMBINING FLAGS:
  python mlb_hr_model.py --refresh-snapshot --refresh-weather
  python mlb_hr_model.py --refresh-odds --top 20
  python mlb_hr_model.py --date 2026-04-15 --top 20 --out apr15.xlsx

CACHING:
  Stat caches (Savant, FanGraphs, bullpen) live in .stat_cache/ and refresh every 4-24h.
  OddsAPI/SGO props are cached once lineups are confirmed (won't re-fetch same day).
  Weather cache refreshes every 3h automatically, or use --refresh-weather to force now.
  Odds snapshot: first run of the day saves baseline; use --refresh-snapshot to reset it.

BUILT-IN DATA SOURCES:
  FantasyLabs file : FantasyLabsMLB.xlsm  (must be open or saved in HR Models folder)
  SportsGameOdds   : api.sportsgameodds.com  (primary odds, 2500 tokens/month)
  OddsAPI          : api.the-odds-api.com    (fallback odds, ~240 credits/day)
  Baseball Savant  : baseballsavant.mlb.com  (Statcast metrics)
  FanGraphs        : fangraphs.com           (advanced batting stats)
  MLB API          : statsapi.mlb.com        (lineups, schedule)
"""
    )
    parser.add_argument(
        "--date", "-d",
        type=str, default=None,
        help="Date to model. Formats: YYYY-MM-DD, MM/DD/YYYY, MM-DD-YYYY (default: today)",
    )
    parser.add_argument(
        "--top", "-t",
        type=int, default=TOP_N,
        help=f"Number of top players to show (default: {TOP_N})",
    )
    parser.add_argument(
        "--out", "-o",
        type=str, default=None,
        help="Output Excel filename (default: hr_model_YYYY-MM-DD.xlsx)",
    )
    parser.add_argument(
        "--refresh-odds", "-r",
        action="store_true", default=False,
        help="Delete cached OddsAPI/SGO data and fetch fresh odds (use when HR odds show N/A)",
    )
    parser.add_argument(
        "--refresh-snapshot", "-s",
        action="store_true", default=False,
        help=(
            "Rebuild the ActionNetwork odds snapshot from the current CSV file\n"
            "  (C:\\Users\\hlee145\\Documents\\FanDuel Spreadsheets\\Data\\actionnetwork_hr_odds.csv)\n"
            "  Use this after re-downloading the CSV so line-move comparisons use fresh odds."
        ),
    )
    parser.add_argument(
        "--refresh-weather", "-w",
        action="store_true", default=False,
        help=(
            "Delete today's weather cache and force a fresh fetch from FantasyLabs/Open-Meteo.\n"
            "  Use this after opening the FantasyLabs sheet to pick up updated temp/wind/precip."
        ),
    )
    parser.add_argument(
        "--refresh-stats",
        action="store_true", default=False,
        help=(
            "Delete pitcher + batter stat caches and re-fetch fresh Statcast/FanGraphs data.\n"
            "  Forces the Statcast pitcher agg, arsenal splits, and batter Savant stats\n"
            "  to be re-fetched rather than loaded from .stat_cache/.\n"
            "  Use when stats seem stale or after a mid-day Savant update."
        ),
    )
    args = parser.parse_args()

    _pre6am_shift = False
    if args.date is None:
        from datetime import datetime as _dt
        _now = _dt.now()
        # Before 6am: yesterday's slate is still the relevant one. DFS slates
        # lock during the day; if you're running at midnight or 1am you're almost
        # certainly still working the previous day's games, not tomorrow's.
        if _now.hour < 9:
            from datetime import timedelta as _td
            target = date.today() - _td(days=1)
            _pre6am_shift = True
            print(f"  🌙 Pre-6am run ({_now.strftime('%H:%M')}) — targeting yesterday's slate ({target}), live-data mode")
        else:
            target = date.today()
    else:
        raw = args.date.strip()
        target = None
        for fmt in ("%Y-%m-%d", "%m/%d/%Y", "%m-%d-%Y", "%Y/%m/%d"):
            try:
                target = datetime.strptime(raw, fmt).date()
                break
            except ValueError:
                continue
        if target is None:
            print(f"Could not parse date: {raw!r}")
            print("  Accepted formats: YYYY-MM-DD, MM/DD/YYYY, MM-DD-YYYY")
            sys.exit(1)

    # is_historical: True only when the user explicitly passed a past date via --date.
    # Pre-6am auto-shift to yesterday is NOT historical — we still want live odds,
    # live weather, and live PropLine data for the games that ran yesterday.
    is_historical = (target < date.today()) and not _pre6am_shift
    out_file = args.out if args.out else str(OUTPUT_DIR / f"hr_model_{target.strftime('%Y-%m-%d')}.xlsx")
    return target, is_historical, args.top, out_file, args.refresh_odds, args.refresh_snapshot, args.refresh_weather, args.refresh_stats


# Module-level travel caches (populated during each run)
_travel_schedule_cache: dict = {}   # {"{team}_{date}": home_team_abbr}
_game_travel_factors:   dict = {}   # {game_pk_str: {"home": f, "away": f}}


def main():
    global SEASON_YEAR, TOP_N, EXPORT_FILE, _UPSET_PROFILES

    target_date, is_historical, TOP_N, EXPORT_FILE, refresh_odds, refresh_snapshot, refresh_weather, refresh_stats = parse_args()
    if refresh_odds:
        _odds_cache = OUTPUT_DIR / ".stat_cache" / f"oddsapi_{target_date.isoformat()}.pkl"
        if _odds_cache.exists():
            _odds_cache.unlink()
            print(f"  🗑️  Deleted OddsAPI cache → fresh fetch will include SGO props")
        else:
            print(f"  ℹ️  No OddsAPI cache found for {target_date} — will fetch fresh")

    if refresh_snapshot:
        # Delete today's snapshot pkl so load_actionnetwork_hr_odds() rebuilds it
        # from the current CSV file (actionnetwork_hr_odds.csv).
        # The first run after --refresh-snapshot saves the current CSV odds as the new
        # baseline; subsequent runs compare live odds to that fresh baseline.
        _snap_path = OUTPUT_DIR / ".stat_cache" / f"actionnetwork_snapshot_{target_date.strftime('%Y-%m-%d')}.pkl"
        _csv_path  = Path(r"C:\Users\hlee145\Documents\FanDuel Spreadsheets\Data\actionnetwork_hr_odds.csv")
        if _snap_path.exists():
            _snap_path.unlink()
            print(f"  🗑️  Deleted odds snapshot → will rebuild baseline from current CSV")
        else:
            print(f"  ℹ️  No snapshot found for {target_date} — fresh baseline will be created")
        if not _csv_path.exists():
            print(f"  ⚠️  CSV not found at {_csv_path} — download from ActionNetwork first")
        else:
            import time as _time2
            age_min = (_time2.time() - _csv_path.stat().st_mtime) / 60
            print(f"  📄  CSV last modified: {age_min:.0f} min ago — this will be the new baseline")

    if refresh_weather:
        # Delete today's weather pkl so weather is re-fetched from FantasyLabs/Open-Meteo
        _wx_path = OUTPUT_DIR / ".stat_cache" / f"weather_{target_date.strftime('%Y-%m-%d')}.pkl"
        if _wx_path.exists():
            _wx_path.unlink()
            print(f"  🗑️  Deleted weather cache → will re-fetch from FantasyLabs on this run")
        else:
            print(f"  ℹ️  No weather cache found for {target_date} — will fetch fresh anyway")

    if refresh_stats:
        # Delete pitcher + batter stat caches so Statcast/FanGraphs is re-fetched
        # from scratch on this run. Clears: pitchers_YYYY.pkl, batters_YYYY.pkl
        # BZM cache (date-stamped) is intentionally left alone — it's expensive
        # to rebuild and doesn't contain the pitcher agg data.
        _cache_dir = OUTPUT_DIR / ".stat_cache"
        _deleted = []
        for _stat_type in ("pitchers", "batters"):
            _sp = _cache_dir / f"{_stat_type}_{target_date.year}.pkl"
            if _sp.exists():
                _sp.unlink()
                _deleted.append(f"{_stat_type}_{target_date.year}.pkl")
        if _deleted:
            print(f"  🗑️  Deleted stat caches: {', '.join(_deleted)}")
            print(f"      → Statcast pitcher agg, arsenal splits, and batter stats will"
                  f" all re-fetch fresh this run (takes ~60-90s)")
        else:
            print(f"  ℹ️  No stat caches found for {target_date.year} — will fetch fresh anyway")

    # SEASON_YEAR: use current season year.
    # Fall back to prior year ONLY if before April 1 (pre-season, no stats yet).
    today = date.today()
    if target_date.month < 4:
        SEASON_YEAR = target_date.year - 1
        print(f"  ℹ️  Pre-season ({target_date}) — using {SEASON_YEAR} stats")
    else:
        SEASON_YEAR = target_date.year

    # ── Rec #4: Load upset profiles (from mlb_hr_upset_builder.py) ───────────
    if not is_historical:
        _UPSET_PROFILES = load_upset_profiles()

    # ── Catcher framing (Statcast) ───────────────────────────────────────────
    global _CATCHER_FRAMING
    _CATCHER_FRAMING = fetch_catcher_framing(SEASON_YEAR)

    # ── ActionNetwork HR odds (PRIMARY source: FanDuel → Consensus) ───────────
    # Free data scraped by mlb_actionnetwork.py. Loaded before PropLine/SGO/OddsAPI.
    # The global _AN_HR_ODDS is referenced in build_batter() for each player.
    global _AN_HR_ODDS
    _AN_HR_ODDS = load_actionnetwork_hr_odds()

    mode = "HISTORICAL" if is_historical else "TODAY"

    sep = "=" * 62
    print(f"\n{sep}")
    print("  MLB HOME RUN MODEL -- Phase 2")
    print(f"  [{mode}]  {target_date.strftime('%A, %B %d, %Y')}")
    print(f"  {SIMULATIONS:,} simulations per player  |  Top {TOP_N}")
    if is_historical:
        print("  Historical mode: PropLine odds skipped | Weather from archive")
        print("  Season stats pulled for year: " + str(SEASON_YEAR))
    print(sep)

    # ── 1. MLB schedule ───────────────────────────────────────
    print("\n-- Lineups & Schedule --")
    mlb_games = fetch_mlb_schedule(target_date)
    if not mlb_games:
        print("No games found for that date.")
        if is_historical:
            print("  MLB API has data back to ~2012. Boxscore lineups available after ~2015.")
        sys.exit(1)

    # ── 2. Check for remaining unconfirmed lineups ─────────────
    unconfirmed = [g for g in mlb_games if not g["lineups_confirmed"]]
    if unconfirmed:
        still_missing = len(unconfirmed)
        if still_missing:
            print(f"  ℹ️  {still_missing} games without confirmed lineups — using projected batting order")

    # ── FantasyLabs: load as primary data source ─────────────────────────────
    fl_players: list = []
    fl_lookup:  dict = {"by_name": {}, "by_team": {}, "weather": {},
                        "implied": {}, "umpire": {}}
    rw_pitcher_props: dict = {"pitchers": {}, "batters": {}, "pitcher_norm": {}, "batter_norm": {}}
    fl_projections: dict = {"pitchers": {}, "batters": {}}
    if not is_historical:
        # Load FantasyLabs player data (always needed — isolated try block)
        try:
            fl_players = load_fantasylabs(FANTASYLABS_FILE)
            if fl_players:
                fl_lookup = fantasylabs_lookup(fl_players)
                print(f"  📋 FantasyLabs: {len(fl_players)} players, "
                      f"{len(fl_lookup['weather'])} teams weather, "
                      f"{len(fl_lookup['implied'])} teams implied runs")
        except Exception as e:
            print(f"  ⚠️  FantasyLabs load failed: {e}")

        # Load RotoWire props (isolated — failure must NOT prevent FL_Data loading)
        try:
            _rw_csv = str(OUTPUT_DIR / "mlb_daily_props.csv")
            import os as _os
            if not _os.path.exists(_rw_csv):
                _rw_csv = ""   # CSV not found — fall back to Excel RotoWire sheet
            rw_pitcher_props = load_rotowire_props(
                csv_path=_rw_csv,
                xlsx_path=FANTASYLABS_FILE
            )
        except Exception as e:
            print(f"  ⚠️  RotoWire props load failed: {e} — continuing without RW props")

        # Load FL_Data projections (isolated — must run even if RotoWire failed)
        try:
            fl_projections = load_fl_projections(FANTASYLABS_FILE)
        except Exception as e:
            print(f"  ⚠️  FL_Data projections load failed: {e}")
        try:
            daily_batter = load_daily_batter(FANTASYLABS_FILE)
        except Exception as e:
            print(f"  ⚠️  DailyBatter load failed: {e}")
            daily_batter = {}
        daily_pitch         = {}   # batter pitch-type wOBA/SLG by pitch
        daily_pitcher_pitch = {}   # pitcher arsenal usage% by pitch type
        try:
            daily_pitcher_pitch, daily_pitch = load_daily_pitch(FANTASYLABS_FILE)
        except Exception as e:
            print(f"  ⚠️  DailyPitch load failed: {e}")
            daily_pitch = {}; daily_pitcher_pitch = {}
        savant_data = {}
        try:
            savant_data = load_savant_sheet(FANTASYLABS_FILE)
        except Exception as e:
            print(f"  ⚠️  Savant sheet load failed: {e}")

    # ── Inject FL projected lineups for unconfirmed games ───────────────────
    if fl_players:
        print("\n-- Lineup Status --")
        mlb_games = inject_fl_lineups(mlb_games, fl_players, fl_lookup)
        confirmed  = sum(1 for g in mlb_games if g.get("lineup_status") == "confirmed")
        projected  = sum(1 for g in mlb_games if g.get("lineup_status") == "projected")
        missing    = sum(1 for g in mlb_games if g.get("lineup_status") == "missing")
        print(f"  ✅ Confirmed: {confirmed}  📋 Projected: {projected}  ⚠️  Missing: {missing}")

    # ── 3. PropLine odds (today/future only) ──────────────────
    print("\n-- Vegas / PropLine --")
    if is_historical:
        print("  Skipping PropLine -- historical dates have no live odds")
        propline_events = []
    else:
        # Skip PropLine events if FL already has implied runs for all games
        # (PropLine is only used for implied runs fallback and HR props;
        #  OddsAPI covers HR props, FL covers implied runs)
        if fl_players:
            print("  ⏭️  PropLine events skipped — FantasyLabs covers implied runs")
            propline_events = []
        else:
            propline_events = fetch_propline_events()

    # ── Odds & Player Props: ActionNetwork → RotoWire → SGO → OddsAPI ─────────
    # Priority 1: ActionNetwork HR odds (free, scraped daily)
    #   Loaded at startup into _AN_HR_ODDS global → injected in build_batter()
    # Priority 2: RotoWire (hits, TB, pitcher K/outs/ER)
    # Priority 3: SGO (HR odds for players NOT in ActionNetwork)
    # Priority 4: OddsAPI (gap-fill only)

    _an_hr  = globals().get("_AN_HR_ODDS", {})
    _an_n   = len(_an_hr)
    if _an_n > 0:
        base_msg = (f"  ✅ ActionNetwork (priority 1): {_an_n} HR odds loaded "
                    f"(FanDuel → Consensus) — 0 SGO/OddsAPI credits")
        if _AN_SNAPSHOT_INFO:
            base_msg += f"\n{_AN_SNAPSHOT_INFO}"
        print(base_msg)
    else:
        print("  ⚠️  ActionNetwork: no HR odds loaded — SGO will cover HR prices")

    _rw_pitchers   = rw_pitcher_props.get("pitchers", {})
    _rw_bat        = rw_pitcher_props.get("batters",  {})
    _rw_p_k        = sum(1 for v in _rw_pitchers.values() if "k_line"    in v)
    _rw_p_outs     = sum(1 for v in _rw_pitchers.values() if "outs_line" in v)
    _rw_p_er       = sum(1 for v in _rw_pitchers.values() if "er_line"   in v)
    _rw_b_hits     = sum(1 for v in _rw_bat.values()      if "hits_line" in v)
    _rw_b_tb       = sum(1 for v in _rw_bat.values()      if "tb_line"   in v)
    if _rw_pitchers or _rw_bat:
        print(f"  ✅ RotoWire (priority 2): "
              f"{len(_rw_pitchers)} pitchers ({_rw_p_k} K, {_rw_p_outs} outs, {_rw_p_er} ER lines) | "
              f"{len(_rw_bat)} batters ({_rw_b_hits} hits, {_rw_b_tb} TB lines) — 0 SGO credits")
    else:
        print("  ⚠️  RotoWire: no props loaded — SGO will cover all markets")
    _fl_p_count = len(fl_projections.get("pitchers", {}))
    _fl_b_count = len(fl_projections.get("batters",  {}))
    if _fl_p_count or _fl_b_count:
        _fl_ers = [v["fl_er"] for v in fl_projections.get("pitchers",{}).values() if v.get("fl_er",0) > 0]
        _fl_hrs = [v["fl_hr"] for v in fl_projections.get("batters", {}).values() if v.get("fl_hr",0) > 0]
        _er_rng = f"{min(_fl_ers):.2f}–{max(_fl_ers):.2f}" if _fl_ers else "—"
        _hr_rng = f"{min(_fl_hrs):.3f}–{max(_fl_hrs):.3f}" if _fl_hrs else "—"
        print(f"  ✅ FL_Data (pitcher vuln + batter HR blend): "
              f"{_fl_p_count} pitchers (ER {_er_rng}) | "
              f"{_fl_b_count} batters (HR proj {_hr_rng})")
    else:
        print("  ⚠️  FL_Data: not loaded — pitcher vuln and batter HR using 2025 Statcast only")

    # SGO: only needed if ActionNetwork didn't cover all HR prices
    # Determine how many FL players are missing from ActionNetwork. This mirrors the
    # real batter-side lookup (exact key → last-name fuzzy) so the count/list reflects
    # what will actually resolve, and prints the unmatched NAMES so a silent N/A on a
    # player who IS on the sheet is visible (vs a player simply absent from the sheet).
    _an_norm = set(_an_hr.keys())
    _an_lastnames = {k.split("_")[0] for k in _an_norm}
    def _norm_an_key(n):
        return _an_name_key(n)
    def _an_has(n):
        k = _norm_an_key(n)
        if k in _an_norm:
            return True
        ln = k.split("_")[0] if "_" in k else k
        return ln in _an_lastnames          # last-name fuzzy fallback, as in the lookup
    _fl_player_names_list = [p.get("player_name","") for p in fl_players if p.get("player_name")]
    _missing_from_an = [n for n in _fl_player_names_list if not _an_has(n)]
    _missing_count = len(_missing_from_an)
    if _an_n > 0 and _missing_count == 0:
        print(f"  📡 SGO (priority 3): gap-fill run — checking for unpriced batters")
    elif _an_n > 0:
        print(f"  📡 SGO (priority 3): {_missing_count} players not in ActionNetwork → gap-fill")
        if _missing_from_an:
            _show = ", ".join(_missing_from_an[:15]) + ("  …" if _missing_count > 15 else "")
            print(f"     ↳ no ActionNetwork match (name absent from sheet, or check spelling): {_show}")
        print(f"  📡 OddsAPI (priority 4): HR gap-fill only if SGO misses")
    else:
        print(f"  📡 SGO (priority 3): HR anytime odds — ActionNetwork not loaded, SGO covers all")
        print(f"  📡 OddsAPI (priority 4): HR gap-fill only — credit usage depends on SGO coverage")

    oddsapi_games = {}
    oddsapi_props = {}
    oddsapi_pitcher_props = {}
    # Never fully skip SGO — always gap-fill players missing from ActionNetwork.
    # SGO is free for the gap-fill call (only fetches missing players).
    # _an_covers_all = True only when ActionNetwork has literally every player
    # AND there are zero missing. This prevents N/A odds for unpriced batters.
    _an_covers_all = False  # always run SGO gap-fill

    if is_historical:
        print("  ✅ Historical run: using ActionNetwork sheet odds — SGO/OddsAPI skipped")
    elif _an_covers_all:
        pass   # already printed "SKIPPED" above
    else:
        _all_confirmed = all(g.get("lineups_confirmed") for g in mlb_games)
        oddsapi_raw = {}
        fl_has_implied = bool(fl_lookup.get("implied"))

        # ── SGO cache: load once per day, skip fetch if already cached ────────
        _sgo_cached = _load_sgo_cache(target_date) if not is_historical else {}
        if _sgo_cached:
            # Use cached SGO data — skip the full fetch entirely
            oddsapi_games         = _sgo_cached.get("games", {})
            oddsapi_props         = _sgo_cached.get("props", {})
            oddsapi_pitcher_props = _sgo_cached.get("pitcher_props", {})
        else:
            try:
                _fl_names_for_props = set()
                for _flp in fl_players:
                    _pname = _flp.get("player_name", "")
                    if _pname:
                        _fl_names_for_props.add(_pname)
                oddsapi_raw = fetch_oddsapi_mlb(target_date=target_date,
                                                lineups_confirmed=_all_confirmed,
                                                skip_game_odds=fl_has_implied,
                                                fl_player_names=_fl_names_for_props or None)
            except Exception as e:
                if fl_has_implied:
                    print(f"  ⚠️  OddsAPI player props failed: {e} — props will default to PropLine/none")
                    oddsapi_raw = {"games": {}, "props": {}, "pitcher_props": {}}
                else:
                    print(f"  ⚠️  Odds API failed: {e} — trying ESPN fallback...")
                    try:
                        oddsapi_raw = {"games": fetch_espn_mlb_odds(), "props": {}, "pitcher_props": {}}
                    except Exception as e2:
                        print(f"  ⚠️  ESPN fallback failed: {e2} — using 4.5 defaults")
            oddsapi_games         = oddsapi_raw.get("games", {})
            oddsapi_props         = oddsapi_raw.get("props", {})
            oddsapi_pitcher_props = oddsapi_raw.get("pitcher_props", {})
            # Save to cache so subsequent runs skip SGO entirely
            if oddsapi_props or oddsapi_pitcher_props:
                _save_sgo_cache(target_date, {
                    "games":         oddsapi_games,
                    "props":         oddsapi_props,
                    "pitcher_props": oddsapi_pitcher_props,
                })

    # ── 4. Weather ────────────────────────────────────────────
    archive_note = " (historical archive)" if is_historical else ""
    print(f"\n-- Weather{archive_note} --")
    game_contexts = []
    game_propline_data = {}


    # ── Weather cache: disk cache first, then FL, then Open-Meteo ───────────
    weather_day_cache: dict = {}
    if not is_historical:
        # Priority 1: disk cache (fastest — skips all API/FL processing)
        disk_weather = _load_weather_cache(target_date)
        if disk_weather:
            weather_day_cache = disk_weather
            # Merge FL weather: add new teams AND override stale entries
            # when FL shows significant precip (>20%) or large temp delta (>5F)
            if fl_lookup["weather"]:
                added = updated = 0
                for team, wx in fl_lookup["weather"].items():
                    _prec = wx.get("precip_pct", 0.0)
                    _hum  = wx.get("humidity", 0.50)
                    cached = weather_day_cache.get(team, {})
                    temp_delta = abs(wx["temp_f"] - cached.get("temp_f", wx["temp_f"]))
                    precip_jump = _prec > 20 and cached.get("precip_pct", 0.0) < 20
                    # Override if: new team, OR FL shows rain that cache doesn't, OR big temp shift
                    if team not in weather_day_cache or precip_jump or temp_delta > 5:
                        _ra, _ba = compute_weather_adjs(
                            wx["temp_f"], wx["wind_speed"], wx["wind_out"],
                            _hum, _prec)
                        weather_day_cache[team] = {
                            "temp_f": wx["temp_f"], "wind_speed": wx["wind_speed"],
                            "wind_out": wx["wind_out"], "dome": False,
                            "humidity": _hum, "precip_pct": _prec,
                            "condition": "Precip" if _prec > 20 else "Clear",
                            "run_adj": _ra, "bso_adj": _ba, "source": "FantasyLabs",
                        }
                        if team not in disk_weather: added += 1
                        else: updated += 1
                if added or updated:
                    print(f"  🌤️  FL weather: +{added} new, {updated} updated (precip/temp shift)")
        elif fl_lookup["weather"]:
            # Priority 2: FL data (no disk cache yet — build from FL)
            for team, wx in fl_lookup["weather"].items():
                _ra, _ba = compute_weather_adjs(
                    wx["temp_f"], wx["wind_speed"], wx["wind_out"],
                    wx.get("humidity", 0.50), wx.get("precip_pct", 0.0))
                _prec = wx.get("precip_pct", 0.0)
                _hum  = wx.get("humidity", 0.50)
                weather_day_cache[team] = {
                    "temp_f": wx["temp_f"], "wind_speed": wx["wind_speed"],
                    "wind_out": wx["wind_out"], "dome": False,
                    "humidity": _hum, "precip_pct": _prec,
                    "condition": "Precip" if _prec > 20 else "Clear",
                    "run_adj": _ra, "bso_adj": _ba, "source": "FantasyLabs",
                }
            print(f"  🌤️  Weather from FantasyLabs ({len(weather_day_cache)} teams) — will save to disk")
        # else: empty dict → Open-Meteo called per game, then saved

    # ── baseballwx for weather run adjustments (supplemental) ─────────────────
    bwx_cache = {}
    if not is_historical and not weather_day_cache:
        # Only fetch baseballwx if we need fresh weather (cache miss)
        print("  📡 baseballwx.com: fetching game weather + run adjustments...")
        try:
            bwx_cache = fetch_baseballwx()
        except Exception as e:
            print(f"  ⚠️  baseballwx failed: {e}")

    for gm in mlb_games:
        home = gm["home_team"]
        away = gm["away_team"]
        sd   = STADIUMS.get(home, STADIUMS["LAD"])
        sname, lat, lon, dome, alt, park_l, park_r, park_o = sd

        weather = fetch_weather(lat, lon, gm["commence_time"], dome, home,
                                away, bwx_cache, target_date=target_date,
                                weather_day_cache=weather_day_cache)
        # If weather source is baseballwx but run_adj is 0 (failed parse),
        # compute run_adj from the actual temp/wind data we do have.
        if weather.get("run_adj", 0.0) == 0.0 and not dome:
            _fl_wx = fl_lookup["weather"].get(home) or fl_lookup["weather"].get(away) or {}
            _hum  = _fl_wx.get("humidity", 0.50)
            _prec = _fl_wx.get("precip_pct", 0.0)
            _ra, _ba = compute_weather_adjs(
                weather["temp_f"], weather["wind_speed"], weather.get("wind_out", False),
                _hum, _prec)
            weather = dict(weather)   # copy to avoid mutating cache
            weather["run_adj"]  = _ra
            weather["bso_adj"]  = _ba if weather.get("bso_adj", 0.0) == 0.0 else weather["bso_adj"]

        # ── Build pl: start with Odds API, fall back to PropLine, then 4.5 ────
        pl = {"home_implied_runs": 4.5, "away_implied_runs": 4.5, "hr_props": {}}

        # ── Implied runs: FL primary → OddsAPI fallback ─────────────────────
        odds_key = (away, home)
        fl_home = fl_lookup["implied"].get(home, {})
        fl_away = fl_lookup["implied"].get(away, {})
        _impl_source = "default"
        if fl_home and fl_away:
            pl["home_implied_runs"] = fl_home.get("own", 4.5)
            pl["away_implied_runs"] = fl_away.get("own", 4.5)
            total_fl = pl["home_implied_runs"] + pl["away_implied_runs"]
            # Plausibility cap removed (Jun 2026, per user): FantasyLabs implied runs are
            # actual Vegas-derived totals and are trusted as-is — including legitimately
            # high run environments like Coors (CHC@COL ~12.8). No fallback to 4.5/4.5.
            _impl_source = "FL"
        elif odds_key in oddsapi_games:
            od = oddsapi_games[odds_key]
            pl["home_implied_runs"] = od["home_implied"]
            pl["away_implied_runs"] = od["away_implied"]
            _impl_source = "OddsAPI"
        elif not is_historical:
            _impl_source = "PropLine"
            ev_id = match_propline_event(gm, propline_events)
            if ev_id:
                pl_raw = fetch_propline_game_data(ev_id)
                # Only use PropLine totals if they pass sanity check
                hi = pl_raw.get("home_implied_runs", 4.5)
                ai = pl_raw.get("away_implied_runs", 4.5)
                total_check = hi + ai
                # Plausibility cap removed (Jun 2026) — trust the PropLine implied total as-is.
                # Only discard if missing/non-positive (a parse failure, not real data).
                if total_check > 0:
                    pl = pl_raw
                else:
                    # No usable total — keep hr_props but discard totals
                    pl["hr_props"] = pl_raw.get("hr_props", {})
            # else: stay at 4.5 default

        # Merge HR props from PropLine if Odds API was primary
        if odds_key in oddsapi_games and not is_historical:
            ev_id = match_propline_event(gm, propline_events)
            if ev_id:
                pl_raw = fetch_propline_game_data(ev_id)
                pl["hr_props"] = pl_raw.get("hr_props", {})

        game_propline_data[gm["game_pk"]] = pl

        # Fix #13: fetch umpire factor for this game
        # Umpire: FL primary → UmpScorecards fallback
        if home in fl_lookup["umpire"]:
            ump_factor = fl_lookup["umpire"][home]
        elif not is_historical:
            ump_factor = get_umpire_factor(home, target_date)
        else:
            ump_factor = 1.0

        ctx = GameContext(
            game_id=str(gm["game_pk"]),
            home_team=home, away_team=gm["away_team"],
            ballpark=sname,
            park_hr_factor=park_o, park_hr_factor_l=park_l, park_hr_factor_r=park_r,
            altitude_ft=alt, dome=dome,
            temp_f=weather["temp_f"], wind_speed=weather["wind_speed"],
            humidity=weather.get("humidity", 0.50),
            precip_pct=weather.get("precip_pct", 0.0),
            wind_out=weather["wind_out"], wind_dir_deg=weather.get("wind_dir_deg", 270.0),
            condition=weather["condition"],
            home_implied_runs=pl["home_implied_runs"],
            away_implied_runs=pl["away_implied_runs"],
            weather_run_adj=weather.get("run_adj", 0.0),
            weather_bso_adj=weather.get("bso_adj", 0.0),
            weather_source=weather.get("source", "default"),
            odds_source=_impl_source,
            umpire_factor=ump_factor,
            travel_factor=1.0,   # overridden per-player in scoring loop below
            game_time_str=format_game_time(gm["commence_time"]),
            catcher_framing_runs=0.0,  # populated below from _CATCHER_FRAMING
        )
        # Inject catcher framing for this game's defensive catcher (opponent team's catcher)
        # home_catcher_framing = framing of HOME team's catcher (affects AWAY batters)
        # away_catcher_framing = framing of AWAY team's catcher (affects HOME batters)
        if _CATCHER_FRAMING:
            _home_framing = _CATCHER_FRAMING.get(home.upper(), 0.0)
            _away_framing = _CATCHER_FRAMING.get(gm.get("away_team","").upper(), 0.0)
            ctx.home_catcher_framing = _home_framing
            ctx.away_catcher_framing = _away_framing
            # catcher_framing_runs on the context = framing faced by home batters
            # (home batters face away catcher; away batters face home catcher)
            # This gets overridden per-batter in the scoring loop
            ctx.catcher_framing_runs = _away_framing  # default for home batters
        game_contexts.append(ctx)

        # Tier 3: record where each team played today for tomorrow's travel calc
        _travel_schedule_cache[f"{home}_{target_date.isoformat()}"] = home
        _travel_schedule_cache[f"{gm['away_team']}_{target_date.isoformat()}"] = home
        # Compute travel factors now (yesterday's entry in cache may be from prior run)
        _game_travel_factors[str(gm["game_pk"])] = {
            "home": compute_travel_factor(home, target_date, _travel_schedule_cache),
            "away": compute_travel_factor(gm["away_team"], target_date, _travel_schedule_cache),
        }

        wind_tag = "→out" if weather["wind_out"] else ""
        # Show odds source in output
        _fl_implied_home = fl_lookup.get("implied", {}).get(gm["home_team"], {}).get("own")
        _odds_src = ("FantasyLabs" if _fl_implied_home is not None else
                     "OddsAPI"     if (gm["away_team"], gm["home_team"]) in oddsapi_games else
                     "PropLine"    if pl["home_implied_runs"] != 4.5 else "default")
        if is_historical:
            _odds_src = "historical"
        odds_tag = f"O/U {pl['home_implied_runs']:.1f}/{pl['away_implied_runs']:.1f} [{_odds_src}]"
        run_adj_tag = ""
        if weather.get("run_adj", 0.0) != 0.0:
            run_adj_tag = f"  runs {weather['run_adj']*100:+.1f}%"
        src_tag = f"[{weather.get('source','')}]" if weather.get("source") not in ("baseballwx","dome") else ""
        _prec = weather.get("precip_pct", 0.0)
        _hum  = weather.get("humidity", 0.50)
        _prec_tag = f"  ☔{_prec:.0f}%rain" if _prec > 20 else ""
        _hum_tag  = f"  💧{_hum*100:.0f}%hum" if _hum > 0.75 else ""
        print(f"  {gm['away_team']:3s} @ {home:3s}  "
              f"{weather['temp_f']:.0f}F  wind {weather['wind_speed']:.0f}mph {wind_tag}  "
              f"{odds_tag}{run_adj_tag}{_prec_tag}{_hum_tag} {src_tag}")

    # Save weather to disk for future runs (works even when sourced from FL)
    if not is_historical and weather_day_cache:
        _save_weather_cache(target_date, weather_day_cache)
        print(f"  ✅ Weather cache: {len(weather_day_cache)} teams saved → {_weather_cache_path(target_date).name}")

    # ── 5. Season stats ───────────────────────────────────────
    print(f"\n-- Season Stats ({SEASON_YEAR}) --")
    batter_stats_map, pitcher_stats_map = fetch_season_stats(SEASON_YEAR, target_date)
    # Only fetch recent form if we are using the current season's stats
    if SEASON_YEAR == target_date.year:
        recent_form_map, _bzm_p_zones, _bzm_b_zones, \
            _PITCHER_L3_BY_HAND, _PITCHER_PITCH_VS_HAND = \
            fetch_recent_form(SEASON_YEAR)
        # HYBRID BZM APPROACH:
        #   Pitchers  → season data (stable zone tendencies; needs 50+ pitches per group)
        #   Batters   → L14 data   (recent form matters; season regresses to mean too fast)
        #
        # Season pitcher zones: 75-day window gives reliable location patterns even for
        # less-used pitch types. Single recent starts can skew L14 pitcher zones badly.
        #
        # L14 batter zones: a batter who squared up a fastball in zone 5 three times in
        # the last two weeks is the BZM target — not their full-season average. Cold bats
        # often get CONFIRMED MATCH picks precisely because the market undervalues their
        # historical pitch-type skill; season zone xwOBA regresses that signal away.
        _s_p_zones, _s_b_zones, _s_l10_bbe, _s_bvp = _fetch_season_bzm_zones(SEASON_YEAR, target_date)
        if _s_p_zones:   # season wins for BOTH pitchers and batters
            _bzm_p_zones = _s_p_zones
            # Season batter zones: 200-400+ contact events per batter vs L14's ~10-20.
            # More zones per pitch type qualify → 2-3 BZM matches per slate instead of always-1.
            if _s_b_zones:
                _bzm_b_zones = _s_b_zones
            print(f"  🎯 BZM full-season: pitcher zones ({len(_s_p_zones)}) + "
                  f"batter zones ({len(_bzm_b_zones)})")
        # Populate module-level caches used by _compute_bzm() in score_batter()
        _BZM_PITCHER_ZONES.update(_bzm_p_zones)
        _BZM_BATTER_ZONES.update(_bzm_b_zones)
        # L10 BBE now comes from season df (full season → guaranteed ≥10 BBE per
        # batter per pitch type). Replaces the 14-day version which was too short.
        if _s_l10_bbe:
            globals()["_L10_BBE_BY_PITCH"] = _s_l10_bbe
            # Extract id→key reverse map stored under reserved key during BZM compute
            _id_to_key_map = _s_l10_bbe.get("__ID_TO_KEY__", {})
            if isinstance(_id_to_key_map, dict):
                globals()["_L10_BBE_ID_TO_KEY"] = _id_to_key_map
        else:
            globals()["_L10_BBE_BY_PITCH"] = _L10_BBE_BY_PITCH  # fallback to L14
        # Pitcher-specific BBE dict (batter × pitcher × pitch_type)
        if _s_bvp:
            globals()["_BBE_VS_PITCHER"] = _s_bvp

        globals()["_PITCHER_L3_BY_HAND"]    = _PITCHER_L3_BY_HAND
        globals()["_PITCHER_PITCH_VS_HAND"] = _PITCHER_PITCH_VS_HAND
    else:
        print("  Skipping recent form -- season year mismatch")
        recent_form_map = {}

    # Statcast keys recent_form_map by "Last, First" (e.g. "Schwarber, Kyle") while
    # the slate uses "First Last". Build a normalized index so the lookup actually
    # matches — without it, every batter falls back to season form and the L14
    # distance / recent-barrel signals (carry, 3-of-5) never fire. Strips accents
    # and suffixes too (matches the FL/RW/AN lookup style).
    import unicodedata as _ud_rf, re as _re_rf
    def _rf_norm(s):
        s = str(s)
        if "," in s:                                    # "Last, First" → "First Last"
            _parts = [p.strip() for p in s.split(",", 1)]
            if len(_parts) == 2 and _parts[1]:
                s = _parts[1] + " " + _parts[0]
        s = _ud_rf.normalize("NFKD", s).encode("ascii", "ignore").decode().lower().strip()
        s = _re_rf.sub(r"\s+(jr|sr|ii|iii|iv)\.?$", "", s)   # strip generational suffix
        s = _re_rf.sub(r"[^a-z ]", "", s)
        return _re_rf.sub(r"\s+", " ", s).strip()
    recent_form_norm = {}
    for _rk, _rv in recent_form_map.items():
        recent_form_norm.setdefault(_rf_norm(_rk), _rv)
    # Last-name + first-initial fallback for abbreviated slate names ("F. Tatis",
    # "Y. Alvarez" from FantasyLabs projected lineups). Only kept when unique, to
    # avoid same-last-name collisions.
    def _rf_li(s):
        _t = _rf_norm(s).split()
        return (_t[-1] + " " + _t[0][0]) if len(_t) >= 2 and _t[0] else ""
    _li_count = {}
    for _nk in recent_form_norm:
        _li = _rf_li(_nk)
        if _li:
            _li_count[_li] = _li_count.get(_li, 0) + 1
    recent_form_li = {}
    for _nk, _rv in recent_form_norm.items():
        _li = _rf_li(_nk)
        if _li and _li_count.get(_li) == 1:
            recent_form_li[_li] = _rv
    if recent_form_map:
        _rf_matchable = sum(1 for _k in recent_form_norm if _k)
        print(f"  🔑 Recent-form name index: {_rf_matchable} normalized keys "
              f"(+{len(recent_form_li)} last-initial) — fixes Last,First vs First Last matching")

    # Fix #6: Auto-fetch bullpen stats (replaces manual BULLPENS when empty)
    print("\n-- Bullpen Stats (auto) --")
    auto_bullpens = fetch_bullpen_stats(SEASON_YEAR)
    merged_bullpens = {**auto_bullpens, **BULLPENS}
    if auto_bullpens:
        print(f"  Bullpen data loaded for {len(auto_bullpens)} teams" +
              (f" | manual overrides: {list(BULLPENS.keys())}" if BULLPENS else ""))
    else:
        print("  ⚠️  Auto bullpen fetch failed -- using manual BULLPENS dict")
        merged_bullpens = BULLPENS

    # ── Bullpen rolling fatigue (last 3 days) — MLB Stats API, no credits ──────
    print("  Fetching bullpen fatigue (last 3 days)...")
    try:
        _fatigue_data = fetch_bullpen_fatigue_3d(target_date=target_date)
        _tired_teams  = []
        for _abbr, _fd in _fatigue_data.items():
            if _abbr in merged_bullpens:
                merged_bullpens[_abbr].recent_ip_3d = _fd["ip_3d"]
                merged_bullpens[_abbr].fatigue_mult  = _fd["fatigue_mult"]
                if _fd["fatigue_mult"] >= 1.12:
                    _tired_teams.append(f"{_abbr}({_fd['ip_3d']:.0f}IP/{_fd['fatigue_mult']:.2f}x)")
        if _tired_teams:
            print(f"  ⚠️  Tired bullpens (high 3d workload): {', '.join(_tired_teams)}")
        else:
            print(f"  ✅ Bullpen fatigue loaded for {len(_fatigue_data)} teams — no tired bullpens (all below fatigue threshold)")
    except Exception as _fe:
        print(f"  ⚠️  Bullpen fatigue fetch failed: {_fe} — using season averages")

        # ── 6. Score ──────────────────────────────────────────────
    print("\n-- Scoring --")
    ctx_by_id     = {c.game_id: c for c in game_contexts}
    pitcher_cache = {}
    all_scores    = []
    batter_obj_cache: dict = {}  # name → BatterProfile, for batch k_vs_opp lookup

    # First pass: count total players to score (for progress bar)
    total_players = 0
    for gm in mlb_games:
        if not gm["lineups_confirmed"]:
            continue
        ctx = ctx_by_id.get(str(gm["game_pk"]))
        if not ctx:
            continue
        for lineup, is_home, opp_pitcher_name in [
            (gm["home_lineup"], True,  gm["away_pitcher"]),
            (gm["away_lineup"], False, gm["home_pitcher"]),
        ]:
            if not opp_pitcher_name:
                continue
            for lineup_entry in lineup:
                if len(lineup_entry) >= 5:
                    bname, pos, order, bat_side, _ = lineup_entry[:5]
                elif len(lineup_entry) == 4:
                    bname, pos, order, bat_side = lineup_entry
                else:
                    bname, pos, order = lineup_entry[:3]
                if not bname or pos in ("P", "SP", "RP"):
                    continue
                if PLAYERS_TO_SCORE and bname not in PLAYERS_TO_SCORE:
                    continue
                total_players += 1

    # ── Pitcher discipline stats (CSW%, O-Swing%, Z-Contact%, SIERA) ─────────
    # Implements video's workflow: efficiency → batted ball quality → outcomes.
    # Fetched once at startup; applied to pitcher objects when they're built.
    _disc_data = {}
    try:
        print("  📡 Pitcher discipline: fetching CSW%, O-Swing%, Z-Contact%, SIERA...")
        _disc_data = fetch_pitcher_discipline(SEASON_YEAR)
    except Exception as _de:
        print(f"  ⚠️  Pitcher discipline fetch failed: {_de}")

    # ── Pitcher L5 starts: three-window recency blend ─────────────────────────
    # Fetch last-5-start ERA/K9/HR9/BB9 for today's starters via MLB game log.
    # Implements video rec: L5 starts + season + prior season blend.
    # IDs were stored in mlb_games during schedule fetch (home_pitcher_id / away_pitcher_id).
    _pitcher_id_map_l5 = {}
    for _gm_l5 in mlb_games:
        for _side_l5 in ("home", "away"):
            _pname_l5 = _gm_l5.get(f"{_side_l5}_pitcher", "")
            _pid_l5   = int(_gm_l5.get(f"{_side_l5}_pitcher_id", 0) or 0)
            if _pname_l5 and _pid_l5:
                _pitcher_id_map_l5[_pname_l5] = _pid_l5
    _l5_data = {}
    if _pitcher_id_map_l5:
        print(f"  📡 Pitcher L5 starts: fetching for {len(_pitcher_id_map_l5)} starters...")
        try:
            _l5_data = fetch_pitcher_l5_starts(_pitcher_id_map_l5, season=SEASON_YEAR)
            _l5_tired   = [n for n, d in _l5_data.items() if d["recent_hr_factor"] >= 1.15]
            _l5_sharp2  = [n for n, d in _l5_data.items() if d["recent_hr_factor"] <= 0.85]
            _l5_extreme = [n for n, d in _l5_data.items()
                           if d.get("l2_hr9", 0) >= 3.0
                           and (d.get("l2_hr9", 0) - d.get("l5_hr9", 0)) >= 2.0]
            print(f"  ✅ Pitcher L5: {len(_l5_data)} loaded"
                  + (f" | 💥 Extreme L2: {', '.join(_l5_extreme[:3])}" if _l5_extreme else "")
                  + (f" | HR-prone: {', '.join(_l5_tired[:3])}" if _l5_tired else "")
                  + (f" | Suppressing: {', '.join(_l5_sharp2[:3])}" if _l5_sharp2 else ""))
        except Exception as _l5e:
            print(f"  ⚠️  Pitcher L5 fetch failed: {_l5e} — using season averages")

    print(f"  Simulating {total_players} player-game outcomes...")
    # Initialize progress bar
    pbar = tqdm(total=total_players, desc="  Scoring", unit="player",
                bar_format="{l_bar}{bar}| {n_fmt}/{total_fmt} [{elapsed}<{remaining}]")
    if not TQDM_AVAILABLE:
        print("  (Install tqdm for a progress bar: pip install tqdm)")

    for gm in mlb_games:
        if not gm["lineups_confirmed"]:
            print(f"  Skipping {gm['away_team']} @ {gm['home_team']} -- lineups pending")
            continue

        ctx = ctx_by_id.get(str(gm["game_pk"]))
        if not ctx:
            continue

        # Merge player props: OddsAPI (primary) + PropLine (supplement for missing players)
        # Keys stored lowercase for case-insensitive matching in build_batter
        propline_hr = game_propline_data.get(gm["game_pk"], {}).get("hr_props", {})
        hr_props = {}
        for _k, _v in propline_hr.items():
            hr_props[_k.lower().strip()] = _v
        for pname, pdata in oddsapi_props.items():
            # Handle both key formats: our pipeline uses "hr_over_price",
            # but cached data from older/alternate code may use "over_price"
            if "hr_over_price" in pdata:
                hr_props[pname.lower().strip()] = {
                    "over_price": pdata["hr_over_price"],
                    "point":      pdata.get("hr_line", 0.5),
                }
            elif "over_price" in pdata:
                hr_props[pname.lower().strip()] = {
                    "over_price": pdata["over_price"],
                    "point":      pdata.get("point", 0.5),
                }
        _batter_extra_props = oddsapi_props

        for pname, phand, pteam in [
            (gm["home_pitcher"], gm["home_pitcher_hand"], gm["home_team"]),
            (gm["away_pitcher"], gm["away_pitcher_hand"], gm["away_team"]),
        ]:
            if not pname or pname in pitcher_cache:
                continue
            # FL pitcher hand override (same as before)
            for _fl_p in fl_lookup.get("by_team", {}).get(pteam, []):
                _fl_pn = _fl_p.get("pitcher_name", "").strip()
                _fl_pn_last = _fl_pn.split()[-1].lower() if _fl_pn else ""
                _pname_last = pname.strip().split()[-1].lower() if pname and pname.strip() else ""
                if _fl_pn_last and _pname_last and _fl_pn_last == _pname_last:
                    if _fl_p.get("pitcher_hand") in ("L", "R"):
                        phand = _fl_p["pitcher_hand"]
                    break
            ov = PITCHER_OVERRIDES.get(pname, {})
            # 3-tier pitcher lookup: exact → accent-normalized → last-name
            # Handles accents (Vásquez→Vasquez), rookies not in 2025 stats, etc.
            import unicodedata as _ud2
            def _norm_p(s):
                return _ud2.normalize("NFKD", s).encode("ascii","ignore").decode().lower().strip()
            _p_row = pitcher_stats_map.get(pname)
            if _p_row is None:
                # Tier 2: accent-normalized match
                _pn_norm = _norm_p(pname)
                for _k, _v in pitcher_stats_map.items():
                    if _norm_p(_k) == _pn_norm:
                        _p_row = _v; break
            if _p_row is None:
                # Tier 3: last-name match (handles middle initials, suffixes)
                _pn_last = _norm_p(pname.split()[-1]) if pname and pname.strip() else ""
                if _pn_last and len(_pn_last) > 3:   # avoid short last names matching wrong pitcher
                    for _k, _v in pitcher_stats_map.items():
                        if _norm_p(_k.split()[-1] if _k.strip() else "") == _pn_last:
                            _p_row = _v; break
            if _p_row is not None:
                pitcher_cache[pname] = build_pitcher(pname, _p_row, phand, pteam, ov)
            else:
                pitcher_cache[pname] = build_pitcher_default(pname, phand, pteam, ov)

            # ── Apply discipline data (CSW%, O-Swing%, Z-Contact%, SIERA) ────
            if _disc_data and pname in _disc_data:
                _dc = _disc_data[pname]
                _p  = pitcher_cache[pname]
                if _dc.get("csw_pct",      0) > 0: _p.csw_pct      = _dc["csw_pct"]
                if _dc.get("o_swing_pct",  0) > 0: _p.o_swing_pct  = _dc["o_swing_pct"]
                if _dc.get("z_contact_pct",0) > 0: _p.z_contact_pct = _dc["z_contact_pct"]
                if _dc.get("foul_pct",     0) > 0: _p.foul_pct     = _dc["foul_pct"]
                if _dc.get("siera",        0) > 0: _p.siera        = _dc["siera"]
                # ERA composite: average of available estimators
                _avail = [v for v in [_p.fip if _p.fip != 4.20 else 0,
                                      _p.xfip if _p.xfip != 4.20 else 0,
                                      _p.siera] if v > 0]
                if _avail:
                    _p.era_composite = sum(_avail) / len(_avail)
            else:
                # Compute ERA composite from what's already loaded (no discipline data)
                _p2 = pitcher_cache.get(pname)
                if _p2:
                    _avail2 = [v for v in [_p2.fip  if _p2.fip  != 4.20 else 0,
                                           _p2.xfip if _p2.xfip != 4.20 else 0] if v > 0]
                    if _avail2:
                        _p2.era_composite = sum(_avail2) / len(_avail2)

            # ── Apply L5 start data to pitcher as soon as it's built ──────────
            if _l5_data and pname in _l5_data:
                _l5e = _l5_data[pname]
                _p = pitcher_cache[pname]
                _p.l5_era  = _l5e["l5_era"]
                _p.l5_k9   = _l5e["l5_k9"]
                _p.l5_hr9  = _l5e["l5_hr9"]
                _p.l5_bb9  = _l5e["l5_bb9"]
                _p.l5_ip   = _l5e["l5_ip"]
                _p.l2_hr9  = _l5e.get("l2_hr9", 0.0)
                _p.l2_ip   = _l5e.get("l2_ip",  0.0)
                _p.first_start_of_season = bool(_l5e.get("first_start_of_season", False))
                if _p.recent_hr_factor == 1.0:   # don't overwrite PITCHER_OVERRIDES
                    _p.recent_hr_factor = _l5e["recent_hr_factor"]

            # ── Inject FL_Data projections into pitcher (highest priority) ─────
            # FL projected ER/K/H/IP have 2x the signal variance vs RotoWire lines.
            # Overwrite prop fields so pitcher_vuln_score and K-suppressor use them.
            _fl_p_data = None
            _fl_pitchers = fl_projections.get("pitchers", {}) if "fl_projections" in dir() else {}
            if _fl_pitchers:
                import unicodedata as _ud4, re as _re4
                def _fl_pn(s):
                    return _re4.sub(r"[^a-z ]",
                        "", _ud4.normalize("NFKD", str(s)).encode("ascii","ignore").decode().lower().strip())
                def _fl_strip(s):
                    return _re4.sub(r"\s+(jr\.?|sr\.?|ii|iii|iv)\s*$", "",
                                    str(s).strip(), flags=_re4.IGNORECASE)
                _fl_pk = _fl_pn(_fl_strip(pname))
                _fl_p_data = _fl_pitchers.get(_fl_pk)
                if _fl_p_data is None:
                    _fl_last = _fl_pk.split()[-1] if _fl_pk.strip() else ""
                    if len(_fl_last) > 3:
                        for _fk, _fv in _fl_pitchers.items():
                            if _fk.split()[-1] == _fl_last:
                                _fl_p_data = _fv; break
            if _fl_p_data:
                pitcher = pitcher_cache[pname]
                fl_ip = _fl_p_data.get("fl_ip", 0)
                fl_er = _fl_p_data.get("fl_er", 0)
                fl_k  = _fl_p_data.get("fl_k",  0)
                fl_h  = _fl_p_data.get("fl_h",  0)
                pitcher._fl_ip = fl_ip   # store for short-start detection in scoring
                if fl_er > 0:
                    pitcher.prop_er_line   = fl_er        # replaces RW ER line
                if fl_ip > 0 and fl_k > 0:
                    pitcher.prop_outs_line = fl_ip * 3    # outs = IP * 3
                    pitcher.prop_k_line    = fl_k
                    pitcher.k9             = (fl_k / fl_ip) * 9
                if fl_h > 0:
                    pitcher.prop_hits_line = fl_h

        for lineup, is_home, opp_pitcher_name in [
            (gm["home_lineup"], True,  gm["away_pitcher"]),
            (gm["away_lineup"], False, gm["home_pitcher"]),
        ]:
            if not opp_pitcher_name:
                continue
            pitcher = pitcher_cache.get(opp_pitcher_name)
            if not pitcher:
                continue

            # ── Inject pitcher props: RotoWire (free) → OddsAPI → SGO ─────────
            def _pit_norm(s):
                import unicodedata
                return unicodedata.normalize("NFKD", s).encode("ascii","ignore").decode().lower().strip()

            # Priority 1: RotoWire props (free — from CSV or Excel sheet)
            _rw_props = None
            _rw_pitchers = rw_pitcher_props.get("pitchers", {}) if isinstance(rw_pitcher_props, dict) else {}
            _rw_pitch_norm = rw_pitcher_props.get("pitcher_norm", {}) if isinstance(rw_pitcher_props, dict) else {}
            if _rw_pitchers:
                _pit_norm_key = _pit_norm(opp_pitcher_name)
                if opp_pitcher_name in _rw_pitchers:
                    _rw_props = _rw_pitchers[opp_pitcher_name]
                elif _pit_norm_key in _rw_pitch_norm:
                    _rw_props = _rw_pitch_norm[_pit_norm_key][1]
                else:
                    _pit_last = _pit_norm(opp_pitcher_name.split()[-1]) if opp_pitcher_name.strip() else ""
                    for _nk, (_orig, _data) in _rw_pitch_norm.items():
                        if _pit_last and len(_pit_last) > 3 and _nk.split()[-1] == _pit_last:
                            _rw_props = _data; break
            if _rw_props:
                if "k_line"    in _rw_props: pitcher.prop_k_line    = _rw_props["k_line"]
                if "outs_line" in _rw_props: pitcher.prop_outs_line = _rw_props["outs_line"]
                if "er_line"   in _rw_props: pitcher.prop_er_line   = _rw_props["er_line"]
                if "hits_line" in _rw_props: pitcher.prop_hits_line = _rw_props["hits_line"]
                # RotoWire projection gives a more accurate K/9 estimate than back-calculating from line
                if "rw_k_proj" in _rw_props and _rw_props["rw_k_proj"] > 0:
                    _ip_est = pitcher.prop_outs_line / 3.0 if pitcher.prop_outs_line > 0 else 5.5
                    pitcher.k9 = _rw_props["rw_k_proj"] / max(_ip_est / 9.0, 0.1)
                _rw_source = "RotoWire"
            else:
                _rw_source = None

            # Priority 2: OddsAPI pitcher props (fills gaps RotoWire doesn't cover — ER, hits, missing pitchers)
            _pit_props = None
            if opp_pitcher_name in oddsapi_pitcher_props:
                _pit_props = oddsapi_pitcher_props[opp_pitcher_name]
            else:
                _pit_norm_name = _pit_norm(opp_pitcher_name)
                _pit_last = opp_pitcher_name.strip().split()[-1].lower() if opp_pitcher_name and opp_pitcher_name.strip() else ""
                for _pn, _pd in oddsapi_pitcher_props.items():
                    if _pit_norm(_pn) == _pit_norm_name:
                        _pit_props = _pd; break
                    if _pit_last and _pn and _pn.strip() and _pn.strip().split()[-1].lower() == _pit_last:
                        _pit_props = _pd; break
            if _pit_props:
                # Only fill fields RotoWire didn't provide
                if "k_line"    in _pit_props and pitcher.prop_k_line == 0:
                    pitcher.prop_k_line    = _pit_props["k_line"]
                if "outs_line" in _pit_props and pitcher.prop_outs_line == 0:
                    pitcher.prop_outs_line = _pit_props["outs_line"]
                if "er_line"   in _pit_props: pitcher.prop_er_line   = _pit_props["er_line"]
                if "hits_line" in _pit_props: pitcher.prop_hits_line = _pit_props["hits_line"]

            opp_team = gm["away_team"] if is_home else gm["home_team"]
            bullpen = merged_bullpens.get(opp_team)
            if bullpen:
                if pitcher.prop_outs_line > 0:
                    sp_ip = round(pitcher.prop_outs_line / 3.0, 1)
                    bullpen.expected_innings = max(1.0, min(9.0 - sp_ip, 6.0))
                else:
                    bullpen.expected_innings = 3.5
                if bullpen.expected_innings >= 4.5:
                    bullpen.hr9_allowed = min(bullpen.hr9_allowed * 1.08, 3.0)

            for lineup_entry in lineup:
                # Extract player info (same as before)
                if len(lineup_entry) >= 5:
                    bname, pos, order, bat_side, lineup_status = lineup_entry[:5]
                elif len(lineup_entry) == 4:
                    bname, pos, order, bat_side = lineup_entry
                    lineup_status = "confirmed"
                else:
                    bname, pos, order = lineup_entry[:3]
                    bat_side = ""
                    lineup_status = "confirmed"

                if not bname or pos in ("P", "SP", "RP"):
                    pbar.update(1)   # still count as processed (skipped)
                    continue
                if PLAYERS_TO_SCORE and bname not in PLAYERS_TO_SCORE:
                    pbar.update(1)
                    continue

                # Populate batter hand cache
                if bat_side in ("L", "R"):
                    _batter_hand_cache[bname] = bat_side
                elif bat_side == "S":
                    _batter_hand_cache[bname] = "S"

                ov = dict(BATTER_OVERRIDES.get(bname, {}))
                ov.setdefault("lineup_spot", order if order > 0 else 5)

                # FantasyLabs stat injection (same as before)
                _fl_entry = fl_lookup_name(fl_lookup["by_name"], bname)
                if _fl_entry:
                    if _fl_entry["lineup_spot"] > 0:
                        ov["lineup_spot"] = _fl_entry["lineup_spot"]
                    if _fl_entry["hand"] in ("L","R","S"):
                        if "hand" not in ov:
                            ov["hand"] = _fl_entry["hand"]
                            _batter_hand_cache[bname] = _fl_entry["hand"]
                    if _fl_entry["woba"] > 0:  ov["xwoba"] = _fl_entry["woba"]
                    if _fl_entry["iso"] > 0:   ov["iso"]   = _fl_entry["iso"]
                    if _fl_entry["slg"] > 0:   ov["xslg"]  = _fl_entry["slg"]
                    if _fl_entry["so_ab"] > 0:
                        ov["zone_contact_rate"] = max(0.55, min(0.78 * (0.22 / max(_fl_entry["so_ab"], 0.05)), 0.92))

                if bname in _batter_hand_cache and "hand" not in ov:
                    ov["hand"] = _batter_hand_cache[bname]

                recent_raw = recent_form_map.get(bname)
                if recent_raw is None:                       # name-format mismatch fallback
                    recent_raw = recent_form_norm.get(_rf_norm(bname))
                if recent_raw is None:                       # abbreviated name ("F. Tatis")
                    recent_raw = recent_form_li.get(_rf_li(bname))
                if recent_raw and len(recent_raw) >= 11:
                    recent = recent_raw
                elif recent_raw and len(recent_raw) >= 5:
                    recent = recent_raw[:5] + (87.5, 86.0, 85.5, 0.040, 0.025, 0.028)
                elif recent_raw and len(recent_raw) >= 2:
                    recent = (recent_raw[0], recent_raw[1], 36.5, 10.5, 0.22,
                              87.5, 86.0, 85.5, 0.040, 0.025, 0.028)
                else:
                    recent = None

                if bname in batter_stats_map:
                    b = build_batter(bname, batter_stats_map[bname], recent, ov, hr_props)
                else:
                    b = build_batter_default(bname, ov, hr_props)

                # ── Apply L10 BBE PropFinder stats to batter object ────────
                # batter_stats_map[bname] was enriched with l10_* keys during
                # the enrichment pipeline — copy onto the BatterProfile object
                # so _score_sharp() can read them via batter attributes.
                # NOTE: batter_stats_map values are pd.Series objects — use
                # .get() on the raw dict, not boolean evaluation, to avoid
                # "truth value of a Series is ambiguous" ValueError.
                _bsm_raw = batter_stats_map.get(bname)
                # Normalise: pd.Series → dict, None → {}
                try:
                    import pandas as _pd_bsm
                    if isinstance(_bsm_raw, _pd_bsm.Series):
                        _bsm_row = _bsm_raw.to_dict()
                    elif isinstance(_bsm_raw, dict):
                        _bsm_row = _bsm_raw
                    else:
                        _bsm_row = {}
                except Exception:
                    _bsm_row = _bsm_raw if isinstance(_bsm_raw, dict) else {}

                def _bsm_get(key, default=0.0):
                    """Safe get from _bsm_row — handles both dict and any remaining edge cases."""
                    try:
                        v = _bsm_row.get(key)
                        return float(v) if v is not None and str(v) not in ('', 'nan', 'NaN') else default
                    except Exception:
                        return default

                # ── Attempt to pull _PF9_AGG from the BZM global cache ──────────
                # _L10_BBE_BY_PITCH is the module-level dict populated by BZM fetch.
                # Each entry may have a "_PF9_AGG" key with cross-pitch aggregate stats.
                # Try normalized name variants to find the match.
                def _pf9_norm(s):
                    import unicodedata as _ud_pf9
                    s = ''.join(c for c in _ud_pf9.normalize('NFD', str(s))
                                if _ud_pf9.category(c) != 'Mn').strip().lower()
                    for _sfx in (" jr.", " sr.", " ii", " iii", " iv", " jr", " sr"):
                        if s.endswith(_sfx): s = s[:-len(_sfx)].strip()
                    return s
                _pf9_bname = getattr(b, "name", bname) if hasattr(b, "name") else bname
                # Expand abbreviated names (e.g. "W. Contreras") using BZM keys directly.
                # FL uses abbreviated names too, so the FL map doesn't help. Instead, scan
                # _L10_BBE_BY_PITCH for keys whose first initial and last name match.
                # Disambiguation: use b.team (or gm teams when UNK) to pick the right player.
                _pf9_bname_norm_check = _pf9_norm(_pf9_bname)
                _pf9_bname_parts_check = _pf9_bname_norm_check.split()
                if (len(_pf9_bname_parts_check) >= 2
                        and len(_pf9_bname_parts_check[0].rstrip(".")) == 1):
                    _pf9_init_check = _pf9_bname_parts_check[0].rstrip(".")
                    _pf9_last_check = _pf9_bname_parts_check[-1]
                    # Find all BZM keys with matching initial + last name
                    _pf9_matches = [
                        k for k in _L10_BBE_BY_PITCH
                        if isinstance(_L10_BBE_BY_PITCH[k], dict)
                        and "_PF9_AGG" in _L10_BBE_BY_PITCH[k]
                        and not k.startswith("__")
                    ]
                    _pf9_matches = [
                        k for k in _pf9_matches
                        if k.split() and k.split()[-1] == _pf9_last_check
                        and k.split()[0].startswith(_pf9_init_check)
                    ]
                    if len(_pf9_matches) == 1:
                        _pf9_bname = _pf9_matches[0]
                        if any(n in _pf9_last_check for n in ("contreras","rooker")):
                            print(f"  🔍 BZM scan [{_pf9_norm(getattr(b,'name',bname))}]: 1 match → {_pf9_bname!r}")
                    elif len(_pf9_matches) > 1:
                        # Multiple matches (e.g. William vs Willson Contreras).
                        # Priority 1: ID map (only works when savant_id is known)
                        _id_to_key_g = globals().get("_L10_BBE_ID_TO_KEY", {})
                        _pf9_sid = getattr(b, "savant_id", 0) or 0
                        if _pf9_sid and int(_pf9_sid) in _id_to_key_g:
                            _pf9_bname = _id_to_key_g[int(_pf9_sid)]
                        else:
                            # Priority 2: derive team from is_home + game dict
                            # (b.team is still UNK at enrichment time; this is reliable)
                            _batter_team = (gm.get("home_team", "") if is_home
                                            else gm.get("away_team", "")).upper()
                            # Build BZM-key → key_id reverse from __ID_TO_KEY__
                            _key_to_id = {v: k for k, v in _id_to_key_g.items()}
                            # Try to find which match's player is on _batter_team
                            # by checking which MLBAM ID belongs to a player on that team.
                            # We use _id_to_key_g keys (MLBAM IDs) and pybaseball's
                            # playerid_reverse_lookup to get team — but that's expensive.
                            # Simpler: the BZM cache was computed from a season Statcast df
                            # that has team info. We can't recover it here, but we can use
                            # the heuristic: William Contreras→MIL, Willson Contreras→BOS.
                            # Store a small hardcoded disambiguation table for known conflicts.
                            _KNOWN_DISAMBIG = {
                                # (initial, last): {team → full_bzm_key}
                                ("w", "contreras"): {
                                    "MIL": "william contreras",
                                    "BOS": "willson contreras",
                                },
                            }
                            _disambig_key = (_pf9_init_check, _pf9_last_check)
                            if _disambig_key in _KNOWN_DISAMBIG and _batter_team in _KNOWN_DISAMBIG[_disambig_key]:
                                _pf9_bname = _KNOWN_DISAMBIG[_disambig_key][_batter_team]
                            else:
                                _pf9_bname = _pf9_matches[0]
                        if any(n in _pf9_last_check for n in ("contreras","rooker")):
                            print(f"  🔍 BZM scan [{_pf9_norm(getattr(b,'name',bname))}]: {len(_pf9_matches)} matches → {_pf9_bname!r} (team={_batter_team if 'w' == _pf9_init_check else '?'})")
                # Try "First Last" directly, then:
                #   "Last, First" → "First Last" conversion  (when b.name has a comma)
                #   "First Last"  → "Last, First" conversion  (when BZM stored Last,First)
                # Statcast's _id_to_name can return either format depending on pybaseball
                # version; this double-direction lookup ensures a cache hit regardless.
                _pf9_candidates = [_pf9_norm(_pf9_bname)]
                if "," in str(_pf9_bname):
                    _pts = str(_pf9_bname).split(",", 1)
                    _pf9_candidates.append(_pf9_norm(_pts[1].strip() + " " + _pts[0].strip()))
                else:
                    # b.name is "First Last" — also try "Last, First" as stored by Statcast
                    _name_parts = str(_pf9_bname).strip().split()
                    if len(_name_parts) >= 2:
                        _pf9_candidates.append(_pf9_norm(_name_parts[-1] + ", " + " ".join(_name_parts[:-1])))
                # ── Middle-name fallback: Chadwick uses legal names (e.g. "Brent Michael Rooker")
                # while lineups use common names ("Brent Rooker"). Scan BZM keys for any
                # entry where the first and last tokens match the batter's first and last name.
                _pf9_agg_found = None
                # ── Priority 0: ID-based lookup (unambiguous, bypasses all name issues) ──
                # _L10_BBE_ID_TO_KEY maps mlbam_id → BZM key built during season compute.
                # Resolves abbreviated names like "W. Contreras" (BOS vs MIL) correctly.
                _pf9_savant_id = getattr(b, "savant_id", 0) or 0
                if _pf9_savant_id:
                    _id_to_key_global = globals().get("_L10_BBE_ID_TO_KEY", {})
                    _pf9_key_by_id = _id_to_key_global.get(int(_pf9_savant_id))
                    if _pf9_key_by_id:
                        _pf9_entry_by_id = _L10_BBE_BY_PITCH.get(_pf9_key_by_id)
                        if isinstance(_pf9_entry_by_id, dict) and "_PF9_AGG" in _pf9_entry_by_id:
                            _pf9_agg_found = _pf9_entry_by_id["_PF9_AGG"]
                # ── Priority 1: name candidate lookup ──────────────────────────────────
                if _pf9_agg_found is None:
                    for _pc in _pf9_candidates:
                        _pf9_entry = _L10_BBE_BY_PITCH.get(_pc)
                        if isinstance(_pf9_entry, dict) and "_PF9_AGG" in _pf9_entry:
                            _pf9_agg_found = _pf9_entry["_PF9_AGG"]
                            break
                if _pf9_agg_found is None:
                    # Last-resort: match on first + last token only (strips middle names)
                    _pf9_parts = _pf9_norm(_pf9_bname).split()
                    if len(_pf9_parts) >= 2:
                        _pf9_first = _pf9_parts[0]
                        _pf9_last  = _pf9_parts[-1]
                        for _bzm_key, _bzm_val in _L10_BBE_BY_PITCH.items():
                            if not isinstance(_bzm_val, dict) or "_PF9_AGG" not in _bzm_val:
                                continue
                            _bzm_parts = _bzm_key.split()
                            if (len(_bzm_parts) >= 2
                                    and _bzm_parts[0] == _pf9_first
                                    and _bzm_parts[-1] == _pf9_last):
                                _pf9_agg_found = _bzm_val["_PF9_AGG"]
                                break
                if _pf9_agg_found and isinstance(_pf9_agg_found, dict):
                    _pf9_cnt = int(_pf9_agg_found.get("l10_bbe_count", 0))
                    if _pf9_cnt >= 3:
                        setattr(b, "pf9_l10_available",   True)
                        setattr(b, "pf9_l10_bbe_count",   _pf9_cnt)
                        setattr(b, "pf9_l10_iso",         float(_pf9_agg_found.get("l10_iso",         _bsm_get("l10_iso", b.iso))))
                        setattr(b, "pf9_l10_barrel_pct",  float(_pf9_agg_found.get("l10_barrel_pct",  _bsm_get("l10_barrel_pct", b.barrel_pct))))
                        setattr(b, "pf9_l10_hh_pct",      float(_pf9_agg_found.get("l10_hh_pct",      _bsm_get("l10_hh_pct", b.hard_hit_pct))))
                        setattr(b, "pf9_l10_air_pct",     float(_pf9_agg_found.get("l10_air_pct",     _bsm_get("l10_air_pct", 100.0 - b.gb_pct))))
                        setattr(b, "pf9_l10_gb_pct",      float(_pf9_agg_found.get("l10_gb_pct",      _bsm_get("l10_gb_pct", b.gb_pct))))
                        setattr(b, "pf9_l10_fb_pct",      float(_pf9_agg_found.get("l10_fb_pct",      _bsm_get("l10_fb_pct", b.fb_pct))))
                        setattr(b, "pf9_l10_pull_pct",    float(_pf9_agg_found.get("l10_pull_pct",    _bsm_get("l10_pull_pct", 0.0))))
                        setattr(b, "pf9_l10_pullbrl_pct", float(_pf9_agg_found.get("l10_pullbrl_pct", _bsm_get("l10_pullbrl_pct", 0.0))))
                        setattr(b, "pf9_l10_blast_pct",   float(_pf9_agg_found.get("l10_blast_pct",   _bsm_get("l10_blast_pct", b.blast_pct))))
                        setattr(b, "pf9_l10_avg_ev",      float(_pf9_agg_found.get("l10_avg_ev",      _bsm_get("l10_avg_ev", b.avg_ev))))

                # ── Fallback: synthesize cross-pitch aggregate from per-pitch BBE dicts ──
                # If _PF9_AGG lookup failed (e.g. rookie with sparse Statcast data),
                # aggregate the per-pitch BBE summaries already in _L10_BBE_BY_PITCH.
                if not getattr(b, "pf9_l10_available", False):
                    try:
                        _synth_entry = None
                        for _pc3 in _pf9_candidates:
                            _cand3 = _L10_BBE_BY_PITCH.get(_pc3)
                            if isinstance(_cand3, dict):
                                _synth_entry = _cand3
                                break
                        # Middle-name fallback for synthesis lookup
                        if _synth_entry is None and len(_pf9_parts) >= 2:
                            for _bzm_key2, _bzm_val2 in _L10_BBE_BY_PITCH.items():
                                if not isinstance(_bzm_val2, dict):
                                    continue
                                _bk2 = _bzm_key2.split()
                                if (len(_bk2) >= 2
                                        and _bk2[0] == _pf9_first
                                        and _bk2[-1] == _pf9_last):
                                    _synth_entry = _bzm_val2
                                    break
                        if _synth_entry:
                            # Pool all pitch-type sub-dicts (skip "_PF9_AGG" key)
                            _s_barrel = _s_hh = _s_air = _s_gb = _s_fb = 0.0
                            _s_pull = _s_pullbrl = _s_blast = _s_ev = _s_hr = 0.0
                            _s_n = 0
                            for _pt3, _ptd3 in _synth_entry.items():
                                if not isinstance(_ptd3, dict) or _pt3 == "_PF9_AGG":
                                    continue
                                _n3 = int(_ptd3.get("l10_bbe_count", _ptd3.get("n", 0)))
                                if _n3 < 1:
                                    continue
                                _s_barrel  += _ptd3.get("l10_barrel_pct", 0.0) * _n3
                                _s_hh      += _ptd3.get("l10_hh_pct",     0.0) * _n3
                                _s_air     += _ptd3.get("l10_air_pct",    0.0) * _n3
                                _s_gb      += _ptd3.get("l10_gb_pct",     0.0) * _n3
                                _s_fb      += _ptd3.get("l10_fb_pct",     0.0) * _n3
                                _s_pull    += _ptd3.get("l10_pull_pct",   0.0) * _n3
                                _s_pullbrl += _ptd3.get("l10_pullbrl_pct",0.0) * _n3
                                _s_blast   += _ptd3.get("l10_blast_pct",  0.0) * _n3
                                _s_ev      += _ptd3.get("l10_avg_ev",     87.5) * _n3
                                _s_hr      += int(_ptd3.get("l10_hr_count", _ptd3.get("hr", 0)))
                                _s_n       += _n3
                            if _s_n >= 3:
                                setattr(b, "pf9_l10_available",   True)
                                setattr(b, "pf9_l10_bbe_count",   _s_n)
                                setattr(b, "pf9_l10_iso",         _bsm_get("l10_iso", b.iso))
                                setattr(b, "pf9_l10_barrel_pct",  _s_barrel  / _s_n)
                                setattr(b, "pf9_l10_hh_pct",      _s_hh      / _s_n)
                                setattr(b, "pf9_l10_air_pct",     _s_air     / _s_n)
                                setattr(b, "pf9_l10_gb_pct",      _s_gb      / _s_n)
                                setattr(b, "pf9_l10_fb_pct",      _s_fb      / _s_n)
                                setattr(b, "pf9_l10_pull_pct",    _s_pull    / _s_n)
                                setattr(b, "pf9_l10_pullbrl_pct", _s_pullbrl / _s_n)
                                setattr(b, "pf9_l10_blast_pct",   _s_blast   / _s_n)
                                setattr(b, "pf9_l10_avg_ev",      _s_ev      / _s_n)
                    except Exception:
                        pass

                # ── Pitch-filtered PullBrl% / FB% / HH% override ────────────────
                # Refine the all-pitch aggregate stats to only BBEs on the pitcher's
                # top 2 most-used pitch types vs this batter's hand.
                # Mirrors PropFinder's pitch-chip filtering.
                # Each pitch-type entry in _L10_BBE_BY_PITCH already stores
                # l10_pullbrl_pct, l10_fb_pct, l10_hh_pct, l10_bbe_count.
                # We compute a BBE-count-weighted average across the top 2 pitch types.
                # ── Pitch-filtered PullBrl% / FB% / HH% override ────────────────
                # IMPORTANT: only run when _PF9_AGG was NOT found (path 1 failed).
                # When _pf9_agg_found is populated, those cross-pitch aggregate stats
                # are authoritative (computed from the full L10 BBE window across all
                # pitch types, refreshed by statcast_batter() for high-gate batters).
                # Running the pitch-filter override on top of _PF9_AGG silently reverts
                # fresh 9/9 results back to stale 8/9 — e.g. Jensen HH% 45% (fresh,
                # passes gate) gets overwritten with 31% (stale per-pitch sub-dict,
                # fails gate). Only use pitch-filter when _PF9_AGG is unavailable.
                _pf9_use_pitch_filter = (
                    _pf9_agg_found is None
                    and getattr(b, "pf9_l10_available", False)
                )
                try:
                    _pvh_global  = globals().get("_PITCHER_PITCH_VS_HAND", {})
                    _pid_for_pf9 = (getattr(pitcher, "savant_id", 0) or
                                    getattr(pitcher, "mlbam_id",  0) or 0)
                    _bhand_pf9   = (b.hand or "R") if hasattr(b, "hand") else "R"
                    _pvh_for_pf9 = _pvh_global.get(_pid_for_pf9, {}).get(_bhand_pf9, {})
                    if _pf9_use_pitch_filter and _pvh_for_pf9:
                        # Pitcher's top 2 pitch types by usage ≥10% vs this batter hand
                        _top2_pts = sorted(
                            [(pt, d.get("pct", 0.0)) for pt, d in _pvh_for_pf9.items()
                             if d.get("pct", 0.0) >= 10.0],
                            key=lambda x: x[1], reverse=True
                        )[:2]
                        # Locate batter's per-pitch BBE summary dict
                        _batter_bbe_dict = None
                        for _pc2 in _pf9_candidates:
                            _cand = _L10_BBE_BY_PITCH.get(_pc2)
                            if isinstance(_cand, dict):
                                _batter_bbe_dict = _cand
                                break
                        if _top2_pts and _batter_bbe_dict:
                            # Weighted average of stats across top 2 pitch types
                            _w_pullbrl = _w_fb = _w_hh = 0.0
                            _w_total   = 0
                            for _pt2, _ in _top2_pts:
                                _pt2_data = _batter_bbe_dict.get(_pt2)
                                if not isinstance(_pt2_data, dict):
                                    continue
                                _n2 = int(_pt2_data.get("l10_bbe_count", 0))
                                if _n2 < 1:
                                    continue
                                _w_pullbrl += _pt2_data.get("l10_pullbrl_pct", 0.0) * _n2
                                _w_fb      += _pt2_data.get("l10_fb_pct",      0.0) * _n2
                                _w_hh      += _pt2_data.get("l10_hh_pct",      0.0) * _n2
                                _w_total   += _n2
                            # Only override if ≥3 BBEs across top 2 pitch types
                            if _w_total >= 3:
                                setattr(b, "pf9_l10_pullbrl_pct", float(_w_pullbrl / _w_total))
                                setattr(b, "pf9_l10_fb_pct",      float(_w_fb      / _w_total))
                                setattr(b, "pf9_l10_hh_pct",      float(_w_hh      / _w_total))
                except Exception:
                    pass  # Silently fall back to all-pitch aggregate values

                _l10_cnt = int(_bsm_get("l10_bbe_count", 0))
                if _l10_cnt >= 3 and not getattr(b, "pf9_l10_available", False):
                    # Use setattr so this works even on older BatterProfile objects
                    # that were built before pf9_l10_* fields were added
                    setattr(b, "pf9_l10_available",   True)
                    setattr(b, "pf9_l10_bbe_count",   _l10_cnt)
                    setattr(b, "pf9_l10_iso",         _bsm_get("l10_iso",         b.iso))
                    setattr(b, "pf9_l10_barrel_pct",  _bsm_get("l10_barrel_pct",  b.barrel_pct))
                    setattr(b, "pf9_l10_hh_pct",      _bsm_get("l10_hh_pct",      b.hard_hit_pct))
                    setattr(b, "pf9_l10_air_pct",     _bsm_get("l10_air_pct",     100.0 - b.gb_pct))
                    setattr(b, "pf9_l10_gb_pct",      _bsm_get("l10_gb_pct",      b.gb_pct))
                    setattr(b, "pf9_l10_fb_pct",      _bsm_get("l10_fb_pct",      b.fb_pct))
                    setattr(b, "pf9_l10_pull_pct",    _bsm_get("l10_pull_pct",    0.0))
                    setattr(b, "pf9_l10_pullbrl_pct", _bsm_get("l10_pullbrl_pct", 0.0))
                    setattr(b, "pf9_l10_blast_pct",   _bsm_get("l10_blast_pct",   b.blast_pct))
                    setattr(b, "pf9_l10_avg_ev",      _bsm_get("l10_avg_ev",      b.avg_ev))

                # ── Freeze odds for in-progress games ─────────────────────
                # If the game has already started, PropLine/ActionNetwork return
                # live in-game odds (e.g. +1100 after a team goes up 3-0) which
                # have nothing to do with the pre-game matchup edge we're scoring.
                # Strip live odds so they don't corrupt scoring, rank, or display.
                # Keep hr_early_price as a fallback display price if it was captured.
                _gts = getattr(ctx, "game_time_str", "") or ""
                _game_live = False
                if _gts:
                    try:
                        import datetime as _dt_live
                        _now_et_live = _dt_live.datetime.now(
                            _dt_live.timezone(_dt_live.timedelta(hours=-4)))
                        _gts_clean = _gts.upper().replace("ET", "").strip()
                        _gt_t_live = _dt_live.datetime.strptime(_gts_clean, "%I:%M %p").time()
                        _gt_dt_live = _dt_live.datetime.combine(
                            _now_et_live.date(), _gt_t_live,
                            tzinfo=_dt_live.timezone(_dt_live.timedelta(hours=-4)))
                        # 5-min buffer: don't strip odds for games that literally just started
                        _game_live = (_now_et_live - _gt_dt_live).total_seconds() > 300
                    except Exception:
                        pass
                if _game_live:
                    # Preserve hr_early_price (pre-game baseline) as the display odds
                    # so the sheet still shows something useful; strip current price
                    # which is a live in-game line unrelated to pre-game edge.
                    _pre_game_odds = b.hr_early_price if b.hr_early_price else 0.0
                    b.hr_over_price     = _pre_game_odds   # revert to pre-game price
                    b.hr_line_movement  = 0.0              # no line-movement signal
                    b.hr_odds_source    = (b.hr_odds_source or "") + " [LOCKED-PRE]"

                # ── Inject RotoWire batter props (hits + TB odds) ─────────
                # These supplement hr_over_price (which comes from SGO/OddsAPI)
                # with hits and total bases lines/odds for market_signal computation
                _rw_batters = rw_pitcher_props.get("batters", {}) if isinstance(rw_pitcher_props, dict) else {}
                _rw_bat_norm = rw_pitcher_props.get("batter_norm", {}) if isinstance(rw_pitcher_props, dict) else {}
                if _rw_batters:
                    import unicodedata as _ud3, re as _re3
                    def _rw_fn(s):
                        """Normalize for RotoWire lookup — strips non-alpha like fl_lookup_name."""
                        s = _ud3.normalize("NFKD", str(s)).encode("ascii","ignore").decode().lower().strip()
                        return _re3.sub(r"[^a-z ]", "", s)

                    def _rw_lookup(name):
                        """
                        5-tier RotoWire batter lookup. Returns (orig_name, data_dict) or (None, None).
                        Tier 0: FL abbreviated names ("N. Lowe" → scan for "nathaniel lowe")
                        Tier 1-4: existing exact/alias/suffix/last-name tiers
                        """
                        import re as _re_lu
                        def _strip(s):
                            return _re_lu.sub(r"\s+(jr\.?|sr\.?|ii|iii|iv)\s*$", "",
                                              str(s).strip(), flags=_re_lu.IGNORECASE)
                        # Tier 0: abbreviated name expansion ("N. Lowe", "E. De La Cruz")
                        _name_raw = str(name).strip()
                        _t0_parts = _name_raw.replace("(R)","").replace("(L)","").replace("(S)","").strip().split()
                        _is_abbrev = bool(_t0_parts and (_t0_parts[0].endswith(".") or
                                           (len(_t0_parts[0]) <= 2 and _t0_parts[0].isalpha())))
                        if _is_abbrev and len(_t0_parts) >= 2:
                            _last_norm = _rw_fn(" ".join(_t0_parts[1:]))
                            _fi = _t0_parts[0].rstrip(".").lower()[:1]
                            _t0 = [(k,v) for k,v in _rw_bat_norm.items()
                                   if " ".join(k.split()[-(len(_last_norm.split())):]) == _last_norm]
                            if len(_t0) == 1: return _t0[0][1]
                            if len(_t0) > 1:
                                _t0i = [(k,v) for k,v in _t0 if k.split()[0][:1] == _fi]
                                if _t0i: return _t0i[0][1]
                                return _t0[0][1]
                        # Tier 1: suffix-stripped exact
                        key = _rw_fn(_strip(name))
                        if key in _rw_bat_norm:
                            return _rw_bat_norm[key]
                        # Tier 2: initial+last alias
                        parts = key.split()
                        if len(parts) >= 2:
                            alias = parts[0][:1] + " " + parts[-1]
                            if alias in _rw_bat_norm:
                                return _rw_bat_norm[alias]
                        # Tier 3: original with suffix
                        key2 = _rw_fn(name)
                        if key2 != key and key2 in _rw_bat_norm:
                            return _rw_bat_norm[key2]
                        # Tier 4: last-name only (unambiguous)
                        if parts:
                            last = parts[-1]
                            if len(last) > 3:
                                _t4 = [(k,v) for k,v in _rw_bat_norm.items() if k.split()[-1] == last]
                                if len(_t4) == 1: return _t4[0][1]
                        return None, None

                    _rw_orig, _rw_full = _rw_lookup(bname)
                    if _rw_full:
                        if "hits_over_price" in _rw_full and b.hits_over_price == 0:
                            b.hits_over_price = _rw_full["hits_over_price"]
                        if "tb_line" in _rw_full and b.tb_line <= 1.5:
                            b.tb_line = _rw_full["tb_line"]
                        if "tb_over_price" in _rw_full and b.tb_over_price == 0:
                            b.tb_over_price = _rw_full["tb_over_price"]
                    b._rw_by_market = _rw_full.get("_by_market", {}) if isinstance(_rw_full, dict) else {}

                    # ── Persist hit-score fields onto batter so they survive post-game-time
                    # RotoWire feed loss. When books close lines after game start, the Hits
                    # market entry disappears from the feed. By writing WHR/L5/L10/season/vs-opp
                    # and over_prob directly onto the batter object here, the stats-based
                    # fallback in score_player can use real data instead of league defaults.
                    _hits_mkt = b._rw_by_market.get("Hits", {}) if b._rw_by_market else {}
                    if _hits_mkt:
                        _whr_val   = _hits_mkt.get("whr", 0) or 0
                        _l5_val    = _hits_mkt.get("hr_l5", 0) or 0
                        _l10_val   = _hits_mkt.get("hr_l10", 0) or 0
                        _szn_val   = _hits_mkt.get("hr_season", 0) or 0
                        _opp_val   = _hits_mkt.get("hr_vs_opp", 0) or 0
                        _oprob_val = _hits_mkt.get("over_prob")
                        if _whr_val  > 0: b._cached_whr        = float(_whr_val)
                        if _l5_val   > 0:
                            b.recent_hit_rate_l5  = float(_l5_val) / 100.0 if _l5_val > 1.0 else float(_l5_val)
                        if _l10_val  > 0:
                            b.recent_hit_rate_l10 = float(_l10_val) / 100.0 if _l10_val > 1.0 else float(_l10_val)
                        if _szn_val  > 0: b._cached_hit_season = float(_szn_val)
                        if _opp_val  > 0: b._cached_hit_vs_opp = float(_opp_val)
                        if _oprob_val is not None: b._cached_hit_over_prob = float(_oprob_val)

                # FL form factor blending (unchanged)
                if _fl_entry and _fl_entry.get("mo_ppg", 0) > 0 and _fl_entry.get("yr_ppg", 0) > 0:
                    fl_form_ratio = _fl_entry["mo_ppg"] / max(_fl_entry["yr_ppg"], 1.0)
                    fl_form_ratio = max(0.75, min(fl_form_ratio, 1.30))
                    b.recent_barrel_pct   = b.barrel_pct   * fl_form_ratio * 0.4 + b.recent_barrel_pct * 0.6
                    b.recent_ev           = b.avg_ev       * fl_form_ratio * 0.4 + b.recent_ev          * 0.6
                    b.recent_hard_hit_pct = b.hard_hit_pct * fl_form_ratio * 0.4 + b.recent_hard_hit_pct * 0.6

                if _fl_entry and _fl_entry.get("consistency", 0) > 0:
                    fl_cons = _fl_entry["consistency"]
                    b.ev_consistency = max(0.88, min(0.80 + fl_cons * 0.40, 1.12))

                if b.team == "UNK":
                    b.team = gm["home_team"] if is_home else gm["away_team"]

                tf = _game_travel_factors.get(str(gm["game_pk"]), {})
                ctx.travel_factor = tf.get("home", 1.0) if is_home else tf.get("away", 1.0)

                # Pre-compute 2D zone grid multiplier (0.005ms, effectively free)
                try_attach_zone_grids(b, pitcher)

                # ── DailyPitch injection: batter wOBA/SLG by pitch type from Savant ──
                # Keyed by player_id (savant_id) — replaces blocked Savant API endpoints
                if daily_pitch and getattr(b, 'savant_id', 0) > 0:
                    _dp = daily_pitch.get(b.savant_id, {})
                    if _dp:
                        # Helper to get field safely
                        def _dpf(pt, field, default=0.0):
                            return float(_dp.get(pt, {}).get(field, default) or default)

                        # Sub-type wOBA and SLG (Path A triggers)
                        b.woba_vs_sinker   = _dpf("SI", "woba")
                        b.woba_vs_cutter   = _dpf("FC", "woba")
                        b.woba_vs_fourseam = _dpf("FF", "woba")
                        b.woba_vs_sweeper  = _dpf("ST", "woba")
                        # ── New: individual SL/CU/CH batter wOBA (June 2026) ─────────────
                        # Previously only stored as grouped woba_vs_breaking / woba_vs_offspeed.
                        # Now stored individually so the _dp_arsenal loop can compute
                        # Cruz's sweeper/curve/slider splits separately.
                        if _dpf("SL","woba") > 0: b.woba_vs_slider    = _dpf("SL","woba")
                        if _dpf("CU","woba") > 0: b.woba_vs_curveball = _dpf("CU","woba")
                        if _dpf("CH","woba") > 0: b.woba_vs_changeup  = _dpf("CH","woba")
                        # Per-pitch barrel% for batter
                        if _dpf("SL","barrel_pct") > 0: b.barrel_pct_vs_slider    = _dpf("SL","barrel_pct")
                        if _dpf("ST","barrel_pct") > 0: b.barrel_pct_vs_sweeper   = _dpf("ST","barrel_pct")
                        if _dpf("CU","barrel_pct") > 0: b.barrel_pct_vs_curveball = _dpf("CU","barrel_pct")
                        if _dpf("CH","barrel_pct") > 0: b.barrel_pct_vs_changeup  = _dpf("CH","barrel_pct")
                        # Per-pitch HR/PA for batter
                        if _dpf("FF","hr_pa") > 0: b.hr_pa_vs_fourseam  = _dpf("FF","hr_pa")
                        if _dpf("SI","hr_pa") > 0: b.hr_pa_vs_sinker     = _dpf("SI","hr_pa")
                        if _dpf("SL","hr_pa") > 0: b.hr_pa_vs_slider     = _dpf("SL","hr_pa")
                        if _dpf("CU","hr_pa") > 0: b.hr_pa_vs_curveball  = _dpf("CU","hr_pa")
                        if _dpf("CH","hr_pa") > 0: b.hr_pa_vs_changeup   = _dpf("CH","hr_pa")
                        b.slg_vs_sinker    = _dpf("SI", "slg")
                        b.slg_vs_cutter    = _dpf("FC", "slg")
                        b.slg_vs_fourseam  = _dpf("FF", "slg")

                        # Combined buckets (Path B fallback + existing PM score)
                        # Fastball = weighted avg of FF+SI+FC
                        _ff_u = _dpf("FF","usage_pct"); _si_u = _dpf("SI","usage_pct"); _fc_u = _dpf("FC","usage_pct")
                        _fb_total = _ff_u + _si_u + _fc_u
                        if _fb_total > 0:
                            b.woba_vs_fastball = (
                                (_dpf("FF","woba")*_ff_u + _dpf("SI","woba")*_si_u + _dpf("FC","woba")*_fc_u)
                                / _fb_total)
                        # Breaking = weighted avg of SL+ST+CU
                        _sl_u = _dpf("SL","usage_pct"); _st_u = _dpf("ST","usage_pct"); _cu_u = _dpf("CU","usage_pct")
                        _brk_total = _sl_u + _st_u + _cu_u
                        if _brk_total > 0:
                            b.woba_vs_breaking = (
                                (_dpf("SL","woba")*_sl_u + _dpf("ST","woba")*_st_u + _dpf("CU","woba")*_cu_u)
                                / _brk_total)
                        # Offspeed = CH+FS
                        _ch_u = _dpf("CH","usage_pct")
                        if _ch_u > 0:
                            b.woba_vs_offspeed = _dpf("CH", "woba")

                # ── Safety net: ensure pf9_l10_* attrs exist on ALL batter objects ──
                # Older pickled BatterProfile objects won't have these fields.
                # setattr is a no-op if the attribute already exists with correct value.
                if not hasattr(b, "pf9_l10_available"):
                    b.__dict__.setdefault("pf9_l10_available",   False)
                    b.__dict__.setdefault("pf9_l10_bbe_count",   0)
                    b.__dict__.setdefault("pf9_l10_iso",         0.0)
                    b.__dict__.setdefault("pf9_l10_barrel_pct",  0.0)
                    b.__dict__.setdefault("pf9_l10_hh_pct",      0.0)
                    b.__dict__.setdefault("pf9_l10_air_pct",     0.0)
                    b.__dict__.setdefault("pf9_l10_gb_pct",      0.0)
                    b.__dict__.setdefault("pf9_l10_fb_pct",      0.0)
                    b.__dict__.setdefault("pf9_l10_pull_pct",    0.0)
                    b.__dict__.setdefault("pf9_l10_pullbrl_pct", 0.0)
                    b.__dict__.setdefault("pf9_l10_blast_pct",   0.0)
                    b.__dict__.setdefault("pf9_l10_avg_ev",      0.0)

                # ── Savant sheet injection (bat speed, attack angle, batted ball profile) ──
                _sv = savant_data.get(b.savant_id, {}) if b.savant_id else {}
                if _sv:
                    if 'avg_bat_speed'           in _sv: b.avg_bat_speed           = _sv['avg_bat_speed']
                    if 'ideal_attack_angle_rate' in _sv: b.ideal_attack_angle_rate = _sv['ideal_attack_angle_rate']
                    if 'swing_tilt'              in _sv: b.swing_tilt              = _sv['swing_tilt']
                    if 'attack_angle'            in _sv: b.attack_angle            = _sv['attack_angle']
                    if 'blast_per_contact'       in _sv: b.blast_per_contact       = _sv['blast_per_contact']
                    if 'squared_up_per_contact'  in _sv: b.squared_up_per_contact  = _sv['squared_up_per_contact']
                    if 'batter_run_value'        in _sv: b.batter_run_value        = _sv['batter_run_value']
                    if 'whiff_per_swing'         in _sv: b.whiff_per_swing         = _sv['whiff_per_swing']
                    if 'pull_air_rate'           in _sv: b.pull_air_pct_savant     = _sv['pull_air_rate']
                    if 'pu_rate'                 in _sv: b.pu_rate_savant          = _sv['pu_rate']
                    if 'ld_rate'                 in _sv: b.ld_rate_savant          = _sv['ld_rate']
                    if 'hard_swing_rate'         in _sv: b.hard_swing_rate         = _sv['hard_swing_rate']
                    if 'competitive_swing_pct'   in _sv: b.competitive_swing_pct   = _sv['competitive_swing_pct']
                    # Fix A: gb_pct from savant sheet (gb_rate is 0-1 decimal → convert to %)
                    if 'gb_rate' in _sv and _sv['gb_rate'] > 0:
                        b.gb_pct = round(_sv['gb_rate'] * 100.0, 1)
                    # Fix B: blast_pct — use direct ×100 when blast_pct_direct available
                    # (blast_per_bat_contact ×100 = true Blast%, not the old ×34 proxy)
                    if 'blast_pct_direct' in _sv and _sv['blast_pct_direct'] > 0:
                        b.blast_pct = round(_sv['blast_pct_direct'], 1)
                    elif 'blast_per_contact' in _sv and _sv['blast_per_contact'] > 0:
                        # Fallback: old ×34 proxy only when blast_pct_direct not present
                        b.blast_pct = round(_sv['blast_per_contact'] * 34.0, 1)

                    # ── New season-stat columns from Jul 2026 Savant export ──────
                    # These are SEASON stats used as PropFinder gate fallback when
                    # L10 BBE data (pybaseball) is not available for a batter.
                    # Applied only when pf9_l10_available is False (set above).
                    if not getattr(b, "pf9_l10_available", False):
                        if 'barrel_pct_season' in _sv and _sv['barrel_pct_season'] > 0:
                            b.barrel_pct  = _sv['barrel_pct_season']
                        if 'hard_hit_pct_season' in _sv and _sv['hard_hit_pct_season'] > 0:
                            b.hard_hit_pct = _sv['hard_hit_pct_season']
                        if 'xiso_season' in _sv and _sv['xiso_season'] > 0:
                            b.xiso = _sv['xiso_season']
                        if 'pull_pct_season' in _sv and _sv['pull_pct_season'] > 0:
                            b._pull_rate_full = _sv['pull_pct_season']
                        if 'gb_pct_season' in _sv and _sv['gb_pct_season'] > 0:
                            b.gb_pct = _sv['gb_pct_season']
                        if 'fb_pct_season' in _sv and _sv['fb_pct_season'] > 0:
                            b.fb_pct = _sv['fb_pct_season']
                    # EV50 / Adjusted EV — always apply these regardless of L10 status
                    if 'ev50' in _sv and _sv['ev50'] > 0:
                        b.ev50 = _sv['ev50']  # type: ignore
                    if 'adjusted_ev' in _sv and _sv['adjusted_ev'] > 0:
                        b.adjusted_ev = _sv['adjusted_ev']  # type: ignore
                    # Also pull pull_rate (overall pull%) into pull_air_pct as supplemental
                    # since we have no dedicated pull_pct field on BatterProfile
                    # Only update pull_air_pct_savant if pull_air_rate is missing
                    if 'pull_rate' in _sv and _sv['pull_rate'] > 0 and b.pull_air_pct_savant == 0.206:
                        # Store pull_rate in a way the PropFinder block can access it
                        # We use pull_air_pct_savant as the fallback only if pull_air_rate absent
                        pass  # pull_rate stored below as b._pull_rate_full for PropFinder
                    # Store full pull% separately — PropFinder uses both pull_air% and pull%
                    if 'pull_rate' in _sv and _sv['pull_rate'] > 0:
                        b._pull_rate_full = round(_sv['pull_rate'] * 100.0, 1)  # type: ignore

                # ── DailyPitcherPitch injection: pitcher arsenal from Savant ─────────────
                # Uses pitcher.savant_id for exact lookup — no name matching needed.
                # Populates sinker_pct/cutter_pct/fourseam_pct/sweeper_pct on PitcherProfile.
                if daily_pitcher_pitch and pitcher is not None and getattr(pitcher, 'savant_id', 0) > 0:
                    _pp = daily_pitcher_pitch.get(pitcher.savant_id, {})
                    if _pp:
                        def _ppf(pt, field, default=0.0):
                            return float(_pp.get(pt, {}).get(field, default) or default)
                        if _ppf("SI","usage_pct") > 0: pitcher.sinker_pct   = _ppf("SI","usage_pct")
                        if _ppf("FC","usage_pct") > 0: pitcher.cutter_pct   = _ppf("FC","usage_pct")
                        if _ppf("FF","usage_pct") > 0: pitcher.fourseam_pct = _ppf("FF","usage_pct")
                        if _ppf("ST","usage_pct") > 0: pitcher.sweeper_pct  = _ppf("ST","usage_pct")
                        # ── New: SL/CU/CH individual usage % (June 2026) ─────────────────
                        if _ppf("SL","usage_pct") > 0: pitcher.slider_pct    = _ppf("SL","usage_pct")
                        if _ppf("CU","usage_pct") > 0: pitcher.curveball_pct = _ppf("CU","usage_pct")
                        if _ppf("CH","usage_pct") > 0: pitcher.changeup_pct  = _ppf("CH","usage_pct")
                        if _ppf("SI","whiff_pct") > 0: pitcher.whiff_pct_sinker  = _ppf("SI","whiff_pct")
                        if _ppf("FC","whiff_pct") > 0: pitcher.whiff_pct_cutter  = _ppf("FC","whiff_pct")
                        if _ppf("ST","whiff_pct") > 0: pitcher.whiff_pct_sweeper = _ppf("ST","whiff_pct")
                        # Store wOBA allowed per pitch type for two-sided correlation
                        for _pt_code, _attr in [("FF","woba_allowed_ff"),("SI","woba_allowed_si"),
                                                 ("FC","woba_allowed_fc"),("SL","woba_allowed_sl"),
                                                 ("ST","woba_allowed_st"),("CH","woba_allowed_ch"),
                                                 ("CU","woba_allowed_cu"),
                                                 ("FF","barrel_pct_ff"),("SI","barrel_pct_si"),
                                                 ("SL","barrel_pct_sl"),("CH","barrel_pct_ch")]:
                            _field = "woba_allowed" if "woba" in _attr else "barrel_pct"
                            _val = _ppf(_pt_code, _field.replace("barrel_pct","barrel_pct") if "barrel" in _attr
                                        else "woba_allowed")
                            if _val > 0: setattr(pitcher, _attr, _val)
                        # ── Compute PitchMix wOBA (Barrel Boyz core signal) ──────────────
                        # Batter wOBA weighted by THIS pitcher's actual pitch distribution.
                        # June 2026: updated to use individual SL/CU/CH splits where available,
                        # falling back to grouped breaking/offspeed only when individual is missing.
                        _pmix_sum = 0.0; _pmix_wgt = 0.0
                        _b = b  # batter reference available in outer scope
                        for _pt_code, _b_woba_attr_primary, _b_woba_attr_fallback in [
                            ("FF", "woba_vs_fourseam",   "woba_vs_fastball"),
                            ("SI", "woba_vs_sinker",     "woba_vs_fastball"),
                            ("FC", "woba_vs_cutter",     "woba_vs_fastball"),
                            ("ST", "woba_vs_sweeper",    "woba_vs_breaking"),
                            ("SL", "woba_vs_slider",     "woba_vs_breaking"),
                            ("CU", "woba_vs_curveball",  "woba_vs_breaking"),
                            ("CH", "woba_vs_changeup",   "woba_vs_offspeed"),
                            ("FS", "woba_vs_changeup",   "woba_vs_offspeed"),
                        ]:
                            _usage = _ppf(_pt_code, "usage_pct")
                            _b_woba = (getattr(_b, _b_woba_attr_primary, 0.0) or 0.0) or (getattr(_b, _b_woba_attr_fallback, 0.0) or 0.0)
                            if _usage > 0 and _b_woba > 0:
                                _pmix_sum += _usage * _b_woba
                                _pmix_wgt += _usage
                        if _pmix_wgt >= 0.30:   # need ≥30% pitch coverage for reliable estimate
                            pitcher.pitchmix_woba = round(_pmix_sum / _pmix_wgt, 3)

                # ── DailyBatter injection: career HR/OPS/HH%/qAB vs today's pitcher ──
                # Keyed by abbreviated name "O. Albies" from DailyBatter sheet
                if daily_batter:
                    _db_match = None
                    _b_parts = b.name.split()
                    if len(_b_parts) >= 2:
                        _db_try = f"{_b_parts[0][0]}. {_b_parts[-1]}"
                        _db_match = daily_batter.get(_db_try) or daily_batter.get(b.name)
                    if _db_match is None:
                        _last = _b_parts[-1].lower() if _b_parts else ""
                        for _dk, _dv in daily_batter.items():
                            if _last and _last in _dk.lower():
                                _db_match = _dv; break
                    if _db_match:
                        if _db_match.get("hrf"):       b.fl_hrf       = float(_db_match["hrf"])
                        if _db_match.get("qab_pct"):   b.fl_qab_pct   = float(_db_match["qab_pct"])
                        if _db_match.get("hh_pct"):    b.fl_hh_pct    = float(_db_match["hh_pct"])
                        if _db_match.get("career_ab"): b.fl_career_ab = int(_db_match["career_ab"])
                        if _db_match.get("career_hr") is not None: b.fl_career_hr = int(_db_match["career_hr"])
                        if _db_match.get("career_ops"): b.fl_career_ops = float(_db_match["career_ops"])
                        if _db_match.get("career_bb") is not None: b.fl_career_bb = int(_db_match["career_bb"])

                batter_obj_cache[b.name] = b  # store for k_vs_opp batch lookup
                # Set pitcher is_home flag so home/away ERA split applies correctly
                if pitcher:
                    pitcher.is_home = not is_home   # pitcher is home when batter is away and vice versa
                # Set per-batter catcher framing: batter faces the OPPOSING team's catcher
                if _CATCHER_FRAMING:
                    if is_home:
                        ctx.catcher_framing_runs = getattr(ctx, 'away_catcher_framing', 0.0)
                    else:
                        ctx.catcher_framing_runs = getattr(ctx, 'home_catcher_framing', 0.0)
                all_scores.append(score_player(b, pitcher, ctx, bullpen, is_home, lineup_status, game_time=ctx.game_time_str))
                pbar.update(1)

    pbar.close()

    if not all_scores:
        print("\nNo players scored.")
        if is_historical:
            print("  Historical lineups may be incomplete in MLB API for this date.")
            print("  Boxscore data is most reliable for dates after 2015.")
        else:
            print("  Re-run ~90 minutes before first pitch when lineups are confirmed.")
        print()
        sys.exit(1)

    # ── Batch-prefetch batter-vs-pitcher K rates ─────────────────────────────
    # Must run AFTER all_scores is built (batter/pitcher objects are now set)
    # and BEFORE scoring output — populates k_vs_opp on batter objects.
    # Load disk cache first: same-day re-runs are instant (no API calls)
    _bvp_disk = _load_bvp_disk_cache(target_date)
    _bvp_k_cache.update(_bvp_disk)

    # batter_obj_cache: name → BatterProfile (built during scoring loop above)
    # pitcher_cache:    name → PitcherProfile (built during game context loop)
    # Both contain real dataclass objects with savant_id — no pandas Series ambiguity.
    _bvp_pairs = []
    for _sc in all_scores:
        _bn = _sc.batter_name; _pn = _sc.pitcher_name
        if (_bn.lower(), _pn.lower()) not in _bvp_k_cache:
            _batt_obj = batter_obj_cache.get(_bn) or next(
                (v for k, v in batter_obj_cache.items() if _norm(k)==_norm(_bn)), None)
            _pitch_obj = pitcher_cache.get(_pn) or next(
                (v for k, v in pitcher_cache.items() if _norm(k)==_norm(_pn)), None)
            _bid = getattr(_batt_obj, "savant_id", 0) if _batt_obj else 0
            _pid = getattr(_pitch_obj, "savant_id", 0) if _pitch_obj else 0
            if _bid and _pid:
                _bvp_pairs.append((_bn, _pn, _batt_obj, _pitch_obj))

    _seen_bvp = set(); _bvp_pairs_dedup = []
    for _item in _bvp_pairs:
        _k = (_item[0].lower(), _item[1].lower())
        if _k not in _seen_bvp:
            _seen_bvp.add(_k); _bvp_pairs_dedup.append(_item)

    if _bvp_pairs_dedup:
        import concurrent.futures as _cf
        print(f"  📊 Fetching career K rates: {len(_bvp_pairs_dedup)} unique batter-pitcher pairings...", end=" ", flush=True)

        def _fetch_one(args):
            bn, pn, bobj, pobj = args
            return bn, pn, _fetch_batter_vs_pitcher_k(bn, pn, {bn: bobj}, {pn: pobj})

        with _cf.ThreadPoolExecutor(max_workers=10) as _pool:
            _futures = {_pool.submit(_fetch_one, item): item for item in _bvp_pairs_dedup}
            for _fut in _cf.as_completed(_futures):
                try:
                    _bn, _pn, (_kr, _kab) = _fut.result(timeout=8)
                    # Write back to the BatterProfile in batter_obj_cache
                    _bobj2 = batter_obj_cache.get(_bn) or next(
                        (v for k2, v in batter_obj_cache.items() if _norm(k2)==_norm(_bn)), None)
                    if _bobj2:
                        _bobj2.k_vs_opp = _kr; _bobj2.k_vs_opp_ab = _kab
                except Exception:
                    pass

        _bvp_found = sum(1 for v in _bvp_k_cache.values() if v[0] > 0)
        print(f"done. {_bvp_found}/{len(_bvp_pairs_dedup)} with career data.")
        _save_bvp_disk_cache(target_date)

    # ── 6b. Game-level HR environment boost (June 2026) ──────────────────────
    # June 4 2026 post-mortem: the model correctly identified WHICH games would
    # produce HRs (CHC/ATH, MIN/KC, MIL/SF, ARI/LAD) but picked wrong individuals.
    # ── PITCHER-FIRST GAME STACKING (Jul 1 2026 redesign) ───────────────────
    # BEFORE: Keyed off game_time — caught ALL batters in a game, including both teams.
    # This is wrong: when Lowder gives up 3 HRs (Chourio, W.Contreras, Bauers), the signal
    # is specifically about LOWDER, not about the Reds' pitcher. The correct unit is the
    # PITCHER, not the game.
    #
    # NEW LOGIC — two-tier pitcher-first design:
    #
    # Tier 1: PITCHER VULNERABILITY CASCADE
    # When a pitcher has BOTH HR-prone L5 (recent_hr_factor ≥1.35) AND command issues L5
    # (l5_bb9 ≥4.5), ALL batters facing them get +2.0 score pts regardless of their own
    # BBE history. This reflects that the pitcher is actively struggling RIGHT NOW —
    # any hitter with reasonable power has elevated HR equity vs a pitcher losing the zone.
    # Lowder Jun 30: 2.37 HR/9 L5 + 6.1 BB/9 L5 → Chourio, W.Contreras, Bauers all HRed.
    # The signal was pitcher-level, not individual batter-level.
    #
    # Tier 2: MULTI-BBE SAME-PITCHER CONFIRMATION
    # When ≥2 batters facing the SAME STARTER each have a T3+ BBE match (individually graded),
    # ALL batters facing that starter get +2.5 score pts. This rewards the model's own
    # pitcher-first evidence: if 2+ batters have independently proven HR contact on this
    # pitcher's weak pitch, the pitcher is structurally vulnerable TODAY, not just for one batter.
    # The boost is pitcher-name keyed — it does NOT spill to the opposing team's batters.
    #
    # The old +1.5 game-time boost is retired; these two targeted boosts are more precise.

    # Tier 1: Pitcher vulnerability cascade
    _pitcher_vuln_cascade: dict = {}   # pitcher_name → (hr_prone, cmd_issues)
    for _sc_g in all_scores:
        _pn = _sc_g.pitcher_name or ""
        if _pn not in _pitcher_vuln_cascade:
            _notes_pv = " ".join(str(n) for n in (_sc_g.notes or []))
            _hr_prone_pv  = "HR-prone L5" in _notes_pv
            _cmd_issues_pv = "Command issues L5" in _notes_pv or "losing zone" in _notes_pv.lower()
            # Jul 1 2026: also trigger cascade on severe velo decline (independent signal)
            _velo_decline_pv = "SEVERE VELO DECLINE" in _notes_pv or (
                "Velo decline L5" in _notes_pv and "EXTREME L2" in _notes_pv
            )
            _pitcher_vuln_cascade[_pn] = (_hr_prone_pv, _cmd_issues_pv, _velo_decline_pv)

    _cascade_pitchers = {
        pn for pn, (hr, cmd, vd) in _pitcher_vuln_cascade.items()
        if (hr and cmd) or vd   # HR-prone + command issues, OR severe velo decline alone
    }
    if _cascade_pitchers:
        _casc_count = len(_cascade_pitchers)
        print(f"  🔥 Pitcher vulnerability cascade: {_casc_count} pitcher(s) with HR-prone L5 + command issues — +3.0 score to all batters facing them")
        for _sc_g in all_scores:
            if (_sc_g.pitcher_name or "") in _cascade_pitchers:
                _sc_g.score = min(_sc_g.score + 3.0, 99.0)
                _sc_g.notes = list(_sc_g.notes or []) + [
                    f"🔥 PITCHER CASCADE: {_sc_g.pitcher_name} is HR-prone L5 + losing zone — "
                    f"elevated HR equity for all batters (+3.0 score, pitcher-first signal)"
                ]

    # Tier 2: Multi-BBE same-pitcher confirmation
    _pitcher_t3_counts: dict = {}   # pitcher_name → count of batters with T3+ BBE match
    for _sc_g in all_scores:
        _pn = _sc_g.pitcher_name or ""
        # hr_grade lives in the sharp dict (not on HRScore directly).
        # Read from notes instead — PTM grades are always injected into sc.notes
        # by score_player() via _ptm_pre_notes (e.g. "PRIME PITCHER TARGET MATCH (FF)",
        # "PITCHER TARGET MATCH HR (T3)", etc.)
        _notes_g2 = " ".join(str(n) for n in (_sc_g.notes or []))
        _is_t3_plus = any(x in _notes_g2 for x in [
            "PRIME PITCHER TARGET MATCH",
            "PITCHER-FIRST MATCH",
            "PITCHER TARGET",
            "T3 MATCH", "T4 MATCH", "T3 CONTACT", "T2 CONTACT",
        ])
        if _is_t3_plus:
            _pitcher_t3_counts[_pn] = _pitcher_t3_counts.get(_pn, 0) + 1

    _multi_bbe_pitchers = {pn for pn, cnt in _pitcher_t3_counts.items() if cnt >= 2}
    if _multi_bbe_pitchers:
        _mb_count = len(_multi_bbe_pitchers)
        print(f"  🔥 Multi-BBE pitcher confirmation: {_mb_count} pitcher(s) with ≥2 T3+ BBE batters — +3.0 score to all batters facing them")
        for _sc_g in all_scores:
            if (_sc_g.pitcher_name or "") in _multi_bbe_pitchers:
                _n_bbe = _pitcher_t3_counts.get(_sc_g.pitcher_name or "", 0)
                _sc_g.score = min(_sc_g.score + 3.0, 99.0)
                _sc_g.notes = list(_sc_g.notes or []) + [
                    f"🎯 MULTI-BBE PITCHER: {_n_bbe} batters have T3+ BBE matches vs "
                    f"{_sc_g.pitcher_name} — pitcher structurally vulnerable TODAY (+3.0 score, pitcher-first)"
                ]

    # ── 7. Console rankings ───────────────────────────────────
    # Primary sort: score descending.
    # Secondary tiebreaker: recent HR rate (last 15 days) — differentiates players
    # from the same team when batter_power hits the 100.0 cap.
    # This prevents identical same-team stacking (e.g. 3 LAD players at 100.0 power).
    # Rank by HR score only — hit score removed from composite.
    # Data: hit score is inversely correlated with HRs and weakly correlated
    # with hits. Mixing it into the HR ranking degraded both use cases.
    ranked_raw = sorted(
        all_scores,
        key=lambda x: (round(x.score, 1), x.hr_probability),
        reverse=True
    )
    # ── Team exposure cap: max MAX_TEAM_EXPOSURE players per team ────────────
    # For teams facing a high-vuln pitcher (vuln >= 57), allow up to 5 picks
    # from that team. High-vuln games produce multiple HR hitters (e.g. 5 HRs
    # off Bello, 4 off Eovaldi) — more coverage = more captures.
    # Game-stack trigger: use implied runs (reliable, calibrated) rather than vuln.
    # Threshold lowered 4.5→4.2 (Jun 17 2026): 4.4 implied (e.g. NYM vs Lodolo in
    # Citi Field 1.20 park) was being capped at 3 players despite a good stack environment.
    # 4.2 is still above the typical 3.9-4.1 average and avoids over-concentration in
    # genuinely weak run environments.
    # Cap raised 5→6 for ≥5.5 runs (the "true stack" environment, e.g. Coors).
    HIGH_IMPL_THRESHOLD  = 4.2
    HIGH_VULN_TEAM_CAP   = 6
    _VULN_STACK_THRESHOLD = 52.0
    _VULN_STACK_CAP       = 5
    # Same-game concentration cap: max 3 per team.
    # May 13 audit: 4 CIN picks in top-6, 0 WSH picks — missed 3 WSH HR hitters.
    # Both teams share the same park/wind conditions.
    SAME_TEAM_MAX = 3
    high_vuln_teams: set = set()
    for sc in ranked_raw:
        if sc.implied_runs >= HIGH_IMPL_THRESHOLD:
            high_vuln_teams.add(sc.team)

    if high_vuln_teams:
        print(f"  🔥 Game stack (impl≥{HIGH_IMPL_THRESHOLD}): {sorted(high_vuln_teams)} teams get expanded cap ({HIGH_VULN_TEAM_CAP}/team)")

    _team_vuln: dict = {}
    for sc in ranked_raw:
        t = sc.team
        if t not in _team_vuln or sc.pitcher_vuln > _team_vuln[t]:
            _team_vuln[t] = sc.pitcher_vuln

    ranked: list = []
    team_counts: dict = {}
    seen_names: set = set()
    for sc in ranked_raw:
        t = sc.team
        if sc.batter_name in seen_names: continue
        if t in high_vuln_teams:
            _team_scores = [x for x in ranked_raw if x.team == t]
            _team_impl = _team_scores[0].implied_runs if _team_scores else 0
            cap = HIGH_VULN_TEAM_CAP if _team_impl >= 5.5 else (SAME_TEAM_MAX + 1)
        elif _team_vuln.get(t, 0) >= _VULN_STACK_THRESHOLD:
            cap = _VULN_STACK_CAP
        else:
            cap = MAX_TEAM_EXPOSURE
        cap = min(cap, SAME_TEAM_MAX + (1 if t in high_vuln_teams else 0))
        # Pitcher-target bypass: T3/T4/PRIME picks with high conviction scores
        # should not be blocked by the team cap — the BBE data confirmed the edge
        # independently of how many teammates are already in the list.
        _sc_grade = getattr(sc, 'hr_grade', '') or ''
        _is_ptm_t3plus = (("PITCHER TARGET MATCH HR" in _sc_grade and
                           any(f"T{n}" in _sc_grade for n in ("3","4")) and
                           getattr(sc, 'conviction_score', 0) >= 30)
                          or "PRIME PITCHER TARGET MATCH HR" in _sc_grade)
        _effective_cap = cap + (1 if _is_ptm_t3plus and team_counts.get(t, 0) >= cap else 0)
        if team_counts.get(t, 0) < _effective_cap:
            ranked.append(sc)
            team_counts[t] = team_counts.get(t, 0) + 1
            seen_names.add(sc.batter_name)
        if len(ranked) >= len(ranked_raw): break
    date_str = target_date.strftime("%B %d, %Y")
    hist_note = " [HISTORICAL -- no PropLine odds]" if is_historical else ""

    # ── L10 BBE promotion: reorder tail of ranked list (Jun 2026) ─────────────
    # Rule: Score > 50 → player earned their spot on raw model quality, keep them.
    #       Score ≤ 50 → their slot is contested. Yield it first to any batter who
    #       has ≥1 HR in their last 10 BBE on a relevant pitch type (L10 BBE signal)
    #       before filling with non-BBE batters. This surfaces legit HR power that
    #       scores below 50 due to model weight limits without inflating all weights.
    #
    # Team caps already applied above — this only reorders within the existing pool.
    # Within each partition, original score order is preserved (stable sort).
    _above_threshold = [sc for sc in ranked if sc.score > 50.0]
    _below_threshold = [sc for sc in ranked if sc.score <= 50.0]

    _bbe_promoted = [sc for sc in _below_threshold
                     if getattr(sc, 'l10_bbe_primary_hr', 0) >= 1]
    _bbe_promoted.sort(
        key=lambda x: (getattr(x, 'l10_bbe_primary_hr', 0),
                       getattr(x, 'ranking_score', x.score)),
        reverse=True
    )
    _bbe_remaining = [sc for sc in _below_threshold
                      if getattr(sc, 'l10_bbe_primary_hr', 0) < 1]

    ranked = _above_threshold + _bbe_promoted + _bbe_remaining
    if _bbe_promoted:
        print(f"  🔥 L10 BBE promotion: {len(_bbe_promoted)} Score≤50 batters "
              f"with ≥1 HR in L10 BBE moved ahead of non-BBE tail "
              f"({len(_above_threshold)} Score>50 slots protected)")

    # ── Marsh-pattern cap bypass: L10 BBE HR ≥ 2 overrides team cap (Jun 2026) ──
    # Players with ≥2 HR in their last 10 BBE on a relevant pitch type (the
    # "Marsh-pattern") represent the strongest recency HR signal in the model.
    # Team caps can silently exclude them even when their signal is elite (e.g.
    # a 3rd BOS batter fills the slot before Abreu's 2-HR SL BBE is evaluated).
    # Fix: scan ranked[TOP_N:] for Marsh picks and pull them into the top-50 pool,
    # bypassing the team cap. Guard rail: max 1 Marsh injection per team so we
    # don't flood a single lineup. The ≥2 HR threshold is the selection gate.
    _marsh_teams: dict = {}   # tracks how many Marsh injections per team
    _marsh_injected: list = []

    # Candidates: any player outside top 50 with ≥2 HR in L10 BBE
    _marsh_candidates = [
        sc for sc in ranked[TOP_N:]
        if getattr(sc, 'l10_bbe_primary_hr', 0) >= 2
    ]
    # Sort best signal first: HR count desc, then ranking_score desc
    _marsh_candidates.sort(
        key=lambda x: (getattr(x, 'l10_bbe_primary_hr', 0),
                       getattr(x, 'ranking_score', x.score)),
        reverse=True
    )

    for _msc in _marsh_candidates:
        _mt = _msc.team
        if _marsh_teams.get(_mt, 0) >= 1:
            continue   # max 1 Marsh injection per team
        _marsh_injected.append(_msc)
        _marsh_teams[_mt] = _marsh_teams.get(_mt, 0) + 1

    if _marsh_injected:
        # Remove Marsh picks from wherever they sit in ranked, then reinsert
        # them at the front of the BBE block (highest priority — ≥2 HR beats ≥1 HR)
        _marsh_names = {sc.batter_name for sc in _marsh_injected}
        ranked = [sc for sc in ranked if sc.batter_name not in _marsh_names]

        # Re-partition and rebuild with Marsh picks leading the BBE tier
        _above_threshold  = [sc for sc in ranked if sc.score > 50.0]
        _below_threshold  = [sc for sc in ranked if sc.score <= 50.0]
        _bbe_ge1 = sorted(
            [sc for sc in _below_threshold if getattr(sc, 'l10_bbe_primary_hr', 0) >= 1],
            key=lambda x: (getattr(x, 'l10_bbe_primary_hr', 0),
                           getattr(x, 'ranking_score', x.score)),
            reverse=True
        )
        _bbe_zero = [sc for sc in _below_threshold
                     if getattr(sc, 'l10_bbe_primary_hr', 0) < 1]
        # Marsh picks (≥2 HR) lead; then ≥1 HR non-Marsh; then the rest
        ranked = _above_threshold + _marsh_injected + _bbe_ge1 + _bbe_zero

        print(f"  🎯 Marsh-pattern injection: {len(_marsh_injected)} player(s) with "
              f"≥2 HR in L10 BBE bypassed team cap into top-50 pool:")
        for _msc in _marsh_injected:
            _mhr = getattr(_msc, 'l10_bbe_primary_hr', 0)
            _mpt = getattr(_msc, 'l10_bbe_primary_pt', '??')
            print(f"     🔥🔥 {_msc.batter_name} ({_msc.team}) — "
                  f"{_mhr} HR in L10 BBE vs {_mpt} | Score {_msc.score:.1f}")

    # ── SUPER NUCLEAR cap bypass: 9/9 PropFinder gates overrides team cap (Jul 2026) ──
    # Scan ranked_raw (all scored batters, pre-cap) so team-cap-excluded batters are
    # found. No team cap — 9/9 is a hard override.
    _sn_names_in_top50 = {sc.batter_name for sc in ranked[:TOP_N]}

    # Debug: show every ranked_raw batter with pf9_gate_count==9 or SUPER NUCLEAR in notes
    _sn_debug = [
        sc for sc in ranked_raw
        if getattr(sc, 'pf9_gate_count', 0) == 9
        or "SUPER NUCLEAR" in " ".join(str(n) for n in (sc.notes or []))
    ]
    if _sn_debug:
        print(f"  🔍 9/9 gate debug — {len(_sn_debug)} batter(s) found in ranked_raw:")
        for _sd in _sn_debug:
            _tag = "✅ in top-50" if _sd.batter_name in _sn_names_in_top50 else "⬆️ needs injection"
            print(f"     {_sd.batter_name} ({_sd.team}) pf9={getattr(_sd,'pf9_gate_count',0)} "
                  f"score={_sd.score:.1f} {_tag}")

    _sn_candidates = [
        sc for sc in ranked_raw
        if sc.batter_name not in _sn_names_in_top50
        and (
            getattr(sc, 'pf9_gate_count', 0) == 9
            or "SUPER NUCLEAR" in " ".join(str(n) for n in (sc.notes or []))
        )
    ]
    _sn_injected = _sn_candidates

    if _sn_injected:
        _sn_inject_names = {sc.batter_name for sc in _sn_injected}
        # Remove injected picks from wherever they already sit in ranked
        ranked = [sc for sc in ranked if sc.batter_name not in _sn_inject_names]
        # Merge injected picks back and re-sort by score
        ranked = ranked + _sn_injected
        ranked.sort(key=lambda x: (round(x.score, 1), x.hr_probability), reverse=True)
        # Guarantee every injected pick is within TOP_N.
        # Collect all that landed outside, remove them all at once, then re-insert
        # them score-sorted into the last slots of the top-N window.
        # This prevents one insertion from overwriting a previous one.
        _outside = sorted(
            [sc for sc in _sn_injected
             if next((i for i, r in enumerate(ranked) if r.batter_name == sc.batter_name), TOP_N) >= TOP_N],
            key=lambda x: x.score, reverse=True
        )
        if _outside:
            _outside_names = {sc.batter_name for sc in _outside}
            # Remove all outside picks from their current positions
            ranked = [sc for sc in ranked if sc.batter_name not in _outside_names]
            # Insert them score-sorted into slots TOP_N-len(_outside) through TOP_N-1
            # so higher-score picks land at better positions within the forced window
            _insert_at = TOP_N - len(_outside)
            for _osc in _outside:  # already sorted score desc
                ranked.insert(_insert_at, _osc)
                _insert_at += 1
        print(f"  🎯 SUPER NUCLEAR injection: {len(_sn_injected)} player(s) with 9/9 PropFinder "
              f"gates guaranteed top-{TOP_N} (team cap bypassed, score-sorted):")
        for _snc in sorted(_sn_injected, key=lambda x: x.score, reverse=True):
            _final_pos = next((i+1 for i, sc in enumerate(ranked[:TOP_N]) if sc.batter_name == _snc.batter_name), '>50')
            print(f"     ☢️☢️ {_snc.batter_name} ({_snc.team}) — 9/9 gates | "
                  f"Conv {getattr(_snc, 'conv_score', 0):.0f} | Score {_snc.score:.1f} → rank #{_final_pos}")

    # Show data source summary
    fl_count = len(fl_players)
    fl_tag = f" | {fl_count} players from FantasyLabs" if fl_count else ""
    # ── Startup version confirmation ───────────────────────────────────────
    print(f"  🔧 Model v{CACHE_VERSION}  |  Cap {MAX_TEAM_EXPOSURE}/team  |  Savant min=1  |  ERA fallback: ON")
    sep2 = "=" * 68
    print(f"\n{sep2}")
    print(f"  TOP {TOP_N} HR PICKS -- {date_str}{hist_note}")
    print(sep2)
    print(f"  {'':4} {'Batter':<22} {'vs Pitcher':<20} {'Odds':>6} {'HR%':>7} {'Score':>7}")
    print("  " + "-" * 65)
    for i, sc in enumerate(ranked[:TOP_N], 1):
        medal = {1: "1st", 2: "2nd", 3: "3rd"}.get(i, f"  {i:2d}")
        odds  = sc.hr_odds_display if sc.hr_odds_display else "  N/A"
        status_tag = "📋" if sc.lineup_status == "projected" else "  "
        _edge_disp = (f"{sc.edge_vs_market:+.1%}" if sc.edge_vs_market != 0 else "  N/A")
        print(f"  {medal:4s} {status_tag} {sc.batter_name:<22} {sc.pitcher_name[:18]:<20} "
              f"{odds:>6} {sc.hr_probability:>6.1%} {sc.score:>6.1f} {_edge_disp:>7}")
    print(sep2 + "\n")

    # ── 8. Save picks to pkl (grade labels + today's picks) ──
    if not is_historical:
        _save_picks_to_pkl(ranked, target_date)

    # ── 8b. Pitcher-First Pitch Correlation Sweep ─────────────────
    # Scans ALL opposing batters (not just top 50) for two-sided pitch
    # correlation vs today's starters — the same signal as CONFIRMED MATCH
    # but applied slate-wide. Surfaces value picks buried by composite score.
    # No new API calls — uses pitch data already loaded into memory.
    if not is_historical and game_contexts:
        print("\n" + "=" * 68)
        print("  🎯 PITCH CORRELATION SWEEP — Full-lineup confirmed match scan")
        print("=" * 68)
        _ranked_names = {sc.batter_name for sc in ranked}
        try:
            _pc_alerts = _run_pitch_corr_sweep(
                game_contexts, batter_obj_cache, pitcher_cache, _ranked_names)
            if _pc_alerts:
                print(f"  {'Batter':<22} {'vs Pitcher':<20} {'Odds':>6}  {'Pitch':>5}  "
                      f"{'P-wOBA':>6}  {'B-wOBA':>6}  {'FB%':>4}  {'PU%':>4}  BZM")
                print("  " + "-" * 76)
                _new_finds = [a for a in _pc_alerts if not a['in_top50']]
                _confirmed = [a for a in _pc_alerts if a['in_top50']]
                if _new_finds:
                    print("  🔍 NEW FINDS (outside top 50):")
                    for a in _new_finds:
                        _bzm_tag = f"  {'⭐'*a['bzm']} {a['bzm_zones']}" if a['bzm'] else ""
                        print(f"  {a['batter']:<22} {a['pitcher'][:18]:<20} {a['odds']:>6}  "
                              f"{a['pitch']:>5}  {a['p_woba']:>6.3f}  {a['b_woba']:>6.3f}  "
                              f"{a['fb_pct']:>3.0f}%  {a['pu_pct']:>3.0f}%{_bzm_tag}")
                if _confirmed:
                    print("  ✅ ALREADY IN TOP 50 (confirmation):")
                    for a in _confirmed:
                        _rank = next((i+1 for i, sc in enumerate(ranked)
                                      if sc.batter_name == a['batter']), '?')
                        _bzm_tag = f"  {'⭐'*a['bzm']} {a['bzm_zones']}" if a['bzm'] else ""
                        print(f"  #{str(_rank):<3} {a['batter']:<20} {a['pitcher'][:18]:<20} "
                              f"{a['odds']:>6}  {a['pitch']:>5}  "
                              f"{a['p_woba']:>6.3f}  {a['b_woba']:>6.3f}{_bzm_tag}")
                if not _new_finds and not _confirmed:
                    print("  No confirmed pitch matches found on today's slate.")
            else:
                print("  No confirmed pitch matches found on today's slate.")
        except Exception as _pce:
            print(f"  ⚠️  Pitch correlation sweep error: {_pce}")
        print("=" * 68 + "\n")

    # ── 9. Export ─────────────────────────────────────────────
    saved_path  = export_excel(ranked, game_contexts, TOP_N, EXPORT_FILE)

    print(f"\nDone! {len(all_scores)} players scored across {len(game_contexts)} games.")
    print(f"Results saved to: {saved_path}\n")

    # ── 10. GitHub Auto-Upload ─────────────────────────────────
    if not is_historical:
        _upload_to_github(saved_path)


if __name__ == "__main__":
    main()